# Module-level SMTP config + smtplib handle so tests can monkeypatch
# app.SMTP_HOST / app.SMTP_USER / app.SMTP_PASS / app.smtplib.SMTP directly.
# (send_magic_link_email / send_portal_welcome_email read os.environ locally
# and are untouched; send_evox_email below uses these module globals.)
import smtplib
SMTP_HOST = os.environ.get("SMTP_HOST")
SMTP_USER = os.environ.get("SMTP_USER")
SMTP_PASS = os.environ.get("SMTP_PASS")


def send_magic_link_email(to_email: str, name: str, magic_url: str) -> tuple:
    # NOTE: auth magic-link (user-requested sign-in) — EXEMPT from email suppression
    # (never lock someone out of account access from a stale/mistaken suppression).
    """Send a magic-link email. Tries (in order):
      1. GHL workflow trigger (if GHL_MAGIC_LINK_WORKFLOW_ID env var is set)
      2. SMTP (if SMTP_HOST/USER/PASS env vars are set)
      3. Console log (development fallback — link visible in Render logs)

    Returns (sent_via, error_or_none).
    """
    subject = "Sign in to Ask Dr. Glen"
    body = (
        f"Hi {name or 'there'},\n\n"
        f"Click the link below to sign in to Ask Dr. Glen. The link expires in "
        f"{AUTH_TOKEN_TTL_LABEL}.\n\n"
        f"{magic_url}\n\n"
        f"If you didn't request this, you can ignore this email.\n\n"
        f"— Dr. Glen Swartwout\n"
    )
    html_body = (
        f"<p>Hi {name or 'there'},</p>"
        f"<p>Click the link below to sign in to Ask Dr. Glen. The link expires in "
        f"{AUTH_TOKEN_TTL_LABEL}.</p>"
        f"<p><a href=\"{magic_url}\">Sign in to Ask Dr. Glen</a></p>"
        f"<p style=\"color:#666;font-size:12px;\">Or paste this URL into your browser: {magic_url}</p>"
        f"<p>If you didn't request this, you can ignore this email.</p>"
        f"<p>— Dr. Glen Swartwout</p>"
    )

    # Path 1: GHL workflow trigger
    if GHL_MAGIC_WORKFLOW:
        try:
            contact_id, _, err = ghl_upsert_contact(to_email, name or "", "",
                                                     source_tag="magic-link-auth")
            if contact_id:
                # Trigger workflow with the magic-link in a custom field
                # NOTE: Shaira must build the workflow in GHL UI:
                #   "Chatbot Magic-Link Send" — single-action workflow that
                #   reads the contact's `magic_link_url` custom value and
                #   sends an email containing it. See
                #   00 System/ghl-magic-link-workflow-spec.md
                _ghl_post(f"/workflows/{GHL_MAGIC_WORKFLOW}/run",
                          {"contactId": contact_id, "customValues": {
                              "magic_link_url": magic_url,
                              "magic_link_expires_min": str(AUTH_TOKEN_TTL_MIN),
                          }})
                return "ghl-workflow", None
        except Exception as e:
            print(f"[auth] GHL magic-link send failed: {e}", flush=True)

    # Path 2: SMTP
    smtp_host = os.environ.get("SMTP_HOST")
    smtp_user = os.environ.get("SMTP_USER")
    smtp_pass = os.environ.get("SMTP_PASS")
    smtp_from = os.environ.get("SMTP_FROM", smtp_user)
    if smtp_host and smtp_user and smtp_pass:
        try:
            import smtplib
            from email.mime.multipart import MIMEMultipart
            from email.mime.text import MIMEText
            msg = MIMEMultipart("alternative")
            msg["Subject"] = subject
            msg["From"]    = smtp_from
            msg["To"]      = to_email
            msg.attach(MIMEText(body, "plain"))
            msg.attach(MIMEText(html_body, "html"))
            port = int(os.environ.get("SMTP_PORT", "587"))
            with smtplib.SMTP(smtp_host, port, timeout=10) as s:
                s.starttls()
                s.login(smtp_user, smtp_pass)
                s.sendmail(smtp_from, [to_email], msg.as_string())
            return "smtp", None
        except Exception as e:
            print(f"[auth] SMTP magic-link send failed: {e}", flush=True)

    # Path 3: console fallback (development / pre-config)
    print(f"\n[auth] MAGIC LINK for {to_email}: {magic_url}\n", flush=True)
    return "console-log", "no email send mechanism configured"


def _send_token_alert(subject: str, body: str) -> bool:
    """One-off operational alert over SMTP (independent of the Gmail token).
    Recipient = ALERT_EMAIL env, else SMTP_USER. Returns whether it sent."""
    to_email = os.environ.get("ALERT_EMAIL") or os.environ.get("SMTP_USER")
    host = os.environ.get("SMTP_HOST")
    user = os.environ.get("SMTP_USER")
    pw = os.environ.get("SMTP_PASS")
    frm = os.environ.get("SMTP_FROM", user)
    if not (to_email and host and user and pw):
        print(f"[token-alert] SMTP not configured; would send: {subject}", flush=True)
        return False
    try:
        import smtplib
        from email.mime.text import MIMEText
        msg = MIMEText(body, "plain")
        msg["Subject"] = subject
        msg["From"] = frm
        msg["To"] = to_email
        with smtplib.SMTP(host, int(os.environ.get("SMTP_PORT", "587")), timeout=10) as s:
            s.starttls()
            s.login(user, pw)
            s.sendmail(frm, [to_email], msg.as_string())
        return True
    except Exception as e:
        print(f"[token-alert] SMTP send failed: {e}", flush=True)
        return False


def send_evox_setup_link(to_email: str, name: str, setup_url: str) -> tuple:
    """Send the EVOX setup link. Mirrors send_magic_link_email's 3-tier cascade
    (GHL workflow -> SMTP -> console-log). The setup_url carries the client's
    portal token, so this link is emailed to the account owner ONLY — it is never
    returned to the (unauthenticated) /api/evox/start caller.
    Returns (sent_via, error_or_none).
    """
    subject = "Your EVOX setup link"
    body = (
        f"Hi {name or 'there'},\n\n"
        f"Click the link below on this device to set up your EVOX remote session.\n\n"
        f"{setup_url}\n\n"
        f"If you didn't request this, you can ignore this email.\n\n"
        f"— Dr. Glen Swartwout\n"
    )
    html_body = (
        f"<p>Hi {name or 'there'},</p>"
        f"<p>Click the link below on this device to set up your EVOX remote session.</p>"
        f"<p><a href=\"{setup_url}\">Set up your EVOX session</a></p>"
        f"<p style=\"color:#666;font-size:12px;\">Or paste this URL into your browser: {setup_url}</p>"
        f"<p>If you didn't request this, you can ignore this email.</p>"
        f"<p>— Dr. Glen Swartwout</p>"
    )

    # Path 1: GHL workflow trigger (reuse the magic-link workflow channel)
    if GHL_MAGIC_WORKFLOW:
        try:
            contact_id, _, err = ghl_upsert_contact(to_email, name or "", "",
                                                     source_tag="evox-setup-link")
            if contact_id:
                _ghl_post(f"/workflows/{GHL_MAGIC_WORKFLOW}/run",
                          {"contactId": contact_id, "customValues": {
                              "magic_link_url": setup_url,
                          }})
                return "ghl-workflow", None
        except Exception as e:
            print(f"[evox] GHL setup-link send failed: {e}", flush=True)

    # Path 2: SMTP
    smtp_host = os.environ.get("SMTP_HOST")
    smtp_user = os.environ.get("SMTP_USER")
    smtp_pass = os.environ.get("SMTP_PASS")
    smtp_from = os.environ.get("SMTP_FROM", smtp_user)
    if smtp_host and smtp_user and smtp_pass:
        try:
            import smtplib
            from email.mime.multipart import MIMEMultipart
            from email.mime.text import MIMEText
            msg = MIMEMultipart("alternative")
            msg["Subject"] = subject
            msg["From"]    = smtp_from
            msg["To"]      = to_email
            msg.attach(MIMEText(body, "plain"))
            msg.attach(MIMEText(html_body, "html"))
            port = int(os.environ.get("SMTP_PORT", "587"))
            with smtplib.SMTP(smtp_host, port, timeout=10) as s:
                s.starttls()
                s.login(smtp_user, smtp_pass)
                s.sendmail(smtp_from, [to_email], msg.as_string())
            return "smtp", None
        except Exception as e:
            print(f"[evox] SMTP setup-link send failed: {e}", flush=True)

    # Path 3: console fallback (development / pre-config)
    print(f"\n[evox] SETUP LINK for {to_email}: {setup_url}\n", flush=True)
    return "console-log", "no email send mechanism configured"


def send_portal_welcome_email(to_email, name, login_url):
    """Send the one-time 'your portal is ready' welcome. Mirrors
    send_magic_link_email's cascade (GHL workflow -> SMTP -> console-log).
    Pure network/IO; the caller (_member_join_welcome) has already checked
    suppression + the once-per-email guard. Returns (sent_via, error_or_none).
    """
    from dashboard import portal_welcome as _pw
    subject, body, html_body = _pw.welcome_email_content(name, login_url)

    # Path 0: bulk router — GHL v2 (Mailgun-backed sending domain) when configured, else
    # Gmail — so onboarding email stops consuming the consumer-Gmail daily quota that
    # transactional mail (invoices) needs. Only active when BULK_VIA_GHL is set; on any
    # failure it falls through to the legacy cascade below.
    if os.environ.get("BULK_VIA_GHL"):
        try:
            from dashboard import inbox as _inbox
            res = _inbox.send_bulk(to_email, subject, body,
                                   from_name="Dr. Glen Swartwout", html=html_body)
            via = res.get("via") or ("skipped:" + res["skipped"] if res.get("skipped") else "gmail")
            return via, None
        except Exception as e:
            print(f"[welcome] bulk-router send failed, trying legacy cascade: {e}", flush=True)

    # Path 1: GHL workflow trigger (reuse the magic-link workflow channel)
    if GHL_MAGIC_WORKFLOW:
        try:
            contact_id, _, err = ghl_upsert_contact(to_email, name or "", "",
                                                     source_tag="portal-welcome")
            if contact_id:
                _ghl_post(f"/workflows/{GHL_MAGIC_WORKFLOW}/run",
                          {"contactId": contact_id, "customValues": {
                              "magic_link_url": login_url,
                          }})
                return "ghl-workflow", None
        except Exception as e:
            print(f"[welcome] GHL send failed: {e}", flush=True)

    # Path 2: SMTP
    smtp_host = os.environ.get("SMTP_HOST")
    smtp_user = os.environ.get("SMTP_USER")
    smtp_pass = os.environ.get("SMTP_PASS")
    smtp_from = os.environ.get("SMTP_FROM", smtp_user)
    if smtp_host and smtp_user and smtp_pass:
        try:
            import smtplib
            from email.mime.multipart import MIMEMultipart
            from email.mime.text import MIMEText
            msg = MIMEMultipart("alternative")
            msg["Subject"] = subject
            msg["From"]    = smtp_from
            msg["To"]      = to_email
            msg.attach(MIMEText(body, "plain"))
            msg.attach(MIMEText(html_body, "html"))
            port = int(os.environ.get("SMTP_PORT", "587"))
            with smtplib.SMTP(smtp_host, port, timeout=10) as s:
                s.starttls()
                s.login(smtp_user, smtp_pass)
                s.sendmail(smtp_from, [to_email], msg.as_string())
            return "smtp", None
        except Exception as e:
            print(f"[welcome] SMTP send failed: {e}", flush=True)

    # Path 3: console fallback
    print(f"\n[welcome] PORTAL WELCOME for {to_email}: {login_url}\n", flush=True)
    return "console-log", "no email send mechanism configured"


def send_evox_email(to_email, name, subject, html_body, text_body, ics_bytes):
    """Three-tier send with an .ics attachment. GHL tier skipped (no attachment path)."""
    if not (SMTP_HOST and SMTP_USER and SMTP_PASS):
        app.logger.info("EVOX email (console fallback) to %s: %s", to_email, subject)
        return ("console-log", "no email send mechanism configured")
    from email.mime.multipart import MIMEMultipart
    from email.mime.text import MIMEText
    from email.mime.base import MIMEBase
    from email import encoders
    msg = MIMEMultipart("mixed")
    msg["Subject"] = subject
    msg["From"] = SMTP_USER
    msg["To"] = to_email
    alt = MIMEMultipart("alternative")
    alt.attach(MIMEText(text_body, "plain"))
    alt.attach(MIMEText(html_body, "html"))
    msg.attach(alt)
    part = MIMEBase("text", "calendar", method="REQUEST", name="invite.ics")
    part.set_payload(ics_bytes)
    encoders.encode_base64(part)
    part.add_header("Content-Disposition", "attachment", filename="invite.ics")
    msg.attach(part)
    port = int(os.environ.get("SMTP_PORT", "587"))
    with smtplib.SMTP(SMTP_HOST, port) as s:
        s.starttls(); s.login(SMTP_USER, SMTP_PASS)
        s.sendmail(SMTP_USER, [to_email], msg.as_string())
    return ("smtp", None)


