def _member_join_welcome(cx, email, source=None):
    """Best-effort: send the one-time portal welcome on a membership join.
    Called from both join chokepoints (_grant_membership + each create_membership
    site). Excludes the $1 biofield trial, respects suppression, and sends at most
    once per email (guard). DB work runs here on the request connection; the
    network send runs in a daemon thread so the join flow never blocks on SMTP.
    Never raises.
    """
    try:
        em = (email or "").strip().lower()
        if not em:
            return
        if source == "biofield_trial":
            return  # $1 biofield trial is not a member join (per spec)
        try:
            from dashboard import email_suppression as _es
            if _es.is_suppressed(cx, em):
                print(f"[welcome] suppressed, skip {em}", flush=True)
                return
        except Exception as _se:
            print(f"[welcome] suppression check failed: {_se!r}", flush=True)
        from dashboard import portal_welcome as _pw
        if not _pw.mark_welcome_sent(cx, em):
            return  # already sent
        name = ""
        try:
            row = cx.execute("SELECT name FROM people WHERE lower(email)=lower(?)", (em,)).fetchone()
            if row and row[0]:
                name = row[0]
        except Exception:
            pass
        login_url = portal_base() + "/portal/login"
        threading.Thread(
            target=send_portal_welcome_email, args=(em, name, login_url), daemon=True
        ).start()
    except Exception as _e:
        print(f"[welcome] _member_join_welcome skipped: {_e!r}", flush=True)


def _send_portal_welcome(email, name, token):
    """Best-effort: send a one-time portal welcome after a portal is minted at
    order time. Suppression-aware, once-guarded, never raises. Network send runs
    in a daemon thread so the caller (order ingest) is never blocked."""
    em = (email or "").strip().lower()
    if not em or not token:
        return
    try:
        from dashboard import email_suppression as _es
        with _db_lock, sqlite3.connect(LOG_DB) as cx:
            _es.init_table(cx)
            if _es.is_suppressed(cx, em):
                return
            # Dedicated once-guard for the order-time PORTAL TOKEN link. Kept
            # SEPARATE from the membership-join /portal/login welcome guard so a
            # member who later buys still receives their token link.
            cx.execute("CREATE TABLE IF NOT EXISTS portal_token_welcome_sent ("
                       "email TEXT PRIMARY KEY, sent_at TEXT)")
            cur = cx.execute(
                "INSERT OR IGNORE INTO portal_token_welcome_sent (email, sent_at) VALUES (?, ?)",
                (em, datetime.now(timezone.utc).isoformat()))
            if cur.rowcount == 0:   # token link already sent to this email
                return
        url = portal_link(token)
        body = (f"Aloha {name or ''},\n\nYour personal healing home is ready:\n\n{url}\n\n"
                f"It is where your remedies, protocol, and your concierge live. "
                f"Reply anytime.\n\nWith aloha,\nDr. Glen & Rae")
        import threading
        threading.Thread(target=_send_full_report_email,
                         args=(em, name, "Your healing home is ready \U0001f33a", body),
                         daemon=True).start()
    except Exception as e:
        print(f"[portal-welcome] {em}: {e!r}", flush=True)


def _link_resend_generic(purpose, url_template, ttl):
    """Factory: mint a fresh `purpose` token (preserving extra) and email its URL."""
    def handler(email, extra):
        tok = secrets.token_urlsafe(32)
        now = datetime.now(timezone.utc)
        with _db_lock, sqlite3.connect(LOG_DB) as cx:
            cx.execute("CREATE TABLE IF NOT EXISTS auth_tokens "
                       "(token_hash TEXT, email TEXT, purpose TEXT, extra TEXT, "
                       "created_at TEXT, expires_at TEXT, consumed_at TEXT)")
            cx.execute("INSERT INTO auth_tokens (token_hash, email, purpose, extra, created_at, expires_at) "
                       "VALUES (?,?,?,?,?,?)",
                       (_hash_token(tok), email, purpose, extra, now.isoformat(), (now + ttl).isoformat()))
            cx.commit()
        send_magic_link_email(email, "", f"{PUBLIC_BASE_URL}" + url_template.format(token=tok))
    return handler


def _household_cc_report(member_email, member_label_or_subject):
    """Best-effort: send a private 'a new report is available for <member>' copy to each
    caregiver who is consented + cc-subscribed for this member. Points them to their own
    portal (no member token forwarded, no shared Cc header — addresses aren't cross-exposed)."""
    if not _household_sharing_enabled():
        return
    try:
        from dashboard import household as _hh
        with sqlite3.connect(LOG_DB) as cx:
            _hh.init_household_tables(cx)
            recips = _hh.cc_recipients_for(cx, (member_email or "").strip().lower())
        for care in recips:
            subj = "A new biofield report is available for someone in your care"
            body = ("A new biofield report was just published for a member of your household. "
                    f"Open your portal to view it.\n\n{portal_base()}/portal/login")
            try:
                _send_inquiry_email(care, subj, body)
            except Exception as _e:
                print(f"[household-cc] report copy to {care}: {_e!r}", flush=True)
    except Exception as _e:
        print(f"[household-cc] report fanout: {_e!r}", flush=True)


def _send_reveal_link(rid):
    """Mint a fresh reveal token (biofield_reveals.token_hash + auth_tokens), email the
    'ready' link, and mark notified only on a successful send. Returns True if sent.
    SMTP runs outside the db lock. No approval gate (callers decide)."""
    from dashboard import biofield_reveals as _br
    with _db_lock, sqlite3.connect(LOG_DB) as cx:
        _br.init_table(cx)
        row = cx.execute("SELECT email FROM biofield_reveals WHERE id=?", (rid,)).fetchone()
        if not row or not row[0]:
            return False
        email = row[0]
        # Suppression guard: reveal-ready emails go via _send_inquiry_email (which is
        # exempt as a low-level sender), so guard the client-facing reveal path here —
        # never email / mint a token for a suppressed (hard-bounced) address.
        from dashboard import email_suppression as _es
        _es.init_table(cx)
        if _es.is_suppressed(cx, email):
            print(f"[suppressed] skip reveal link to {email}", flush=True)
            return False
        tok = secrets.token_urlsafe(32)
        _br.set_token(cx, rid, _hash_token(tok))
        now = datetime.now(timezone.utc)
        cx.execute("INSERT INTO auth_tokens (token_hash, email, purpose, created_at, expires_at) "
                   "VALUES (?,?,?,?,?)",
                   (_hash_token(tok), email, "biofield_reveal", now.isoformat(),
                    (now + timedelta(days=30)).isoformat()))
        cx.commit()
    url = f"{PUBLIC_BASE_URL}/begin/biofield/{tok}"
    body = ("Aloha,\n\nYour Biofield Analysis is ready. View your reading here:\n"
            f"{url}\n\nIn wellness,\nDr. Glen and Rae\n")
    sent = _send_inquiry_email(email, "Your Biofield Analysis is ready", body)
    if sent:
        with _db_lock, sqlite3.connect(LOG_DB) as cx:
            _br.set_notified(cx, rid)
        try:
            _household_cc_report(email, None)
        except Exception as _e:
            print(f"[household-cc] report fanout call: {_e!r}", flush=True)
    return bool(sent)


def _resend_biofield_reveal(email, extra):
    """Resend path (not approval-gated): find the latest reveal for the email and send it."""
    from dashboard import biofield_reveals as _br
    with _db_lock, sqlite3.connect(LOG_DB) as cx:
        _br.init_table(cx)
        row = cx.execute("SELECT id FROM biofield_reveals WHERE email=? ORDER BY id DESC LIMIT 1",
                         (email,)).fetchone()
    if not row:
        return
    _send_reveal_link(row[0])


def _resend_inquiry_reply(inquiry_id, practitioner_id):
    """Mint a fresh inquiry reply token for (inquiry_id, practitioner_id) and email the
    practitioner the secure reply link. No-op if the practitioner is unknown."""
    with _db_lock, sqlite3.connect(LOG_DB) as cx:
        prow = cx.execute(
            "SELECT practitioner_email FROM inquiry_practitioners "
            "WHERE inquiry_id=? AND practitioner_id=? AND practitioner_email IS NOT NULL "
            "AND practitioner_email <> '' ORDER BY email_sent_at DESC LIMIT 1",
            (inquiry_id, practitioner_id)).fetchone()
        if not prow:
            return
        pmail = prow[0]
        tok = secrets.token_urlsafe(32)
        now = datetime.utcnow()
        cx.execute("INSERT OR REPLACE INTO inquiry_reply_tokens "
                   "(token_hash, inquiry_id, practitioner_id, created_at, expires_at) VALUES (?,?,?,?,?)",
                   (_hash_token(tok), inquiry_id, practitioner_id,
                    now.isoformat() + "Z", (now + timedelta(days=30)).isoformat() + "Z"))
        cx.commit()
    url = f"{PUBLIC_BASE_URL}/inquiries/{inquiry_id}/{practitioner_id}/reply?token={tok}"
    body = ("Aloha,\n\nHere is your fresh secure reply link for this inquiry:\n"
            f"{url}\n\nIn wellness,\nDr. Glen\n")
    _send_inquiry_email(pmail, "Your fresh reply link", body)


