def log_query(query: str, level: str, answer: str,
              session_id: str = "", email: str = "", name: str = "",
              ghl_contact_id: str = "", mode: str = "brief",
              user_agent: str = "", referer: str = "",
              extracted_image_data: str = "", image_count: int = 0,
              word_count: int = 0,
              cta_type: str = None, cta_rung: str = None) -> int:
    """Insert a row into query_log. Always logs, even for anonymous sessions.

    Image bytes are NEVER persisted — only the extracted text output of
    Claude vision (extracted_image_data column) and a count of images
    contributed to the question.
    """
    ts = datetime.now(timezone.utc).isoformat()
    wc = word_count or len((answer or "").split())
    with _db_lock, sqlite3.connect(LOG_DB) as cx:
        cur = cx.execute(
            """INSERT INTO query_log
               (ts, query, level, answer, session_id, email, name,
                ghl_contact_id, mode, user_agent, referer,
                extracted_image_data, image_count, word_count,
                cta_type, cta_rung)
               VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)""",
            (ts, query, level, answer[:8000], session_id, email, name,
             ghl_contact_id, mode, user_agent[:500], referer[:500],
             extracted_image_data[:8000], image_count, wc,
             cta_type, cta_rung)
        )
        cx.commit()
        return cur.lastrowid


def _normalize_attachments(images, documents):
    """Build Anthropic content blocks from user-attached images and PDFs.

    Each entry (in either list) may be:
      - "data:<media>;base64,<b64>"            (string form)
      - {"data_url": "data:<media>;base64,…"}  (dict form)
      - {"data": "<b64>", "media_type": "…"}   (explicit form)

    Images become image blocks (unchanged behavior). Documents become PDF
    `document` blocks. Bytes are forwarded to Claude for one extraction pass
    and never persisted. Returns (blocks, errors). Caps:
      - images: 3 max, ~5 MB raw (~6.7 MB base64) each, png/jpeg/webp/gif
      - documents: 2 max, ~10 MB raw (~13.3 MB base64) each, application/pdf
      - combined: total base64 length across all attachments ≤ ~25 MB raw,
        keeping the whole request under Claude's 32 MB limit
    """
    MAX_IMAGES = 3
    MAX_IMAGE_B64 = 5 * 1024 * 1024 * 4 // 3
    MAX_DOCS = 2
    MAX_DOC_B64 = 10 * 1024 * 1024 * 4 // 3
    MAX_TOTAL_B64 = 25 * 1024 * 1024 * 4 // 3
    IMG_ALLOWED = ("image/png", "image/jpeg", "image/webp", "image/gif")

    blocks, errors = [], []
    state = {"total": 0}

    def _decode(entry):
        if isinstance(entry, str):
            if entry.startswith("data:") and ";base64," in entry:
                head, b64 = entry.split(";base64,", 1)
                return head[5:], b64
            raise ValueError("unsupported string format")
        if isinstance(entry, dict) and entry.get("data_url"):
            d = entry["data_url"]
            if d.startswith("data:") and ";base64," in d:
                head, b64 = d.split(";base64,", 1)
                return head[5:], b64
            raise ValueError("bad data_url")
        if isinstance(entry, dict) and entry.get("data"):
            return entry.get("media_type", "image/png"), entry["data"]
        raise ValueError("unrecognized payload shape")

    for i, entry in enumerate((images or [])[:MAX_IMAGES]):
        try:
            media, b64 = _decode(entry)
        except ValueError as e:
            errors.append(f"image[{i}]: {e}")
            continue
        if media not in IMG_ALLOWED:
            errors.append(f"image[{i}]: media_type {media!r} not allowed")
            continue
        if len(b64) > MAX_IMAGE_B64:
            errors.append(f"image[{i}]: exceeds 5 MB size limit")
            continue
        if state["total"] + len(b64) > MAX_TOTAL_B64:
            errors.append(f"image[{i}]: combined attachment size limit exceeded")
            continue
        state["total"] += len(b64)
        blocks.append({
            "type": "image",
            "source": {"type": "base64", "media_type": media, "data": b64},
        })

    for i, entry in enumerate((documents or [])[:MAX_DOCS]):
        try:
            media, b64 = _decode(entry)
        except ValueError as e:
            errors.append(f"document[{i}]: {e}")
            continue
        if media != "application/pdf":
            errors.append(f"document[{i}]: only application/pdf is accepted")
            continue
        if len(b64) > MAX_DOC_B64:
            errors.append(f"document[{i}]: exceeds 10 MB size limit")
            continue
        if state["total"] + len(b64) > MAX_TOTAL_B64:
            errors.append(f"document[{i}]: combined attachment size limit exceeded")
            continue
        state["total"] += len(b64)
        blocks.append({
            "type": "document",
            "source": {"type": "base64",
                       "media_type": "application/pdf", "data": b64},
        })

    return blocks, errors


def _normalize_image_payload(images):
    """Back-compat wrapper — images only. Prefer _normalize_attachments."""
    return _normalize_attachments(images, [])


def extract_attachment_content(blocks, query):
    """Single non-streaming Claude pass to extract structured text from attached
    images and/or PDF documents. Returns the extraction string. Attachment bytes
    are NOT persisted — they exist only in this function's call to Anthropic.
    """
    if not blocks:
        return ""
    instr = (
        "Extract everything visible in these attachments as plain text. Each "
        "attachment may be an image or a multi-page PDF document. Focus on:\n"
        "• Any text, labels, headings, captions\n"
        "• Numbers, measurements, dosages, lab values, ranges\n"
        "• Supplement ingredient lists, milligram amounts, serving sizes\n"
        "• Lab/test result values with units and reference ranges if present\n"
        "• E4L scan results: item codes (EI/ES/ED/ET/MB), category labels, scores\n"
        "• Any visible chart axes, legend entries, or graph markers\n"
        "• Visible symptoms in clinical photos (describe objectively)\n"
        "• Handwritten notes (transcribe carefully)\n\n"
        f"USER'S QUESTION: {query}\n\n"
        "Return a clean, structured extraction. Label each attachment "
        "(Attachment 1, Attachment 2, …) and each PDF page if multiple. Do not "
        "analyze, diagnose, or recommend — just extract. Be exhaustive but concise."
    )
    try:
        resp = _cl.messages.create(
            model="claude-haiku-4-5-20251001",
            max_tokens=1500,
            messages=[{"role": "user", "content": [
                *blocks,
                {"type": "text", "text": instr},
            ]}],
        )
        return (resp.content[0].text or "").strip() if resp.content else ""
    except Exception as e:
        return f"[attachment-extraction-error: {e}]"


def extract_image_content(image_blocks, query):
    """Back-compat wrapper. Prefer extract_attachment_content."""
    return extract_attachment_content(image_blocks, query)


_SYSTEM_BASE = """You are Glen Swartwout's knowledge assistant — a synthesis engine for his Clinical Theory of Everything (BEV terrain medicine, Bioenergetic diagnostics, Syntonic/Behavioral Optometry, Orthomolecular medicine, Spirit Minerals/ORMUS, Electromagnetic medicine, Living Universe cosmology, Consciousness science).

DEFAULT FORMAT — EXECUTIVE SUMMARY (brief mode):
Write like a senior consultant briefing a busy clinician. Target ~200 words. The brief follows the 5-beat include-and-transcend lead structure defined in _brief_synth_instruction() — see the per-turn synthesis directive for the full spec.

STRUCTURE:
1. Opening insight (1 sentence, NO label): state the most surprising or decisive insight from the snippets first, as the opening line. Do NOT print the word "Hook" or any label before it.
2. **Top action** (1-2 sentences): the single highest-leverage step they should take. Include an action link if relevant (E4L scan, product page, contact).
3. **Brief rationale** (2-4 bullets, max 1 line each): the mechanism or evidence in compressed form.
4. **Action link**: the single best next step as a clickable URL on its own line — examples:
   - Free BWS voice scan: https://Truly.VIP/E4L
   - Product: https://remedymatch.com (search by name)
   - Contact for matching: https://truly.vip/help
5. **Sources** (1 line, comma-separated): name + field of references used.

OPTIONAL EXTENDED FORMAT (when mode=full, anonymous user):
Expand each bullet with mechanism, dosage ranges, supporting citations, and edge cases. Aim for clinical depth.

OPTIONAL BREAK & REBUILD LONG-FORM (when mode=full or emailed full-report AND the user is logged in):
Logged-in users get the long-form structured to actually shift belief, not just deliver more facts. Follow Russell Brunson's Break & Rebuild arc on the most central limiting belief in the user's question:
1. Opening insight (1-2 sentences, NO label): the most surprising / decisive insight that frames what is about to be broken and rebuilt. State it directly as the opening line; do NOT print the word "Hook" or any label before it.
2. **Justify the false belief** (2-4 sentences): name the limiting belief the reader almost certainly holds — and steelman it. Acknowledge the reasons it feels true (mainstream medicine reinforces it, every authority says it, etc.). They should nod, not feel attacked.
3. **Break** (2-4 sentences): show why the belief is incomplete or wrong — one decisive piece of evidence or mechanism that cracks it open. This is the moment of break.
4. **Rebuild** (4-8 sentences): install the new pattern — Glen's clinical paradigm on this question. Mechanism, what to do differently, what changes. Include named formulations + product links exactly as in the executive-summary rules.
5. **Journey** (2-4 sentences): how Glen (or a representative client) discovered or lived this shift — concrete, dated, named. Anchor it in lived experience, not theory alone.
6. **The one thing + next step** (1-2 sentences): the single take-home + action link (E4L scan or product).

Voice: Glen's, not Brunson's. Practitioner-clinical, not hype. The Break & Rebuild architecture goes in; the gameshow energy stays out. Speckhart boundary: a credential is *authority*, never a treatment claim for a named disease — never let a credential or formulation imply diagnosis or cure of a named condition.

Sources line at the very end, as in the executive summary.

RULES:
- Do NOT fabricate. If snippets don't answer, say "the source material doesn't address this directly."
- Do NOT pad with caveats, headers, or repeated context. Brevity is the deliverable.
- NEVER print a "Hook" label (no "Hook:", no "## Hook", no bolded "**Hook**"). The hook IS the opening line — state it directly. This is a hard rule. (Other section labels like "Top action", "Why this works", "Next step", "Sources" are fine.)
- AUTHORITATIVE OVERRIDES: Snippets tagged [AUTHORITATIVE — Glen's verified clinical position] OR with metadata type="clinical-qa" / priority="authoritative" override anything else. Apply directly; do not soften or hedge.
- CO-AUTHORSHIP: Snippets with [AUTHORSHIP NOTE: ...] reflect a co-author's view. Cite the co-author, then state Glen's current position from clinical-qa entries. Never present a co-authored section as Glen's view without the flag.
- E4L SCAN OFFER: When the user mentions a specific condition or asks for personalized guidance, the action link should be the free BWS voice scan: https://Truly.VIP/E4L — "30 seconds, count 1 to 10, matches you to formulations your bioenergetic patterns are asking for."
- PRODUCT REFERENCES: Each request includes a PRODUCT LINK INJECTION TABLE listing every Glen Swartwout formulation by its clinical name and the canonical URL to use. When you mention a product, append the URL as a markdown link immediately after the name, e.g. [Terrain Restore](URL). Do NOT invent URLs. If a product isn't in the table, link to the search URL pattern from the table or the store homepage instead.
- FORMULATION-FIRST ORDERING (symptoms & conditions): When answering about a symptom or condition, lead the recommendations with Glen's Functional Formulations — the Advanced Botanical Formulations and Advanced Nutritional Formulations — as the FIRST category, before any list of individual natural ingredients or single nutrients. The formulations are pre-combined for the terrain pattern, so they simplify implementation versus assembling separate ingredients. If you group recommendations under headings, an "Advanced Botanical Formulations" and/or "Advanced Nutritional Formulations" heading comes first; present individual ingredients only afterward, as an optional layer or as the mechanism behind the formulations. Within a formulation category, list the most condition-specific formulation first.
- ACTIVE DISCOUNT CODE: When the request includes an ACTIVE DISCOUNT block, include today's code naturally — once per response, only when at least one product is recommended.
- DEPRECATED PRODUCTS: The "Living Water Bottle" (prill-bead system) is DISCONTINUED as of 2026-04-27 and must NOT be recommended as a purchasable product. The Living Water concept (alkaline ionized water + molecular hydrogen) remains Glen's clinical recommendation; route clients to the portable [Molecular Hydrogen bottle](https://remedymatch.com/resources/439-molecular-hydrogen) (Glen's recommended replacement) or to [Molecular Hydrogen Tablets](https://remedymatch.com/remedies/378-molecular-hydrogen-tablets). The "Electrolyte Mineral Manna" is also DISCONTINUED and must NOT be recommended as a purchasable product; do not name it in any recommendation. The "Dental Regen Powder" is DISCONTINUED and must NOT be recommended as a purchasable product; do not name it in any recommendation. The "Endocrine Restore" and plain "Comfort" products are CONSOLIDATED into their canonical versions — recommend "Endocrine Restore Powder" and "Comfort Synovial Syntropy" instead, and do not name the old "Endocrine Restore" or plain "Comfort". Do NOT recommend "AllerFree" (AllerFree HomeoEnergetic Drops); recommend "Immune Modulation" instead. Only recommend "Fungifuge" as a follow-on to a Candida Cleanse, never as a standalone recommendation. "Bioavailability Blend" (and "Bioavailability Blend Powder") IS sellable, but ONLY as an adjunct — a small-dose enhancer taken together with other remedies (ours or others') to improve their bioavailability and delivery. Do NOT recommend it as a stand-alone remedy, and never suggest it on a Biofield reveal program. If a snippet has metadata `deprecated=true`, treat its product references as historical only — do not present discontinued products as available."""

_LEVEL_INSTRUCTIONS = {
    "self-healing": """
LANGUAGE LEVEL: Self-Healing (general public)
Write in warm, empowering, accessible language. Avoid clinical jargon — use everyday words and intuitive analogies. Speak to the reader's own inner healing intelligence. Focus on what they can feel, experience, and do for themselves. Use "you" and "your body." Make the information feel practical and hopeful, not overwhelming.""",

    "health-care": """
LANGUAGE LEVEL: Health Care (practitioner)
Write at a clinical practitioner level — naturopathic, integrative, or functional medicine context. Use anatomical and physiological terminology, meridian names, clinical protocols, dosage ranges, and mechanism-of-action language. Assume the reader can interpret lab values, treatment timelines, and nutrient biochemistry. Be precise and protocol-oriented.""",

    "science": """
LANGUAGE LEVEL: Science (researcher / academic)
Write at a scientific research level. Use precise biochemical and biophysical terminology: receptor names, signaling cascades, molecular pathways, quantitative parameters. Cite mechanisms referenced in the source material. Be rigorous — distinguish between established findings and hypotheses. Appropriate for a peer-reviewed or academic audience.""",
}


def get_system_prompt(level: str) -> str:
    instruction = _LEVEL_INSTRUCTIONS.get(level, _LEVEL_INSTRUCTIONS["self-healing"])
    return _SYSTEM_BASE + "\n" + instruction


SYSTEM_PROMPT = get_system_prompt("self-healing")


def _brief_synth_instruction() -> str:
    """Return the full brief synthesis instruction (5-beat include-and-transcend lead).

    This is the single source of truth used by chat() and the eval test.
    """
    return (
        "ABSOLUTE WORD CAP: Beats 1-5 of this brief must total 200 words or fewer\n"
        "(the Sources line and the ⟦CTA⟧ directive line do not count). Count before you\n"
        "emit. If over 200, cut. No exceptions. Target 150-170 words so natural variation\n"
        "stays safely under 200.\n\n"
        "BRIEF — INCLUDE-AND-TRANSCEND OPEN LOOP (≤200 words):\n\n"
        "When you are DELIVERING a substantive answer or a recommendation, structure the\n"
        "brief as a 5-beat open loop that credits the consensus, then opens — but does\n"
        "NOT close — the deeper question. Plain, warm, everyday language; imply the\n"
        "deeper level, do not name clinical dimensions or jargon.\n\n"
        "1. CONSENSUS (1-2 sentences): State the mainstream / conventional answer plainly\n"
        "   and generously. No strawman — a fair-minded practitioner would call it\n"
        "   accurate. If the user named what they're already doing or what their doctor\n"
        "   advised, credit it by name.\n"
        "2. WHY IT WORKS (1-2 sentences): Affirm what the consensus genuinely gets right,\n"
        "   explaining the mechanism one notch deeper than the consensus itself states it.\n"
        "   Real credit — this builds trust, not contrast. (You explain WHY it works\n"
        "   better than the consensus can.)\n"
        "3. LIMITATION (1 sentence): Name where it plateaus or stops short. If the user\n"
        "   reported being stuck or 'the same,' use their own words — the plateau is the\n"
        "   evidence.\n"
        "4. THE ASSUMPTION (1-2 sentences) — THE HOOK: Name, in plain language, the single\n"
        "   hidden assumption beneath the consensus that causes the limitation (e.g. 'it\n"
        "   assumes the problem is what you're putting in,' or 'it assumes this is a\n"
        "   thyroid problem'). State the assumption and STOP — do not reveal what is true\n"
        "   instead. This unresolved assumption is the open loop. Leave it open.\n"
        "5. TEASE + READINESS-MATCHED NEXT STEP (1-2 sentences): Point past the assumption\n"
        "   — 'when you stop assuming X and look at what's actually driving this, a more\n"
        "   complete and personal answer opens up' — then offer EXACTLY ONE next step,\n"
        "   matched to the reader's readiness (see READINESS TRIAGE below).\n\n"
        "READINESS TRIAGE GOVERNS THE NEXT STEP. It SUPERSEDES the system prompt's default\n"
        "behavior of offering the E4L voice scan / a generic action link on every answer.\n"
        "Do NOT default to the E4L scan. Follow these rules exactly:\n"
        "  CURIOUS -> `page` (link the source/product page that answers it).\n"
        "  ENGAGED -> `email` (offer the personalized report; leave target empty).\n"
        "  READY -> `action` (NOW the E4L scan https://Truly.VIP/E4L is appropriate).\n"
        "  COMMITTED -> `inline`.\n\n"
        "CRITICAL EXAMPLES:\n"
        "  'What foods are best for macular degeneration?' -> CURIOUS -> `page`\n"
        "    (general question, no personal ownership claimed).\n"
        "  'I have wet AMD; I changed my diet but my bloodwork is the same. Should I try\n"
        "   Gundry protocol?' -> ENGAGED -> `email` (personal ownership: 'I have'; personal\n"
        "    plateau: 'my bloodwork'; asking for personalized synthesis, not a buy link).\n"
        "  'Let\\'s start the scan now' -> READY -> `action`.\n"
        "  NEVER choose `action` for 'I have [condition], should I try X?' -- that is\n"
        "  ENGAGED. `action` requires explicit purchase/start/scan intent, not just asking\n"
        "  for a recommendation.\n\n"
        "If you do NOT have a real page/product URL from the retrieved sources or the\n"
        "product injection table, do NOT invent one and do NOT fall back to the scan --\n"
        "choose `email` (the personalized report needs no URL).\n\n"
        "READINESS TRIAGE — choose exactly one next step for beat 5:\n"
        "First decide GENERIC vs PERSONAL depth. If a retrieved source page already answers\n"
        "the deeper question for anyone, the depth is GENERIC. If the real answer requires\n"
        "synthesizing THIS person's specifics (their labs, history, scan, several named\n"
        "factors at once), it is PERSONAL.\n"
        "Then match the rung:\n"
        "  - CURIOUS (cold): The user has NOT claimed the condition, symptom, or situation\n"
        "    as their own. A question like 'What foods are best for macular degeneration?'\n"
        "    is CURIOUS even though it mentions a specific condition -- because the person\n"
        "    has not said 'I have AMD' or 'my eyes'. No personal ownership = CURIOUS.\n"
        "    Choose `page`: link the retrieved source page or the relevant product page.\n"
        "    NO email ask. Even if the topic sounds personal, absent explicit personal\n"
        "    claim it is CURIOUS.\n"
        "  - ENGAGED (warm): The user EXPLICITLY CLAIMED the condition, history, or plateau\n"
        "    as their own: 'I have [condition]', 'my bloodwork', 'I changed my diet',\n"
        "    'I tried X but it\\'s not working', 'should I try X?' stated with their own\n"
        "    history or labs. Explicit personal ownership makes the answer PERSONAL.\n"
        "    Even if a product URL is available, choose `email` -- their situation needs\n"
        "    individual synthesis, not a generic link.\n"
        "  - READY (hot): They explicitly said 'let\\'s start', 'I want to order', 'where\n"
        "    do I buy', 'sign me up', or have already completed a scan. NOT merely asking\n"
        "    'should I try X?' -- that is ENGAGED. READY = unmistakable purchase intent.\n"
        "    -> DIRECT ACTION: E4L scan or product page.\n"
        "  - COMMITTED (logged-in member): give the deeper answer INLINE, no gate; offer to\n"
        "    save it to their portal.\n"
        "RUNG SELECTION RULES:\n"
        "  1. Ask: did the user EXPLICITLY claim 'I have this'/'my [situation]'? If yes\n"
        "     -> ENGAGED or above. If no -> CURIOUS.\n"
        "  2. A specific condition mentioned without personal ownership = CURIOUS (page).\n"
        "  3. Personal ownership + plateau/history = ENGAGED (email).\n"
        "  4. Explicit buy/start/scan intent = READY (action).\n"
        "  5. When unsure: choose LOWER friction (CURIOUS < ENGAGED < READY).\n"
        "Never skip a rung. A page link or email is not a dead end -- each carries the\n"
        "next rung.\n\n"
        "HARD CONSTRAINTS:\n"
        "- HARD LIMIT: Beats 1-5 combined must total NO MORE THAN 200 words (the Sources\n"
        "  line and the ⟦CTA⟧ directive do not count toward the limit). Target 160-180;\n"
        "  treat every word above 160 as fat to be cut. Compress beats 1 and 2 first.\n"
        "  Do not go over 200. Brevity is a hard requirement.\n"
        "- Beats 1-3 must deliver a genuine, act-on-able quick win on their own — the\n"
        "  brief has to help a reader who never opens the full report.\n"
        "- Do NOT resolve beat 4. The full report breaks the assumption; the brief only\n"
        "  names it. Brief and full are a pair — never pre-empt the full's reveal.\n"
        "- SAFETY OVERRIDE: never withhold safety-critical or time-sensitive information\n"
        "  behind the loop. If something matters now — a drug/nutrient interaction, a\n"
        "  red-flag symptom, an urgent contraindication — state it plainly in the brief.\n"
        "  Tease optimization and depth, never safety.\n"
        "- Keep ALL existing rules: never print a 'Hook' label; formulation-first ordering\n"
        "  for symptoms/conditions; product links only from the injection table; Speckhart\n"
        "  boundary (a credential is authority, never a disease cure claim); active\n"
        "  discount-code rule; Sources line at the end.\n"
        "- NOT EVERY TURN: if this turn is a clarifying question, a greeting, name/consent\n"
        "  capture, or logistics, do NOT force the 5 beats — respond naturally and briefly.\n"
        "  The open loop is for answer and recommendation moments only.\n\n"
        "Do NOT print the beat labels — weave the 5 beats into natural prose.\n\n"
        "END your response with the Sources line, then on a FINAL separate line emit a "
        "machine directive the user will NOT see. "
        "The directive format is exactly: `⟦CTA⟧ <type> | <target> | <label>` "
        "where <type> is ONE of these four literal words — page, email, action, inline — "
        "chosen by the readiness rung you selected: "
        "CURIOUS rung -> write `page`, "
        "ENGAGED rung -> write `email`, "
        "READY rung -> write `action`, "
        "COMMITTED rung -> write `inline`. "
        "Do NOT write the rung name; write the mapped word (page/email/action/inline). "
        "For page/action, <target> is the EXACT URL from the retrieved sources or the "
        "product injection table — never invent one; if you have no real URL, use email "
        "instead. For email, leave <target> empty and set <label> to a short report offer. "
        "Examples: `⟦CTA⟧ page | https://truly.vip/e4l | Learn more` or "
        "`⟦CTA⟧ email |  | Send my full report` or "
        "`⟦CTA⟧ action | https://truly.vip/e4l | Start your scan`."
    )


def _long_form_synth_instr(is_logged_in: bool) -> str:
    """Pick the long-form synthesis instruction.

    Logged-in users get the Break & Rebuild teaching arc described in the
    system prompt; anonymous users keep the existing extended clinical
    format. The default executive-summary path (mode=brief) is unchanged.
    """
    if is_logged_in:
        return (
            "Produce the BREAK & REBUILD LONG-FORM response — follow the "
            "6-step arc described in the system prompt (opening insight -> Justify the "
            "false belief -> Break -> Rebuild -> Journey -> The one thing + "
            "next step). Do NOT print a 'Hook' label; the opening insight is just "
            "the first line. Glen's voice, not Brunson's; practitioner-clinical, "
            "no hype. List sources at the end. "
            "If the question implies a single hidden assumption a brief answer would "
            "credit-then-question, make breaking THAT assumption the central belief "
            "you break and rebuild."
        )
    return (
        "Produce the EXTENDED FORMAT response — full clinical depth, "
        "mechanism, dosage ranges, supporting citations, edge cases. "
        "List sources at the end. "
        "If the question implies a single hidden assumption a brief answer would "
        "credit-then-question, make breaking THAT assumption the central belief "
        "you break and rebuild."
    )


# ── Helpers ───────────────────────────────────────────────────────────────────
def embed(text):
    return _oa.embeddings.create(input=[text], model="text-embedding-ada-002").data[0].embedding


def query_ns(vec, ns, k):
    try:
        return _idx.query(vector=vec, top_k=k, namespace=ns, include_metadata=True).matches
    except Exception:
        return []


def query_all_namespaces(vec):
    """Query all namespaces in parallel."""
    all_matches = []
    with ThreadPoolExecutor(max_workers=len(NAMESPACES)) as pool:
        futures = {pool.submit(query_ns, vec, ns, TOP_K_PER_NS): ns for ns in NAMESPACES}
        for future in as_completed(futures):
            all_matches.extend(future.result())
    return all_matches


def surface_case_study_cards(q_vec, max_cards=1, threshold=0.80):
    """Query the `case-studies` namespace; return up to max_cards proof cards
    for any match scoring above threshold. Cards carry kind='case-study' plus an
    excerpt and (optional) video url so the frontend can render proof inline."""
    try:
        res = _idx.query(vector=q_vec, top_k=4, namespace="case-studies", include_metadata=True)
    except Exception:
        return []
    cards, seen = [], set()
    for m in getattr(res, "matches", []) or []:
        if (m.score or 0) < threshold:
            continue
        md = m.metadata or {}
        cond = (md.get("condition") or "general")
        if cond in ("general", "case-studies") or cond in seen:
            continue
        seen.add(cond)
        excerpt = (md.get("text") or "").strip()
        if len(excerpt) > 240:
            excerpt = excerpt[:240].rsplit(" ", 1)[0] + "…"
        cards.append({
            "key": "case:" + cond,
            "kind": "case-study",
            "title": md.get("title") or cond.replace("-", " ").title(),
            "sub": excerpt,
            "href": md.get("url") or "",
            "video": md.get("url") or "",
            "source": md.get("source") or "",
            "name": md.get("name") or "",
        })
        if len(cards) >= max_cards:
            break
    return cards


# ── R2 clip proxy ─────────────────────────────────────────────────────────────
_r2_client = None


def _r2():
    global _r2_client
    if _r2_client is None:
        _r2_client = _boto3.client(
            "s3",
            endpoint_url=os.environ.get("R2_ENDPOINT"),
            aws_access_key_id=os.environ.get("R2_ACCESS_KEY_ID"),
            aws_secret_access_key=os.environ.get("R2_SECRET_ACCESS_KEY"),
            region_name="auto",
        )
    return _r2_client


@app.route("/clip/<path:key>")
def serve_clip(key):
    rng = request.headers.get("Range")
    kw = {"Bucket": os.environ.get("R2_BUCKET", "rm-clips"), "Key": key}
    if rng:
        kw["Range"] = rng
    try:
        obj = _r2().get_object(**kw)
    except Exception:
        return "not found", 404
    body = obj["Body"]
    headers = {
        "Content-Type": obj.get("ContentType", "video/mp4"),
        "Accept-Ranges": "bytes",
        "Cache-Control": "public, max-age=86400",
    }
    status = 200
    if rng and obj.get("ContentRange"):
        headers["Content-Range"] = obj["ContentRange"]
        status = 206
    if obj.get("ContentLength") is not None:
        headers["Content-Length"] = str(obj["ContentLength"])
    return Response(body.iter_chunks(chunk_size=65536), status=status, headers=headers)


def surface_approved_clips(q_vec, max_cards=1, threshold=0.80):
    """Query the `clips` namespace; return up to max_cards clip cards for any
    approved match scoring above threshold."""
    try:
        res = _idx.query(
            vector=q_vec,
            top_k=3,
            namespace="clips",
            include_metadata=True,
            filter={"status": "approved"},
        )
    except Exception:
        return []
    cards = []
    for m in getattr(res, "matches", []) or []:
        if (m.score or 0) < threshold:
            continue
        md = m.metadata or {}
        if not md.get("r2_key"):
            continue
        cards.append({
            "key": "clip:" + m.id,
            "kind": "clip",
            "title": md.get("title") or "Watch this",
            "sub": md.get("why") or "",
            "clip_url": "/clip/" + md["r2_key"],
        })
        if len(cards) >= max_cards:
            break
    return cards


def build_context(matches):
    seen, sources, parts, total = set(), {}, [], 0
    # Authoritative clinical-qa chunks go in FIRST so the context-char cap can
    # never starve them out — Glen's verified positions must always reach the
    # model. Everything else follows by descending score.
    def _rank(m):
        meta = m.metadata or {}
        auth = meta.get("type") == "clinical-qa" or meta.get("priority") == "authoritative"
        return (0 if auth else 1, -m.score)
    for m in sorted(matches, key=_rank):
        if m.id in seen:
            continue
        seen.add(m.id)
        meta = m.metadata or {}
        text = meta.get("text", "").strip()
        if not text or total + len(text) > MAX_CONTEXT_CHARS:
            continue
        name  = meta.get("name") or meta.get("book") or meta.get("source") or "Unknown"
        field = meta.get("field") or meta.get("source_type") or ""
        score = round(m.score, 3)
        if name not in sources:
            sources[name] = {"name": name, "field": field,
                             "source_file": meta.get("source", ""),
                             "score": score, "chunks": []}
        sources[name]["chunks"].append(meta.get("chunk_index", 0))
        sources[name]["score"] = max(sources[name]["score"], score)
        is_authoritative = meta.get("type") == "clinical-qa" or meta.get("priority") == "authoritative"
        tag = "[AUTHORITATIVE — Glen's verified clinical position] " if is_authoritative else ""
        authorship = meta.get("authorship_note") or ""
        if authorship:
            authorship = f"\n[AUTHORSHIP NOTE: {authorship}]"
        deprecated_flag = ""
        if str(meta.get("deprecated", "")).lower() == "true":
            depr_note = meta.get("deprecation_note", "Product or guidance is deprecated.")
            deprecated_flag = f"\n[DEPRECATED — {depr_note}]"
        parts.append(f"{tag}[SOURCE: {name} | {field} | score {score}]{authorship}{deprecated_flag}\n{text}")
        total += len(text)
    return "\n\n---\n\n".join(parts), sorted(sources.values(), key=lambda x: -x["score"])


def sse(payload: dict) -> str:
    return f"data: {json.dumps(payload)}\n\n"


def _strip_dash(s):
    """Enforce Glen's no-em-dash rule on generated copy (models ignore the prompt
    rule intermittently). Em dash -> comma; en dash left alone (number ranges OK)."""
    return s.replace("—", ", ") if s else s


