def _confirm_post_page(action_url, *, title, heading, blurb, button,
                       hidden=None, status=200):
    """One-button interstitial that turns a state-changing GET into a POST.

    Corporate mail scanners, link checkers and browser prefetch all issue GET
    on every URL in an email. A single-use token consumed by a GET is therefore
    burned before the human clicks -- they land on 'link already used'. Rendering
    this page on GET and doing the work on POST fixes that, because none of those
    agents submit forms.

    Deliberately contains NO javascript: an auto-submitting form would restore
    the exact behaviour this exists to prevent.
    """
    import html as _html
    fields = "".join(
        f"<input type='hidden' name='{_html.escape(str(k))}' "
        f"value='{_html.escape(str(v))}'>"
        for k, v in (hidden or {}).items())
    return (
        "<!doctype html><meta charset=utf-8>"
        "<meta name='viewport' content='width=device-width,initial-scale=1'>"
        "<meta name='robots' content='noindex,nofollow'>"
        f"<title>{_html.escape(title)}</title>"
        "<div style='font-family:Georgia,serif;max-width:560px;margin:60px auto;"
        "padding:0 20px;color:#1f2a37'>"
        f"<h1>{_html.escape(heading)}</h1>"
        f"<p>{_html.escape(blurb)}</p>"
        f"<form method='post' action='{_html.escape(action_url)}'>{fields}"
        "<button type='submit' style='font-family:Georgia,serif;font-size:1.05rem;"
        "background:#2f6f5e;color:#fff;border:0;border-radius:6px;"
        "padding:12px 28px;cursor:pointer;margin-top:8px'>"
        f"{_html.escape(button)}</button></form></div>"
    ), status, {"Content-Type": "text/html; charset=utf-8"}


def _magic_link_login_view(token, *, purpose, cookie, dest, invalid_html,
                           heading, blurb, button, title="Sign in",
                           cookie_max_age=60 * 60 * 24 * 30):
    """Shared body for the emailed sign-in links (reorder / cert / biofield /
    coaching). GET validates and renders the confirm page; POST consumes the
    token and sets the cookie. See _confirm_post_page for why."""
    from flask import redirect as _redirect
    th = _hash_token((token or "").strip())
    with _db_lock, sqlite3.connect(LOG_DB) as cx:
        cx.row_factory = sqlite3.Row
        row = cx.execute(
            "SELECT email, expires_at, consumed_at FROM auth_tokens "
            "WHERE token_hash=? AND purpose=?", (th, purpose)).fetchone()
        email = None
        if row and not row["consumed_at"]:
            try:
                if _parse_utc(row["expires_at"]) >= _now_utc():
                    email = row["email"]
            except Exception:
                email = None
        if not email:
            return invalid_html, 400
        if request.method == "POST":
            # consumed_at IS NULL makes the burn atomic: a double submit loses
            # the race and falls through to the invalid page rather than
            # signing a second visitor in.
            cur = cx.execute(
                "UPDATE auth_tokens SET consumed_at=? "
                "WHERE token_hash=? AND consumed_at IS NULL",
                (_now_utc().isoformat(), th))
            if cur.rowcount != 1:
                return invalid_html, 400
            cx.commit()
            # Wishlist Task 4: this magic-link sign-in (reorder / cert / biofield)
            # just tied the browsing session to a real email — merge the anonymous
            # session's wishlist into it so the list follows the visitor home.
            # Flag-gated + best-effort: a merge failure must never break sign-in.
            if _WISHLIST_ENABLED:
                try:
                    import sqlite3 as _wsq
                    from dashboard import wishlist as _wl
                    # Already inside the enclosing `with _db_lock, ...` block above,
                    # so _db_lock is held here — do NOT re-acquire it (threading.Lock
                    # is not reentrant; nesting would deadlock). Use a dedicated
                    # connection so merge_wishlist's internal commit() never touches
                    # this handler's shared `cx`.
                    with _wsq.connect(LOG_DB) as _cxw:
                        _wl.init_wishlist_table(_cxw)
                        _wl.merge_wishlist(_cxw, request.cookies.get("amg_session", ""), email)
                except Exception as _e:
                    print(f"[wishlist] merge skipped: {_e}", flush=True)

    if request.method == "GET":
        return _confirm_post_page(request.path, title=title, heading=heading,
                                  blurb=blurb, button=button)
    resp = _redirect(dest, code=302)
    resp.set_cookie(cookie, email, max_age=cookie_max_age, httponly=True,
                    samesite="Lax", secure=request.is_secure)
    return resp


# The old copy promised "We'll email it to you as soon as it's ready." Nothing
# sends that email: LEAD_MAGNET_PDF_KEY is read in exactly one place, the guide
# route below, and there is no sender or cron anywhere. Until the guide exists
# and something delivers it, the page must not promise a message we never send.
# The window is interpolated from the constant so the copy cannot drift from
# the token's real lifetime.
_GUIDE_PENDING_HTML = (
    "<!doctype html><meta charset=utf-8><title>Your guide</title>"
    "<div style='font-family:Georgia,serif;max-width:560px;margin:60px auto;padding:0 20px;color:#1f2a37'>"
    "<h1>Your guide is almost ready</h1>"
    "<p>Thank you. Dr. Glen is putting the finishing touches on it.</p>"
    f"<p>Your link stays live for {LEAD_MAGNET_GUIDE_TTL_DAYS} days. Bookmark this page "
    "and come back anytime to download it.</p>"
    "<p><a href='/begin/quiz/result' style='color:#4b6b57'>Back to your result</a></p></div>")

_GUIDE_EXPIRED_HTML = (
    "<!doctype html><meta charset=utf-8><title>Link expired</title>"
    "<div style='font-family:Georgia,serif;max-width:560px;margin:60px auto;padding:0 20px;color:#1f2a37'>"
    "<h1>That link has expired</h1>"
    "<p>For your security, guide links expire. "
    "<a href='/begin/quiz' style='color:#4b6b57'>Take the assessment again</a> to get a fresh link.</p></div>")


@app.route("/begin/quiz/guide")
def begin_quiz_guide():
    token = (request.args.get("token") or "").strip()
    email = _validate_lead_magnet_guide_link(token)
    if not email:
        return Response(_GUIDE_EXPIRED_HTML, mimetype="text/html")
    key = (os.environ.get("LEAD_MAGNET_PDF_KEY") or "").strip()
    if not key:
        return Response(_GUIDE_PENDING_HTML, mimetype="text/html")
    try:
        obj = _r2().get_object(Bucket=os.environ.get("R2_BUCKET", "rm-clips"), Key=key)
    except Exception as e:
        print(f"[quiz-guide] r2 fetch failed key={key}: {e!r}", flush=True)
        return Response(_GUIDE_PENDING_HTML, mimetype="text/html")
    headers = {
        "Content-Type": obj.get("ContentType", "application/pdf"),
        "Content-Disposition": 'inline; filename="foundational-eye-and-brain-guide.pdf"',
        "Cache-Control": "private, max-age=0, no-store",
    }
    if obj.get("ContentLength") is not None:
        headers["Content-Length"] = str(obj["ContentLength"])
    return Response(obj["Body"].iter_chunks(chunk_size=65536), status=200, headers=headers)


