@app.route("/begin/choose", methods=["GET"])
def begin_choose():
    """Two-door 'see & choose' surface: Door A ($100 one-off program) vs Door B (Continuous Care).

    Reached from the reveal page's handoff CTA with ?token=<reveal token>. Flag-dark behind
    TWO_DOOR_ENABLED. The token is verified server-side (same path as the reveal route). The
    verified client email is injected into the page body (NOT the URL) so Door A can start the
    $100 program checkout exactly like the reveal's program CTA; a fallback reveal_url keeps the
    door from ever dead-ending when there is no email/program flag."""
    if not TWO_DOOR_ENABLED:
        return redirect("/")

    token = (request.args.get("token") or "").strip()
    valid_token = None
    email = None
    reveal_url = "/begin"
    if token:
        valid, row = _biofield_verify_token(_hash_token(token))
        if valid and row is not None:
            valid_token = token
            email = (row.get("email") or "").strip().lower() or None
            reveal_url = f"/begin/biofield/{token}"

    payload = {
        "token": valid_token,
        "email": email,
        "reveal_url": reveal_url,
        "program_enabled": PROGRAM_CARE_TASTER_ENABLED,
        "program_tier": PROGRAM_SCALABLE_TIER,
        "prepay_enabled": PREPAY_LADDER_ENABLED,
    }
    _safe = (json.dumps(payload).replace("<", "\\u003c")
             .replace(">", "\\u003e").replace("&", "\\u0026"))
    html = (STATIC / "begin-choose.html").read_text()
    html = html.replace("</head>", f"<script>window.__CHOOSE__ = {_safe};</script>\n</head>")
    resp = Response(html, mimetype="text/html", status=200)
    resp.headers["Cache-Control"] = "no-cache, no-store, must-revalidate"
    resp.headers["Pragma"] = "no-cache"
    return resp


def _biofield_remedy_payload(r):
    """Return {name, meaning, slug, buy_url, page_url} for any remedy dict. Never raises."""
    try:
        slug = (r.get("slug") or "").strip()
        buy_url = f"/begin/buy/{slug}" if slug else "/begin/match"
        page_url = f"/begin/product/{slug}" if slug else "/begin/match"
        return {"name": r.get("name", ""), "meaning": r.get("meaning", ""),
                "slug": slug, "buy_url": buy_url, "page_url": page_url}
    except Exception:
        return None


def _biofield_top_payload(row):
    """Return {name, meaning, buy_url, page_url} from remedies[0]. Never raises."""
    try:
        remedies = row.get("remedies") or []
        if not remedies:
            return None
        return _biofield_remedy_payload(remedies[0])
    except Exception:
        return None


def _biofield_layer_payload(layer, include_remedy):
    """Layer payload: title + summary ALWAYS; the remedy only when include_remedy and present.
    A withheld remedy is emitted as remedy=None, remedy_blurred=True (its details never leave)."""
    try:
        rem = layer.get("remedy") if isinstance(layer, dict) else None
        has_rem = isinstance(rem, dict) and ((rem.get("slug") or "").strip() or (rem.get("name") or "").strip())
        out = {"n": layer.get("n"), "title": (layer.get("title") or ""),
               "summary": (layer.get("summary") or "")}
        if include_remedy and has_rem:
            out["remedy"] = _biofield_remedy_payload(rem)
            out["remedy_blurred"] = False
        else:
            out["remedy"] = None
            out["remedy_blurred"] = bool(has_rem)
        return out
    except Exception:
        return {"n": None, "title": "", "summary": "", "remedy": None, "remedy_blurred": False}


def _biofield_verify_token(th):
    """Verify a biofield_reveal token hash against auth_tokens.
    Returns (valid: bool, row: dict|None) where row is the biofield_reveals row.
    Never raises; on any error returns (False, None)."""
    from dashboard import biofield_reveals as _br
    try:
        with _db_lock, sqlite3.connect(LOG_DB) as cx:
            cx.row_factory = sqlite3.Row
            at = cx.execute(
                "SELECT email, expires_at FROM auth_tokens WHERE token_hash=? AND purpose='biofield_reveal'",
                (th,)).fetchone()
            valid = False
            if at is not None:
                try:
                    valid = _parse_utc(at["expires_at"]) >= _now_utc()
                except Exception:
                    valid = False
            if not valid:
                return False, None
            _br.init_table(cx)
            _br.init_free_unlocks(cx)
            row = _br.get_by_token_hash(cx, th)
            return True, row
    except Exception as e:
        print(f"[biofield-reveal] token verify failed: {e!r}", flush=True)
        return False, None


def _biofield_unlock_flags(row, email):
    """Compute (paid, first_approved, top_unlocked, free_available) for a reveal row + member.
    Single source of truth for reveal visibility. Never raises."""
    from dashboard import biofield_reveals as _br
    email = (email or "").strip().lower()
    first_approved = bool(row.get("first_approved"))
    try:
        paid = bool(_active_membership_for_email(email))
    except Exception:
        paid = False
    fu_rid = None
    try:
        with _db_lock, sqlite3.connect(LOG_DB) as cx:
            _br.init_free_unlocks(cx)
            fu_rid = _br.free_unlock_reveal_id(cx, email)
            # A reveal earned by >= $100 spend is fully un-blurred, same as paid,
            # for this reveal only (does not grant real membership).
            if _br.is_spend_unlocked(cx, row.get("id")):
                paid = True
    except Exception:
        fu_rid = None
    top_unlocked = bool(first_approved and fu_rid == row.get("id"))
    free_available = bool(first_approved and fu_rid is None)
    return {"paid": paid, "first_approved": first_approved,
            "top_unlocked": top_unlocked, "free_available": free_available}


def _biofield_visible_slugs(row, email):
    """Slugs this member may order from the reveal: paid -> all matched remedies;
    else the top remedy if unlocked; else []. Never raises."""
    try:
        remedies = row.get("remedies") or []
        if not remedies:
            return []
        flags = _biofield_unlock_flags(row, email)
        if flags["paid"]:
            return [(r.get("slug") or "").strip() for r in remedies if (r.get("slug") or "").strip()]
        if flags["top_unlocked"]:
            s = (remedies[0].get("slug") or "").strip()
            return [s] if s else []
        return []
    except Exception:
        return []


@app.route("/begin/biofield/<token>", methods=["GET"])
def begin_biofield_reveal(token):
    """Token-verified Biofield reveal: interpretation always shown + remedies blurred.
    Top remedy un-blurred free after Glen approves and member requests it (one-time).
    Sets the biofield gate on member view. Token is NOT consumed (reopenable, 30-day TTL)."""
    from dashboard import biofield_reveals as _br
    th = _hash_token((token or "").strip())
    valid, row = _biofield_verify_token(th)

    html = (STATIC / "begin-biofield.html").read_text()

    _no_store_headers = {"Cache-Control": "no-cache, no-store, must-revalidate", "Pragma": "no-cache"}

    if not valid or row is None:
        injection = "<script>window.__REVEAL__ = null;</script>"
        html = html.replace("</head>", injection + "\n</head>")
        resp = Response(html, mimetype="text/html", status=200)
        for k, v in _no_store_headers.items():
            resp.headers[k] = v
        return resp

    email = (row.get("email") or "").strip().lower()
    member = is_member(email=email)

    if not member:
        # ToS gate: do NOT reveal interpretation or remedies; do NOT set gate
        payload = {"needs_tos": True, "email": email}
        _safe = (json.dumps(payload).replace("<", "\\u003c")
                 .replace(">", "\\u003e").replace("&", "\\u0026"))
        injection = f"<script>window.__REVEAL__ = {_safe};</script>"
        html = html.replace("</head>", injection + "\n</head>")
        resp = Response(html, mimetype="text/html", status=200)
        for k, v in _no_store_headers.items():
            resp.headers[k] = v
        return resp

    # Member path: compute unlock state (single source of truth)
    flags = _biofield_unlock_flags(row, email)
    first_approved = flags["first_approved"]
    top_unlocked = flags["top_unlocked"]
    free_available = flags["free_available"]
    paid = flags["paid"]

    _layers_raw = row.get("layers") or []
    if paid:
        _layers_payload = [_biofield_layer_payload(L, include_remedy=True) for L in _layers_raw]
    else:
        _layers_payload = [_biofield_layer_payload(L, include_remedy=(top_unlocked and i == 0))
                           for i, L in enumerate(_layers_raw)]
    _blurred_layers = (sum(1 for lp in _layers_payload if lp["remedy_blurred"])
                       if _layers_raw
                       else len(row.get("remedies") or []) - (1 if top_unlocked else 0))

    # Pre-fill the in-app shipping review from the client's last order address (their
    # own data on their own token) so ordering shows a review step, not a bare Stripe
    # screen. {} when unknown -> the form starts empty.
    _ship_prefill = _resolve_ship_address(email, {})
    if paid:
        all_remedies = row.get("remedies") or []
        payload = {
            "interpretation": row.get("interpretation") or {},
            "blurred_count": 0,
            "first_approved": first_approved,
            "free_available": False,
            "top_unlocked": True,
            "paid": True,
            "trial_enabled": BIOFIELD_TRIAL_ENABLED,
            "cart_enabled": BIOFIELD_CART_ENABLED,
            "ship_prefill": _ship_prefill,
            "remedies": [_biofield_remedy_payload(r) for r in all_remedies],
            "layers": _layers_payload,
            "email": email,
            "program_enabled": PROGRAM_CARE_TASTER_ENABLED,
            "program_tier": PROGRAM_SCALABLE_TIER,
            "choose_enabled": TWO_DOOR_ENABLED,
        }
    else:
        payload = {
            "interpretation": row.get("interpretation") or {},
            "blurred_count": _blurred_layers,
            "first_approved": first_approved,
            "free_available": free_available,
            "top_unlocked": top_unlocked,
            "top": _biofield_top_payload(row) if top_unlocked else None,
            "paid": False,
            "trial_enabled": BIOFIELD_TRIAL_ENABLED,
            "cart_enabled": BIOFIELD_CART_ENABLED,
            "ship_prefill": _ship_prefill,
            "layers": _layers_payload,
            "email": email,
            "program_enabled": PROGRAM_CARE_TASTER_ENABLED,
            "program_tier": PROGRAM_SCALABLE_TIER,
            "choose_enabled": TWO_DOOR_ENABLED,
        }

    # Set the biofield gate (idempotent, wrapped) -> Find step 2 fills.
    _record_entry_unlock("biofield", email)

    # Escape <, >, & so a remedy name containing "</script>" cannot break out
    _safe = (json.dumps(payload).replace("<", "\\u003c")
             .replace(">", "\\u003e").replace("&", "\\u0026"))
    injection = f"<script>window.__REVEAL__ = {_safe};</script>"
    html = html.replace("</head>", injection + "\n</head>")
    resp = Response(html, mimetype="text/html", status=200)
    for k, v in _no_store_headers.items():
        resp.headers[k] = v
    return resp


@app.route("/begin/biofield/<token>/reveal-top", methods=["POST"])
def begin_biofield_reveal_top(token):
    """One-time free top-remedy unblock. Requires member + first_approved + unused free slot."""
    from dashboard import biofield_reveals as _br
    try:
        th = _hash_token((token or "").strip())
        valid, row = _biofield_verify_token(th)
        if not valid or row is None:
            return jsonify({"ok": False, "reason": "invalid"})

        email = (row.get("email") or "").strip().lower()

        if not is_member(email=email):
            return jsonify({"ok": False, "reason": "tos"})

        if not bool(row.get("first_approved")):
            return jsonify({"ok": False, "reason": "pending"})

        with _db_lock, sqlite3.connect(LOG_DB) as cx:
            _br.init_free_unlocks(cx)
            if _br.free_unlock_reveal_id(cx, email) is not None:
                return jsonify({"ok": False, "reason": "used"})
            granted = _br.record_free_unlock(cx, email, row["id"])

        if not granted:
            # Race: another request granted it between our check and insert
            return jsonify({"ok": False, "reason": "used"})

        top = _biofield_top_payload(row)
        return jsonify({"ok": True, "top": top})
    except Exception as e:
        print(f"[biofield-reveal-top] {e!r}", flush=True)
        return jsonify({"ok": False, "reason": "error"})


@app.route("/begin/biofield/<token>/order-preview", methods=["POST"])
def begin_biofield_order_preview(token):
    """Live volume-priced preview of the member's matched-set cart. Never raises."""
    if not BIOFIELD_CART_ENABLED:
        return jsonify({"ok": False}), 200
    try:
        th = _hash_token((token or "").strip())
        valid, row = _biofield_verify_token(th)
        if not valid or row is None:
            return jsonify({"ok": False, "error": "invalid"}), 404
        email = (row.get("email") or "").strip().lower()
        body = request.get_json(silent=True) or {}
        visible = set(_biofield_visible_slugs(row, email))
        items = []
        for it in (body.get("items") or []):
            s = (it.get("slug") or "").strip()
            if s and s in visible:
                items.append({"slug": s, "qty": max(1, min(int(it.get("qty") or 1), 99))})
        if not items:
            return jsonify({"ok": True, "lines": [], "subtotal_cents": 0,
                            "shipping_cents": 0, "savings_cents": 0, "total_cents": 0})
        ship = _resolve_ship_address(email, {})
        # Gate Type-2 order-total pricing on membership so the preview matches what the
        # buyer is actually charged at checkout (begin_biofield_order_checkout does the same).
        pc = _price_cart(items, ship=ship, program_member=_is_paid_member(email), email=email)
        priced = pc["priced"]
        lines = [{"slug": ln.get("slug"), "name": ln.get("name"), "qty": ln.get("qty"),
                  "list_cents": int(ln.get("list_cents") or 0),
                  "line_total_cents": int(ln.get("line_total_cents") or 0),
                  "savings_cents": int(ln.get("list_cents") or 0) - int(ln.get("line_total_cents") or 0)}
                 for ln in priced.get("lines", [])]
        subtotal = int(priced.get("subtotal_cents") or 0)
        shipping = int(pc.get("shipping_cents") or 0)
        return jsonify({"ok": True, "lines": lines, "subtotal_cents": subtotal,
                        "shipping_cents": shipping,
                        "savings_cents": int(priced.get("discount_cents") or 0),
                        "total_cents": subtotal + shipping})
    except Exception as e:
        print(f"[biofield-cart] preview failed: {e!r}", flush=True)
        return jsonify({"ok": False}), 200


@app.route("/begin/biofield/<token>/order-checkout", methods=["POST"])
def begin_biofield_order_checkout(token):
    """Check out the member's matched-set cart in one Stripe session (kind=reorder)."""
    if not BIOFIELD_CART_ENABLED:
        return jsonify({"ok": False}), 200
    try:
        th = _hash_token((token or "").strip())
        valid, row = _biofield_verify_token(th)
        if not valid or row is None:
            return jsonify({"ok": False, "error": "invalid"}), 404
        email = (row.get("email") or "").strip().lower()
        _sid = (request.cookies.get("amg_session") or "").strip()
        if not is_member(_sid, email):
            return jsonify({"ok": False, "need_optin": True,
                            "error": "Please agree to our Terms to continue your order."}), 403
        body = request.get_json(silent=True) or {}
        requested = body.get("items") or []
        visible = set(_biofield_visible_slugs(row, email))
        items = []
        for it in requested:
            s = (it.get("slug") or "").strip()
            if s and s in visible:
                items.append({"slug": s, "qty": max(1, min(int(it.get("qty") or 1), 99))})
        if not items:
            # Distinguish an empty cart from a LOCKED reveal: if the client asked to
            # order specific remedies but none are unlocked yet, tell them the truth
            # and flag need_unlock so the page routes them to the unlock CTA (not a
            # dead-end "no longer available" — the bug Steve Fox hit on an unapproved
            # reveal where the visible set is empty).
            if requested:
                return jsonify({"ok": False, "need_unlock": True,
                                "error": "These matches aren't unlocked yet — "
                                         "unlock your full analysis to order them."}), 400
            return jsonify({"ok": False, "error": "Your cart is empty."}), 400
        ship = _resolve_ship_address(email, body.get("address") or {})
        try:
            res = _checkout_cart(email, items, ship=ship)
        except CheckoutError as e:
            return jsonify({"ok": False, "error": str(e)}), 400
        out, stripe_url = res["out"], res["stripe_url"]
        _pe = {"payment_error": _CARD_UNAVAILABLE} if (_STRIPE_ACTIVE and not stripe_url) else {}
        return jsonify({"ok": True, "stripe_url": stripe_url, **out, **_pe})
    except Exception as e:
        app.logger.exception("biofield order checkout failed")
        return jsonify({"ok": False, "error": f"{type(e).__name__}: {e}"}), 500


