@app.route("/prepay/return")
def prepay_return():
    """Stripe return for a prepaid Continuous Care term. Re-fetches the session +
    PaymentIntent (the security guarantee), verifies a succeeded prepay_term payment,
    then grants the day-based term idempotently (claim-then-create on a session-id
    PRIMARY KEY, mirroring _fulfill_biofield_trial). Never raises."""
    from flask import redirect as _redir
    sid = (request.args.get("session_id") or "").strip()
    # Fulfillment is idempotent + self-verifying (re-fetches the session, checks kind +
    # succeeded payment), and the webhook is the safety net — so honor any paid session
    # here regardless of the flag. The shared fulfiller never raises.
    res = _fulfill_prepay_term(sid) if sid else {"ok": False}
    ok = bool(res.get("ok"))
    return _redir(f"{PUBLIC_BASE_URL.rstrip('/')}/?prepay={'ok' if ok else 'err'}")


def _continuous_care_checkout_session(email, term_months):
    """Create the continuous-care Stripe checkout session (mode=payment: $99 now +
    card vault). Single source of truth for metadata / save_card / success+cancel
    URLs shared by /continuous-care/checkout and the portal wrapper. Returns the
    session dict (read .get("url"))."""
    from dashboard import stripe_pay as _sp, prepay as _pp
    base = PUBLIC_BASE_URL.rstrip("/")
    return _sp.create_checkout_session(
        _pp.MONTHLY_ANCHOR_CENTS, customer_email=email,
        description=f"Remedy Match Continuous Care - {term_months} month (monthly)",
        metadata={"email": email, "kind": "continuous_care_monthly",
                  "term_months": str(term_months)},
        success_url=f"{base}/continuous-care/return?session_id={{CHECKOUT_SESSION_ID}}",
        cancel_url=f"{base}/",
        save_card=True)


def _membership_checkout_session(email, tier_key):
    """Create the membership-tier Stripe checkout session. Single source of truth
    for metadata / save_card / success+cancel URLs for /membership/checkout. One-time
    tiers (month, year_prepay) never vault a card; the recurring_capped tier
    (year_monthly) vaults it so the charge cron can bill months 2..12. Returns the
    session dict (read .get("url"))."""
    from dashboard import membership_products as _mp
    tier = _mp.get_tier(tier_key)
    base = PUBLIC_BASE_URL.rstrip("/")
    return stripe_pay.create_checkout_session(
        tier["price_cents"], customer_email=email,
        description=f"Remedy Match {tier['label']}",
        metadata={"email": email, "kind": "membership_product", "tier": tier_key},
        success_url=f"{base}/membership/return?session_id={{CHECKOUT_SESSION_ID}}",
        cancel_url=f"{base}/",
        save_card=(tier["billing"] == "recurring_capped"))


