@app.route("/membership/cancel/<token>", methods=["GET"])
def membership_cancel(token):
    """One-click cancel via a tokened link minted at biofield-trial grant time."""
    from dashboard import subscriptions as _subs
    th = _hash_token((token or "").strip())
    with _db_lock, sqlite3.connect(LOG_DB) as cx:
        row = cx.execute(
            "SELECT email, expires_at FROM auth_tokens "
            "WHERE token_hash=? AND purpose='membership_cancel'",
            (th,)
        ).fetchone()
        email = None
        if row:
            try:
                exp = _parse_utc(row[1])
                if exp >= datetime.now(timezone.utc):
                    email = row[0]
            except Exception:
                pass
        if email:
            _subs.init_subscriptions_table(cx)
            _subs.migrate_add_membership_columns(cx)
            _subs.migrate_add_term_cap_column(cx)
            _subs.migrate_add_attribution_column(cx)
            _subs.migrate_add_consent_column(cx)
            sub = cx.execute(
                "SELECT id FROM subscriptions "
                "WHERE email=? AND kind='membership' AND status='active' "
                "ORDER BY id DESC LIMIT 1",
                (email,)
            ).fetchone()
            if sub:
                _subs.set_status(cx, sub[0], "cancelled")
    resp = send_from_directory(STATIC, "membership-cancel.html")
    resp.headers["Cache-Control"] = "no-cache, no-store, must-revalidate"
    return resp


@app.route("/membership/pause/<token>", methods=["GET", "POST"])
def membership_pause(token):
    """Soft, month-by-month pause as a gentler alternative to cancel. Two steps:
    GET previews what a paused month means (no state change); POST confirms and
    sets skip_next so the NEXT charge is skipped, then the cycle auto-resumes one
    month later (no action needed). Loyalty/standing preserved -- nothing is
    permanently lost. Tokened via the same membership_cancel token (member id)."""
    from dashboard import subscriptions as _subs
    th = _hash_token((token or "").strip())
    with _db_lock, sqlite3.connect(LOG_DB) as cx:
        cx.row_factory = sqlite3.Row   # subscriptions helpers need Row for _row_to_dict
        row = cx.execute(
            "SELECT email, expires_at FROM auth_tokens "
            "WHERE token_hash=? AND purpose='membership_cancel'", (th,)).fetchone()
        email = None
        if row:
            try:
                exp = _parse_utc(row["expires_at"])
                if exp >= datetime.now(timezone.utc):
                    email = row["email"]
            except Exception:
                pass
        if not email:
            payload = {"valid": False}
        else:
            _subs.init_subscriptions_table(cx)
            _subs.migrate_add_membership_columns(cx)
            _subs.migrate_add_term_cap_column(cx)
            _subs.migrate_add_attribution_column(cx)
            _subs.migrate_add_consent_column(cx)
            rows = _subs.active_memberships_by_email(cx, email)
            cancel_url = f"{PUBLIC_BASE_URL}/membership/cancel/{token}"
            # Continuous Care is a fixed 6/12-month term (term_charges_total set): it has no
            # cadence to switch and no month-by-month pause. Offer cancel only (stop future
            # charges; access runs through the paid term). Never pause/re-cadence a CC term.
            is_continuous_care = bool(rows and rows[0].get("term_charges_total"))
            if is_continuous_care:
                payload = {"valid": True, "confirmed": False, "continuous_care": True,
                           "cancel_url": cancel_url}
            elif request.method == "POST":
                mode = (request.form.get("mode") or "once").strip()
                if mode == "cadence":
                    months = 2 if (request.form.get("months") or "").strip() == "2" else 3
                    res = _subs.set_membership_cadence_by_email(cx, email, months)
                    payload = {"valid": True, "confirmed": True, "mode": "cadence",
                               "ok": bool(res), **(res or {})}
                else:
                    res = _subs.pause_membership_by_email(cx, email)
                    payload = {"valid": True, "confirmed": True, "mode": "once",
                               "ok": bool(res), **(res or {})}
            else:
                if rows:
                    sub = rows[0]
                    payload = {"valid": True, "confirmed": False,
                               "paused_charge_date": sub["next_charge_date"],
                               "resume_date": _subs.add_months(
                                   sub["next_charge_date"], int(sub.get("cadence_months") or 1)),
                               "already_paused": bool(sub.get("skip_next")),
                               "cancel_url": cancel_url}
                else:
                    payload = {"valid": True, "confirmed": False, "no_membership": True}
    html = (STATIC / "membership-pause.html").read_text()
    safe = (json.dumps(payload).replace("<", "\\u003c")
            .replace(">", "\\u003e").replace("&", "\\u0026"))
    html = html.replace("</head>", f"<script>window.__PAUSE__ = {safe};</script>\n</head>")
    resp = Response(html, mimetype="text/html", status=200)
    resp.headers["Cache-Control"] = "no-cache, no-store, must-revalidate"
    resp.headers["Pragma"] = "no-cache"
    return resp


@app.route("/begin/state", methods=["GET"])
def begin_state():
    session_id = (request.cookies.get("amg_session") or "").strip()
    auth_user = get_authenticated_user(request)
    email = auth_user["email"] if auth_user else ""
    with _db_lock, sqlite3.connect(LOG_DB) as cx:
        state = begin_funnel.get_state(cx, session_id=session_id, email=email)
    ref_slug = (request.cookies.get("rm_ref") or "").strip()
    query_texts = _recent_query_texts(session_id, email)
    payload = dict(state)
    payload["surfaced_cards"] = begin_funnel.surface(state, query_texts, ref_slug)
    _sig_email = state.get("email") or email
    with sqlite3.connect(LOG_DB) as _cx:
        signals = _begin_signals(_cx, _sig_email, state)
    payload["journey_map"] = begin_funnel.journey_map(state, ref_slug, signals)
    payload["next_step"] = {
        "prompt": begin_funnel.next_step_prompt(state, query_texts),
        "chips":  begin_funnel.next_step_chips(state, ref=ref_slug,
                                               query_texts=query_texts, signals=signals),
    }
    return jsonify(payload)


