def _gifting_active(cx, email):
    if not email:
        return False
    try:
        row = cx.execute("SELECT gifting_activated_at FROM affiliate_signups WHERE LOWER(email)=?",
                         (email.lower(),)).fetchone()
        return bool(row and row[0])
    except Exception:
        return False


@app.route("/api/journey/activate-gifting", methods=["POST"])
def journey_activate_gifting():
    if not REWARDS_1B_GIFT_ENABLED:
        return ("", 404)
    session_id = (request.cookies.get("amg_session") or "").strip()
    au = get_authenticated_user(request)
    email = (au["email"] if au else "").strip()
    with _db_lock, sqlite3.connect(LOG_DB) as cx:
        state = begin_funnel.get_state(cx, session_id=session_id, email=email)
        email = (state.get("email") or email or "").strip().lower()
        if not email or not state.get("tos_agreed_at"):
            return jsonify({"ok": False, "needs": "email_tos"}), 409
        now = begin_funnel._now()
        row = cx.execute("SELECT id FROM affiliate_signups WHERE LOWER(email)=?", (email,)).fetchone()
        if row:
            cx.execute("UPDATE affiliate_signups SET gifting_activated_at=? WHERE id=?", (now, row[0]))
        else:
            nm = ((state.get("first_name") or "") + " " + (state.get("last_name") or "")).strip() or email
            slug = f"gift-{uuid.uuid4().hex[:8]}"
            token = uuid.uuid4().hex
            cx.execute(
                "INSERT INTO affiliate_signups (created_at,name,email,slug,token,status,gifting_activated_at) "
                "VALUES (?,?,?,?,?,?,?)", (now, nm, email, slug, token, "pending", now))
        cx.commit()
        # mint gift twins for every remedy the visitor has already collected (self-coupons)
        from dashboard import coupons as _coupons
        _coupons.init_coupons_table(cx)
        gifts = []
        for sc in _coupons.wallet(cx, email=email, kind="self"):
            gifts.append(_coupons.mint_gift(cx, email=email, product_slug=sc["product_slug"]))
    return jsonify({"ok": True, "gifting": True, "gifts": gifts})


@app.route("/api/journey/quest-state", methods=["GET", "POST"])
def journey_quest_state():
    if not JOURNEY_QUEST_ENABLED:
        return ("", 404)
    from dashboard.journey_quest import (
        normalize as _nq_normalize,
        merge_quest as _nq_merge,
        load as _nq_load,
        save as _nq_save,
        empty_state as _nq_empty,
    )
    try:
        session_id = (request.cookies.get("amg_session") or "").strip()
        au = get_authenticated_user(request)
        email = (au["email"] if au else "").strip()
        with _db_lock, sqlite3.connect(LOG_DB) as cx:
            state = begin_funnel.get_state(cx, session_id=session_id, email=email)
            email = (state.get("email") or email or "").strip().lower()
            if request.method == "POST":
                try:
                    posted = request.get_json(force=True, silent=True) or {}
                except Exception:
                    posted = {}
                client_state = _nq_normalize(posted)
                if not email:
                    return jsonify({"ok": True, "state": client_state})
                stored = _nq_load(cx, email)
                merged = _nq_merge(stored, client_state)
                _nq_save(cx, email, merged)
                return jsonify({"ok": True, "state": merged})
            else:
                # GET
                if not email:
                    return jsonify({"ok": True, "state": _nq_empty()})
                stored = _nq_load(cx, email)
                return jsonify({"ok": True, "state": stored})
    except Exception:
        try:
            fallback = _nq_normalize(
                request.get_json(force=True, silent=True) or {}
            ) if request.method == "POST" else _nq_empty()
        except Exception:
            from dashboard.journey_quest import empty_state as _fb_empty
            fallback = _fb_empty()
        return jsonify({"ok": True, "state": fallback})


# ToS version stamp for the /begin free-tier gate. The in-app T&C page at
# /terms (static/terms.html) carries no version string, so we date-stamp
# agreement here. Bump when the T&C content materially changes.
BEGIN_TOS_VERSION = "rm-e4l-tc-2026-07-15"


@app.route("/begin/unlock", methods=["POST", "OPTIONS"])
def begin_unlock():
    if request.method == "OPTIONS":
        return "", 200
    data = request.get_json() or {}
    trigger = (data.get("trigger") or "").strip()
    session_id = (
        request.cookies.get("amg_session")
        or (data.get("session_id") or "").strip()
        or uuid.uuid4().hex
    )
    name = (data.get("name") or "").strip()
    first_name_explicit = (data.get("first_name") or "").strip()
    last_name = (data.get("last_name") or "").strip()
    # first_name: use explicit field if provided, else fall back to first token of name
    first_name = first_name_explicit if first_name_explicit else (name.split(None, 1)[0] if name else "")
    email = (data.get("email") or "").strip().lower()
    tos = bool(data.get("tos"))
    detail = (data.get("detail") or "").strip()
    ref_slug = (request.cookies.get("rm_ref") or (data.get("ref") or "")).strip()
    want = (data.get("want") or "").strip().lower()
    path = (data.get("path") or "").strip()

    # Fetch recent chat queries OUTSIDE the lock block (_recent_query_texts
    # acquires _db_lock itself; _db_lock is not reentrant).
    query_texts = _recent_query_texts(session_id, email)

    try:
        with _db_lock, sqlite3.connect(LOG_DB) as cx:
            state = begin_funnel.record_unlock(
                cx, session_id=session_id, trigger=trigger,
                email=email, detail=detail, first_name=first_name,
                last_name=last_name, tos=tos,
                ref_slug=ref_slug,
                tos_version=BEGIN_TOS_VERSION if (tos or trigger == "tos") else "",
                want=want, query_texts=query_texts, path=path,
            )
    except ValueError as e:
        return jsonify({"error": str(e)}), 400

    # Free-tier transition (email + ToS): onboard to GHL + concierge referral,
    # non-blocking — same pattern as /chat.
    if (state["current_rung"] == "free_tier"
            and state.get("rung_before") != "free_tier"
            and state.get("email")):
        import threading as _threading

        def _onboard():
            try:
                ghl_first = state.get("first_name") or ""
                ghl_last = state.get("last_name") or ""
                tags = ["begin", "concierge"]
                if ref_slug:
                    tags.append(f"ref:{ref_slug}")
                    _capture_concierge_referral(state["email"], ghl_first, ghl_last, ref_slug)
                ghl_onboard_contact(state["email"], ghl_first, ghl_last,
                                    source_tag="begin", extra_tags=tags)
            except Exception as e:
                print(f"[begin-onboard] {e!r}", flush=True)

        _threading.Thread(target=_onboard, daemon=True).start()

    # Background awareness classification once enough chat has accrued.
    # Best-effort, fire-once-ish: under rare concurrent unlocks the read-then-spawn
    # gap can spawn two classifier threads, but set_awareness is idempotent so the
    # only cost is a duplicate API call + event row — acceptable.
    try:
        already = False
        with _db_lock, sqlite3.connect(LOG_DB) as cx:
            row = cx.execute(
                "SELECT awareness_classified_at FROM journey_state WHERE session_id=? "
                "ORDER BY id DESC LIMIT 1", (session_id,)).fetchone()
            already = bool(row and row[0])
        if not already and len(query_texts) >= 3:
            _heur = begin_funnel.infer_awareness_heuristic(
                want, set(state.get("unlocked_gates") or []), query_texts)
            import threading as _t
            _t.Thread(target=_classify_awareness_haiku,
                      args=(session_id, list(query_texts), _heur),
                      daemon=True).start()
    except Exception:
        pass

    redirect = begin_funnel.resolve_want(want, ref_slug) if want else None
    payload = dict(state)
    _founding_open = False
    try:
        from dashboard import founding as _founding
        if _founding.get_launch("neuro-magnesium"):
            with sqlite3.connect(LOG_DB) as _fcx:
                _fcx.row_factory = sqlite3.Row
                _founding_open = _founding.is_open(
                    _fcx, "neuro-magnesium", now_iso=_now_utc().strftime("%Y-%m-%d"))
    except Exception:
        _founding_open = False
    payload["surfaced_cards"] = begin_funnel.surface_with_founding(
        state, query_texts, ref_slug, founding_open=_founding_open)
    if redirect:
        payload["redirect"] = redirect
    resp = jsonify(payload)
    if not request.cookies.get("amg_session"):
        resp.set_cookie(
            "amg_session", session_id, max_age=60 * 60 * 24 * 365,
            httponly=True, samesite="Lax", secure=request.is_secure,
        )
    return resp


