# Functional Formulations ($69.97 base) — volume pricing is OPEN TO ALL, driven by the
# order-wide FF quantity through the pricing engine (_inhouse_ff_unit_cents below).
_FF_BASE_CENTS = 6997     # $69.97 — the functional-formulation (FF) capsule regular price
_FF_SRP_CENTS  = 8000     # $80.00 — FF SRP/Value anchor (shown above the $69.97 Regular)
_FORMATS = [
    {"id": "bottle", "label": "Standard bottles", "note": "30 capsules per bottle"},
    {"id": "larger", "label": "Larger bottle", "note": "90, 180, or 360 capsules in one bottle (quantity 3, 6, or 12)"},
    {"id": "refill", "label": "Cellophane refill packs", "note": "Capsules only, no bottle"},
]
# id -> label for the non-default packaging formats. "bottle" (the default) is omitted
# on purpose: only a non-standard choice becomes a fulfillment note on the order line.
_FORMAT_LABELS = {f["id"]: f["label"] for f in _FORMATS if f["id"] != "bottle"}


def _qty_eligible(p):
    # A Functional Formulation that gets the volume curve. Keyed on the explicit
    # qty_pricing FF flag (NOT on price == $69.97): flagging by price is fragile —
    # change FF pricing and volume silently dies, and it left ~55 real FFs (Scar
    # Solve, Nerve Repair, Neuro Magnesium, Terrain Restore…) without volume because
    # the flag was never set. info-only stays excluded. Flag the product = it's an FF.
    return bool(p.get("qty_pricing")) and not p.get("info_only")


def _inhouse_ff_unit_cents(p, total_ff_qty, settings, *, program_member=False, line_qty=1):
    """Effective in-house unit price (cents) for a $69.97 functional-formulation
    capsule (_qty_eligible): a linear volume rate. Clamped at the wholesale
    discount floor. Non-FF products return list price.

    Glen policy (2026-07): the order-wide MIX/MATCH aggregation (rate driven by
    the TOTAL FF quantity across every different FF SKU in the order) is a paid-
    member perk only. A non-paid/$1-trial member still keeps the SAME-SKU
    quantity discount (rate driven by just THIS line's own qty) — they just don't
    get credit for other SKUs in the cart. program_member selects which quantity
    the rate is computed on; the rate curve itself (volume_pct/volume_anchors) is
    unchanged either way."""
    if not _qty_eligible(p):
        return int(p.get("price_cents") or 0)
    from dashboard import pricing as _pricing
    # Base the volume math on the product's OWN price, not a hardcoded $69.97, so
    # changing FF pricing flows through instead of breaking the discount.
    base = int(p.get("price_cents") or 0)
    qty_for_rate = int(total_ff_qty or 0) if program_member else max(1, int(line_qty or 1))
    pct = _pricing.volume_pct(qty_for_rate, settings)
    # Clamp to the canonical discount floor (unit_floor_cents), which also enforces the
    # FF minimum unit price ($50) — keeping the in-house builder identical to compute().
    floor = _pricing.unit_floor_cents(p, base, settings, "discount")
    return _pricing.apply_discount(base, pct, floor)


def _inhouse_total_ff_qty(lines_in):
    """Sum of qty across $69.97 functional-formulation lines in the cart."""
    tot = 0
    for ln in lines_in:
        p = _get_product((ln.get("slug") or "").strip())
        if p and _qty_eligible(p):
            tot += max(1, min(int(ln.get("qty") or 1), 99))
    return tot


def _inhouse_line_unit_cents(p, override, total_ff_qty, settings, repertoire_slugs=None,
                             program_member=False, line_qty=1):
    """Explicit owner override wins; else FF capsules get a volume rate — the
    order-wide mix/match rate for a paid member (program_member=True), or the
    same-SKU (this line's own qty) rate for a non-member (Glen 2026-07 policy;
    see _inhouse_ff_unit_cents) — everything else its list price.

    repertoire_slugs (optional): a member's repertoire SKU set, resolved ONCE per
    checkout by the caller (see _resolve_repertoire_slugs) — already FF-filtered
    there (Glen 2026-07: the repertoire reorder discount is FF-margin-only) — and
    forwarded here so a fresh DB lookup isn't repeated per line. When this line has
    no override, is FF-eligible (_qty_eligible, mirroring the FF-only filter the
    caller already applied to repertoire_slugs), and its slug is already in the
    set, it gets AT LEAST settings['repertoire_reorder_pct'] off list — applied via
    the SAME pricing.apply_discount/unit_floor_cents helpers dashboard.pricing.compute()
    uses for the identical case (Task 3/5's display path), so the two paths agree
    to the cent. Never stacked with the FF volume rate — the lower of the two
    (best-of) wins, matching compute()'s max(...) non-additive rule.
    (repertoire_slugs is only ever non-empty for a paid member already — see
    _resolve_repertoire_slugs — so it never conflicts with the program_member gate.)"""
    if override not in (None, ""):
        return int(override)
    base = _inhouse_ff_unit_cents(p, total_ff_qty, settings,
                                  program_member=program_member, line_qty=line_qty)
    if repertoire_slugs and _qty_eligible(p):
        slug = (p.get("slug") or "").strip().lower()
        if slug in repertoire_slugs:
            from dashboard import pricing as _pricing
            list_cents = int(p.get("price_cents") or 0)
            pct = float(settings.get("repertoire_reorder_pct") or 0.0) * 100.0
            floor = _pricing.unit_floor_cents(p, list_cents, settings, "discount")
            rep_cents = _pricing.apply_discount(list_cents, pct, floor)
            base = min(base, rep_cents)
    return base


def _ff_filter_slugs(slugs):
    """Narrow a repertoire slug set to Functional Formulations only (_qty_eligible —
    the qty_pricing flag, not info_only). Glen 2026-07: the member repertoire
    reorder discount is FF-margin-only, so a non-FF SKU in a member's repertoire
    must never reach the discount logic, at display or at charge. Slugs whose
    product is missing/inactive are dropped (never priced anyway). None/falsy in
    -> empty set out (never None, so callers can treat the result uniformly)."""
    out = set()
    for slug in (slugs or ()):
        p = _get_product(slug)
        if p and _qty_eligible(p):
            out.add(slug)
    return out


def _resolve_repertoire_slugs(email):
    """A paid member's repertoire SKU set, FF-filtered (_ff_filter_slugs — the
    member reorder discount is FF-only), resolved once per checkout (fresh-DB-safe,
    best-effort — mirrors _price_cart's inline resolution). None when the flag is off,
    there's no email, the email isn't a currently-active paid member, or the lookup
    fails; callers treat None/empty the same as "no repertoire effect"."""
    if not (REPERTOIRE_ENABLED and email and _is_paid_member(email)):
        return None
    try:
        with sqlite3.connect(LOG_DB) as _rep_cx:
            repertoire.init_repertoire_table(_rep_cx)  # defensive: fresh-DB guard
            return _ff_filter_slugs(repertoire.repertoire_slugs(_rep_cx, email))
    except Exception as e:
        print(f"[repertoire] inhouse lookup failed for {email!r}: {e!r}", flush=True)
        return None


def _is_paid_member(email):
    """True iff the email gets member (quantity/volume) pricing: an active
    membership of ANY kind EXCEPT an unconverted $1-trial buyer
    (membership_category == 'trial', the free first month). Founding, studio-credit,
    coaching, paused-but-still-current, and full $99/mo members all keep volume
    pricing — only the trial cohort pays regular (its missed discount is accrued and
    handed back as upgrade credit on conversion). The cheap grant check short-circuits
    non-members first (the common funnel case) so only actual members pay for the
    second lookup. Fail-closed (False on error) so a lookup hiccup never hands a
    non-member a discount."""
    try:
        if not (email and _active_membership_for_email(email)):
            return False
        return membership_category(email) != "trial"
    except Exception:
        return False


