def _catalog_products():
    """Every catalog product as a dict carrying its own slug. Used to resolve a
    bundle's component NAMES to products for packing. Includes inactive records on
    purpose: a bundle's contents must stay packable after a component is retired
    from the storefront."""
    return [dict(p, slug=s) for s, p in (_PRODUCTS.get("products") or {}).items()]


def _get_product(slug):
    """The sellable product for a slug, following a retired duplicate to its live twin.

    Duplicate FMP records are retired with `inactive: true` rather than deleted, because
    order history, storefront links and Atlas ids still reference their slugs. Routing
    through `_superseded` here means EVERY consumer — product page, checkout, cart,
    images — keeps mapping a stale slug to the surviving record, and carries the
    survivor's slug forward. A record that is inactive with no `superseded_by` still
    resolves to None: retired means retired."""
    slug = _superseded(slug)
    p = (_PRODUCTS.get("products") or {}).get(slug)
    if not p or p.get("inactive"):
        return None  # inactive products are not sellable/visible on the funnel
    out = dict(p)
    out["slug"] = slug
    out.setdefault("price_cents", _PRODUCTS.get("default_price_cents", 6997))
    return out


def _superseded(slug):
    """Follow a deprecated product's `superseded_by` pointer to its live twin.

    Delegates to dashboard.products.superseded_slug — the one implementation — but hands
    it app's already-in-memory catalog rather than letting it re-read the file. Two copies
    of this walk would drift, and the purchase_history / repertoire write boundaries call
    the same resolver."""
    from dashboard import products as _products_mod  # module cached; attr read at CALL time
    return _products_mod.superseded_slug(slug, (_PRODUCTS.get("products") or {}))


def _live_slug(slug):
    """A slug the caller can actually sell: redirected past any deprecated record.
    None when it resolves to nothing sellable, so callers report it rather than
    carrying an unsellable slug forward."""
    slug = _superseded(slug)
    return slug if slug and _get_product(slug) else None


def _resolve_remedy_slug(r):
    """Resolve a pushed/typed remedy to a SELLABLE catalog slug: its slug if valid,
    else its name via _TITLE_TO_SLUG (exact then case-insensitive), else the name/title
    index (matches by catalog `name` too, HTML-unescaped), else the code fallback.

    Every hit is routed through _live_slug, so a name that lands on a deprecated
    duplicate redirects to its surviving twin (`superseded_by`) instead of returning an
    unsellable slug. None when nothing sellable matches -- callers list those as
    dropped rather than carrying a dead end. Never raises."""
    try:
        s = (r.get("slug") or "").strip()
        if s:
            live = _live_slug(s)
            if live:
                return live
        name = (r.get("name") or "").strip()
        if not name:
            return None
        if name in _TITLE_TO_SLUG:
            return _live_slug(_TITLE_TO_SLUG[name])
        low = name.lower()
        for title, slug in _TITLE_TO_SLUG.items():
            if (title or "").strip().lower() == low:
                return _live_slug(slug)
        # In-catalog rescue: match by catalog `name` OR pinecone_title, HTML-unescaped.
        # Fixes drops where name != pinecone_title (e.g. 'Brain Boost' vs title
        # 'Brain Boost Nootropic') or the title carried entities ('Free &amp; Easy').
        hit = _RESOLVE_NAME_INDEX.get(_ihtml.unescape(name).strip().lower())
        if hit:
            return _live_slug(hit)
        # Infoceutical code fallback: the matcher pushes the bare code ("EI8") while
        # the catalog name is "EI8 Microbes-Liver Integrator". Match by code prefix so
        # infoceuticals resolve (and so are recommended, not dropped).
        if re.match(r"^(ei|es|ed|et|mb|mr|sk|bfa)\d+$", low):
            for title, slug in _TITLE_TO_SLUG.items():
                t = (title or "").strip().lower()
                if t == low or t.split(" ")[0] == low:
                    return _live_slug(slug)
        return None
    except Exception:
        return None


def _is_pure_powder(p):
    return "pure powder" in (p.get("name") or "").lower() or "pure-powder" in (p.get("slug") or "")


def _engine_item(p, qty):
    """Build a dashboard.pricing.compute() item from a product dict + quantity.
    Derives months (months_per_unit*qty, default 1/unit), volume eligibility
    (all Functional Formulations; Pure Powders + info_only excluded), and the
    per-SKU floor override for Pure Powders (0.75 -> ~$30)."""
    qty = max(1, int(qty))
    months_per_unit = int(p.get("months_per_unit", 1))
    if "volume_eligible" in p:
        eligible = bool(p["volume_eligible"])
    elif p.get("info_only"):
        eligible = False
    elif p.get("qty_pricing"):
        eligible = True   # a flagged FF (incl. FF powder blends) → full volume, same as in-house
    else:
        eligible = not _is_pure_powder(p)   # non-FF unchanged: true pure powders excluded
    prod = dict(p)
    # The ~$30 pure-powder floor applies only to a TRUE pure powder, never to a
    # flagged FF powder blend (which gets the full FF volume curve).
    if _is_pure_powder(p) and not p.get("qty_pricing") and "sku_discount_floor_pct" not in prod:
        prod["sku_discount_floor_pct"] = 0.75
        prod["sku_points_floor_pct"] = 0.75
    return {
        "slug": p.get("slug"), "name": p.get("name", p.get("slug")), "qty": qty,
        "product": prod, "unit_cents": int(p.get("price_cents") or 0),
        "months": months_per_unit * qty, "volume_eligible": eligible,
    }


class CheckoutError(Exception):
    """Raised for a checkout the customer must fix (e.g. non-US ship-to)."""


# USPS flat-rate box thresholds by total bottle count (Glen 2026-06-14): <=4 S, <=12 M, else L.
# Used as a fail-safe when the box-fit catalog can't pick a box; the catalog (when Rae fills it
# at /admin/shipping) takes precedence via shipping.quote().
_SHIP_FALLBACK_HARD = {"S": 1300, "M": 2300, "L": 3200}   # rounded rates if even the rates table is down


def _fallback_shipping_cents(total_bottles):
    """Qty-based USPS box fallback (rounded charged rate). Never raises."""
    n = int(total_bottles or 0)
    if n <= 0:
        return 0
    size = "S" if n <= 4 else ("M" if n <= 12 else "L")
    try:
        rates = _shipping.get_current_rates() or {}
        r = rates.get(size) or {}
        cents = int(r.get("charged_cents") or r.get("usps_retail_cents") or 0)
        return cents or _SHIP_FALLBACK_HARD[size]
    except Exception:
        return _SHIP_FALLBACK_HARD[size]


def _shipping_for_cart(box_counts, total_bottles):
    """Real USA shipping for a cart, always charged, never breaking checkout.
    Tries the box-fit catalog (shipping.quote keyed by bottle type); if the catalog
    is empty / a type is unknown / no box fits, falls back to the qty->box rule."""
    if not box_counts:
        return 0
    try:
        q = _shipping.quote(box_counts) or {}
        cents = int(q.get("shipping_cents") or 0)
        if cents > 0:
            return cents
    except Exception as e:
        print(f"[shipping] quote fell back ({e!r}); using qty rule for {total_bottles} bottles", flush=True)
    return _fallback_shipping_cents(total_bottles)


def _subscription_tier_resolver(order_count, active=True):
    """Per-line subscriber-discount resolver for a subscription charge.
    Bundle lines flagged autoship_eligible climb the 12->29 bundle ladder;
    every other line climbs the standard 3->25 ladder. When the member is not
    paid-through (active False) all lines get 0 — matching the prior cron gate."""
    from dashboard import subscriptions as _subs
    oc = int(order_count or 0)

    def _resolve(it):
        if not active:
            return 0
        p = it.get("product") or {}
        if p.get("bundle") and p.get("autoship_eligible"):
            return _subs.tier_for_bundle(oc)
        return _subs.tier_for(oc)

    return _resolve


def _cart_has_noautoship_bundle(cart):
    """True if any cart line is a bundle explicitly barred from autoship
    (autoship_eligible False) — device bundles are one-time purchase only."""
    for c in (cart or []):
        p = _get_product((c.get("slug") or "").strip())
        if p and p.get("bundle") and not p.get("autoship_eligible", False):
            return True
    return False


def _price_cart(cart, *, ship, coupon_pct=None, subscriber_tier_pct=None,
                subscriber_order_count=None, subscriber_active=True,
                points_to_redeem_cents=0, channel="retail", program_member=False,
                email=None):
    """Price a reorder/checkout cart through the pricing engine + shipping.
    Returns {priced, qbo_lines, discount_cents, points_redeemed_cents, shipping_cents,
    items_rec, subtotal_list_cents}. Raises CheckoutError for non-US ship-to.

    email (optional): when REPERTOIRE_ENABLED and the email belongs to a currently
    active paid member (_is_paid_member), resolves that member's repertoire SKU set
    and forwards it to the pricing engine so repertoire reorders price at the flat
    member rate. Gated on CURRENT membership at read time — no stored per-SKU expiry.
    Flag off (or no/non-member email) -> repertoire_slugs stays None, pricing unchanged."""
    from dashboard import pricing as _pricing, tax as _tax
    rep_slugs = None
    if REPERTOIRE_ENABLED and email and _is_paid_member(email):
        try:
            with sqlite3.connect(LOG_DB) as _rep_cx:
                repertoire.init_repertoire_table(_rep_cx)  # defensive: fresh-DB guard
                # FF-only (Glen 2026-07, margin): non-FF repertoire SKUs never reach
                # the discount engine, matching _resolve_repertoire_slugs.
                rep_slugs = _ff_filter_slugs(repertoire.repertoire_slugs(_rep_cx, email))
        except Exception as e:
            print(f"[repertoire] lookup failed for {email!r}: {e!r}", flush=True)
            rep_slugs = None
    country = (ship.get("country") or "US").strip().upper()
    settings = _pricing.load_settings(_pricing_settings())
    items, qbo_lines, items_rec, box_counts, subtotal_list, total_bottles = [], [], [], {}, 0, 0
    flat_ship_cents = 0   # sum of per-product fixed shipping overrides (own-parcel items)
    for c in (cart or []):
        p = _get_product((c.get("slug") or "").strip())
        if not p:
            continue
        qty = max(1, min(int(c.get("qty", 1) or 1), 99))
        it = _engine_item(p, qty)
        items.append(it)
        subtotal_list += it["unit_cents"] * qty
        # A non-default packaging format (larger bottle / refill packs) becomes a
        # fulfillment note folded into the display name (kanban) and QBO line description
        # (invoice). "bottle"/unset -> plain product name. Keeps the QBO line NAME clean
        # for item mapping; only the description is decorated.
        _fmt_label = _FORMAT_LABELS.get((c.get("format") or "").strip().lower(), "")
        _disp_name = f'{p["name"]} ({_fmt_label})' if _fmt_label else p["name"]
        qbo_lines.append({"name": p["name"], "amount": round(it["unit_cents"] / 100.0, 2),
                          "qty": qty, "item_id": p.get("qbo_item_id"), "description": _disp_name})
        # shipping.pick_box keys by BOTTLE TYPE (not product name); default-typed if unset.
        # Use the RESOLVED slug: a retired duplicate redirects to its live twin, and the
        # stored order line + bottle lookup must both name the survivor, not the dead slug.
        slug = p["slug"]
        # Persist per-line LIST pricing on the stored order (cart-level discounts ride
        # the order's discount_cents, which the invoice renders separately, so
        # subtotal − discount still reconciles to the total).
        items_rec.append({"name": _disp_name, "qty": qty, "desc": _disp_name,
                          "slug": slug, "unit_cents": it["unit_cents"], "line_cents": it["unit_cents"] * qty})
        # Services / digital goods carry no bottle: counting them would push the
        # "default" placeholder into quote(), which raises UnknownBottleType and
        # drops the whole cart to the coarse qty rule — charging a phantom bottle.
        if _shipping.is_shippable(p):
            _flat = int(p.get("flat_shipping_cents") or 0)
            if _flat > 0 and not p.get("bundle"):
                # Own-parcel item with a FIXED shipping charge (e.g. the water ionizers,
                # which each ship in their own box). Bill the flat rate per unit and keep
                # it OUT of the box packer: its bottle_type is own-box, which quote()
                # can't fit → the qty fallback would otherwise undercharge a heavy device
                # at the Small-box rate. Still counts as a shipment for the US-only guard.
                flat_ship_cents += _flat * qty
            elif p.get("bundle"):
                # A bundle is ONE line holding several bottles and has no bottle_type
                # of its own. Pack its CONTENTS, or it counts as one bottle: undersized
                # box, undercharged shipping. Price is untouched — the bundle's own
                # price_cents already priced the line above.
                try:
                    _comps = _shipping.bundle_component_products(p, _catalog_products())
                except _shipping.UnknownBundleComponent as e:
                    # Loud: a bundle whose contents can't be identified can't be packed
                    # correctly by a human either. Never fall back to the one-bottle
                    # undercharge. CheckoutError surfaces as a 400, not a 500.
                    raise CheckoutError(str(e))
                for _comp in _comps:
                    _bt = _shipping.resolve_bottle_type(_comp["slug"], _comp)
                    box_counts[_bt] = box_counts.get(_bt, 0) + qty
                    total_bottles += qty
            else:
                bt = _shipping.resolve_bottle_type(slug, p)
                box_counts[bt] = box_counts.get(bt, 0) + qty
                total_bottles += qty
    # US-only shipping — but only a cart with something to ship has an opinion
    # about the address. An overseas client buying a service prices fine.
    if (box_counts or flat_ship_cents) and country not in ("US", "USA", ""):
        raise CheckoutError("We ship to US addresses only — please use a US forwarding address.")
    tier_arg = subscriber_tier_pct
    if subscriber_order_count is not None:
        tier_arg = _subscription_tier_resolver(subscriber_order_count, subscriber_active)
    priced = _pricing.compute(items, settings=settings, coupon_pct=coupon_pct,
                              subscriber_tier_pct=tier_arg, channel=channel,
                              points_to_redeem_cents=int(points_to_redeem_cents or 0),
                              ship_to_state=ship.get("state", ""),
                              tax_fn=_tax.compute_get_cents,
                              program_member=bool(program_member),
                              repertoire_slugs=rep_slugs)
    shipping_cents = flat_ship_cents + _shipping_for_cart(box_counts, total_bottles)
    return {
        "priced": priced, "qbo_lines": qbo_lines, "items_rec": items_rec,
        "subtotal_list_cents": subtotal_list,
        "discount_cents": priced["discount_cents"],
        "points_redeemed_cents": priced["points_redeemed_cents"],
        "shipping_cents": shipping_cents,
    }


def _rewards_enabled() -> bool:
    """True when the rewards/referral system is switched on."""
    return bool(os.environ.get("REWARDS_TIERS_ENABLED", ""))


def _referrer_slug_for_email(cx, email: str):
    """Return the slug of the most-recent approved affiliate who referred this email, or None."""
    email = (email or "").strip().lower()
    if not email:
        return None
    row = cx.execute(
        """SELECT re.utm_source FROM referral_events re
           JOIN affiliate_signups a ON a.slug = re.utm_source AND a.status = 'approved'
           WHERE LOWER(re.email) = ?
           ORDER BY re.received_at DESC LIMIT 1""",
        (email,)
    ).fetchone()
    return row[0] if row else None


def _referral_pct_for_referrer(referrer_email, settings):
    """Cert-scaled referral FRACTION. If the referrer is a practitioner, interpolate their
    modules_completed through referral_cert_anchors; otherwise (or on any lookup error) the
    base referral_reward_pct. Best-effort: never raises."""
    from dashboard import rewards as _rewards
    base = float(settings.get("referral_reward_pct", 0.05))
    try:
        modules = _pp.modules_completed_for_email(referrer_email)
        if modules is None:
            return base
        return _rewards.referral_pct_for_modules(modules, settings)
    except Exception as _e:
        print(f"[rewards] cert lookup failed for {referrer_email}: {_e!r}", flush=True)
        return base


def _settle_referral(order, *, order_ref: str) -> None:
    """Credit the referrer (points or cash) on a full-price referred sale.
    Idempotent per order_ref. Best-effort -- never raises."""
    if not _rewards_enabled():
        return
    try:
        from dashboard import points as _points
        from dashboard import rewards as _rewards
        buyer_email = (order.get("email") or "").strip().lower()
        if not buyer_email:
            return
        product_cents = (int(order.get("total_cents") or 0)
                         - int(order.get("shipping_cents") or 0)
                         - int(order.get("get_cents") or 0))
        # Only credit on full-price sales
        if int(order.get("discount_cents") or 0) != 0:
            return
        with sqlite3.connect(LOG_DB) as cx:
            cx.row_factory = sqlite3.Row
            _points.init_points_table(cx)
            _rewards.init_affiliate_earnings_table(cx)
            slug = _referrer_slug_for_email(cx, buyer_email)
            if not slug:
                return
            referrer_email = _rewards.referrer_email_for_slug(cx, slug)
            if not referrer_email:
                return
            # Exclude self-referral
            if referrer_email.strip().lower() == buyer_email:
                return
            settings = _rewards.load_settings(_rewards_settings())
            referral_reward_pct = _referral_pct_for_referrer(referrer_email, settings)
            reward = round(product_cents * referral_reward_pct)
            if reward <= 0:
                return
            mode = _rewards.reward_mode_for_slug(cx, slug)
            if mode == "points":
                _points.credit(cx, referrer_email,
                               value_cents=reward, reason="referral", order_ref=order_ref)
            else:
                _rewards.accrue_cash(cx, slug=slug, email=referrer_email,
                                     order_ref=order_ref, amount_cents=reward)
            _maybe_raise_cashout_review(cx, slug, mode)
    except Exception as _e:
        print(f"[rewards] _settle_referral failed inv={order_ref}: {_e!r}", flush=True)


def _maybe_raise_cashout_review(cx, slug: str, mode: str) -> None:
    """Insert a review todo if a CASH-mode affiliate's pending earnings cross a
    threshold band. Points are store-credit/gift only and not cashable, so
    points-mode raises no review. Idempotent: dedup_key prevents duplicates
    within the same threshold band."""
    try:
        from dashboard import rewards as _rewards
        settings = _rewards.load_settings(_rewards_settings())
        threshold = int(settings["cash_out_threshold_cents"])
        if mode != "cash":
            return  # points are not cashable; no cash-out review
        amount = _rewards.pending_cash_total(cx, slug)
        if amount < threshold:
            return
        band = amount // threshold
        dedup_key = f"cashout:{slug}:{band}"
        body = (f"Affiliate '{slug}' has ${amount/100:.2f} pending cash earnings "
                f"(threshold ${threshold/100:.2f}). Approve payout via rewards.process_payout.")
        from datetime import datetime as _dt, timezone as _tz
        now = _dt.now(_tz.utc).isoformat()
        cx.execute(
            """INSERT INTO todos (created_at, owner, category, title, body, priority, source, dedup_key)
               VALUES (?, ?, ?, ?, ?, ?, ?, ?)
               ON CONFLICT(dedup_key) DO NOTHING""",
            (now, "glen", "Finance",
             f"Review ${amount/100:.2f} cash-out for {slug}",
             body, "high", "affiliate-cashout", dedup_key)
        )
        cx.commit()
    except Exception as _e:
        print(f"[rewards] _maybe_raise_cashout_review failed slug={slug}: {_e!r}", flush=True)


def _raise_settlement_skip_todo(order_ref, kind, skipped):
    """Best-effort: when per-kind settlement skipped one or more effects (a settler
    raised and was swallowed best-effort, then the order was marked settled and will
    NOT retry), raise ONE deduped console todo so the stranded effect is visible +
    actionable. Never raises into the request path."""
    try:
        if not order_ref or not skipped:
            return
        from datetime import datetime as _dt, timezone as _tz
        now = _dt.now(_tz.utc).isoformat()
        names = ", ".join(str(s) for s in skipped)
        dedup_key = f"settle-skip:{order_ref}"
        _init_todos_table()
        _tcx = sqlite3.connect(LOG_DB)
        try:
            _tcx.execute(
                """INSERT INTO todos (created_at, owner, category, title, body, priority, source, dedup_key)
                   VALUES (?, ?, ?, ?, ?, ?, ?, ?)
                   ON CONFLICT(dedup_key) DO NOTHING""",
                (now, "glen", "Fulfillment",
                 f"Settlement skipped for order {order_ref}",
                 f"Order {order_ref} (kind={kind}) was marked settled but these effects were "
                 f"skipped and will not auto-retry: {names}. Re-run settlement manually if needed.",
                 "high", "settlement-skip", dedup_key))
            _tcx.commit()
        finally:
            _tcx.close()
    except Exception as _e:
        print(f"[settlement] skip-todo failed ref={order_ref!r}: {_e!r}", flush=True)


def _settle_referrer_reward(cx, order, order_ref):
    """On a paid referral order: credit the referrer pct% of the referee's product spend.
    Returns cents credited (0 if none). Idempotent per referee; never raises into the caller."""
    if not _REFERRALS:
        return 0
    from dashboard import referrals as _rf, points as _points
    _points.init_points_table(cx)
    pct = _referrer_reward_pct()
    if pct <= 0:
        return 0
    red = _rf.redemption_by_order_ref(cx, order_ref)
    if not red or (red.get("rewarded_at") or "") or not (red.get("owner_email") or "").strip():
        return 0
    product_cents = max(0, int(order.get("total_cents") or 0)
                        - int(order.get("shipping_cents") or 0)
                        - int(order.get("get_cents") or 0))
    reward = product_cents * pct // 100
    # Drop-ship / portal sales are paid at wholesale (the practitioner's markup IS their pay),
    # so NO L1 is credited on them — only the L2 override below. Ambassador referrals
    # (kind='referral') keep L1. The row is still stamped (mark_rewarded) so it never pays later.
    l1_suppressed = (red.get("kind") == "dispensary_portal")
    if reward > 0 and not l1_suppressed:
        _points.credit(cx, red["owner_email"], value_cents=reward, reason="referral_reward",
                       order_ref=f"referral:{red['referee_email']}")
    # Tier-2 (non-cashable points, half the Tier-1 rate): the referrer's OWN referrer
    # earns on this sale too. Forward-only — this runs before mark_rewarded, so a replay
    # hits the rewarded_at early-return above and never double-credits either tier. Flag-dark.
    # dispensary_portal L2 is settled per-order by dashboard.dispensary_rewards
    # (every reorder, every pay method), so it is excluded here to avoid double-paying
    # the first order. Ambassador (kind='referral') L2 is unchanged.
    if REFERRAL_TIER2_ENABLED and not l1_suppressed:
        l2_owner = _rf.owner_of_referee(cx, red["owner_email"])
        # No self-dealing / cycles: L2 must exist and differ from the buyer AND from L1.
        if l2_owner and l2_owner != red["referee_email"] and l2_owner != red["owner_email"]:
            reward_l2 = product_cents * pct // 200
            if reward_l2 > 0:
                _points.credit(cx, l2_owner, value_cents=reward_l2, reason="referral_reward_l2",
                               order_ref=f"referral_l2:{red['referee_email']}")
    _rf.mark_rewarded(cx, red["referee_email"], reward_cents=reward)
    return 0 if l1_suppressed else reward


def _capture_portal_referral(dispensary_code, patient_email, practitioner_email, order_ref):
    """Bridge a dispensary-link sale into the referral graph: first-touch write of a
    kind='dispensary_portal' redemption so all this patient's future orders attribute to
    the practitioner (L2 points only, never L1). Best-effort — never raises into checkout."""
    if not _REFERRALS or not (patient_email or "").strip() or not (practitioner_email or "").strip():
        return
    try:
        from dashboard import referrals as _rf
        with _db_lock, sqlite3.connect(LOG_DB) as cx:
            _rf.record_redemption(cx, dispensary_code or "", practitioner_email, patient_email,
                                  order_ref or "", kind="dispensary_portal")
    except Exception as _e:
        print(f"[referrals] portal capture skipped: {_e!r}", flush=True)


def _settle_order_points(order, *, order_ref):
    """On a PAID order: deduct redeemed points, and earn 5% if it was a full-price order.
    Idempotent per order_ref. Best-effort -- never raises into the return handler.
    Buyer earn is suppressed on an affiliate-acquired first order (REWARDS_TIERS_ENABLED)."""
    from dashboard import points as _points
    email = (order.get("email") or "").strip().lower()
    if not email:
        return
    earn_pct = float(_pricing_settings().get("points_earn_pct", 0.05))
    redeemed = int(order.get("points_redeemed_cents") or 0)
    discount = int(order.get("discount_cents") or 0)
    # Earn on PRODUCT spend only: total includes GET (absorbed) when TAX_ENABLED, so net out
    # both shipping and get_cents to avoid earning points on tax/shipping.
    product_cents = (int(order.get("total_cents") or 0)
                     - int(order.get("shipping_cents") or 0)
                     - int(order.get("get_cents") or 0))
    with sqlite3.connect(LOG_DB) as cx:
        cx.row_factory = sqlite3.Row
        _points.init_points_table(cx)
        if redeemed > 0 and not _points.has_entry(cx, order_ref=order_ref, reason="redeem"):
            try:
                _points.redeem(cx, email, value_cents=redeemed, order_ref=order_ref)
            except ValueError:
                pass   # balance already spent elsewhere; don't block the order
        # Slice 2 (dark): consume any shipping credit that a checkout auto-applied to
        # THIS order, debiting the customer's ship_credit balance. Central + idempotent
        # per order_ref, so every checkout flow settles the same way (mirrors points).
        applied = int(order.get("ship_credit_applied_cents") or 0)
        if applied > 0:
            from dashboard import ship_credit as _ship_credit
            _ship_credit.consume(cx, email, applied, applied_ref=order_ref)
        # Earn only on a full-price order (no discount AND no points used) -- the "full-price only" rule.
        # Additional suppression: skip buyer earn on an affiliate-acquired FIRST order.
        if discount == 0 and redeemed == 0 and product_cents > 0 \
                and not _points.has_entry(cx, order_ref=order_ref, reason="earn"):
            # Suppression gate: if rewards are enabled AND this is buyer's first order
            # AND there is an attributed referrer, don't give the buyer earn points.
            suppress = False
            if _rewards_enabled():
                try:
                    order_count = cx.execute(
                        "SELECT COUNT(*) FROM orders WHERE lower(email)=?",
                        (email,)
                    ).fetchone()[0]
                    if order_count <= 1 and _referrer_slug_for_email(cx, email) is not None:
                        suppress = True
                except Exception as _se:
                    print(f"[rewards] suppression check failed: {_se!r}", flush=True)
            if not suppress:
                _points.earn(cx, email, full_price_cents=product_cents, earn_pct=earn_pct,
                             order_ref=order_ref)
        # ── Phase 4: image-pick reward (1 point per product the buyer picked both pairs for) ──
        try:
            from dashboard import sales_votes as _sv4
            for _it in (order.get("items") or []):
                _islug = (_it.get("slug") or "").strip()
                if not _islug:
                    continue
                if _sv4.picked_both(cx, _islug, email=email) and not _points.has_entry(
                        cx, order_ref=f"imgpick_{_islug}", reason="image_pick"):
                    _points.credit(cx, email, value_cents=_IMAGE_PICK_REWARD_CENTS,
                                   reason="image_pick", order_ref=f"imgpick_{_islug}")
        except Exception as _ipe:
            print(f"[img-pick] credit skipped: {_ipe!r}", flush=True)
        # ── 2b-2: referrer reward (pct of referee's product spend on a paid referral order) ──
        try:
            _settle_referrer_reward(cx, order, order_ref)
        except Exception as _rre:
            print(f"[referrals] referrer reward skipped: {_rre!r}", flush=True)
        # Dispensary sales pay L2-only (upline), on every paid order incl. reorders,
        # via the dedicated per-order settler. Gated on source so it never touches
        # non-dispensary orders.
        if (order.get("source") or "") == "dispensary":
            try:
                from dashboard import dispensary_rewards as _dr
                _dr.settle_dispensary_l2(cx, order, order_ref)
            except Exception as _de:
                print(f"[dispensary-l2] card settle skipped: {_de!r}", flush=True)


# ── Per-kind paid-order settlers (extracted from begin_checkout_return) ──────
# These four functions are the block bodies that used to live inline in the
# /begin/checkout-return "paid" branch. They are dispatched by
# dashboard.order_settlement.settle_paid_order_effects (via _SETTLEMENT_DEPS) so
# the redirect and the Stripe webhook settle a paid order identically. Every one
# is idempotent per order_ref / invoice and best-effort (never raises).

def _ensure_subscription_row(md, pi_id):
    """Subscribe-kind settler: vault the card + create the subscription row,
    deduped on the originating order_ref (create_once replaces bare create so a
    redirect refresh / redirect-vs-webhook race never double-creates)."""
    if not pi_id:
        return
    try:
        from dashboard import stripe_pay as _sp
        from dashboard import subscriptions as _subs_ret
        pi_data = _sp.get_payment_intent(pi_id)
        stripe_cus = pi_data.get("customer") or ""
        stripe_pm  = pi_data.get("payment_method") or ""
        cadence    = int(md.get("cadence_months") or 1)
        sub_email  = md.get("email") or ""

        # Recover items + ship from metadata or stash
        stash_key = md.get("stash_key")
        if stash_key:
            with sqlite3.connect(LOG_DB) as _scx:
                _scx.row_factory = sqlite3.Row
                _sr = _scx.execute(
                    "SELECT items_json, ship_json FROM pending_subscriptions WHERE key=?",
                    (stash_key,)).fetchone()
            if not _sr:
                app.logger.warning(
                    "subscribe stash miss for key=%s — subscription will have "
                    "empty items/address", stash_key)
            items_list = json.loads(_sr["items_json"]) if _sr else []
            ship_dict  = json.loads(_sr["ship_json"])  if _sr else {}
        else:
            items_list = json.loads(md.get("items") or "[]")
            ship_dict  = json.loads(md.get("ship")  or "{}")

        today = _now_utc().strftime("%Y-%m-%d")
        next_date = _subs_ret.add_months(today, cadence)

        with sqlite3.connect(LOG_DB) as _scx2:
            _scx2.row_factory = sqlite3.Row
            _subs_ret.init_subscriptions_table(_scx2)
            _rowid = _subs_ret.create_once(
                _scx2,
                order_ref=(md.get("invoice_id") or ""),
                email=sub_email,
                stripe_customer_id=stripe_cus,
                stripe_payment_method_id=stripe_pm,
                items=items_list,
                cadence_months=cadence,
                ship_address=ship_dict,
                next_charge_date=next_date,
                order_count=1)   # the setup checkout already placed order #1 (5%)
            if _rowid is None:
                return  # already created for this order_ref (dedup) — no-op
        print(f"[subscribe-return] subscription created for {sub_email}", flush=True)
    except Exception as _se:
        print(f"[subscribe-return] failed to create subscription: {_se!r}", flush=True)


def _grant_group_bundle(md, pi_id):
    """Group-bundle settler: grant the free live-group window + start the $99/mo
    membership (flag-gated, idempotent per invoice). Fires for any paid kind that
    carries grant_group_months (today only retail program orders do)."""
    if not (os.environ.get("GROUP_BUNDLE_ENABLED")
            and int(md.get("grant_group_months") or 0) > 0 and pi_id):
        return
    try:
        from dashboard import stripe_pay as _sp
        from dashboard import subscriptions as _subs_gb, group_bundle as _gb
        from datetime import date as _date_gb
        n = int(md.get("grant_group_months"))
        g_email = (md.get("email") or "").strip().lower()
        g_invoice = (md.get("invoice_id") or pi_id or "").strip()
        if g_email:
            pi_d = _sp.get_payment_intent(pi_id)
            g_cus = pi_d.get("customer") or ""
            g_pm  = pi_d.get("payment_method") or ""
            with sqlite3.connect(LOG_DB) as _gcx:
                _gcx.row_factory = sqlite3.Row
                _subs_gb.init_subscriptions_table(_gcx)
                _subs_gb.migrate_add_membership_columns(_gcx)
                _subs_gb.migrate_add_term_cap_column(_gcx)
                _subs_gb.migrate_add_attribution_column(_gcx)
                _subs_gb.migrate_add_consent_column(_gcx)
                _gcx.execute(
                    "CREATE TABLE IF NOT EXISTS group_bundle_grants "
                    "(invoice_id TEXT PRIMARY KEY, created_at TEXT)")
                _gcx.commit()
                # Claim the grant marker ATOMICALLY before any side effect: exactly one
                # run wins ON CONFLICT, so a concurrent redirect+webhook settle (or a
                # second delivery) can't double-create the membership or double-send the
                # welcome. (Trade-off: a hard crash between this commit and create_membership
                # would strand this one free-window grant — rare, and strictly better than
                # the double-grant it replaces.)
                claim = _gcx.execute(
                    "INSERT INTO group_bundle_grants (invoice_id, created_at) VALUES (?,?) "
                    "ON CONFLICT(invoice_id) DO NOTHING", (g_invoice, _now_utc().isoformat()))
                _gcx.commit()
                if claim.rowcount == 0:
                    return  # another run already claimed/granted this invoice
                existing = _subs_gb.active_memberships_by_email(_gcx, g_email)
                if existing:
                    cur = existing[0]
                    _subs_gb.set_next_charge_date(
                        _gcx, cur["id"],
                        _subs_gb.add_months(cur["next_charge_date"], n))
                elif g_cus and g_pm:
                    start = _subs_gb.add_months(_date_gb.today().isoformat(), n)
                    _subs_gb.create_membership(
                        _gcx, email=g_email, stripe_customer_id=g_cus,
                        stripe_payment_method_id=g_pm,
                        amount_cents=_gb.MEMBERSHIP_AMOUNT_CENTS,
                        next_charge_date=start)
                    _member_join_welcome(_gcx, g_email, "subscription")
                _gcx.commit()
                print(f"[group-bundle] granted {n}mo to {g_email} inv={g_invoice}", flush=True)
    except Exception as _ge:
        app.logger.exception("group bundle grant failed: %s", _ge)
        raise


def _settle_client_effects(md):
    """Client-kind settler: credit practitioner dropship margin to the wallet,
    record the dispensary order, settle dispensary-scope points (flag-gated), and
    consume any auto-applied ship credit. (The `kind=='client'` guard is now the
    orchestrator's dispatch.)"""
    try:
        from dashboard import wallet as _wallet_ret
        _pid   = md.get("practitioner_id")
        _marg  = int(md.get("margin_cents") or 0)
        _inv   = md.get("invoice_id")
        _wallet_ret.earn_dropship_margin(
            _pid, _marg, qbo_invoice_id=_inv)
        if hasattr(_pp, "record_dispensary_order"):
            _pp.record_dispensary_order(
                _pid,
                invoice_id=_inv,
                credit_earned_cents=_marg,
            )
        if os.environ.get("CLIENT_POINTS_ENABLED"):
            try:
                from dashboard import points as _points_ret
                p_email = (md.get("patient_email") or "").strip().lower()
                redeemed = int(md.get("points_redeemed_cents") or 0)
                subtotal = int(md.get("subtotal_cents") or 0)
                scope = f"dispensary:{_pid}"
                if p_email:
                    with sqlite3.connect(LOG_DB) as _pcx:
                        _pcx.row_factory = sqlite3.Row
                        _points_ret.init_points_table(_pcx)
                        if redeemed > 0:
                            # redeem() writes reason "redeem"; guard on that
                            # so a re-run of the same invoice does not double-redeem.
                            if not _points_ret.has_entry(_pcx, order_ref=_inv,
                                    reason="redeem", scope=scope):
                                take = min(redeemed,
                                           _points_ret.balance(_pcx, p_email, scope=scope))
                                if take > 0:
                                    _points_ret.redeem(_pcx, p_email, value_cents=take,
                                                       order_ref=_inv, scope=scope)
                        elif subtotal > 0:
                            earn_pct = float(_pricing_settings().get("points_earn_pct", 0.05))
                            _points_ret.credit(_pcx, p_email,
                                value_cents=round(subtotal * earn_pct),
                                reason="earn:dispensary", order_ref=_inv, scope=scope)
            except Exception as _pe:
                app.logger.exception("client points settle failed: %s", _pe)
        # Slice 2b: consume any shipping credit auto-applied to this
        # dispensary order (global ship_credit scope, email-keyed —
        # NOT the dispensary points scope). This flow settles here, not
        # via _settle_order_points/set_order_payment; idempotent per
        # invoice. Read the applied amount off the ingested order.
        try:
            _p_email = (md.get("patient_email") or "").strip().lower()
            if _p_email and _inv:
                with sqlite3.connect(LOG_DB) as _sccx:
                    _sccx.row_factory = sqlite3.Row
                    _o = _bos_orders.find_order_by_external_ref(_sccx, str(_inv))
                    _applied = int((_o or {}).get("ship_credit_applied_cents") or 0)
                    if _applied > 0:
                        from dashboard import ship_credit as _shc
                        _shc.consume(_sccx, _p_email, _applied, applied_ref=str(_inv))
        except Exception as _sce:
            app.logger.exception("client ship-credit settle failed: %s", _sce)
    except Exception as _ce:
        app.logger.exception(
            "client margin credit failed: %s", _ce)


def _settle_biofield_effects(md, sid):
    """Biofield-kind settler: seed paid readiness + grant the 30-day Continuous
    Care taster. ONLY these two — biofield's points/referral settle via the common
    path, and its PI-stamp + Sales-Receipt booking stay inline in the handler
    (common, not per-kind)."""
    try:
        from dashboard import biofield_store as _bf
        bf_email = (md.get("email") or "").strip().lower()
        bf_inv = md.get("invoice_id") or ""
        if bf_email:
            _bcx = _sqlite3.connect(LOG_DB)
            try:
                _bf.init_table(_bcx)
                _bf.seed_paid(_bcx, bf_email, via="stripe", order_ref=bf_inv)
            finally:
                _bcx.close()
            # ── Continuous Care taster: 30-day paid grant (flag-gated) ──
            # Shared with the Stripe webhook so a closed tab still delivers the
            # paid care window. Idempotent via care_taster_grants.
            _fulfill_biofield_program(sid)
    except Exception as _be:
        print(f"[biofield] return seed failed: {_be!r}", flush=True)


