@app.route("/begin/product-data/<slug>")
def begin_product_data(slug):
    p = _get_product(slug)
    if not p:
        return jsonify({"error": "not found"}), 404
    # Generated content (ingredients + benefits + short description). Static JSON
    # values override the generated card when present (lets Glen pin copy).
    card = _product_card(p) if not p.get("info_only") else {}
    how = "" if p.get("info_only") else _product_how(p)
    ingredients = p.get("ingredients") or card.get("ingredients", [])
    qty_tiers, formats = None, None
    if _qty_eligible(p):
        from dashboard import pricing as _pricing
        _s = _pricing.load_settings(_pricing_settings())
        _base = int(p["price_cents"])
        qty_tiers = []
        _floor = _pricing.unit_floor_cents(p, _base, _s, "discount")  # incl. FF $50 min
        for m in (1, 3, 6, 12):
            u = _pricing.apply_discount(_base, _pricing.same_sku_pct(m, _s), _floor)
            qty_tiers.append({"min": m, "unit_cents": u, "unit": f"${u/100:.2f}",
                              "save": ((_base - u) // 100) if u < _base else 0})
        formats = _FORMATS
    _comp = p.get("competitor") if isinstance(p.get("competitor"), dict) else None
    data = {
        "slug": slug, "name": p["name"],
        "price_cents": p["price_cents"], "price": f"${p['price_cents']/100:.2f}",
        # Real product photo (physical goods). Optional: only apparel/devices carry it.
        "image": p.get("image", ""),
        # Compare-at (SRP) strikethrough — only when a genuine higher list price is set.
        "regular": (f"${p['regular_cents']/100:.2f}"
                    if p.get("regular_cents") and p["regular_cents"] > p["price_cents"] else ""),
        # Named-competitor value anchor (e.g. DefenderShield). Priced fields formatted here.
        "competitor": ({"brand": _comp.get("brand", ""), "name": _comp.get("name", ""),
                        "price": f"${_comp['price_cents']/100:.2f}" if _comp.get("price_cents") else "",
                        "regular": f"${_comp['regular_cents']/100:.2f}" if _comp.get("regular_cents") else ""}
                       if _comp else None),
        "description": p.get("description") or card.get("description", ""),
        "ingredients": ingredients,
        "benefits": p.get("benefits") or card.get("benefits", []),
        "how_it_works": how,
        "info_only": bool(p.get("info_only")), "affiliate_url": p.get("affiliate_url", ""),
        "payments_active": _QBO_PAYMENTS_ACTIVE or _STRIPE_ACTIVE,
        "group_bundle_enabled": bool(os.environ.get("GROUP_BUNDLE_ENABLED")),
        "learn_url": f"/begin/learn/{slug}",
        "qty_pricing": qty_tiers, "formats": formats,
        "open_sections": _read_open_sections(
            request.cookies.get("amg_session", ""),
            (get_authenticated_user(request) or {}).get("email", "")),
    }
    _viewer_email = (((get_authenticated_user(request) or {}).get("email", "")
                      or request.cookies.get("rm_reorder_email", "")).strip().lower())
    # Autoship eligibility: a bundle must carry autoship_eligible (device bundles are
    # false); a single SKU must be a Functional Formulation (_qty_eligible = qty_pricing
    # and not info_only), which excludes devices (ionizers/nightlights) and services.
    _autoship_ok = (bool(p.get("autoship_eligible")) if p.get("bundle")
                    else _qty_eligible(p))
    data["autoship_eligible"] = _autoship_ok
    data["bundle"] = bool(p.get("bundle"))
    data["is_paid_member"] = _is_paid_member(_viewer_email)
    if _autoship_ok:
        from dashboard import subscriptions as _subs
        if p.get("bundle"):
            data["autoship"] = {"first_pct": _subs.tier_for_bundle(0),
                                "cap_pct": _subs.tier_for_bundle(99)}
        else:
            data["autoship"] = {"first_pct": _subs.tier_for(0),
                                "cap_pct": _subs.tier_for(99)}
    try:
        from dashboard import founding as _founding
        _launch = _founding.get_launch(slug)
        if _launch:
            with sqlite3.connect(LOG_DB) as _fcx:
                _fcx.row_factory = sqlite3.Row
                _rem = _founding.remaining(_fcx, slug)
            data["founding"] = {"batch_label": _launch.get("batch_label", ""),
                                "cap": int(_launch.get("cap", 0)), "remaining": _rem}
            data["founding_video_url"] = _launch.get("video_url", "")
    except Exception as _fe:
        print(f"[founding] product-data enrich failed: {_fe!r}", flush=True)
    return jsonify(data)


def _related_semantic(slug, k=12):
    """Up to k catalog slugs semantically nearest to `slug`'s product-copy vector
    (cached in LOG_DB). Returns [] on ANY problem — this must never raise into
    the product page.

    Vectors in the `specific-formulations` namespace are NOT keyed by catalog
    slug (their ids come from the page-copy scraper/ingest, e.g. chunked
    `{ns_prefix}-{title-slug}-{i:03d}` ids), so a `fetch(ids=[slug])` would not
    find this product's vector. Instead this follows the same pattern already
    used by `_resolve_complement()` / `qbo_price_coverage()`: embed the
    product's own `pinecone_title` (or `name`) text, query the
    `specific-formulations` namespace for nearest neighbours by similarity,
    then map each neighbour's `metadata['title']` back to a catalog slug via
    `_TITLE_TO_SLUG` (deterministic in-catalog resolution)."""
    import sqlite3 as _sq, json as _json
    try:
        with _sq.connect(LOG_DB) as cx:
            cx.execute("CREATE TABLE IF NOT EXISTS related_semantic ("
                       "slug TEXT PRIMARY KEY, slugs_json TEXT, generated_at TEXT)")
            row = cx.execute("SELECT slugs_json FROM related_semantic WHERE slug=?",
                              (slug,)).fetchone()
            if row:
                return _json.loads(row[0])
    except Exception as e:
        print(f"[related-sem] cache read failed: {e}", flush=True)

    try:
        p = _get_product(slug)
        query_text = (p or {}).get("pinecone_title") or (p or {}).get("name")
        if not query_text:
            return []
        vec = embed(query_text)
        res = _idx.query(vector=vec, top_k=k + 20, namespace="specific-formulations",
                          include_metadata=True)
        slugs, seen = [], set()
        for m in (res.matches or []):
            md = m.metadata or {}
            title = md.get("title")
            cand = _TITLE_TO_SLUG.get(title) if title else None
            if not cand or cand == slug or cand in seen:
                continue
            seen.add(cand)
            slugs.append(cand)
            if len(slugs) >= k:
                break
    except Exception as e:
        print(f"[related-sem] query failed: {e}", flush=True)
        return []

    try:
        with _sq.connect(LOG_DB) as cx:
            cx.execute("INSERT OR REPLACE INTO related_semantic(slug,slugs_json,generated_at) "
                       "VALUES (?,?,datetime('now'))", (slug, _json.dumps(slugs)))
    except Exception as e:
        print(f"[related-sem] cache write failed: {e}", flush=True)
    return slugs


@app.route("/begin/product-page-data/<slug>")
def begin_product_page_data(slug):
    p = _get_product(slug)
    if not p:
        return jsonify({"error": "not found"}), 404
    card = _product_card(p) if not p.get("info_only") else {}
    how = "" if p.get("info_only") else _product_how(p)
    from dashboard.ingredients import slugify as _slugify
    from dashboard import entity_refs as _er
    _raw_ingredients = p.get("ingredients") or card.get("ingredients", [])
    ingredients = []
    for _ing in _raw_ingredients:
        if isinstance(_ing, dict):
            _ing = dict(_ing)
            _ing["slug"] = _slugify(_ing.get("name") or "")
        else:
            _ing = {"name": str(_ing), "dose": "", "slug": _slugify(str(_ing))}
        ingredients.append(_ing)
    # Attach a short 'basic info' string per ingredient for the hover pop-up on the
    # product page. Best-effort: any failure leaves info absent -> plain link.
    try:
        with sqlite3.connect(LOG_DB) as _icx:
            for _ing in ingredients:
                _ing["info"] = _er.ingredient_ref(_icx, _ing.get("name", ""), _ing.get("slug", "")).get("info", "")
    except Exception:
        pass
    intro = p.get("intro") or (card.get("description", "") or "").split(". ")[0]
    # Formulation-only surfaces (ingredient list, the formula comparison table + its Miron
    # rotator/story, the Miron educational video) are misleading on a device/book/service
    # SKU that has no ingredient list, so they are withheld below (see product_page_sections).
    _has_ings = bool(ingredients)
    _own_vids = list(p.get("videos", []))
    _vids = list(_own_vids)
    _mv = _MIRON_ASSETS.get("video")
    if _has_ings and _mv and _mv.get("src"):
        _vids.append({"src": _mv["src"], "title": _mv.get("title", ""), "provider": "mp4", "kind": "educational"})
    sections = [
        {"id": "intro",       "title": "What this does",  "default_open": True,  "body": intro},
        {"id": "description", "title": "Overview",        "default_open": False,
         "body": p.get("description") or card.get("description", "")},
        {"id": "video",       "title": "Watch",           "default_open": False, "body": {"videos": _vids}},
        {"id": "ingredients", "title": "What's inside",   "default_open": False, "body": {"ingredients": ingredients}},
        {"id": "comparison",  "title": "How it compares", "default_open": False, "body": _SALES_ARCHETYPES},
        {"id": "research",    "title": "The research",    "default_open": False,
         "body": {"how_it_works": how, "learn_url": f"/begin/learn/{slug}"}},
        {"id": "images",      "title": "Help shape this", "default_open": False, "body": {"images": p.get("page_images", [])}},
        {"id": "cta",         "title": "Order",           "default_open": False, "body": {}},
    ]
    from dashboard.product_page_sections import filter_sections as _filter_sections
    sections = _filter_sections(sections, has_ingredients=_has_ings, has_own_video=bool(_own_vids))
    if _RELATED_PRODUCTS_ENABLED:
        try:
            from dashboard import related_products as _rp, related_store as _rstore
            _prods = _PRODUCTS.get("products") or {}
            _res = _rp.resolve_related(
                slug,
                manual=_rstore.load_manual(slug),
                harvested=_rstore.load_harvested(slug),
                semantic=_related_semantic(slug),
                products=_prods)
            if _res["featured"]:
                _reasons = _res.get("reasons", {})
                def _card(rs):
                    rp_ = _get_product(rs) or _prods.get(rs, {})
                    imgs = rp_.get("page_images") or []
                    return {"slug": rs, "name": rp_.get("name", rs),
                            "price": f"${rp_.get('price_cents', 0) / 100:.2f}",
                            "url": f"/begin/product/{rs}",
                            "image": (imgs[0] if imgs else ""),
                            "reason": _reasons.get(rs, "")}
                sections.append({
                    "id": "related", "title": "Dr. Glen recommends", "default_open": True,
                    "body": {"featured": [_card(s) for s in _res["featured"]],
                             "more": [_card(s) for s in _res["more"]]}})
        except Exception as _e:
            print(f"[related] page-data section skipped: {_e}", flush=True)
    if _REVIEWS_ENABLED:
        from dashboard import product_reviews as _pr
        try:
            with sqlite3.connect(LOG_DB) as _rcx:
                _agg = _pr.aggregate(_rcx, slug)
                _approved = _pr.approved_for_slug(_rcx, slug)
            _revs = [{"name": (r.get("name") or "A verified buyer"),
                      "rating": (None if (r.get("kind") == "gift") else r.get("rating")),
                      "body": r.get("body") or ""}
                     for r in _approved if (r.get("body") or "").strip() and (r.get("kind") != "gift" or r.get("consent_public"))]
            _rsec = {"id": "reviews", "title": "What people are saying", "default_open": False,
                     "body": {"aggregate": _agg, "reviews": _revs,
                              "disclaimer": "Individual results vary."}}
            _ri = next((i for i, s in enumerate(sections) if s["id"] == "research"), len(sections) - 1)
            sections.insert(_ri + 1, _rsec)
            # approved UGC videos -> existing video section
            _ugc = [r for r in _approved if (r.get("video_kind") in ("link", "upload")) and r.get("video_ref")]
            if _ugc:
                _vsec = next((s for s in sections if s["id"] == "video"), None)
                if _vsec and isinstance(_vsec.get("body"), dict):
                    for r in _ugc:
                        _src = (r["video_ref"] if r["video_kind"] == "link"
                                else f"/review-media/{slug}/{r['video_ref']}")
                        _prov = "link" if r["video_kind"] == "link" else "mp4"
                        _vsec["body"].setdefault("videos", []).append(
                            {"src": _src, "title": f"Review from {r.get('name') or 'a verified buyer'}",
                             "provider": _prov, "kind": "ugc"})
        except Exception as _e:
            print(f"[reviews] page-data section skipped: {_e}", flush=True)
    _ai_state = "none"
    if _SALES_AI_COPY_ENABLED:
        import sqlite3 as _sq
        from dashboard import sales_pages as _sp
        try:
            with _sq.connect(LOG_DB) as _cx:
                for _s in sections:
                    if _s["id"] not in ("intro", "description", "research"):
                        continue
                    _draft = _sp.get_section(_cx, slug, _s["id"])
                    if _draft:
                        _s["ai"] = "cached"
                        if _s["id"] == "research" and isinstance(_s["body"], dict):
                            _s["body"]["how_it_works"] = _draft
                        else:
                            _s["body"] = _draft
                    else:
                        _s["ai"] = "pending"
                _pg = _sp.get_page(_cx, slug)
                _ai_state = _pg["state"] if _pg else "none"
                if _ai_state != "approved":
                    try:
                        from dashboard import sales_page_viewers as _spv
                        _vau = get_authenticated_user(request) or {}
                        _vemail = (_vau.get("email") or "").strip().lower()
                        if _vemail:
                            _spv.record_viewer(_cx, slug, _vemail, _vau.get("name", ""))
                    except Exception as _ve:
                        print(f"[sales-viewers] capture skipped: {_ve}", flush=True)
        except Exception as _e:
            print(f"[sales-ai] page-data marker skipped: {_e}", flush=True)
    if _SALES_AI_IMAGES_ENABLED:
        import sqlite3 as _sq2
        from dashboard import sales_images as _si2
        try:
            _img_sec = next((s for s in sections if s["id"] == "images"), None)
            if _img_sec is not None:
                with _sq2.connect(LOG_DB) as _cx2:
                    if _SALES_IMAGE_VARIATIONS_ENABLED:
                        _grouped = _si2.display_images_grouped(_cx2, slug)
                        _state = _si2.images_grouped_state(_cx2, slug)
                        _img_sec["body"] = {"grouped": _grouped, "state": _state, "target": 8}
                        if _SALES_IMAGE_VOTE_ENABLED:
                            from dashboard import sales_votes as _sv2
                            _vsess = request.cookies.get("amg_session", "")
                            _vau = get_authenticated_user(request)
                            _vem = ((_vau or {}).get("email") or "").strip().lower() if _vau else ""
                            _img_sec["body"]["picks"] = _sv2.get_picks(_cx2, slug, session_id=_vsess, email=_vem)
                            if any(_grouped.values()):
                                from dashboard import sales_image_exposures as _ex2
                                _ex2.record(_cx2, slug, _vsess)
                    else:
                        _disp = _si2.display_images(_cx2, slug)
                        _qstate = _si2.queue_state(_cx2, slug)
                        _imgs = [{"kind": k, "url": f"/begin/product-image/{slug}/{fn}"}
                                 for k, fn in _disp.items() if fn]
                        if _imgs:
                            _img_sec["body"] = {"images": _imgs, "state": "ready"}
                        elif _qstate == "pending":
                            _img_sec["body"] = {"images": [], "state": "generating"}
                        else:
                            _img_sec["body"] = {"images": [], "state": "none"}
        except Exception as _e:
            print(f"[sales-img] page-data marker skipped: {_e}", flush=True)
    if _SALES_IMAGE_PICK_ENABLED and not _SALES_IMAGE_VARIATIONS_ENABLED:
        import sqlite3 as _sq3
        from dashboard import sales_images as _si3, sales_votes as _sv3, sales_image_prompts as _sip3
        try:
            _sess = request.cookies.get("amg_session", "")
            _au = get_authenticated_user(request)
            _em = ((_au or {}).get("email") or "").strip().lower() if _au else ""
            with _sq3.connect(LOG_DB) as _cx3:
                _all = _si3.get_images(_cx3, slug)
                _picks = _sv3.get_picks(_cx3, slug, session_id=_sess, email=_em)
                _both = _sv3.picked_both(_cx3, slug, session_id=_sess, email=_em)
            _by_kind = {}
            for im in _all:
                _by_kind.setdefault(im["kind"], []).append(im)
            _pick = {}
            for _k in _sip3.IMAGE_KINDS:
                _opts = [{"variant": im["variant"], "url": f"/begin/product-image/{slug}/{im['filename']}"}
                         for im in sorted(_by_kind.get(_k, []), key=lambda x: x["variant"])]
                if len(_opts) >= 2:
                    _pick[_k] = {"chosen": _picks.get(_k) if (_picks.get(_k) or 0) >= 1 else None, "options": _opts}
            # Phase 4b: restrict the pick options to the active champion/challenger pair
            if _SALES_IMAGE_TOURNAMENT_ENABLED:
                from dashboard import sales_image_pairs as _sp4b
                with _sq3.connect(LOG_DB) as _cxp:
                    for _k in _sip3.IMAGE_KINDS:
                        _vs = [im["variant"] for im in _all if im["kind"] == _k]
                        _pr = _sp4b.ensure_pair(_cxp, slug, _k, _vs)
                        if not _pr:
                            continue
                        if _pr["converged"]:
                            _pick.pop(_k, None)          # converged -> no picking; champion shows as hero
                            continue
                        if _k in _pick:
                            _active = {_pr["champion_variant"], _pr["challenger_variant"]}
                            _pick[_k]["options"] = [o for o in _pick[_k]["options"] if o["variant"] in _active]
            if _pick:
                _img_sec3 = next((s for s in sections if s["id"] == "images"), None)
                if _img_sec3 is not None and isinstance(_img_sec3["body"], dict):
                    _pick["both_picked"] = _both
                    _img_sec3["body"]["pick"] = _pick
        except Exception as _e:
            print(f"[img-pick] page-data skipped: {_e}", flush=True)
    _pc = p.get("competitor") if isinstance(p.get("competitor"), dict) else None
    _page_data = {
        "slug": slug, "name": p["name"], "price_cents": p["price_cents"],
        "price": f"${p['price_cents']/100:.2f}", "cta_url": f"/begin/buy/{slug}",
        # Real product photo (physical goods only), compare-at SRP, and named-competitor anchor.
        "image": p.get("image", ""),
        "regular": (f"${p['regular_cents']/100:.2f}"
                    if p.get("regular_cents") and p["regular_cents"] > p["price_cents"] else ""),
        "competitor": ({"brand": _pc.get("brand", ""), "name": _pc.get("name", ""),
                        "price": f"${_pc['price_cents']/100:.2f}" if _pc.get("price_cents") else "",
                        "regular": f"${_pc['regular_cents']/100:.2f}" if _pc.get("regular_cents") else ""}
                       if _pc else None),
        "ai_state": _ai_state,
        "sections": sections,
        "miron_assets": _MIRON_ASSETS["assets"] if _has_ings else [],
        "miron_story": _MIRON_ASSETS.get("story", []) if _has_ings else [],
        "open_sections": _read_open_sections(request.cookies.get("amg_session", ""),
                                             (get_authenticated_user(request) or {}).get("email", "")),
    }
    try:
        from dashboard import founding as _founding2
        _launch2 = _founding2.get_launch(slug)
        if _launch2:
            with sqlite3.connect(LOG_DB) as _fcx2:
                _fcx2.row_factory = sqlite3.Row
                _rem2 = _founding2.remaining(_fcx2, slug)
            _page_data["founding"] = {"batch_label": _launch2.get("batch_label", ""),
                                      "cap": int(_launch2.get("cap", 0)), "remaining": _rem2}
            _page_data["founding_video_url"] = _launch2.get("video_url", "")
    except Exception as _fe2:
        print(f"[founding] product-page-data enrich failed: {_fe2!r}", flush=True)
    if _WISHLIST_ENABLED:
        try:
            import sqlite3 as _wsq
            from dashboard import wishlist as _wl
            _wem, _wses = _wishlist_ids(request)
            with _db_lock, _wsq.connect(LOG_DB) as _wcx:
                _wl.init_wishlist_table(_wcx)
                _page_data["wishlist_saved"] = slug in _wl.list_union(_wcx, _wem, _wses)
        except Exception as _e:
            print(f"[wishlist] page-data flag skipped: {_e}", flush=True)
    return jsonify(_page_data)


@app.route("/begin/product-page-gen/<slug>/<section>")
def begin_product_page_gen(slug, section):
    """SSE endpoint: stream (or serve cached) AI-generated copy for one narrative section."""
    from dashboard import sales_copy as _sc
    if not _SALES_AI_COPY_ENABLED or section not in _sc.NARRATIVE_SECTIONS:
        return ("", 404)
    p = _get_product(slug)
    if not p:
        return ("", 404)

    def generate():
        import sqlite3 as _sq
        from dashboard import sales_pages as _sp
        try:
            try:
                with _sq.connect(LOG_DB) as cx:
                    cached = _sp.get_section(cx, slug, section)
            except Exception as _dbe:
                print(f"[sales-gen] cache read failed (degrading to generate): {_dbe}", flush=True)
                cached = None
            if cached:
                yield sse({"token": cached})
                yield sse({"done": True, "cached": True})
                return
            prod = dict(p)
            if not prod.get("ingredients"):
                prod["ingredients"] = (_product_card(p) or {}).get("ingredients", [])
            system, user = _sc.build_section_prompt(section, prod)
            acc = []
            with _cl.messages.stream(
                model="claude-haiku-4-5-20251001",
                max_tokens=600,
                system=system,
                messages=[{"role": "user", "content": user}],
            ) as stream:
                for tok in stream.text_stream:
                    tok = _strip_dash(tok)
                    acc.append(tok)
                    yield sse({"token": tok})
            text = "".join(acc).strip()
            if text:
                try:
                    with _sq.connect(LOG_DB) as cx:
                        _sp.upsert_section(cx, slug, section, text, model="claude-haiku-4-5-20251001")
                except Exception as e:
                    print(f"[sales-gen] cache write failed: {e}", flush=True)
            yield sse({"done": True})
        except Exception as e:
            print(f"[sales-gen] {e}", flush=True)
            yield sse({"error": True})

    resp = Response(stream_with_context(generate()), content_type="text/event-stream")
    resp.headers["Cache-Control"] = "no-cache"
    resp.headers["X-Accel-Buffering"] = "no"
    return resp


