@app.route("/learn/pattern-data/<slug>")
def learn_pattern_data(slug):
    from dashboard import pattern_glossary as _pg
    cx = _pg.open_ro()
    if cx is None:
        return jsonify({"state": "unknown"}), 404
    try:
        p = _pg.get_pattern(cx, slug)
        if not p:
            return jsonify({"state": "unknown"}), 404
        # Phase 3: link each organ structure to its clinical-glossary Organs entry.
        try:
            from dashboard import glossary_crosslinks as _gx, clinical_glossary as _cg
            cidx = _gx.clinical_organ_index(_cg.load())
            for s in p.get("structures", []):
                if s.get("stype") == "organ":
                    s["clinical_slug"] = cidx.get(_gx.canon(s.get("structure", "")))
        except Exception:
            pass
        # "What may help": the formulations mapped to this pattern, each resolved to
        # a product page where the name matches (exact + curated overrides; no fuzzy).
        try:
            from dashboard import clinical_glossary as _cg, products as _pr
            rem = _pg.pattern_remedies(cx, p.get("code", ""))
            if rem:
                ridx = _cg.product_name_index(_pr.load_products())
                rov = _cg.load_overrides()
                for r in rem:
                    r["product_slug"] = _cg.remedy_product_slug(r.get("name", ""), ridx, rov)
                p["remedies"] = rem
        except Exception:
            pass
        # Characteristic stress factors of the organs this pattern involves
        # (aggregated + deduped from the organ/meridian stress-factor layer).
        try:
            from dashboard import organ_stressors as _os, clinical_glossary as _cg
            organ_names = [s.get("structure", "") for s in p.get("structures", [])
                           if s.get("stype") == "organ"]
            sf = _os.for_pattern_organs(organ_names, _cg.load(), _os.load())
            if sf:
                p["stress_factors"] = sf
        except Exception:
            pass
        return jsonify(p)
    finally:
        try:
            cx.close()
        except Exception:
            pass


