@app.route("/learn/glossary-data/<dim>")
def learn_clinical_glossary_dim_data(dim):
    from dashboard import clinical_glossary as _cg
    d = _cg.get_dimension(dim)
    if not d:
        return jsonify({"state": "unknown"}), 404
    # Phase 2: attach a product_slug to each remedy (exact name match + overrides).
    try:
        from dashboard import products as _pr
        idx = _cg.product_name_index(_pr.load_products())
        d = _cg.with_product_links(d, idx, _cg.load_overrides())
    except Exception:
        pass
    # Phase 3: for the Organs dimension, attach the E4L stress patterns involving
    # each organ (bidirectional cross-link with the pattern glossary).
    if dim == "organs":
        try:
            from dashboard import glossary_crosslinks as _gx, pattern_glossary as _pg
            cxe = _pg.open_ro()
            if cxe is not None:
                try:
                    o2p = _gx.organ_to_patterns(cxe)
                finally:
                    cxe.close()
                for e in d.get("entries", []):
                    e["patterns"] = o2p.get(_gx.canon(e.get("name", "")), [])
        except Exception:
            pass
    # 'Affects' organ cross-links: for stressor entries that list affected organs,
    # resolve each to its clinical Organ entry slug (deep-link) where it matches.
    try:
        if any(e.get("affects") for e in d.get("entries", [])):
            from dashboard import glossary_crosslinks as _gx, clinical_glossary as _cg
            cidx = _gx.clinical_organ_index(_cg.load())
            for e in d.get("entries", []):
                if e.get("affects"):
                    e["affects_links"] = [{"name": a, "slug": cidx.get(_gx.canon(a))} for a in e["affects"]]
    except Exception:
        pass
    # Stress-factor layer: attach characteristic stress factors (toxin / microbe /
    # emotional / physical) to Organ and Meridian entries (meridians inherit their
    # organ's factors via the map).
    if dim in ("organs", "meridians"):
        try:
            from dashboard import organ_stressors as _os
            _sf = _os.load()
            for e in d.get("entries", []):
                sf = _os.stressors_for(e.get("name", ""), _sf)
                if sf:
                    e["stress_factors"] = sf
        except Exception:
            pass
    return jsonify(d)


