# ── Review invite tokens (Task 7) ─────────────────────────────────────────────

def _init_review_link_tokens():
    with _db_lock, sqlite3.connect(LOG_DB) as cx:
        cx.execute(
            "CREATE TABLE IF NOT EXISTS review_link_tokens "
            "(token TEXT PRIMARY KEY, email TEXT, product_slug TEXT, created_at TEXT)"
        )
        cx.commit()

_init_review_link_tokens()


def _review_token_mint(email: str, slug: str) -> str:
    """Mint a random token bound to (email, slug), store it, return the plaintext token."""
    tok = secrets.token_urlsafe(24)
    with _db_lock, sqlite3.connect(LOG_DB) as cx:
        cx.execute(
            "INSERT OR IGNORE INTO review_link_tokens (token, email, product_slug, created_at) "
            "VALUES (?,?,?,?)",
            (tok, (email or "").strip().lower(), slug, _now_utc().isoformat()),
        )
        cx.commit()
    return tok


def _review_token_verify(tok: str):
    """Look up a review invite token. Returns (email, slug) or (None, None) for unknown tokens."""
    if not tok:
        return (None, None)
    with sqlite3.connect(LOG_DB) as cx:
        row = cx.execute(
            "SELECT email, product_slug FROM review_link_tokens WHERE token=?", (tok,)
        ).fetchone()
    if not row:
        return (None, None)
    return (row[0], row[1])


@app.route("/review/<token>")
def review_form_page(token):
    if not _REVIEWS_ENABLED:
        return ("", 404)
    email, slug = _review_token_verify(token)
    if not email or not _get_product(slug):
        return ("Invalid or expired link.", 404)
    return redirect(f"/begin/product/{slug}?review=1&rt={token}")


def _send_review_invite(email: str, name: str, slug: str):
    """Send a post-purchase review invite email (best-effort; never raises)."""
    try:
        from dashboard import inbox as _inbox
        p = _get_product(slug) or {}
        tok = _review_token_mint(email, slug)
        url = f"{PUBLIC_BASE_URL}/review/{tok}"
        subject = f"How is your {p.get('name', 'order')}? Share a quick review"
        body = (
            f"Aloha {name or ''},\n\n"
            f"If you have a moment, I would love your honest review of "
            f"{p.get('name', 'your recent order')}. "
            f"It helps others and earns you store credit:\n\n{url}\n\n"
            f"In wellness,\nDr. Glen & Rae"
        )
        _inbox.send_email(
            email, subject, _strip_dash(body), from_name="Dr. Glen Swartwout"
        )
    except Exception as _e:
        print(f"[reviews] _send_review_invite failed for {email}/{slug}: {_e!r}", flush=True)


# ── Testimonials (Phase 1: in-house Boast.io replacement) ─────────────────────
# Reuse the product_reviews engine under the reserved campaign slug "_results"
# (kind='testimonial'). Open submission (no verified-buyer gate, no points/gift);
# rewards stay exclusive to the verified-buyer product-review path. Practitioner
# attribution resolves a ?p= token against a LOCAL table (no Supabase dependency).

def _init_testimonial_tokens():
    with _db_lock, sqlite3.connect(LOG_DB) as cx:
        cx.execute(
            "CREATE TABLE IF NOT EXISTS testimonial_tokens "
            "(token TEXT PRIMARY KEY, practitioner_id INTEGER, created_at TEXT)"
        )
        cx.commit()

_init_testimonial_tokens()


def _norm_pid(practitioner_id) -> str:
    """Practitioner ids are Supabase UUIDs (strings) — NOT integers. Normalize to a string,
    empty for none/0. (Never int() a practitioner id; that crashes on a UUID.)"""
    s = str(practitioner_id or "").strip()
    return "" if s == "0" else s


def _testimonial_token_mint(practitioner_id) -> str:
    """Mint a ?p= token attributing a testimonial to a practitioner. Returns plaintext token."""
    tok = secrets.token_urlsafe(24)
    with _db_lock, sqlite3.connect(LOG_DB) as cx:
        cx.execute(
            "INSERT OR IGNORE INTO testimonial_tokens (token, practitioner_id, created_at) "
            "VALUES (?,?,?)", (tok, _norm_pid(practitioner_id), _now_utc().isoformat()))
        cx.commit()
    return tok


def _testimonial_practitioner_id(tok: str) -> str:
    """Resolve a ?p= token to a practitioner id (UUID string). '' for unknown/blank tokens."""
    if not tok:
        return ""
    with sqlite3.connect(LOG_DB) as cx:
        row = cx.execute(
            "SELECT practitioner_id FROM testimonial_tokens WHERE token=?", (tok,)).fetchone()
    return str(row[0]) if row and row[0] is not None else ""


def _testimonial_token_for_practitioner(practitioner_id) -> str:
    """Stable per-practitioner ?p= token: reuse an existing one, else mint. '' for no pid."""
    pid = _norm_pid(practitioner_id)
    if not pid:
        return ""
    _init_testimonial_tokens()
    with sqlite3.connect(LOG_DB) as cx:
        row = cx.execute(
            "SELECT token FROM testimonial_tokens WHERE practitioner_id=? LIMIT 1", (pid,)).fetchone()
        if row:
            return row[0]
    return _testimonial_token_mint(pid)


# ── Cert L1 portal assignment (subsystem A beachhead) ─────────────────────────
_ASH_L1_TAG = "ash-cert-l1"
# Owner's own coach record — never receives the cohort assignment blast (belt-and-suspenders;
# Level-12 instructors are also filtered out below).
_COHORT_EXCLUDE_EMAILS = {"drglenswartwout@gmail.com"}


def _assignment_status(modules_completed, has_submission) -> str:
    """not_started -> in_review (submitted, awaiting approval) -> complete (Level 1 granted)."""
    if int(modules_completed or 0) >= 1:
        return "complete"
    return "in_review" if has_submission else "not_started"


# Member-facing feedback dimensions: (label, column, pass-min). Compliance bars at 8, rest at 6.
_FEEDBACK_DIMS = [
    ("Compliance", "compliance_score", 8),
    ("Publication", "publication_score", 6),
    ("Authenticity", "authenticity_score", 6),
    ("Specificity", "specificity_score", 6),
    ("Audio", "audio_quality", 6),
    ("Visual", "visual_quality", 6),
]


def _cert_feedback(sub):
    """Member-facing feedback for a REVIEWED cohort submission: outcome + framed scores.
    Returns None until a human has decided (status approved/rejected) — we never surface
    raw pre-review AI scores to the submitter. Only scored (>0) dimensions are included."""
    if not sub:
        return None
    st = str(sub.get("status") or "").lower()
    if st not in ("approved", "rejected"):
        return None
    scores = []
    for label, col, mn in _FEEDBACK_DIMS:
        v = int(sub.get(col) or 0)
        if v <= 0:
            continue
        level = "strong" if v >= 8 else ("low" if v < mn else "ok")
        scores.append({"label": label, "value": v, "min": mn, "level": level})
    return {
        "outcome": "approved" if st == "approved" else "refine",
        "headline": ("Your Level 1 assignment is approved." if st == "approved"
                     else "Thank you — let's refine it together."),
        "scores": scores,
    }


def _cert_l1_assignment(practitioner_id, email, modules_completed):
    """Assignment card for a practitioner: auto-attributed record link, status, and (once
    reviewed) a feedback block."""
    tok = _testimonial_token_for_practitioner(practitioner_id)
    base = f"{PUBLIC_BASE_URL}/results?tag={_ASH_L1_TAG}"
    record_url = f"{base}&p={tok}" if tok else base
    sub = None
    try:
        with sqlite3.connect(LOG_DB) as cx:
            sub = _pr_module().cohort_submission(
                cx, _ASH_L1_TAG, email=email or "", practitioner_id=_norm_pid(practitioner_id))
    except Exception:
        sub = None
    out = {
        "key": "ash-cert-l1-video",
        "title": "Level 1 — Share your story on video",
        "body": ("Record a short video (60-90 seconds) about something you've learned in the course "
                 "that's been meaningful, or a result you've experienced. Completing this reflection "
                 "earns your Level 1 assignment."),
        "record_url": record_url,
        "status": _assignment_status(modules_completed, sub is not None),
    }
    fb = _cert_feedback(sub)
    if fb:
        out["feedback"] = fb
    return out


def _pr_module():
    from dashboard import product_reviews as _pr
    return _pr


