@app.route("/api/testimonials", methods=["POST"])
def api_submit_testimonial():
    if not _TESTIMONIALS_ENABLED:
        return ("", 404)
    data = request.get_json(silent=True) or request.form
    au = get_authenticated_user(request) or {}
    email = ((data.get("email") or au.get("email") or "")).strip().lower()
    name = (data.get("name") or au.get("name") or "").strip()
    try:
        rating = int(data.get("rating") or 0)
    except (TypeError, ValueError):
        rating = 0
    consent = str(data.get("consent_public") or "").strip().lower() in ("1", "true", "yes", "on")
    if not name or not email or rating < 1 or rating > 5:
        return jsonify({"ok": False, "error": "name, email and rating 1-5 required"}), 400
    if not consent:
        return jsonify({"ok": False, "error": "public-use consent is required"}), 400
    body = (data.get("body") or "").strip()
    pid = _testimonial_practitioner_id((data.get("p") or "").strip())
    # Optional campaign/cohort tag from ?tag= (e.g. ash-cert-l1) — for finding/grading a cohort.
    tag = re.sub(r"[^\w.\-]", "", (data.get("tag") or "").strip())[:64]

    try:
        video_kind, video_ref = _extract_review_video("_results", data)
    except _ReviewVideoError as ve:
        return jsonify({"ok": False, "error": str(ve)}), 400

    from dashboard import product_reviews as _pr
    from dashboard import review_scoring as _rs
    _ctx = {"name": "Dr. Glen Swartwout — Biofield Analysis & Functional Formulations"}
    with sqlite3.connect(LOG_DB) as cx:
        rid = _pr.upsert_review(cx, "_results", email, name, rating, body, video_kind, video_ref,
                                kind="testimonial", practitioner_id=pid, consent_public=1,
                                source_tag=tag)
        score = _rs.score_review(_cl, _ctx, body, strip=_strip_dash) if body else {
            "compliance_ok": True, "reasons": "", "quality_points": 0, "recommend_publish": False}
        _pr.set_ai_result(cx, rid, score["quality_points"], score["reasons"], score["recommend_publish"])
        _pr.set_scores(cx, rid, compliance=score.get("compliance_score", 0),
                       publication=score.get("publication_score", 0),
                       authenticity=score.get("authenticity_score", 0),
                       specificity=score.get("specificity_score", 0))
        # NOTE: ungated path — no points/store-credit and no review-gift by design.
        _video_status = ""
        if _REVIEWS_VIDEO and video_kind == "upload" and video_ref:
            from dashboard import review_video_jobs as _vj
            _pr.set_video_result(cx, rid, 0, "", "pending")
            _vj.enqueue(cx, rid)
            _video_status = "pending"
    return jsonify({"ok": True, "review_id": rid, "status": "pending",
                    "video_status": _video_status})


# ── Phase 4: positive-sentiment-triggered testimonial invites (review-queue-first) ──

def _ts_complete(system, user):
    """LLM completer for the positive-result classifier (Haiku). '' on error."""
    try:
        msg = _cl.messages.create(model="claude-haiku-4-5-20251001", max_tokens=300,
                                  system=system, messages=[{"role": "user", "content": user}])
        return "".join(getattr(b, "text", "") for b in msg.content if getattr(b, "type", "") == "text")
    except Exception as e:  # noqa: BLE001
        print(f"[testimonial-invites] complete failed: {e!r}", flush=True)
        return ""


def _recent_active_emails(cx, days=7, limit=500):
    """Distinct client emails with chat/inquiry activity in the window (the scan population).
    Uses sqlite datetime('now', '-N days') to match the stored 'YYYY-MM-DD HH:MM:SS' ts format
    (an ISO cutoff string would mis-compare and silently match nothing)."""
    win = f"-{int(days)} days"
    emails = set()
    for sql in (
        "SELECT DISTINCT lower(email) FROM query_log "
        "WHERE email IS NOT NULL AND email<>'' AND ts > datetime('now', ?)",
        "SELECT DISTINCT lower(client_email) FROM inquiries "
        "WHERE client_email IS NOT NULL AND client_email<>'' AND created_at > datetime('now', ?)",
        # email feedback (where clients reply 'this helped me') — joined to users for the email
        "SELECT DISTINCT lower(u.email) FROM personal_email_feedback pf "
        "JOIN users u ON u.id = pf.user_id "
        "WHERE u.email IS NOT NULL AND u.email<>'' AND pf.received_at > datetime('now', ?)",
    ):
        try:
            for row in cx.execute(sql, (win,)).fetchall():
                if row[0]:
                    emails.add(row[0])
        except sqlite3.OperationalError:
            pass
    return sorted(emails)[:limit]


def _known_client_emails(cx, limit=5000):
    """Distinct known client emails (to filter the Gmail inbox to clients only)."""
    out = set()
    for sql in ("SELECT DISTINCT lower(email) FROM people WHERE email LIKE '%@%'",
                "SELECT DISTINCT lower(email) FROM users WHERE email LIKE '%@%'",
                "SELECT DISTINCT lower(client_email) FROM inquiries WHERE client_email LIKE '%@%'"):
        try:
            for row in cx.execute(sql).fetchall():
                if row[0]:
                    out.add(row[0])
        except sqlite3.OperationalError:
            pass
    return set(list(out)[:limit])


def _gmail_client_texts(cx, days, limit=200, diag=None):
    """{client_email: text} from the Gmail inbox (known clients only). Off unless enabled."""
    if not _GMAIL_FEEDBACK_ENABLED:
        if diag is not None:
            diag["enabled"] = False
        return {}
    try:
        known = _known_client_emails(cx)
        from dashboard import gmail_feedback as _gf
        return _gf.recent_client_messages(known, days=int(days), limit=int(limit), diag=diag)
    except Exception as e:  # noqa: BLE001
        if diag is not None:
            diag["error"] = repr(e)[:200]
        print(f"[testimonial-invites] gmail read failed: {e!r}", flush=True)
        return {}


def _gather_comms_text(cx, email, days=14):
    """Assemble a client's recent comms into one blob for the classifier — AI summaries / their own
    words only (recent_comms never exposes email raw_text)."""
    parts = []
    try:
        from dashboard import recent_comms as _rc
        rc = _rc.recent_comms(cx, email, days_window=max(14, int(days)))
        if rc.get("intake_summary"):
            parts.append("Intake: " + str(rc["intake_summary"]))
        for q in (rc.get("recent_queries") or []):
            parts.append("Chat: " + str(q.get("question") or q.get("query") or ""))
        for inq in (rc.get("recent_inquiries") or []):
            parts.append("Inquiry: " + str(inq.get("main_challenge") or "")
                         + " / " + str(inq.get("main_goal") or ""))
        for fb in (rc.get("recent_feedback") or []):
            parts.append("Email feedback: " + str(fb.get("ai_summary") or ""))
    except Exception as e:  # noqa: BLE001
        print(f"[testimonial-invites] gather failed for {email!r}: {e!r}", flush=True)
    return "\n".join(p for p in parts if p.strip())


@app.route("/api/console/testimonial-invites/scan", methods=["POST"])
def api_testimonial_invites_scan():
    if not _TESTIMONIAL_INVITES_ENABLED:
        return ("", 404)
    if not _console_key_ok():
        return jsonify({"error": "Unauthorized"}), 401
    dry = (request.args.get("dry_run") or "").strip().lower() in ("1", "true", "yes")
    try:
        days = max(1, min(365, int(request.args.get("days") or 7)))
    except (TypeError, ValueError):
        days = 7
    from dashboard import testimonial_signals as _ts, testimonial_invites as _ti
    found, scanned = [], 0
    try:
        gmail_limit = max(1, min(1000, int(request.args.get("gmail_limit") or 200)))
    except (TypeError, ValueError):
        gmail_limit = 200
    gmail_diag = {"enabled": _GMAIL_FEEDBACK_ENABLED}
    with sqlite3.connect(LOG_DB) as cx:
        gmail_texts = _gmail_client_texts(cx, days, limit=gmail_limit, diag=gmail_diag)
        active = sorted(set(_recent_active_emails(cx, days=days)) | set(gmail_texts.keys()))
        for e in active:
            if _ti.should_skip(cx, e):
                continue
            db_text = _gather_comms_text(cx, e, days=days)
            gm_text = gmail_texts.get(e, "")
            text = (db_text + "\n" + gm_text).strip()
            if not text:
                continue
            scanned += 1
            r = _ts.classify_positive_result(text, _ts_complete)
            if r["positive"] and r["confidence"] >= _TESTIMONIAL_INVITE_MIN_CONFIDENCE:
                src = ("comms+gmail" if (gm_text and db_text.strip())
                       else "gmail" if gm_text else "comms")
                if not dry:
                    name = (_people_brief(cx, e) or {}).get("client_name", "")
                    _ti.upsert_candidate(cx, e, name, r["quote"], src, r["kind"], r["confidence"])
                found.append({"email": e, "quote": r["quote"], "confidence": r["confidence"],
                              "kind": r["kind"], "source": src})
    return jsonify({"ok": True, "dry_run": dry, "days": days, "active": len(active),
                    "gmail_clients": len(gmail_texts), "gmail_diag": gmail_diag,
                    "scanned": scanned, "candidates": found})


