@app.route("/api/console/points-ledger", methods=["GET"])
def api_console_points_ledger():
    """Read-only points_ledger audit. Returns totals grouped by reason (so L1
    'referral_reward' vs L2 'referral_reward_l2' are visible at a glance) plus the most
    recent rows. Optional ?reason=<r> filters the row list; ?limit=N (default 50, max 200)."""
    if not _console_key_ok():
        return jsonify({"error": "Unauthorized"}), 401
    reason = (request.args.get("reason") or "").strip()
    try:
        limit = min(200, max(1, int(request.args.get("limit") or 50)))
    except (TypeError, ValueError):
        limit = 50
    from dashboard import points as _points
    with sqlite3.connect(LOG_DB) as cx:
        cx.row_factory = sqlite3.Row
        _points.init_points_table(cx)
        summ = cx.execute(
            "SELECT reason, scope, COUNT(*) AS n, COALESCE(SUM(delta_cents),0) AS cents "
            "FROM points_ledger GROUP BY reason, scope ORDER BY cents DESC").fetchall()
        where, args = ("WHERE reason=?", [reason]) if reason else ("", [])
        rows = cx.execute(
            "SELECT email, delta_cents, reason, order_ref, scope, created_at "
            "FROM points_ledger %s ORDER BY id DESC LIMIT ?" % where,
            (*args, limit)).fetchall()
    return jsonify({"ok": True,
                    "summary": [{"reason": r["reason"], "scope": r["scope"],
                                 "entries": r["n"], "total_cents": r["cents"]} for r in summ],
                    "rows": [dict(r) for r in rows]})


@app.route("/api/console/points-dedup", methods=["POST"])
def api_console_points_dedup():
    """Owner-gated one-off: remove duplicate (order_ref, reason, scope) points_ledger
    rows (keeping the earliest id) and ensure the UNIQUE index. Dry-run by default;
    ?apply=1 performs the deletion. Idempotent/re-runnable. Prereq for the UNIQUE
    index (dashboard.points.init_points_table) to create cleanly on prod."""
    if not _console_key_ok():
        return jsonify({"error": "Unauthorized"}), 401
    apply = request.args.get("apply") == "1"
    cx = sqlite3.connect(LOG_DB); cx.row_factory = sqlite3.Row
    try:
        dupes = cx.execute(
            "SELECT order_ref, reason, scope, COUNT(*) c, MIN(id) keep "
            "FROM points_ledger WHERE order_ref IS NOT NULL "
            "GROUP BY order_ref, reason, scope HAVING c > 1").fetchall()
        groups = [dict(r) for r in dupes]
        removed = 0
        if apply:
            for g in groups:
                cur = cx.execute(
                    "DELETE FROM points_ledger WHERE order_ref=? AND reason=? AND scope=? AND id<>?",
                    (g["order_ref"], g["reason"], g["scope"], g["keep"]))
                removed += cur.rowcount
            cx.execute("CREATE UNIQUE INDEX IF NOT EXISTS ux_points_order_ref_reason_scope "
                       "ON points_ledger(order_ref, reason, scope)")
            cx.commit()
        index_exists = cx.execute(
            "SELECT 1 FROM sqlite_master WHERE type='index' "
            "AND name='ux_points_order_ref_reason_scope'").fetchone() is not None
        return jsonify({"ok": True, "applied": apply, "duplicate_groups": len(groups),
                        "rows_removed": removed, "index_exists": index_exists,
                        "groups": groups[:50]})
    finally:
        cx.close()


@app.route("/api/console/dispensary-pay-mix", methods=["GET"])
def api_console_dispensary_pay_mix():
    """Read-only: card vs alt-pay (zelle/wise) split of dispensary sales, PROXIED by
    stripe_payment_intent presence (card = has one; alt-pay = NULL). pay_method is not
    recorded on dispensary ingest, so this is an inference, not a stored field."""
    if not _console_key_ok():
        return jsonify({"error": "Unauthorized"}), 401
    with sqlite3.connect(LOG_DB) as cx:
        cx.row_factory = sqlite3.Row
        rows = cx.execute(
            "SELECT CASE WHEN stripe_payment_intent IS NOT NULL AND stripe_payment_intent!='' "
            "            THEN 'card' ELSE 'alt_pay' END AS bucket, "
            "       COUNT(*) AS n, COALESCE(SUM(total_cents),0) AS cents "
            "FROM orders WHERE source='dispensary' GROUP BY bucket").fetchall()
    by = {r["bucket"]: {"orders": r["n"], "total_cents": r["cents"]} for r in rows}
    card = by.get("card", {"orders": 0, "total_cents": 0})
    alt = by.get("alt_pay", {"orders": 0, "total_cents": 0})
    total = card["orders"] + alt["orders"]
    return jsonify({"ok": True, "source": "dispensary",
                    "proxy": "stripe_payment_intent present=card, NULL=alt_pay(zelle/wise)",
                    "card": card, "alt_pay": alt, "total_orders": total,
                    "alt_pay_order_share": round(alt["orders"] / total, 3) if total else 0.0})


