BIOFIELD_PRICE_CENTS = 30000   # $300 Causal Biofield Analysis (service, no shipping)
_BIOFIELD_ITEM_NAME = "Causal Biofield Analysis"

PROGRAM_PREMIUM_TIER = "premium"
PROGRAM_SCALABLE_TIER = "scalable"
# Single source of truth for the two program tiers. Premium = the existing $300 1:1
# program (behavior unchanged); scalable = the $100 headline the $1-deposit front door
# flows into.
PROGRAM_TIERS = {
    PROGRAM_PREMIUM_TIER:  {"price_cents": BIOFIELD_PRICE_CENTS, "name": _BIOFIELD_ITEM_NAME},
    PROGRAM_SCALABLE_TIER: {"price_cents": 10000,               "name": "Biofield Program"},
}


def _biofield_enabled() -> bool:
    return os.environ.get("BIOFIELD_CHECKOUT_ENABLED", "").strip().lower() \
        in ("1", "true", "yes", "on")


def _price_biofield(points_to_redeem_cents=0, tier=PROGRAM_PREMIUM_TIER):
    """Price the single Biofield service line through the engine.

    A service item has no bottle_type and is volume-ineligible, so it yields NO
    shipping. We build the engine line directly (not via _price_cart, which keys
    shipping off bottle counts) so shipping_cents is always 0. Points are applied
    by the engine and clamped at the per-SKU points floor (43% of list). `tier`
    resolves price/name from PROGRAM_TIERS (defaults to premium = existing $300)."""
    _t = PROGRAM_TIERS.get(tier) or PROGRAM_TIERS[PROGRAM_PREMIUM_TIER]
    _price = _t["price_cents"]
    _name = _t["name"]
    from dashboard import pricing as _pricing, tax as _tax
    settings = _pricing.load_settings(_pricing_settings())
    product = {"slug": "biofield-analysis", "name": _name,
               "volume_eligible": False}
    item = {"slug": "biofield-analysis", "name": _name, "qty": 1,
            "product": product, "unit_cents": _price,
            "months": 0, "volume_eligible": False}
    priced = _pricing.compute([item], settings=settings,
                              points_to_redeem_cents=int(points_to_redeem_cents or 0),
                              channel="retail", ship_to_state=None,
                              tax_fn=_tax.compute_get_cents,
                              program_member=False)  # service line is volume_eligible=False; explicit for clarity
    qbo_lines = [{"name": _name,
                  "amount": round(_price / 100.0, 2), "qty": 1,
                  "description": _name}]
    items_rec = [{"name": _name, "qty": 1, "desc": _name}]
    return {"priced": priced, "qbo_lines": qbo_lines, "items_rec": items_rec,
            "discount_cents": priced["discount_cents"],
            "points_redeemed_cents": priced["points_redeemed_cents"],
            "shipping_cents": 0}


def _charge_cents(pc):
    """The customer is charged merch + shipping; Hawai'i GET is absorbed and only
    recorded on the order for remittance, never charged. `pc["priced"]["total_cents"]`
    (subtotal + get_cents, from the pricing engine) is NOT the charge basis -- back
    the GET out and add shipping: subtotal + shipping."""
    return (int(pc["priced"]["total_cents"]) - int(pc["priced"]["get_cents"])
            + int(pc["shipping_cents"]))


@app.route("/biofield/checkout", methods=["POST"])
def biofield_checkout():
    """Sell the $300 Biofield as a points-redeemable service. Ships dark behind
    BIOFIELD_CHECKOUT_ENABLED. On payment, /begin/checkout-return (kind=biofield)
    seeds the readiness record and routes the customer to the readiness gate."""
    if not _biofield_enabled():
        return jsonify({"ok": False, "error": "Biofield checkout is not available."}), 404
    data  = request.get_json(silent=True) or {}
    email = (data.get("email") or "").strip().lower()
    name  = (data.get("name") or "").strip()
    tier  = (data.get("tier") or PROGRAM_PREMIUM_TIER).strip()
    tier  = tier if tier in PROGRAM_TIERS else PROGRAM_PREMIUM_TIER
    if not email:
        return jsonify({"ok": False, "error": "email required"}), 400
    if not _STRIPE_ACTIVE:
        return jsonify({"ok": False, "error": "card payment not active"}), 400
    try:
        redeem = int(data.get("points_to_redeem_cents") or 0)
    except (TypeError, ValueError):
        redeem = 0
    if redeem > 0:
        from dashboard import points as _points
        with sqlite3.connect(LOG_DB) as _bcx:
            _points.init_points_table(_bcx)
            redeem = min(redeem, _points.balance(_bcx, email))
    elif PROGRAM_CARE_TASTER_ENABLED:
        # No explicit redeem requested: auto-apply the $1 deposit credit (if any) so
        # it actually lands as $1 off the program at checkout.
        from dashboard import points as _points
        with sqlite3.connect(LOG_DB) as _bcx:
            _points.init_points_table(_bcx)
            redeem = min(PROGRAM_DEPOSIT_CREDIT_CENTS, _points.balance(_bcx, email))
    pc = _price_biofield(points_to_redeem_cents=redeem, tier=tier)
    charged_cents = _charge_cents(pc)
    redeemed = pc["points_redeemed_cents"]

    checkout_ref = _uuid.uuid4().hex   # stable order/correlation key (no QBO invoice yet)
    qbo_payload = {"lines": pc["qbo_lines"],
                   "discount_cents": pc["discount_cents"] + redeemed, "tax_cents": 0}
    out = {"ok": True, "invoice_id": checkout_ref, "doc_number": "",
           "customer_id": "", "total": round(charged_cents / 100.0, 2)}

    _ingest_order(source="biofield", external_ref=checkout_ref, email=email, name=name,
                  items=pc["items_rec"], total_cents=charged_cents, channel="retail",
                  get_cents=pc["priced"]["get_cents"], discount_cents=pc["discount_cents"],
                  points_redeemed_cents=redeemed, shipping_cents=pc["shipping_cents"])
    try:
        with _sqlite3.connect(LOG_DB) as _lcx:
            _bos_orders.set_order_qbo_lines(_lcx, checkout_ref, qbo_payload)
    except Exception as _e:
        print(f"[biofield] persist qbo_lines failed: {_e!r}", flush=True)
    try:
        from dashboard import stripe_pay
        success = (f"{PUBLIC_BASE_URL}/begin/checkout-return"
                   f"?session_id={{CHECKOUT_SESSION_ID}}")
        metadata = {"kind": "biofield", "email": email,
                    "invoice_id": checkout_ref,
                    "customer_id": "",
                    "points_redeemed_cents": str(int(redeemed)),
                    "tier": tier}
        sess = stripe_pay.create_checkout_session(
            charged_cents, customer_email=email,
            description=f"{PROGRAM_TIERS[tier]['name']}",
            metadata=metadata, success_url=success,
            cancel_url=f"{PUBLIC_BASE_URL}/begin")
        out["stripe_url"] = sess.get("url") or ""
    except Exception as e:
        print(f"[biofield] session create failed: {e!r}", flush=True)
        out["stripe_url"] = ""
    return jsonify(out)


@app.route("/begin/checkout/<slug>", methods=["POST"])
def begin_checkout(slug):
    p = _get_product(slug)
    if not p:
        return jsonify({"ok": False, "error": "unknown product"}), 404
    if p.get("info_only"):
        return jsonify({"ok": True, "info_only": True, "affiliate_url": p.get("affiliate_url", "")})
    data   = request.get_json(silent=True) or {}
    email  = (data.get("email") or "").strip().lower()
    name   = (data.get("name") or "").strip()
    method = (data.get("method") or "").strip().lower()   # zelle | wise | card
    fmt    = (data.get("format") or "").strip().lower()    # bottle | larger | refill
    try:
        qty = max(1, min(int(data.get("qty", 1) or 1), 99))
    except Exception:
        qty = 1
    # Ship-to address — drives GET tax (HI vs out-of-state) and auto-fills the
    # EasyPost label. Normalized to the shape easypost.build_shipment reads.
    ship = _normalize_ship_address(data.get("address") or {}, fallback_name=name)
    if not email:
        return jsonify({"ok": False, "error": "email required"}), 400

    # ── Consent gate ── ordering requires Tier-1 Membership (ToS agreed +
    # identified). Enforced here at the API so it can't be bypassed by hitting
    # the endpoint directly. The front-end shows the soft opt-in on need_optin.
    _sid = request.cookies.get("amg_session", "")
    if not is_member(_sid, email):
        return jsonify({"ok": False, "need_optin": True,
                        "error": "Please add your name and agree to our Terms "
                                 "to place an order."}), 403
    session_id = request.cookies.get("amg_session", "")
    try:
        redeem = int((data.get("points_to_redeem_cents") or 0))
    except (TypeError, ValueError):
        redeem = 0
    if redeem > 0:
        from dashboard import points as _points
        with sqlite3.connect(LOG_DB) as _bcx:
            _points.init_points_table(_bcx)
            redeem = min(redeem, _points.balance(_bcx, email))
    _ref_pct, _ref_ctx = _resolve_checkout_coupon_pct(data.get("referral_code"), email)
    _coupon_code = (data.get("coupon_code") or "").strip() or _best_active_self_coupon_code(email, slug)
    _self_pct, _self_coupon = _resolve_self_coupon_pct(_coupon_code, slug)
    _gift_pct, _gift_coupon = _resolve_gift_coupon_pct((data.get("gift") or "").strip(), email)
    # a gift code is product-bound — only honor it when buying the right product
    if _gift_coupon and _gift_coupon.get("product_slug") != slug:
        _gift_pct, _gift_coupon = 0, None
    _eff_pct = max(_ref_pct or 0, _self_pct or 0, _gift_pct or 0)
    try:
        pc = _price_cart([{"slug": slug, "qty": qty, "format": fmt}], ship=ship,
                         coupon_pct=_eff_pct,
                         points_to_redeem_cents=redeem,
                         program_member=_is_paid_member(email), email=email)
    except CheckoutError as ce:
        return jsonify({"ok": False, "error": str(ce)}), 400
    # Shipping credit (slice 2b, flag-gated): auto-apply the customer's outstanding
    # ship_credit balance to this order, bounded by the payable (net product + shipping;
    # GET is absorbed, not charged). Folded into the invoice discount so the charge
    # drops; the ledger is debited centrally at payment settle.
    _sc_apply = _plan_ship_credit(email, int(pc["priced"]["subtotal_cents"]) + int(pc["shipping_cents"]))
    # The charge must match the booked receipt: receipt total is subtotal + shipping
    # (via the discount above, which already folds in _sc_apply) so the actual card
    # charge -- and the order's stored total -- must be reduced by _sc_apply too,
    # floored at 0 (a credit can never make the charge negative).
    _charged = max(0, _charge_cents(pc) - _sc_apply)
    checkout_ref = _uuid.uuid4().hex   # stable order/correlation key (no QBO invoice yet)
    qbo_payload = {
        "lines": pc["qbo_lines"] + _shipping_line(pc["shipping_cents"]),
        "discount_cents": pc["discount_cents"] + pc["points_redeemed_cents"] + _sc_apply,
        "tax_cents": 0}
    _gift_won = bool(_gift_coupon and _gift_pct >= max(_ref_pct or 0, _self_pct or 0))
    if not _gift_won:
        _record_referral_if_any(_ref_ctx, email, checkout_ref)
    if _self_coupon and _self_pct >= (_ref_pct or 0) and _self_pct > (_gift_pct or 0):
        try:
            from dashboard import coupons as _coupons
            with _db_lock, sqlite3.connect(LOG_DB) as _ccx:
                _coupons.mark_redeemed(_ccx, _self_coupon["code"], order_ref=checkout_ref)
        except Exception as e:  # noqa: BLE001
            print(f"[coupons] redeem-mark failed: {e!r}", flush=True)
    if _gift_won:
        try:
            from dashboard import coupons as _coupons
            from dashboard import referrals as _rf
            with _db_lock, sqlite3.connect(LOG_DB) as _gcx:
                _coupons.mark_redeemed(_gcx, _gift_coupon["code"], order_ref=checkout_ref)
                _rf.record_redemption(_gcx, _gift_coupon["code"], _gift_coupon["email"], email, checkout_ref)
        except Exception as e:  # noqa: BLE001
            print(f"[coupons] gift redeem/attrib failed: {e!r}", flush=True)
    out = {"ok": True, "invoice_id": checkout_ref, "doc_number": "",
           "total": round(_charged / 100.0, 2),
           "method": method, "customer_id": ""}
    try:
        with _db_lock, sqlite3.connect(LOG_DB) as cx:
            cx.execute("INSERT INTO journey_events (ts, session_id, email, trigger, detail, rung_before, rung_after) "
                       "VALUES (?,?,?,?,?,?,?)",
                       (begin_funnel._now(), session_id, email, "purchase",
                        f"buy-{slug}-{method}", "", ""))
            cx.commit()
    except Exception:
        pass
    _ingest_order(source="funnel", external_ref=checkout_ref, email=email, name=name,
                  items=pc["items_rec"],
                  total_cents=_charged,
                  address=ship, channel="retail", get_cents=pc["priced"]["get_cents"],
                  discount_cents=pc["discount_cents"],
                  points_redeemed_cents=pc["points_redeemed_cents"],
                  shipping_cents=pc["shipping_cents"],
                  ship_credit_applied_cents=_sc_apply)
    try:
        with _sqlite3.connect(LOG_DB) as _lcx:
            _bos_orders.set_order_qbo_lines(_lcx, checkout_ref, qbo_payload)
    except Exception as _e:
        print(f"[funnel] persist qbo_lines failed: {_e!r}", flush=True)
    if method in ("zelle", "wise"):
        out["pay_instructions"] = _ALT_PAY.get(method, {})
    elif method == "card" and _STRIPE_ACTIVE:
        # Group-bundle opt-in: when the flag is on AND the buyer opted in AND the buyer
        # is a PAID Biofield Analysis client (designed-program gate; the free E4L scan
        # does not qualify) AND the cart carries >=1 program month, grant 1 free
        # live-group month per program month (capped at 3). Vaults the card so the
        # membership can auto-continue.
        _gb_months = 0
        if (os.environ.get("GROUP_BUNDLE_ENABLED") and bool(data.get("group_bundle"))
                and _has_paid_biofield(email)):
            from dashboard import group_bundle
            _gb_months = group_bundle.included_group_months(
                pc["priced"].get("volume_months", 0))
        out["stripe_url"] = _stripe_checkout_url_for_retail(
            out, email, slug, group_bundle_months=_gb_months)
        if _STRIPE_ACTIVE and not out.get("stripe_url"):
            out["payment_error"] = _CARD_UNAVAILABLE
    try:
        disp = (request.cookies.get("rm_dispensary") or "").strip()
        if disp:
            _record_dispensary_sale(disp, email, qty, checkout_ref)
    except Exception as e:
        print(f"[dispensary] hook: {e!r}", flush=True)
    return jsonify(out)


def _fulfill_biofield_trial(session_id):
    """Create the $1-trial membership (subscription + access grant + cancel token) from a
    paid biofield_trial Stripe session, idempotently. Callable from the redirect return AND
    the webhook. Re-fetches the session + PaymentIntent from Stripe (the security guarantee);
    only proceeds on a succeeded payment with a vaulted card. Never raises."""
    try:
        from dashboard import stripe_pay as _sp
        sess = _sp.get_session(session_id)
        md = sess.get("metadata") or {}
        if md.get("kind") != "biofield_trial":
            return {"ok": False, "reason": "not_trial"}
        bt_email = (md.get("email") or "").strip().lower()
        pi_id = sess.get("payment_intent")
        if not pi_id:
            return {"ok": False, "reason": "unpaid"}
        pi = _sp.get_payment_intent(pi_id)
        if not (pi.get("status") == "succeeded" and pi.get("customer") and pi.get("payment_method")):
            return {"ok": False, "reason": "unpaid"}
        with _db_lock, sqlite3.connect(LOG_DB) as _bc:
            _bc.execute("CREATE TABLE IF NOT EXISTS biofield_trial_grants (session_id TEXT PRIMARY KEY, email TEXT, granted_at TEXT)")
            # Claim-then-create: write the idempotency marker FIRST and commit, so the redirect
            # and the webhook (in any order, even simultaneously) create exactly one membership.
            claimed = bool(bt_email) and _bc.execute(
                "INSERT OR IGNORE INTO biofield_trial_grants (session_id, email, granted_at) VALUES (?,?,?)",
                (session_id, bt_email, datetime.utcnow().isoformat() + "Z")).rowcount == 1
            _bc.commit()
            if not claimed:
                return {"ok": True, "already": True, "email": bt_email}
            init_membership_tables(_bc)
            # Model #2: the $1 is a credited activation DEPOSIT, not an opt-out trial.
            # It unlocks the full Biofield Analysis + portal preview (a day-based grant),
            # but creates NO subscription row -> nothing auto-charges, ever. Paid
            # membership (the DISCOUNT + Continuous Care) begins only when the client
            # activates on their first order (or prepays); the $1 credit persists
            # (tracked by the biofield_trial order row). The member DISCOUNT is withheld
            # (membership_category -> 'trial' via the grant-aware fallback, keyed on
            # source not duration). The $1 buys LIFETIME access to the free-level
            # membership (un-blur, #497), so the grant runs effectively forever; no cancel
            # token is minted because there is nothing to cancel. Plus (#498) the $1 is
            # credited to points and auto-redeemed at program checkout.
            _grant_membership(_bc, bt_email, BIOFIELD_UNLOCK_DAYS, "biofield_trial")
            if PROGRAM_CARE_TASTER_ENABLED:
                try:
                    from dashboard import points as _points
                    _points.init_points_table(_bc)
                    _points.credit(_bc, bt_email, value_cents=PROGRAM_DEPOSIT_CREDIT_CENTS,
                                   reason="deposit_credit", order_ref=pi_id)
                except Exception as _pce:
                    print(f"[deposit-credit] grant failed: {_pce!r}", flush=True)
            _bc.commit()
        # Lock released. Record the $1 charge as a captured-charge order so it shows in
        # the Payments ledger (digital unlock -> status 'done', not a fulfillment task).
        # Best-effort + idempotent on (source, external_ref); never undoes the membership.
        try:
            _trial_cents = (int(sess.get("amount_total") or pi.get("amount_received") or 0)
                            or _bos_payments.TRIAL_AMOUNT_CENTS)
            _ingest_order(source="biofield_trial", external_ref=pi_id, email=bt_email,
                          total_cents=_trial_cents, channel="retail", status="done",
                          paid_cents=_trial_cents)
        except Exception as _oe:
            print(f"[biofield-trial] order-ledger record failed: {_oe!r}", flush=True)
        # Send the deposit-unlock welcome email best-effort: it must never undo the
        # committed grant. Inside the won-claim path, so exactly once.
        try:
            if bt_email and PUBLIC_BASE_URL:
                subject = "You're in - your Biofield Analysis is unlocked"
                body = (
                    "Aloha,\n\n"
                    "Your $1 just unlocked your full Biofield Analysis and opened your member "
                    "portal - your matched remedies, your causal chain, and your AI ally are "
                    "waiting for you inside.\n\n"
                    "That $1 buys you LIFETIME access to your analysis and your member portal - "
                    "they're yours to return to anytime, for good. It's a deposit, not a trial "
                    "that turns into a bill: nothing auto-charges, no card is waiting to spring on "
                    "you. Your paid membership - with your member discount - begins only when you "
                    "decide to start, with your first order, and your $1 is credited toward it then. "
                    "Until that day you're never charged, and the door stays open.\n\n"
                    "Take all the time you need. When you're ready to begin, I'm right here.\n\n"
                    "In wellness,\n"
                    "Dr. Glen and Rae\n"
                )
                _send_inquiry_email(bt_email, subject, body)
            else:
                print("[biofield-trial] welcome-email skipped (missing email or base url)", flush=True)
        except Exception as _e:
            print(f"[biofield-trial] welcome-email failed: {_e!r}", flush=True)
        return {"ok": True, "created": True, "email": bt_email}
    except Exception as e:
        print(f"[biofield-trial] fulfill failed: {e!r}", flush=True)
        return {"ok": False, "reason": "error"}


def _window_days_for_term(term_months):
    """Map a membership term length (months) to the lookback window (days) used to
    seed a new member's repertoire from their purchase history: short terms get a
    tight recent window, longer terms get more history."""
    m = int(term_months or 0)
    if m <= 1:
        return 90
    if m <= 6:
        return 180
    return 365


def _order_slugs_since(cx, email, window_days):
    """Distinct-ish list of item slugs from this email's non-cancelled orders in the
    last window_days. Used to seed dashboard.repertoire on membership conversion."""
    import json as _json
    from datetime import datetime as _dt, timedelta as _td, timezone as _tz
    cutoff = (_dt.now(_tz.utc) - _td(days=int(window_days or 0))).isoformat()
    cx.row_factory = sqlite3.Row
    rows = cx.execute(
        "SELECT items_json FROM orders WHERE lower(email)=? "
        "AND status!='cancelled' AND created_at>=?",
        ((email or "").strip().lower(), cutoff)).fetchall()
    out = []
    for r in rows:
        for it in (_json.loads(r["items_json"] or "[]") or []):
            s = (it.get("slug") or "").strip().lower()
            if s:
                out.append(s)
    return out


def _notify_first_cc_signup(email, plan_label, amount_cents):
    """Email Glen ONCE when the first Continuous Care signup lands (monthly OR
    up-front). Global once-guard via ops_notices(key PRIMARY KEY) — atomic under the
    DB lock, so concurrent/replayed fulfillments send exactly one alert. Best-effort:
    never raises into the fulfiller (an alert must never undo a committed signup)."""
    try:
        with _db_lock, sqlite3.connect(LOG_DB) as cx:
            cx.execute("CREATE TABLE IF NOT EXISTS ops_notices "
                       "(key TEXT PRIMARY KEY, created_at TEXT)")
            first = cx.execute(
                "INSERT OR IGNORE INTO ops_notices (key, created_at) VALUES (?,?)",
                ("first_cc_signup", datetime.utcnow().isoformat() + "Z")).rowcount == 1
            cx.commit()
        if not first:
            return
        to = os.environ.get("GLEN_EMAIL", "drglenswartwout@gmail.com")
        amt = f"${int(amount_cents) / 100:.2f}" if amount_cents else ""
        subject = "First Continuous Care signup"
        body = (
            "Aloha Glen,\n\n"
            "Your first Continuous Care signup just came in.\n\n"
            f"Client: {email}\n"
            f"Plan: {plan_label}\n"
            + (f"Amount: {amt}\n" if amt else "")
            + "\nThe offer redesign is converting. Onward.\n\nIn wellness,\nYour AI\n"
        )
        _send_full_report_email(to, "Dr. Glen", subject, body)
    except Exception as e:
        print(f"[cc-signup-alert] {e!r}", flush=True)


def _last_attributed_practitioner(email, *, db_path=None):
    """The patient's most-recent attributed doctor across prepay grants + memberships.
    Returns {'pid': str, 'consent': int} or None. Sticky: most-recent-wins (no window).
    Only considers rows with a non-null attributed_practitioner_id; table-guarded."""
    e = (email or "").strip().lower()
    if not e:
        return None
    cands = []  # (timestamp, pid, consent)
    with sqlite3.connect(db_path or LOG_DB) as cx:
        try:
            r = cx.execute(
                "SELECT granted_at, attributed_practitioner_id, practitioner_share_consent "
                "FROM prepay_term_grants WHERE lower(email)=? AND attributed_practitioner_id IS NOT NULL "
                "ORDER BY granted_at DESC LIMIT 1", (e,)).fetchone()
            if r:
                cands.append((r[0] or "", str(r[1]), int(r[2] or 0)))
        except sqlite3.OperationalError:
            pass
        try:
            r = cx.execute(
                "SELECT created_at, attributed_practitioner_id, practitioner_share_consent "
                "FROM subscriptions WHERE lower(email)=? AND attributed_practitioner_id IS NOT NULL "
                "AND kind='membership' ORDER BY created_at DESC LIMIT 1", (e,)).fetchone()
            if r:
                cands.append((r[0] or "", str(r[1]), int(r[2] or 0)))
        except sqlite3.OperationalError:
            pass
    if not cands:
        return None
    best = max(cands, key=lambda c: c[0])   # ISO timestamps compare lexically by recency
    return {"pid": best[1], "consent": best[2]}


def _practitioner_display_name(pid):
    """Best-effort practitioner display name from the practitioners record. None on any failure."""
    try:
        from db_supabase import supabase_cursor
        with supabase_cursor() as cur:
            cur.execute("SELECT name FROM practitioners WHERE id=%s", (str(pid),))
            row = cur.fetchone()
        return (row["name"] or "").strip() or None if row else None
    except Exception:
        return None


def _patient_practitioner_brand(email, *, db_path=None):
    """The patient's attributed doctor's PUBLIC identity for co-branding the patient
    portal: {name, practice_name, photo_url, logo_url, accent} or None. Attribution-only
    (NOT gated on results-sharing consent — the band is the doctor's public identity, not
    patient health data). Best-effort — returns None on any failure or when there's no
    attributed doctor / no branding set.

    Note: accent uses the real practitioner_settings branding_json key confirmed from
    static/practitioner-settings.html — the color picker saves brand_color_1 (header/
    primary) and brand_color_2, labeled "Brand color 2 (accent)" in the settings UI."""
    try:
        inh = _last_attributed_practitioner(email, db_path=db_path)
        if not inh:
            return None
        pid = inh["pid"]
        with sqlite3.connect(db_path or LOG_DB) as cx:
            cx.row_factory = sqlite3.Row
            from dashboard import practitioner_settings as _ps
            _ps.init_settings_table(cx)
            branding = (_ps.get_settings(cx, pid) or {}).get("branding") or {}
        name = _practitioner_display_name(pid)
        practice_name = (branding.get("practice_name") or "").strip()
        photo_url = (branding.get("photo_url") or "").strip()
        logo_url = (branding.get("logo_url") or "").strip()
        accent = (branding.get("brand_color_2") or "").strip()
        # Require SOME brand to show (name alone isn't "branding set").
        if not (practice_name or photo_url or logo_url):
            return None
        return {"name": name or practice_name, "practice_name": practice_name,
                "photo_url": photo_url, "logo_url": logo_url, "accent": accent}
    except Exception:
        return None


def _ensure_prepay_grant_columns(cx):
    """Idempotently add the attribution columns to prepay_term_grants."""
    have = {r[1] for r in cx.execute("PRAGMA table_info(prepay_term_grants)")}
    if "attributed_practitioner_id" not in have:
        cx.execute("ALTER TABLE prepay_term_grants ADD COLUMN attributed_practitioner_id TEXT")
    if "practitioner_share_consent" not in have:
        cx.execute("ALTER TABLE prepay_term_grants ADD COLUMN practitioner_share_consent INTEGER NOT NULL DEFAULT 0")
    if "term_end" not in have:
        cx.execute("ALTER TABLE prepay_term_grants ADD COLUMN term_end TEXT")


def _fulfill_prepay_term(session_id):
    """Grant a prepaid Continuous Care term from a paid prepay_term Stripe session,
    idempotently. Callable from the /prepay/return redirect AND the webhook, so a
    closed tab / dropped redirect still gets fulfilled (money captured => term granted).
    Re-fetches the session + PaymentIntent (the security guarantee); only proceeds on a
    succeeded payment. Claim-then-create on prepay_term_grants(session_id) makes the
    redirect and webhook race safely. Never raises."""
    try:
        from dashboard import stripe_pay as _sp, prepay as _pp
        sess = _sp.get_session(session_id)
        md = sess.get("metadata") or {}
        if md.get("kind") != "prepay_term":
            return {"ok": False, "reason": "not_prepay"}
        email = (md.get("email") or "").strip().lower()
        tier_key = (md.get("tier_key") or "").strip()
        tier = _pp.get_tier(tier_key)
        pi_id = sess.get("payment_intent")
        if not (email and tier and pi_id):
            return {"ok": False, "reason": "incomplete"}
        pi = _sp.get_payment_intent(pi_id)
        if pi.get("status") != "succeeded":
            return {"ok": False, "reason": "unpaid"}
        claimed = False
        with _db_lock, sqlite3.connect(LOG_DB) as cx:
            # Wishlist Task 4: payment just verified succeeded, so this is a real
            # purchaser email — merge the anonymous session's wishlist into it so
            # the list follows the visitor home. Called from both the /prepay/return
            # redirect (browser request, amg_session cookie present) and the Stripe
            # webhook (no browser cookies, so session_id is empty and this is a
            # harmless no-op there). Flag-gated + best-effort: a merge failure must
            # never break fulfillment.
            if _WISHLIST_ENABLED:
                try:
                    import sqlite3 as _wsq
                    from dashboard import wishlist as _wl
                    # Already inside the enclosing `with _db_lock, ...` block above,
                    # so _db_lock is held here — do NOT re-acquire it (threading.Lock
                    # is not reentrant; nesting would deadlock). Use a dedicated
                    # connection so merge_wishlist's internal commit() never touches
                    # this handler's shared `cx`.
                    with _wsq.connect(LOG_DB) as _cxw:
                        _wl.init_wishlist_table(_cxw)
                        _wl.merge_wishlist(_cxw, request.cookies.get("amg_session", ""), email)
                except Exception as _e:
                    print(f"[wishlist] merge skipped: {_e}", flush=True)
            cx.execute(
                "CREATE TABLE IF NOT EXISTS prepay_term_grants "
                "(session_id TEXT PRIMARY KEY, email TEXT, tier_key TEXT, granted_at TEXT)")
            _ensure_prepay_grant_columns(cx)
            init_membership_tables(cx)
            claimed = cx.execute(
                "INSERT OR IGNORE INTO prepay_term_grants "
                "(session_id, email, tier_key, granted_at) VALUES (?,?,?,?)",
                (session_id, email, tier_key, datetime.utcnow().isoformat() + "Z")).rowcount == 1
            cx.commit()
            if claimed:
                _grant_prepay_term(cx, email, tier_key)
                cx.commit()
                # Attributed dispensary prepay (Task 2): stamp the grant with
                # attribution + consent + term_end, then credit the enrolling
                # doctor ONCE on the FULL prepaid lump. Public (no dispensary_pid)
                # prepay is unchanged: no stamp, no credit. Inside the won-claim
                # path so the redirect+webhook double-call credits exactly once;
                # the care-share credit is best-effort AFTER the committed grant —
                # a credit failure must never undo the term.
                disp_pid = (md.get("dispensary_pid") or "").strip() or None
                share_consent = 1 if (md.get("share_consent") or "").strip() == "1" else 0
                if not disp_pid:
                    _inh = _last_attributed_practitioner(email)   # sticky renewal attribution
                    if _inh:
                        disp_pid = _inh["pid"]
                        share_consent = int(_inh["consent"])
                _term_end = _pp.term_end_date(
                    datetime.utcnow().date().isoformat(), tier["months"])
                if disp_pid:
                    cx.execute(
                        "UPDATE prepay_term_grants SET attributed_practitioner_id=?, "
                        "practitioner_share_consent=?, term_end=? WHERE session_id=?",
                        (str(disp_pid), share_consent, _term_end, session_id))
                    cx.commit()
                    try:
                        from dashboard import care_share as _cshare, wallet as _wallet
                        m = _cshare.modules_for_practitioner(disp_pid)
                        if m is not None:
                            cents = _cshare.share_cents(int(tier["price_cents"]), m)
                            if cents > 0:
                                _wallet.earn_care_share(
                                    str(disp_pid), cents,
                                    event_ref=f"care_share:prepay:{session_id}")
                    except Exception as _ce:
                        print(f"[prepay] care-share credit failed sid={session_id}: {_ce!r}",
                              flush=True)
                if REPERTOIRE_ENABLED:
                    try:
                        repertoire.init_repertoire_table(cx)
                        repertoire.seed_from_history(
                            cx, email, _window_days_for_term(tier["months"]),
                            order_slugs_fn=_order_slugs_since)
                    except Exception as _re:
                        print(f"[prepay] repertoire seed failed: {_re!r}", flush=True)
                # Union in FMP/GK backfilled purchase history (Task 4) — the same
                # windowed proven-remedies logic as the orders seed above, but for
                # purchases recorded outside the live orders board. Best-effort,
                # flag-gated, fresh-DB-safe (own connection, own init).
                try:
                    if REPERTOIRE_ENABLED:
                        import dashboard.purchase_history as purchase_history
                        with sqlite3.connect(LOG_DB) as _hcx:
                            purchase_history.init_purchase_history_table(_hcx)
                            _hist = purchase_history.slugs_since(
                                _hcx, email, _window_days_for_term(tier["months"]))
                        if _hist:
                            repertoire.add_skus(cx, email, list(_hist))
                except Exception as _e:
                    print(f"[prepay] purchase_history seed failed: {_e!r}", flush=True)
        if not claimed:
            return {"ok": True, "already": True, "email": email}
        # Ledger (idempotent on source+ref) + confirmation email, best-effort — must
        # never undo the committed grant. Inside the won-claim path, so exactly once.
        try:
            _ingest_order(source="prepay_term", external_ref=pi_id, email=email,
                          total_cents=tier["price_cents"], channel="retail", status="done")
        except Exception as _oe:
            print(f"[prepay] order-ledger record failed: {_oe!r}", flush=True)
        try:
            if PUBLIC_BASE_URL:
                per_mo = _pp.per_month_cents(tier_key)
                subject = "Your Continuous Care is active"
                body = (
                    "Aloha,\n\n"
                    f"Your {tier['label']} of Continuous Care is active - you're all set. "
                    f"That's ${tier['price_cents']/100:.0f} prepaid (about "
                    f"${per_mo/100:.0f}/mo). I'll keep re-matching your protocol as you "
                    "progress, with live group coaching, your AI ally, and Terrain Restore "
                    "the whole way.\n\n"
                    "There's nothing to cancel and no surprise charges - when your term "
                    "ends we'll simply check in about renewing.\n\n"
                    "In wellness,\nDr. Glen and Rae\n"
                )
                _send_inquiry_email(email, subject, body)
        except Exception as _e:
            print(f"[prepay] confirmation email failed: {_e!r}", flush=True)
        _notify_first_cc_signup(email, f"Continuous Care up front ({tier['label']})",
                                tier["price_cents"])
        return {"ok": True, "created": True, "email": email}
    except Exception as e:
        print(f"[prepay] fulfill failed: {e!r}", flush=True)
        return {"ok": False, "reason": "error"}


def _fulfill_continuous_care_monthly(session_id):
    """Grant a Continuous Care MONTHLY (card-on-file, 6- or 12-month capped term)
    membership from a paid continuous_care_monthly Stripe session, idempotently.
    Callable from the /continuous-care/return redirect AND the webhook, so a closed
    tab / dropped redirect still gets fulfilled (money captured => membership
    created). Re-fetches the session + PaymentIntent (the security guarantee);
    only proceeds on a succeeded payment WITH a vaulted customer + payment method
    (no membership without a chargeable card on file). Claim-then-create on
    continuous_care_grants(session_id) makes the redirect and webhook race safely.
    Never raises."""
    try:
        from dashboard import stripe_pay as _sp, prepay as _pp, subscriptions as _subs
        sess = _sp.get_session(session_id)
        md = sess.get("metadata") or {}
        if md.get("kind") != "continuous_care_monthly":
            return {"ok": False, "reason": "not_continuous_care"}
        email = (md.get("email") or "").strip().lower()
        # Dispensary-attributed enrollment (Task 6): a doctor's dispensary channel
        # stamps this so the membership + its month-1 charge credit the doctor.
        # Absent (direct front-door enrollment) => None => unattributed, unchanged.
        disp_pid = (md.get("dispensary_pid") or "").strip() or None
        # Practitioner-share consent (Task 3): captured at enrollment via the
        # "Start Continuous Care" card's authorization checkbox, threaded through
        # session metadata the same way as dispensary_pid. Absent/unset => 0.
        share_consent = 1 if (md.get("share_consent") or "").strip() == "1" else 0
        if not disp_pid:
            _inh = _last_attributed_practitioner(email)   # sticky renewal attribution
            if _inh:
                disp_pid = _inh["pid"]
                share_consent = int(_inh["consent"])
        try:
            term_months = int(md.get("term_months") or 0)
        except (TypeError, ValueError):
            term_months = 0
        pi_id = sess.get("payment_intent")
        if not (email and term_months in (6, 12) and pi_id):
            return {"ok": False, "reason": "incomplete"}
        pi = _sp.get_payment_intent(pi_id)
        if pi.get("status") != "succeeded":
            return {"ok": False, "reason": "unpaid"}
        customer = pi.get("customer")
        pm = pi.get("payment_method")
        if not (customer and pm):
            # No vaulted card => nothing to bill months 2..N off of. Do not create
            # a membership that the cron could never charge correctly.
            print(f"[continuous-care] no vaulted card on {session_id} — skipping", flush=True)
            return {"ok": False, "reason": "no_card"}
        claimed = False
        with _db_lock, sqlite3.connect(LOG_DB) as cx:
            cx.row_factory = sqlite3.Row  # active_memberships_by_email returns dict-rows
            cx.execute(
                "CREATE TABLE IF NOT EXISTS continuous_care_grants "
                "(session_id TEXT PRIMARY KEY, email TEXT, created_at TEXT)")
            _subs.init_subscriptions_table(cx)
            _subs.migrate_add_membership_columns(cx)
            _subs.migrate_add_term_cap_column(cx)
            _subs.migrate_add_attribution_column(cx)
            _subs.migrate_add_consent_column(cx)
            init_membership_tables(cx)
            claimed = cx.execute(
                "INSERT OR IGNORE INTO continuous_care_grants "
                "(session_id, email, created_at) VALUES (?,?,?)",
                (session_id, email, datetime.utcnow().isoformat() + "Z")).rowcount == 1
            cx.commit()
            next_charge = None
            if claimed:
                from datetime import date as _date
                today = _date.today().isoformat()
                next_charge = _subs.add_months(today, 1)
                # Never create a SECOND active membership for an email that already has
                # one — the charge cron bills every active membership row, so a duplicate
                # row = double $99/mo. (Idempotency above is per-session, not per-email:
                # two checkout sessions, or an already-monthly member, would collide.)
                # Match the sibling minting paths (portal_group_join_return / group-bundle),
                # which all guard on active_memberships_by_email. Still extend the access
                # grant for the month just paid, and log for manual reconciliation of the
                # duplicate month-1 charge.
                if _subs.active_memberships_by_email(cx, email):
                    print(f"[continuous-care] {email} already has an active membership; "
                          f"NOT creating a 2nd sub (session={session_id}) — reconcile the "
                          f"duplicate month-1 charge manually", flush=True)
                    _grant_membership(cx, email, _pp.term_days(today, 1) + 4, "continuous_care")
                    cx.commit()
                    # This paid term still owes retroactive repertoire seeding — the
                    # member's existing active membership may have originated from a
                    # path that never seeds (group-bundle / studio-bridge), so without
                    # this the buyer pays for continuous_care_monthly and silently gets
                    # zero repertoire benefit. Same call as the won-claim branch below;
                    # add_skus is INSERT OR IGNORE idempotent, so re-seeding is safe.
                    if REPERTOIRE_ENABLED:
                        try:
                            repertoire.init_repertoire_table(cx)
                            repertoire.seed_from_history(
                                cx, email, _window_days_for_term(term_months),
                                order_slugs_fn=_order_slugs_since)
                        except Exception as _re:
                            print(f"[continuous-care] duplicate-member repertoire seed "
                                  f"failed: {_re!r}", flush=True)
                    # Union in FMP/GK backfilled purchase history (Task 4) — same
                    # windowed logic as the orders seed just above, for the
                    # duplicate-member retroactive-seed path. Best-effort,
                    # flag-gated, fresh-DB-safe (own connection, own init).
                    try:
                        if REPERTOIRE_ENABLED:
                            import dashboard.purchase_history as purchase_history
                            with sqlite3.connect(LOG_DB) as _hcx:
                                purchase_history.init_purchase_history_table(_hcx)
                                _hist = purchase_history.slugs_since(
                                    _hcx, email, _window_days_for_term(term_months))
                            if _hist:
                                repertoire.add_skus(cx, email, list(_hist))
                    except Exception as _e:
                        print(f"[continuous-care] duplicate-member purchase_history "
                              f"seed failed: {_e!r}", flush=True)
                    return {"ok": True, "duplicate_member": True, "email": email}
                # order_count=1 records the month-1 charge just taken at checkout, so
                # membership_category reads 'full' (member pricing) immediately —
                # this is a paid card-on-file membership, not the $1-trial. Capped
                # at term_months total charges (the Task-2 cron cap stops it there).
                new_sid = _subs.create_membership(
                    cx, email=email, stripe_customer_id=customer,
                    stripe_payment_method_id=pm, amount_cents=_pp.MONTHLY_ANCHOR_CENTS,
                    next_charge_date=next_charge, cadence_months=1,
                    term_charges_total=term_months, initial_order_count=1,
                    attributed_practitioner_id=disp_pid,
                    practitioner_share_consent=share_consent)
                # Immediate access grant until the first cron charge extends it
                # (~35 days) — mirrors _grant_prepay_term's day-based access pattern.
                _grant_membership(cx, email, _pp.term_days(today, 1) + 4, "continuous_care")
                cx.commit()
                # Turnkey continuity fee-share (Task 6): credit the enrolling doctor
                # for the month-1 (enrollment) charge just taken at checkout. The row
                # (order_count=1 from initial_order_count) gives a unique event_ref
                # care_share:<id>:1, distinct from the first cron renewal (order_count=2).
                # No-op when unattributed. Best-effort — never fails the enrollment.
                try:
                    sub_row = _subs.get(cx, new_sid)
                    if sub_row and sub_row.get("attributed_practitioner_id"):
                        from dashboard import care_share as _cshare
                        _cshare.credit_for_charge(
                            sub_row, charge_cents=int(sub_row.get("amount_cents") or 0))
                except Exception as _cse:
                    print(f"[care-share] enrollment credit failed sid={new_sid}: {_cse!r}",
                          flush=True)
                if REPERTOIRE_ENABLED:
                    try:
                        repertoire.init_repertoire_table(cx)
                        repertoire.seed_from_history(
                            cx, email, _window_days_for_term(term_months),
                            order_slugs_fn=_order_slugs_since)
                    except Exception as _re:
                        print(f"[continuous-care] repertoire seed failed: {_re!r}", flush=True)
                # Union in FMP/GK backfilled purchase history (Task 4) — same
                # windowed proven-remedies logic as the orders seed above, for
                # purchases recorded outside the live orders board. Best-effort,
                # flag-gated, fresh-DB-safe (own connection, own init).
                try:
                    if REPERTOIRE_ENABLED:
                        import dashboard.purchase_history as purchase_history
                        with sqlite3.connect(LOG_DB) as _hcx:
                            purchase_history.init_purchase_history_table(_hcx)
                            _hist = purchase_history.slugs_since(
                                _hcx, email, _window_days_for_term(term_months))
                        if _hist:
                            repertoire.add_skus(cx, email, list(_hist))
                except Exception as _e:
                    print(f"[continuous-care] purchase_history seed failed: {_e!r}", flush=True)
        if not claimed:
            return {"ok": True, "already": True, "email": email}
        # FTC/ROSCA easy-cancel token, minted exactly as the removed biofield-trial
        # auto-charge block did. Outside the write lock (own connection + commit).
        cancel_url = ""
        try:
            with sqlite3.connect(LOG_DB) as _cx:
                cancel_url = _mint_membership_cancel_url(_cx, email) or ""
        except Exception as _ce:
            print(f"[continuous-care] cancel-token mint failed: {_ce!r}", flush=True)
        # Ledger (idempotent on source+ref) + confirmation email, best-effort — must
        # never undo the committed membership. Inside the won-claim path, so exactly
        # once.
        try:
            _ingest_order(source="continuous_care_monthly", external_ref=pi.get("id"),
                          email=email, items=[], total_cents=_pp.MONTHLY_ANCHOR_CENTS,
                          address={}, channel="retail", status="done")
        except Exception as _oe:
            print(f"[continuous-care] order-ledger record failed: {_oe!r}", flush=True)
        try:
            _send_subscription_email(email, "receipt", {
                "kind": "membership", "product": "continuous_care",
                "total_cents": _pp.MONTHLY_ANCHOR_CENTS, "cancel_url": cancel_url,
                "next_charge_date": next_charge, "invoice_id": pi.get("id")})
        except Exception as _e:
            print(f"[continuous-care] confirmation email failed: {_e!r}", flush=True)
        _notify_first_cc_signup(email, f"Continuous Care monthly ({term_months}mo term)",
                                _pp.MONTHLY_ANCHOR_CENTS)
        return {"ok": True, "created": True, "email": email}
    except Exception as e:
        print(f"[continuous-care] fulfill failed: {e!r}", flush=True)
        return {"ok": False, "reason": "error"}


def _book_membership_qbo(email, tier):
    """Record a paid one-time membership purchase (month / year_prepay) as a QBO
    SalesReceipt — paid-only, no A/R invoice. Best-effort — a QBO failure must never
    break the membership grant, which is already committed by the time this runs.
    Never raises."""
    try:
        from dashboard import qbo_billing as qb
        cust = qb.find_or_create_customer(email, "")
        qb.create_sales_receipt(
            cust,
            [{"name": tier["label"], "amount": tier["price_cents"] / 100.0, "qty": 1}],
            email_to=email)
    except Exception as e:
        print(f"[membership] QBO booking skipped for {email}/{tier.get('key')}: {e!r}",
              flush=True)


def _record_membership_reconcile_alert(cx, session_id, email, tier):
    """Durable, owner-retrievable alert for the duplicate_member case in
    _fulfill_membership_product: an active membership already existed at
    year_monthly fulfillment, so no new subscription was created for the
    month-1 charge just taken -- it needs manual reconcile. Idempotent on
    session_id (INSERT OR IGNORE), on the caller's connection/transaction.
    Best-effort: a failure here must never break the grant-extend/return path
    the caller is on, so every error is swallowed and logged."""
    try:
        cx.execute(
            "INSERT OR IGNORE INTO membership_reconcile_alerts "
            "(session_id, email, tier, amount_cents, note, created_at, status) "
            "VALUES (?,?,?,?,?,?,'open')",
            (session_id, email, tier["key"], tier["price_cents"],
             "member already had an active membership; month-1 charge needs "
             "manual reconcile", datetime.utcnow().isoformat() + "Z"))
        cx.commit()
    except Exception as e:
        print(f"[membership] reconcile-alert record failed sid={session_id}: {e!r}",
              flush=True)


def _fulfill_membership_product(session_id):
    """Fulfill a /membership/checkout Stripe session for a membership-product
    tier (month / year_monthly / year_prepay from dashboard.membership_products),
    idempotently. Callable from the /membership/return redirect AND the Stripe
    webhook, so a closed tab / dropped redirect still gets fulfilled (money
    captured => membership granted). Re-fetches the session + PaymentIntent (the
    security guarantee). Self-dispatching: no-ops unless metadata
    kind == 'membership_product'. Claim-then-create on
    membership_product_grants(session_id) makes the redirect and webhook race
    safely. Never raises. Returns a status string: "ok" | "duplicate_member" |
    "no_card" | "not_paid" | "already" | "skip"."""
    from dashboard import membership_products as _mp
    from dashboard import subscriptions as _subs
    from dashboard import prepay as _pp
    from datetime import date as _date
    try:
        sess = stripe_pay.get_session(session_id)
    except Exception as e:
        print(f"[membership] get_session failed sid={session_id}: {e!r}", flush=True)
        return "skip"
    md = sess.get("metadata") or {}
    if md.get("kind") != "membership_product":
        return "skip"
    tier = _mp.get_tier(md.get("tier") or "")
    email = (md.get("email") or "").strip().lower()
    if not (tier and email):
        return "skip"
    pi_id = sess.get("payment_intent")
    try:
        pi = stripe_pay.get_payment_intent(pi_id) if pi_id else {}
    except Exception as e:
        print(f"[membership] get_payment_intent failed sid={session_id}: {e!r}", flush=True)
        return "skip"
    status = pi.get("status") or sess.get("payment_status")
    if status not in ("succeeded", "paid"):
        return "not_paid"
    today = _date.today()
    today_s = today.isoformat()
    with _db_lock, sqlite3.connect(LOG_DB) as cx:
        cx.row_factory = sqlite3.Row
        init_membership_tables(cx)
        try:
            cx.execute(
                "INSERT INTO membership_product_grants (session_id, email, tier, created_at) "
                "VALUES (?,?,?,?)",
                (session_id, email, tier["key"], datetime.utcnow().isoformat() + "Z"))
            cx.commit()
        except sqlite3.IntegrityError:
            return "already"
        days = _mp.grant_days(tier["key"], today)
        # From here on the idempotency claim is committed. Any exception below
        # (e.g. from create_membership, which commits internally before
        # _grant_membership runs) must not leave a billable subscription with
        # no access grant AND a permanently-blocking "already" retry — so the
        # whole post-claim body is guarded: on ANY exception, unwind the claim
        # row and return "error". A subsequent retry then re-enters cleanly:
        # if create_membership already committed, the duplicate-member guard
        # below finds it and self-heals by extending the grant instead of
        # creating a second subscription.
        try:
            if tier["billing"] == "recurring_capped":
                customer, pm = pi.get("customer"), pi.get("payment_method")
                if not (customer and pm):
                    # No vaulted card => the cron could never bill months 2..N off of
                    # it. Unwind the claim so a retry (e.g. with a card added) is not
                    # blocked by this session's own idempotency row.
                    cx.execute("DELETE FROM membership_product_grants WHERE session_id=?",
                               (session_id,))
                    cx.commit()
                    print(f"[membership] no vaulted card on {session_id} — skipping", flush=True)
                    return "no_card"
                # Subscriptions-table migrations — every other subscriptions call
                # site runs these first; init_membership_tables above does NOT
                # create/migrate the subscriptions table. Mirrors the exact
                # bootstrap _fulfill_continuous_care_monthly runs.
                _subs.init_subscriptions_table(cx)
                _subs.migrate_add_membership_columns(cx)
                _subs.migrate_add_term_cap_column(cx)
                _subs.migrate_add_attribution_column(cx)
                _subs.migrate_add_consent_column(cx)
                # Rolling ~1-month access window off the month-1 charge — mirrors
                # _fulfill_continuous_care_monthly, which grants term_days(1 month) + a
                # 4-day grace rather than the full term up front. The charge cron
                # (_extend_membership_grant, tagged "membership_renewal") extends this
                # on each successful monthly charge, so access rolls forward with
                # payment and stops if payment stops. NOT `days` (that is the full
                # 12-month grant.grant_days window, still correct for the one_time
                # tiers below, which are never billed again).
                roll_days = _pp.term_days(today_s, 1) + 4
                if _subs.active_memberships_by_email(cx, email):
                    # Never create a SECOND active membership for an email that
                    # already has one — the charge cron bills every active
                    # membership row, so a duplicate row = double $99/mo. Still
                    # extend the access grant for the month just paid (rolling
                    # window, not the full term — same reasoning as above: there is
                    # no new subscription here to justify more than one month).
                    until = datetime.combine(
                        today + timedelta(days=roll_days), datetime.min.time()).isoformat() + "Z"
                    _extend_membership_grant(cx, email, until, tier["source"])
                    cx.commit()
                    print(f"[membership] {email} already has an active membership; "
                          f"NOT creating a 2nd sub (session={session_id}) — reconcile "
                          f"the duplicate month-1 charge manually", flush=True)
                    _record_membership_reconcile_alert(cx, session_id, email, tier)
                    return "duplicate_member"
                # order_count=1 records the month-1 charge just taken at checkout, so
                # membership_category reads 'full' (member pricing) immediately.
                # Capped at term_charges (the charge cron self-cancels there).
                _subs.create_membership(
                    cx, email=email, stripe_customer_id=customer,
                    stripe_payment_method_id=pm, amount_cents=tier["price_cents"],
                    next_charge_date=_subs.add_months(today_s, 1),
                    cadence_months=tier["cadence_months"],
                    term_charges_total=tier["term_charges"], initial_order_count=1)
                _grant_membership(cx, email, roll_days, tier["source"])
                cx.commit()
            else:  # one_time (month, year_prepay) — grant-only, never billed again
                _grant_membership(cx, email, days, tier["source"])
                cx.commit()
                _book_membership_qbo(email, tier)
        except Exception as e:
            print(f"[membership] fulfill failed after claim sid={session_id}: {e!r}",
                  flush=True)
            try:
                # Discard any uncommitted work from the failed attempt FIRST (e.g.
                # a _grant_membership insert that hadn't reached its cx.commit()
                # yet) — otherwise the delete+commit below would inadvertently
                # commit it alongside the claim-row delete.
                cx.rollback()
                cx.execute("DELETE FROM membership_product_grants WHERE session_id=?",
                           (session_id,))
                cx.commit()
            except Exception as _de:
                print(f"[membership] claim-unwind failed sid={session_id}: {_de!r}",
                      flush=True)
            return "error"
        return "ok"


def _fulfill_biofield_program(session_id):
    """Grant the 30-day Continuous Care taster from a paid biofield PROGRAM purchase,
    idempotently. Callable from the /begin/checkout-return redirect AND the Stripe
    webhook, so a closed tab / dropped redirect still delivers the paid care window
    (money captured => care granted). Re-fetches the session + PaymentIntent (the
    security guarantee); only proceeds on a succeeded biofield payment. Claim-then-create
    on care_taster_grants(order_ref). Flag-gated; never raises. NOTE: the readiness-seed +
    points-settle stay on the redirect path (pre-existing) — only the paid care grant is
    made webhook-safe here."""
    try:
        if not PROGRAM_CARE_TASTER_ENABLED:
            return {"ok": False, "reason": "disabled"}
        from dashboard import stripe_pay as _sp
        sess = _sp.get_session(session_id)
        md = sess.get("metadata") or {}
        if md.get("kind") != "biofield":
            return {"ok": False, "reason": "not_biofield"}
        bf_email = (md.get("email") or "").strip().lower()
        bf_inv = md.get("invoice_id") or ""
        pi_id = sess.get("payment_intent")
        if not (bf_email and pi_id):
            return {"ok": False, "reason": "incomplete"}
        pi = _sp.get_payment_intent(pi_id)
        if pi.get("status") != "succeeded":
            return {"ok": False, "reason": "unpaid"}
        claimed = False
        with _db_lock, sqlite3.connect(LOG_DB) as _ctc:
            _ctc.execute(
                "CREATE TABLE IF NOT EXISTS care_taster_grants "
                "(order_ref TEXT PRIMARY KEY, email TEXT, granted_at TEXT)")
            claimed = _ctc.execute(
                "INSERT OR IGNORE INTO care_taster_grants (order_ref, email, granted_at) VALUES (?,?,?)",
                (bf_inv or bf_email, bf_email, datetime.utcnow().isoformat() + "Z")).rowcount == 1
            _ctc.commit()
            if claimed:
                init_membership_tables(_ctc)
                _grant_membership(_ctc, bf_email, PROGRAM_CARE_TASTER_DAYS, CARE_TASTER_SOURCE)
                _ctc.commit()
        return {"ok": True, "created": claimed, "email": bf_email}
    except Exception as e:
        print(f"[biofield-program] fulfill failed: {e!r}", flush=True)
        return {"ok": False, "reason": "error"}


def _fulfill_masterclass(session_id):
    """Mark a MasterClass registration paid + send the Zoom join link confirmation
    from a completed Stripe checkout, idempotently. Re-fetches the session +
    PaymentIntent (the security guarantee); only proceeds on a succeeded masterclass
    payment. Best-effort; never raises."""
    try:
        from dashboard import stripe_pay as _sp, masterclass as _mc
        sess = _sp.get_session(session_id)
        md = sess.get("metadata") or {}
        if md.get("kind") != "masterclass":
            return {"ok": False, "reason": "not_masterclass"}
        email = (md.get("email") or "").strip().lower()
        try:
            event_id = int(md.get("event_id"))
        except Exception:
            return {"ok": False, "reason": "no_event"}
        pi_id = sess.get("payment_intent")
        if not (email and pi_id):
            return {"ok": False, "reason": "incomplete"}
        if _sp.get_payment_intent(pi_id).get("status") != "succeeded":
            return {"ok": False, "reason": "unpaid"}
        with _db_lock, sqlite3.connect(LOG_DB) as cx:
            cx.row_factory = sqlite3.Row
            _mc.init_masterclass_tables(cx)
            _mc.mark_paid(cx, event_id, email)
            ev = _mc.get_event(cx, event_id)
        _masterclass_send_confirmation(ev, email, md.get("name") or "")
        return {"ok": True, "email": email, "event_id": event_id}
    except Exception as e:
        print(f"[masterclass] fulfill failed: {e!r}", flush=True)
        return {"ok": False, "reason": "error"}


@app.route("/begin/checkout-return")
def begin_checkout_return():
    """Stripe retail return: verify the session, record the QBO payment, capture
    the PaymentIntent on the order, then back to the buy page (paid)."""
    from flask import redirect as _redir
    sid = (request.args.get("session_id") or "").strip()
    slug = ""
    paid = "0"
    _kind = ""
    _bt_token = ""
    if sid:
        try:
            from dashboard import stripe_pay as _sp
            sess = _sp.get_session(sid)
            md = sess.get("metadata") or {}
            slug = md.get("slug", "")
            _kind = md.get("kind", "")
            _bt_token = md.get("token", "")
            if sess.get("payment_status") == "paid":
                paid = "1"
                pi_id = sess.get("payment_intent")
                inv, cid = md.get("invoice_id"), md.get("customer_id")
                # In-house pay-link (Phase 3): a card payment on an in-house proposed/
                # confirmed invoice auto-records as paid and drops into fulfillment.
                if _kind == "in-house" and inv:
                    try:
                        _cxih = _sqlite3.connect(LOG_DB); _cxih.row_factory = _sqlite3.Row
                        try:
                            _oih = _bos_orders.find_order_by_external_ref(_cxih, inv)
                            if _oih:
                                _op.ensure_table(_cxih)
                                _op.add_payment(
                                    _cxih, _oih["id"],
                                    int(sess.get("amount_total") or 0),
                                    "Credit card (Stripe)", source="stripe",
                                    external_ref=pi_id)
                                _bos_orders.set_order_payment(
                                    _cxih, _oih["id"], method="card",
                                    amount_cents=int(sess.get("amount_total") or 0))
                                if pi_id:
                                    _bos_orders.set_order_stripe_pi(_cxih, _oih["id"], pi_id)
                                # Settle points (redeem applied + earn), idempotent.
                                _bos_orders.settle_order_points(
                                    _cxih, _bos_orders.get_order(_cxih, _oih["id"]))
                        finally:
                            _cxih.close()
                    except Exception as _e:
                        print(f"[begin-return] in-house pay record: {_e!r}", flush=True)
                # NOTE: retail/funnel checkout (begin_checkout), cart checkout
                # (_checkout_cart), and reorder/portal-reorder/subscribe are ALL
                # paid-only as of the QBO Stage 3+ migration -- each sets metadata
                # customer_id="" (no QBO customer/invoice exists at checkout time),
                # so `cid` is falsy for every one of these kinds. There is no
                # invoice-payment application (record_payment) anymore -- that
                # legacy routing was removed. The only thing this block does for
                # a matched order is: capture the Stripe PaymentIntent id, settle
                # points/referral, and book ONE line-faithful QBO Sales Receipt
                # (idempotent via qbo_sales_receipt_id). The outer gate is `inv`
                # alone; the inner gate `pi_id and (cid or _kind in (...))` just
                # widens eligibility to include a genuine invoice-based order (a
                # real, non-empty QBO customer_id) alongside the paid-only kinds.
                # biofield is excluded here on purpose -- it has its own dedicated block below
                # (kind=="biofield") so it isn't double-settled/double-booked via this path.
                if inv:
                    if pi_id and (cid or _kind in ("retail", "reorder", "portal-reorder", "subscribe",
                                                    "client")):
                        _o_for_points = None
                        try:
                            _cxo = _sqlite3.connect(LOG_DB); _cxo.row_factory = _sqlite3.Row
                            try:
                                _o = _bos_orders.find_order_by_external_ref(_cxo, inv)
                                if _o:
                                    _bos_orders.set_order_stripe_pi(_cxo, _o["id"], pi_id)
                                    _o_for_points = _o  # plain dict; safe after close
                            finally:
                                _cxo.close()
                        except Exception as _e:
                            print(f"[begin-return] pi capture: {_e!r}", flush=True)
                        # points/referral now settle via order_settlement.settle_paid_order_effects
                        # (the single dispatch at the end of this paid block), NOT inline here.
                        if _o_for_points:
                            # ── Book ONE line-faithful QBO Sales Receipt now that payment is
                            # confirmed. Paid-only orders (retail/funnel, reorder, portal-reorder,
                            # subscribe) all carry a qbo_lines_json payload from checkout and book
                            # a real Sales Receipt here; idempotent via qbo_sales_receipt_id. A
                            # harmless no-op only for a genuine invoice-based order (real cid, no
                            # stored qbo_lines_json). ──
                            try:
                                from dashboard import qbo_sale as _qsale
                                _fcxo2 = _sqlite3.connect(LOG_DB); _fcxo2.row_factory = _sqlite3.Row
                                try:
                                    _fo2 = _bos_orders.find_order_by_external_ref(_fcxo2, inv)
                                    if _fo2:
                                        _qsale.book_sale_on_payment(_fcxo2, dict(_fo2))
                                finally:
                                    _fcxo2.close()
                            except Exception as _fqe:
                                print(f"[begin-return] qbo sale booking failed inv={inv}: {_fqe!r}",
                                      flush=True)

                # NOTE: subscribe-kind subscription creation now settles via
                # order_settlement -> _ensure_subscription_row (single dispatch at the
                # end of this paid block).

                # NOTE: group-bundle grant (free live-group window, flag-gated) now
                # settles via order_settlement -> _grant_group_bundle (single dispatch
                # at the end of this paid block), dispatched kind-agnostically by
                # grant_group_months presence in md -- not just for kind=='subscribe'.
                # See dashboard/order_settlement.py.

                # NOTE: founding_reserve uses a setup-mode ($0) Stripe session and is
                # handled BELOW, outside this "paid" block, so it is reachable for
                # payment_status == "no_payment_required" setup sessions.

                # NOTE: client-kind wallet-margin + dispensary points + ship-credit now
                # settle via order_settlement -> _settle_client_effects (single dispatch
                # below).

                # ── Biofield kind: stamp PaymentIntent + book the Sales Receipt ──
                # These two are COMMON (not per-kind) — the webhook does them too — so
                # they stay INLINE. Biofield's readiness seed + care taster settle via
                # order_settlement -> _settle_biofield_effects, and its points/referral
                # via the common path of that same dispatch (below).
                if md.get("kind") == "biofield":
                    try:
                        bf_email = (md.get("email") or "").strip().lower()
                        bf_inv = md.get("invoice_id") or ""
                        if bf_email:
                            # Book ONE line-faithful QBO Sales Receipt now that payment is
                            # confirmed (paid-only; idempotent via qbo_sales_receipt_id).
                            try:
                                from dashboard import qbo_sale as _qsale
                                _bcxo2 = _sqlite3.connect(LOG_DB); _bcxo2.row_factory = _sqlite3.Row
                                try:
                                    _bo2 = _bos_orders.find_order_by_external_ref(_bcxo2, bf_inv)
                                    if _bo2:
                                        _qsale.book_sale_on_payment(_bcxo2, dict(_bo2))
                                finally:
                                    _bcxo2.close()
                            except Exception as _bqe:
                                print(f"[biofield] qbo sale booking failed inv={bf_inv}: {_bqe!r}",
                                      flush=True)
                            # Stamp the Stripe PaymentIntent onto the order (mirrors the
                            # non-biofield gate above, which is dead here since biofield
                            # checkout sets metadata customer_id="").
                            if pi_id:
                                try:
                                    _bcxo3 = _sqlite3.connect(LOG_DB); _bcxo3.row_factory = _sqlite3.Row
                                    try:
                                        _bo3 = _bos_orders.find_order_by_external_ref(_bcxo3, bf_inv)
                                        if _bo3:
                                            _bos_orders.set_order_stripe_pi(_bcxo3, _bo3["id"], pi_id)
                                    finally:
                                        _bcxo3.close()
                                except Exception as _bpie:
                                    print(f"[biofield] stripe pi stamp failed inv={bf_inv}: {_bpie!r}",
                                          flush=True)
                    except Exception as _be:
                        print(f"[biofield] return book/stamp failed: {_be!r}", flush=True)

                # ── Single per-kind settlement dispatch (parity with the Stripe webhook) ──
                # Common points/referral (retail/reorder/portal-reorder/subscribe/client/
                # biofield) + kind-specific effects (subscribe -> subscription + group
                # bundle no-op; client -> wallet margin; biofield -> seed + care taster).
                # Every dep is idempotent per order_ref; the pre-existing gating is
                # preserved because paid card orders always carry pi_id and the common
                # settlers no-op without a matching order row.
                _settle_order = None
                if inv:
                    try:
                        _scx0 = _sqlite3.connect(LOG_DB); _scx0.row_factory = _sqlite3.Row
                        try:
                            _fo = _bos_orders.find_order_by_external_ref(_scx0, inv)
                            _settle_order = dict(_fo) if _fo else None
                        finally:
                            _scx0.close()
                    except Exception as _e:
                        print(f"[begin-return] settle order lookup: {_e!r}", flush=True)
                from dashboard import order_settlement as _osx
                _res = _osx.settle_paid_order_effects(
                    kind=_kind, order=_settle_order, md=md, pi_id=pi_id, sid=sid,
                    deps=_SETTLEMENT_DEPS)
                if _res and _res.get("skipped"):
                    _raise_settlement_skip_todo(inv, _res.get("kind"), _res["skipped"])
                # Mark settlement attempted so a Stripe redelivery of the webhook
                # skips re-settling this order (I1 crash-strand close). Best-effort:
                # if this fails, the webhook's own settled_at gate still backfills.
                if inv and _settle_order:
                    try:
                        _mcx = _sqlite3.connect(LOG_DB)
                        try:
                            _bos_orders.mark_order_settled(_mcx, _settle_order["id"])
                        finally:
                            _mcx.close()
                    except Exception as _me:
                        print(f"[begin-return] mark settled: {_me!r}", flush=True)

            # Biofield trial: membership creation is shared with the Stripe webhook so a
            # closed tab still gets fulfilled. Idempotent via biofield_trial_grants.
            if _kind == "biofield_trial":
                _fulfill_biofield_trial(sid)

            # ── Founding reserve: vault card, create pending reservation, comp membership ──
            # Setup-mode ($0) session: payment_status == "no_payment_required" (NOT "paid"),
            # so this block lives OUTSIDE the payment_status == "paid" gate.
            if md.get("kind") == "founding_reserve" and sess.get("setup_intent") and \
                    sess.get("payment_status") in ("paid", "no_payment_required"):
                try:
                    from dashboard import subscriptions as _subs_f, founding as _founding_ret
                    seti = sess.get("setup_intent")
                    si = _sp.get_setup_intent(seti) if seti else {}
                    stripe_cus = si.get("customer") or ""
                    stripe_pm = si.get("payment_method") or ""
                    f_email = md.get("email") or ""
                    f_slug = md.get("slug") or ""
                    stash_key = md.get("stash_key")
                    if stash_key:
                        with sqlite3.connect(LOG_DB) as _scx:
                            _scx.row_factory = sqlite3.Row
                            _sr = _scx.execute(
                                "SELECT items_json, ship_json FROM "
                                "pending_subscriptions WHERE key=?",
                                (stash_key,)).fetchone()
                        items_list = json.loads(_sr["items_json"]) if _sr else []
                        ship_dict = json.loads(_sr["ship_json"]) if _sr else {}
                    else:
                        items_list = json.loads(md.get("items") or "[]")
                        ship_dict = json.loads(md.get("ship") or "{}")
                    # Cap re-check: abort gracefully if founding is no longer open.
                    with sqlite3.connect(LOG_DB) as _cap_cx:
                        _cap_cx.row_factory = sqlite3.Row
                        _subs_f.init_subscriptions_table(_cap_cx)
                        _subs_f.migrate_add_founding_columns(_cap_cx)
                        today_iso = _now_utc().strftime("%Y-%m-%d")
                        _cap_still_open = _founding_ret.is_open(_cap_cx, f_slug, now_iso=today_iso)
                    if not _cap_still_open:
                        print(f"[founding-return] cap hit after payment — skipping reservation for {f_email}",
                              flush=True)
                    else:
                        with sqlite3.connect(LOG_DB) as _fcx:
                            _fcx.row_factory = sqlite3.Row
                            _subs_f.init_subscriptions_table(_fcx)
                            _subs_f.migrate_add_founding_columns(_fcx)
                            _subs_f.create_founding_reservation(
                                _fcx, email=f_email, stripe_customer_id=stripe_cus,
                                stripe_payment_method_id=stripe_pm, items=items_list,
                                ship_address=ship_dict, founding_slug=f_slug)
                            _grant_membership(_fcx, f_email, 30, "founding")
                            _fcx.commit()
                        _ingest_order(source="founding", external_ref=seti or "",
                                      email=f_email, items=items_list, total_cents=0,
                                      address=ship_dict, channel="retail")
                        # Only now is the reservation real. The nurture sequence
                        # exits on this tag; tagging at POST time would tag people
                        # who merely opened the Stripe page.
                        _tag_founding_reserved(f_email, f_slug)
                        print(f"[founding-return] reservation created for {f_email}", flush=True)
                except Exception as _fe:
                    print(f"[founding-return] reservation failed: {_fe!r}", flush=True)

        except Exception as e:
            print(f"[begin-return] {e!r}", flush=True)
    # Biofield checkouts land on the readiness gate; everything else returns to the funnel.
    if _kind == "biofield":
        return _redir(f"/biofield/ready?paid={paid}")
    if _kind == "biofield_trial":
        return _redir(f"/begin/biofield/{_bt_token}")
    dest = (f"/begin/buy/{slug}?paid={paid}" if slug else f"/begin?paid={paid}")
    return _redir(dest)


# ── Post-buy concierge (consultative upsell) ─────────────────────────────────
_PAIRINGS = _load_json(DATA_DIR / "upsell-pairings.json", default={"pairings": {}})
# pinecone_title -> catalog slug (deterministic in-catalog resolution; avoids the
# "Stress Release" vs "Emotional Stress Release" false match).
_TITLE_TO_SLUG = {(p.get("pinecone_title") or p.get("name")): s
                  for s, p in (_PRODUCTS.get("products") or {}).items()}
_COMPLEMENT_CACHE = {}

# Resolve a remedy by EITHER its catalog name or pinecone_title, HTML-unescaped and
# lowercased — so in-catalog products aren't dropped when name != pinecone_title or
# the title carries entities. pinecone_titles indexed first so they win a collision
# with a different product's name; setdefault = first-wins (don't clobber).
import html as _ihtml  # noqa: E402
_RESOLVE_NAME_INDEX = {}
for _ckey in ("pinecone_title", "name"):
    for _s, _p in (_PRODUCTS.get("products") or {}).items():
        if _p.get("inactive"):
            continue
        _v = _p.get(_ckey)
        if _v:
            _RESOLVE_NAME_INDEX.setdefault(_ihtml.unescape(_v).strip().lower(), _s)

# `aliases` are the spellings a record answers to but is not named after: an E4L scan says
# "BFA"; the catalog says "BFA Big Field Aligner Infoceutical". Indexed LAST with setdefault,
# so an alias can never shadow a real product's name or pinecone_title. Inactive records are
# skipped, exactly as above.
for _s, _p in (_PRODUCTS.get("products") or {}).items():
    if _p.get("inactive"):
        continue
    for _a in (_p.get("aliases") or []):
        if _a:
            _RESOLVE_NAME_INDEX.setdefault(_ihtml.unescape(_a).strip().lower(), _s)


def _resolve_complement(name):
    """Resolve a complement product NAME to {name, title, url, price, slug, in_catalog}.
    in_catalog (slug present) -> addable to the invoice; else -> open on the store."""
    if not name:
        return None
    key = name.strip().lower()
    if key in _COMPLEMENT_CACHE:
        return _COMPLEMENT_CACHE[key]
    title = url = price = None
    try:
        vec = embed(name)
        res = _idx.query(vector=vec, top_k=1, namespace="specific-formulations", include_metadata=True)
        if res.matches and res.matches[0].score >= 0.83:
            md = res.matches[0].metadata or {}
            title, url, price = md.get("title"), md.get("url"), md.get("price")
    except Exception as e:
        print(f"[concierge] resolve {name}: {e}", flush=True)
    slug = _TITLE_TO_SLUG.get(title) if title else None
    out = {"name": name, "title": title, "url": url, "price": price,
           "slug": slug, "in_catalog": bool(slug)}
    _COMPLEMENT_CACHE[key] = out
    return out


_CONCIERGE_SYSTEM = (
    "You are Dr. Glen Swartwout's warm post-purchase concierge (naturopathic physician, Hilo "
    "Hawai'i). The person just ordered a remedy. Your job is to help them complete their protocol "
    "in a calm, consultative, concierge way: they should feel served and in control, because they "
    "are.\n\n"
    "How you work:\n"
    "- Open by affirming their choice and what it supports. Then ask ONE gentle question at a time "
    "to understand their fuller goal or terrain (energy, sleep, stress, digestion, what else they "
    "are working on).\n"
    "- When it fits, suggest ONE complementary remedy at a time, with a short plain reason it pairs "
    "well with what they bought. Prefer the SUGGESTED COMPLEMENTS provided; you may go beyond them "
    "if the person's needs point elsewhere. Functional Formulations first.\n"
    "- Never pressure. After a suggestion, invite them to add it or keep exploring, and make clear "
    "they can stop anytime and they are all set whenever they choose.\n"
    "- Keep replies short and warm. Do not invent prices or URLs. Sign off warmly as Dr. Glen only "
    "when concluding.\n"
    "- Style: do NOT use em dashes (use commas, colons, or periods). Do NOT use ALL CAPS. Never "
    "prefix anything with the word 'Hook:'."
)

_CONCIERGE_EXTRACT_SYSTEM = (
    "You read a concierge turn. If the assistant is suggesting ONE specific product to add now, "
    "return JSON {\"suggest\": true, \"name\": \"<exact product name>\"}. If it is just asking a "
    "question or chatting with no single specific product offered, return {\"suggest\": false}. "
    "Output ONLY the JSON, no prose, no code fences."
)


@app.route("/begin/concierge/chat", methods=["POST", "OPTIONS"])
def begin_concierge_chat():
    if request.method == "OPTIONS":
        return "", 200
    data = request.get_json() or {}
    query = (data.get("query") or "").strip()
    history = data.get("history") or []
    bought_slug = (data.get("bought_slug") or "").strip()
    bought = _get_product(bought_slug) if bought_slug else None
    session_id = (request.cookies.get("amg_session")
                  or (data.get("session_id") or "").strip() or uuid.uuid4().hex)
    email = (data.get("email") or "").strip().lower()
    _tier, _eff_email = _resolve_chat_tier(request, session_id, email)
    _blocked = _velocity_guard(request, _tier, session_id)
    if _blocked is not None:
        return _blocked
    if not query:
        return jsonify({"error": "Empty query"}), 400

    images_consented = bool(data.get("images_consented"))
    raw_images = data.get("images") or []
    raw_documents = data.get("documents") or []
    attachment_blocks = []
    if raw_images or raw_documents:
        if not images_consented:
            return jsonify({
                "error": "Attachment consent required. Check the consent box "
                         "before attaching documents or images."
            }), 400
        attachment_blocks, _ = _normalize_attachments(raw_images, raw_documents)

    # Pairing priors for what they bought.
    priors = (_PAIRINGS.get("pairings", {}) or {}).get(bought_slug, []) if bought_slug else []
    priors_block = (f"SUGGESTED COMPLEMENTS for {bought['name'] if bought else 'their purchase'} "
                    f"(offer these first, one at a time): {', '.join(priors)}\n\n") if priors else ""

    _ally_ov = ash_ally.ally_overlay(LOG_DB, email)
    _sys_concierge = (_ally_ov + "\n\n" + _CONCIERGE_SYSTEM) if _ally_ov else _CONCIERGE_SYSTEM

    def generate():
        if not is_member(session_id, email):
            yield sse({"gate": True})
            return

        extracted_text = ""
        if attachment_blocks:
            yield sse({"status": f"Reading {len(attachment_blocks)} attachment(s)…"})
            extracted_text = extract_attachment_content(attachment_blocks, query)

        # A little RAG for rationale/benefits (inside generate so the extracted
        # attachment text can sharpen retrieval).
        context_str = ""
        try:
            emb_q = query + " " + (bought["name"] if bought else "")
            if extracted_text:
                emb_q += "\n\nATTACHMENT CONTENT:\n" + extracted_text
            matches = _match_query_namespaces(embed(emb_q))
            context_str, _ = build_context(matches) if matches else ("", [])
        except Exception as e:
            print(f"[concierge] retrieval: {e}", flush=True)

        attach_block = (f"ATTACHMENT CONTENT (from the person's uploaded files; "
                        f"quote specific values when relevant):\n{extracted_text}\n\n"
                        if extracted_text else "")
        messages = []
        for turn in history[-8:]:
            if turn.get("role") in ("user", "assistant") and turn.get("content"):
                messages.append({"role": turn["role"], "content": turn["content"]})
        messages.append({"role": "user", "content":
            f"THEY JUST BOUGHT: {bought['name'] if bought else 'a remedy'}.\n"
            f"{priors_block}{attach_block}"
            f"RETRIEVED SNIPPETS (for rationale/benefits):\n{context_str}\n\n"
            f"MEMBER MESSAGE: {query}\n\n"
            "Continue as the concierge: affirm, ask the single best next question, or suggest ONE "
            "complement with a short why. Keep it warm and brief."})
        full = []
        try:
            with _cl.messages.stream(model="claude-haiku-4-5-20251001", max_tokens=700,
                                     system=_sys_concierge, messages=messages) as stream:
                for tok in stream.text_stream:
                    tok = _strip_dash(tok); full.append(tok); yield sse({"token": tok})
        except Exception as e:
            yield sse({"error": f"Claude error: {e}"}); return
        answer = "".join(full)
        try:
            import threading as _t
            _t.Thread(target=ash_ally.record_turn,
                      args=(LOG_DB, _db_lock, email, query, answer),
                      daemon=True).start()
        except Exception:
            pass

        # Extract a single suggested complement (separate call) and resolve it.
        try:
            convo = "\n".join(f"{m['role']}: {m['content']}" for m in messages[-2:]) + f"\nassistant: {answer}"
            mx = _cl.messages.create(model="claude-haiku-4-5-20251001", max_tokens=120,
                                     system=_CONCIERGE_EXTRACT_SYSTEM,
                                     messages=[{"role": "user", "content": convo[:3500]}])
            txt = mx.content[0].text.strip()
            if txt.startswith("```"):
                txt = txt.split("```", 2)[1]
                if txt.startswith("json\n"): txt = txt[5:]
            obj = json.loads(txt)
            if obj.get("suggest") and obj.get("name"):
                c = _resolve_complement(obj["name"])
                if c and (c["in_catalog"] or c["url"]):
                    yield sse({"suggestion": c})
        except Exception as e:
            print(f"[concierge] extract: {e!r}", flush=True)
        yield sse({"done": True, "session_id": session_id})

    resp = Response(stream_with_context(generate()), content_type="text/event-stream",
                    headers={"Cache-Control": "no-cache", "X-Accel-Buffering": "no"})
    return resp


@app.route("/begin/concierge/add", methods=["POST"])
def begin_concierge_add():
    """Add a catalog complement to the member's pending (unpaid) order. Paid-only:
    there is no live QBO invoice to append to pre-payment, so this appends the line
    to the order's qbo_lines_json and re-totals; the Sales Receipt booked at payment
    reads qbo_lines_json, so that's sufficient -- no QBO call happens here."""
    data = request.get_json(silent=True) or {}
    slug = (data.get("slug") or "").strip()
    invoice_id = (data.get("invoice_id") or "").strip()  # checkout_ref token (frontend compat name)
    _sid = (request.cookies.get("amg_session") or "").strip()
    email = (data.get("email") or "").strip().lower()
    if not is_member(_sid, email):
        return jsonify({"ok": False, "need_optin": True,
                        "error": "Please agree to our Terms to continue."}), 403
    p = _get_product(slug)
    if not p or p.get("info_only"):
        return jsonify({"ok": False, "error": "not an addable catalog product"}), 400
    if not invoice_id:
        return jsonify({"ok": False, "error": "invoice_id required"}), 400
    try:
        qty = max(1, min(int(data.get("qty", 1) or 1), 99))
    except Exception:
        qty = 1
    unit = round(p["price_cents"] / 100.0, 2)
    cx = _sqlite3.connect(LOG_DB)
    cx.row_factory = _sqlite3.Row
    try:
        order = _bos_orders.find_order_by_external_ref(cx, invoice_id)
        if not order:
            return jsonify({"ok": False, "error": "order not found"}), 404
        payload = (json.loads(order["qbo_lines_json"]) if order["qbo_lines_json"]
                   else {"lines": [], "discount_cents": 0, "tax_cents": 0})
        payload.setdefault("lines", [])
        payload["lines"].append({"name": p["name"], "amount": unit, "qty": qty})
        _bos_orders.set_order_qbo_lines(cx, invoice_id, payload)
        new_total = int(order["total_cents"] or 0) + int(round(unit * qty * 100))
        # Re-total via upsert_order (idempotent on source+external_ref). upsert_order
        # unconditionally overwrites email/name/phone/channel/get_cents/discount_cents/
        # points_redeemed_cents/shipping_cents/adjustment_cents on every call, so pass
        # the order's current values through -- otherwise a re-total here would zero
        # them out (see the ff-match-drafts route's warning on this same footgun).
        _bos_orders.upsert_order(
            cx, source=order["source"], external_ref=invoice_id,
            email=order.get("email") or "", name=order.get("name") or "",
            phone=order.get("phone") or "", channel=order.get("channel") or "retail",
            total_cents=new_total, get_cents=order.get("get_cents") or 0,
            discount_cents=order.get("discount_cents") or 0,
            points_redeemed_cents=order.get("points_redeemed_cents") or 0,
            shipping_cents=order.get("shipping_cents") or 0,
            adjustment_cents=order.get("adjustment_cents") or 0)
        return jsonify({"ok": True, "added": p["name"], "qty": qty,
                        "total": round(new_total / 100.0, 2)})
    except Exception as e:
        return jsonify({"ok": False, "error": str(e)}), 500
    finally:
        cx.close()


@app.route("/api/qbo/price-coverage", methods=["GET"])
def qbo_price_coverage():
    """Diagnostic: for each products.json product, query specific-formulations for a
    price (the last scrape stored price_your/price_retail). Shows match title + score
    so we can judge coverage + match quality before populating products.json."""
    if not _qbo_auth_ok():
        return jsonify({"error": "Unauthorized"}), 401
    out = []
    for slug, p in (_PRODUCTS.get("products") or {}).items():
        name = p["name"]
        try:
            vec = embed(name)
            res = _idx.query(vector=vec, top_k=4, namespace="specific-formulations",
                             include_metadata=True)
            best = None
            for m in res.matches:
                md = m.metadata or {}
                price = md.get("price") or md.get("price_your") or md.get("price_retail")
                if price:
                    best = {"match_title": md.get("title", ""), "price": str(price),
                            "score": round(float(m.score), 3)}
                    break
            row = {"slug": slug, "name": name, "found": bool(best)}
            if best:
                row.update(best)
            out.append(row)
        except Exception as e:
            out.append({"slug": slug, "name": name, "error": str(e)[:120]})
    return jsonify({"ok": True, "covered": sum(1 for o in out if o.get("found")),
                    "total": len(out), "products": out})


