def _mint_membership_magic_link(email, ttl_min=MEMBERSHIP_MAGIC_TTL_MIN, *, cx=None):
    """Mint a single-use magic-link token for a membership grant or return-flow.
    Returns the plaintext token; caller is responsible for emailing it.
    Unprompted grant emails must pass MEMBERSHIP_GRANT_TTL_MIN — the default
    only suits a link the member requested moments ago.

    Pass `cx` when you already hold a connection that has written to LOG_DB.
    Opening a second connection against an open write transaction is an
    instant `database is locked`, and joining the caller's transaction also
    means the token and whatever the caller is granting commit together.
    """
    import secrets, json
    plain = secrets.token_urlsafe(32)
    th = _hash_token(plain)
    now_iso = datetime.utcnow().isoformat() + "Z"
    exp_iso = (datetime.utcnow() + timedelta(minutes=int(ttl_min))).isoformat() + "Z"
    row = (th, email, "membership_magic_link", json.dumps({}), now_iso, exp_iso)
    sql = ("INSERT INTO auth_tokens (token_hash, email, purpose, extra, created_at, expires_at) "
           "VALUES (?,?,?,?,?,?)")
    if cx is not None:
        cx.execute(sql, row)          # caller's transaction; caller commits
        return plain
    with _db_lock, sqlite3.connect(LOG_DB) as own_cx:
        own_cx.execute(sql, row)
    return plain


def _mint_coaching_activate_link(email, order_id, ttl_min=60 * 24 * 30):
    """Single-use token (purpose coaching_activate, 30-day TTL) carrying the order id.
    Returns plaintext token; caller emails it (e.g. on the tracking email)."""
    import secrets, json
    plain = secrets.token_urlsafe(32)
    th = _hash_token(plain)
    now_iso = datetime.utcnow().isoformat() + "Z"
    exp_iso = (datetime.utcnow() + timedelta(minutes=int(ttl_min))).isoformat() + "Z"
    with _db_lock, sqlite3.connect(LOG_DB) as cx:
        cx.execute(
            "INSERT INTO auth_tokens (token_hash, email, purpose, extra, created_at, expires_at) "
            "VALUES (?,?,?,?,?,?)",
            (th, email, "coaching_activate", json.dumps({"order_id": order_id}), now_iso, exp_iso))
    return plain


def _validate_membership_magic_link(token):
    """Return the email if the token is a valid (purpose, not consumed, not expired)
    membership_magic_link, else None. Does NOT mark consumed_at; caller decides."""
    if not token:
        return None
    th = _hash_token(token)
    with sqlite3.connect(LOG_DB) as cx:
        row = cx.execute(
            "SELECT email, expires_at, consumed_at FROM auth_tokens "
            "WHERE token_hash=? AND purpose='membership_magic_link'",
            (th,)
        ).fetchone()
    if not row:
        return None
    email, expires_at, consumed_at = row
    if consumed_at:
        return None
    try:
        exp_dt = _parse_utc(expires_at)
        if exp_dt < _now_utc():
            return None
    except Exception:
        return None
    return email


def _mint_gift_note_link(email, *, order_ref, ttl_min=60 * 24 * 30):
    """Single-use token (purpose pif_gift_note, 30-day TTL) carrying the redemption
    order_ref so the submit can attribute the note to the giver + product.
    Returns plaintext token; caller emails it."""
    import secrets, json
    plain = secrets.token_urlsafe(32)
    th = _hash_token(plain)
    now_iso = datetime.utcnow().isoformat() + "Z"
    exp_iso = (datetime.utcnow() + timedelta(minutes=int(ttl_min))).isoformat() + "Z"
    with _db_lock, sqlite3.connect(LOG_DB) as cx:
        cx.execute(
            "INSERT INTO auth_tokens (token_hash, email, purpose, extra, created_at, expires_at) "
            "VALUES (?,?,?,?,?,?)",
            (th, (email or "").strip().lower(), "pif_gift_note",
             json.dumps({"order_ref": order_ref or ""}), now_iso, exp_iso))
    return plain


def _validate_gift_note_link(token):
    """Return {'email', 'order_ref'} for a valid (purpose, unconsumed, unexpired)
    pif_gift_note token, else None. Does NOT consume."""
    if not token:
        return None
    import json
    th = _hash_token(token)
    with sqlite3.connect(LOG_DB) as cx:
        row = cx.execute(
            "SELECT email, extra, expires_at, consumed_at FROM auth_tokens "
            "WHERE token_hash=? AND purpose='pif_gift_note'", (th,)).fetchone()
    if not row:
        return None
    email, extra, expires_at, consumed_at = row
    if consumed_at:
        return None
    try:
        if _parse_utc(expires_at) < _now_utc():
            return None
    except Exception:
        return None
    try:
        order_ref = (json.loads(extra or "{}") or {}).get("order_ref", "")
    except Exception:
        order_ref = ""
    return {"email": email, "order_ref": order_ref}


def _consume_gift_note_token(token):
    """Mark a pif_gift_note token consumed (single-use). Best-effort."""
    if not token:
        return
    th = _hash_token(token)
    now_iso = datetime.utcnow().isoformat() + "Z"
    with _db_lock, sqlite3.connect(LOG_DB) as cx:
        cx.execute("UPDATE auth_tokens SET consumed_at=? WHERE token_hash=? AND purpose='pif_gift_note'",
                   (now_iso, th))


def _mint_lead_magnet_guide_link(email, ttl_min=60 * 24 * LEAD_MAGNET_GUIDE_TTL_DAYS):
    """Token (purpose lead_magnet_guide) for the free-guide download. Returns the
    plaintext token; the caller hands it to the result page. Re-downloadable, so
    it is never consumed. The pending page quotes LEAD_MAGNET_GUIDE_TTL_DAYS, so
    change the lifetime there, not here."""
    import secrets, json as _json
    plain = secrets.token_urlsafe(32)
    th = _hash_token(plain)
    now_iso = datetime.utcnow().isoformat() + "Z"
    exp_iso = (datetime.utcnow() + timedelta(minutes=int(ttl_min))).isoformat() + "Z"
    with _db_lock, sqlite3.connect(LOG_DB) as cx:
        cx.execute(
            "INSERT INTO auth_tokens (token_hash, email, purpose, extra, created_at, expires_at) "
            "VALUES (?,?,?,?,?,?)",
            (th, email, "lead_magnet_guide", _json.dumps({}), now_iso, exp_iso))
    return plain


def _validate_lead_magnet_guide_link(token):
    """Return the email for a valid (not consumed, not expired) lead_magnet_guide
    token, else None. Does not mark consumed (the guide is re-downloadable)."""
    if not token:
        return None
    th = _hash_token(token)
    with sqlite3.connect(LOG_DB) as cx:
        row = cx.execute(
            "SELECT email, expires_at, consumed_at FROM auth_tokens "
            "WHERE token_hash=? AND purpose='lead_magnet_guide'", (th,)).fetchone()
    if not row:
        return None
    email, expires_at, consumed_at = row
    if consumed_at:
        return None
    try:
        if _parse_utc(expires_at) < _now_utc():
            return None
    except Exception:
        return None
    return email


def _grant_membership(cx, email, days, source):
    """Insert a memberships access grant row and return its id.

    Ordering matters. `customers.find_or_create_by_email` calls cx.commit(), so
    anything already written on this connection becomes durable the moment it
    runs. Do the people upsert FIRST: a commit cannot make the grant durable
    ahead of the caller if the grant row does not exist yet.

    Otherwise a caller that fails before its own commit leaves an orphaned
    memberships row behind -- and membership access is read straight off this
    table by email, with no token involved, so an orphan is a free membership.
    """
    import uuid as _uuid
    mid = str(_uuid.uuid4())
    now = datetime.utcnow()
    try:
        from dashboard import customers as _customers
        _customers.find_or_create_by_email(cx, email=email)   # commits
    except Exception as _e:
        print(f"[grant-membership] people upsert skipped: {_e!r}", flush=True)
    # Last write, and nothing below commits: the grant rolls back with the caller.
    cx.execute(
        "INSERT INTO memberships (id, email, granted_at, expires_at, granted_by, source, truly_vip_ref, notes) "
        "VALUES (?,?,?,?,?,?,?,?)",
        (mid, email, now.isoformat() + "Z", (now + timedelta(days=days)).isoformat() + "Z",
         source, source, "", ""))
    _member_join_welcome(cx, email, source)   # does not commit (guard rolls back too)
    return mid


def _grant_prepay_term(cx, email, tier_key):
    """Record a prepaid N-month membership as a day-based access grant (NOT a
    subscriptions row). A grant-only member reads as category 'none' -> _is_paid_member
    True, so they get member/volume pricing for the whole term; and because there is no
    subscriptions row, the charge cron can never bill it -> a prepaid term can never
    silently auto-renew. It expires cleanly; renewal is a prompt, not a charge.
    Returns the grant id, or None for an unknown tier."""
    from datetime import date as _date
    tier = _prepay.get_tier(tier_key)
    if not tier:
        return None
    email = (email or "").strip().lower()
    days = _prepay.term_days(_date.today().isoformat(), tier["months"])
    mid = _grant_membership(cx, email, days, f"prepay_{tier_key}")
    try:
        import json as _json
        cx.execute(
            "INSERT INTO journey_events "
            "(ts, session_id, email, trigger, detail, rung_before, rung_after) "
            "VALUES (?, ?, ?, 'prepay_term_granted', ?, '', '')",
            (datetime.utcnow().isoformat() + "Z", "", email,
             _json.dumps({"tier_key": tier_key, "months": tier["months"],
                          "price_cents": tier["price_cents"], "days": days,
                          "membership_id": mid})))
    except Exception as _e:
        print(f"[prepay] journey_events insert failed: {_e!r}", flush=True)
    return mid


MEMBERSHIP_GRANT_GRACE_DAYS = 3


def _extend_membership_grant(cx, email, until_iso, source="membership_renewal"):
    """Ensure the member's access grant reaches at least `until_iso`. The access
    gate reads MAX(expires_at), so we insert a row only when no existing grant
    already reaches that far (monotonic / idempotent — never shortens access)."""
    if not (email and until_iso):
        return
    row = cx.execute("SELECT MAX(expires_at) FROM memberships WHERE email=?", (email,)).fetchone()
    have = row[0] if row else None
    if have:
        try:
            if datetime.fromisoformat(have.rstrip("Z")) >= datetime.fromisoformat(until_iso.rstrip("Z")):
                return
        except Exception:
            if have >= until_iso:   # fall back to string compare on unparseable timestamps
                return
    import uuid as _uuid
    cx.execute(
        "INSERT INTO memberships (id, email, granted_at, expires_at, granted_by, source, truly_vip_ref, notes) "
        "VALUES (?,?,?,?,?,?,?,?)",
        (str(_uuid.uuid4()), email, datetime.utcnow().isoformat() + "Z", until_iso, source, source, "", ""))


def _maybe_extend_founding_membership(cx, sub, updated):
    """A founding product autoship keeps its comp membership alive: on each
    successful charge, extend the grant to next_charge_date + grace. No-op for
    non-founding subs."""
    if not sub.get("founding"):
        return
    try:
        if updated and updated.get("next_charge_date"):
            until = (datetime.fromisoformat(updated["next_charge_date"])
                     + timedelta(days=MEMBERSHIP_GRANT_GRACE_DAYS)).isoformat() + "Z"
            _extend_membership_grant(cx, sub["email"], until, "founding")
    except Exception as _ge:
        print(f"[sub-cron] founding grant-extend sub={sub.get('id')}: {_ge!r}", flush=True)


def _studio_credit_grant_and_notify(cx, email, days):
    """Grant a studio-credit comp membership and log the journey event, all on
    the caller's transaction. Returns {membership_id, magic_link_url, notify}.

    `notify` is a zero-arg callable that sends the grant email. It is NOT called
    here. The email carries a magic link, so sending it before the caller
    commits means a later failure rolls the link away while the member is
    already holding the URL. The caller invokes notify() after its commit.

    Nothing here commits, for the same reason: the grant, the token, the journey
    event and the caller's own writes must land in one transaction or none.
    """
    import json as _json
    email = (email or "").strip().lower()
    mid = _grant_membership(cx, email, days, "studio_credit")
    # Same connection: _grant_membership just opened a write transaction on it.
    plain = _mint_membership_magic_link(email, ttl_min=MEMBERSHIP_GRANT_TTL_MIN, cx=cx)
    try:
        base = request.host_url.rstrip("/")
    except Exception:
        base = (PUBLIC_BASE_URL or "").rstrip("/")
    magic_link_url = f"{base}/coaching/auth/{plain}"
    subject = "Your free month of Remedy Match coaching is open"
    body = (
        f"Hi,\n\n"
        f"Thanks for getting the studio coaching app. As a thank-you, your Remedy Match "
        f"coaching membership is open free for the next {days} days.\n\n"
        f"Click here to sign in:\n{magic_link_url}\n\n"
        f"You'll land in your member dashboard with the AI agent loaded for your context.\n\n"
        f"---\n"
        f"Remedy Match LLC, 351 Wailuku Drive, Hilo, Hawai'i 96720 USA\n"
    )
    def _notify():
        """Called by the caller once its transaction has committed. A bounced
        send must not undo a granted membership -- the member can always ask for
        a fresh link -- so failures are logged, not raised."""
        try:
            _send_inquiry_email(to_email=email, subject=subject, body=body,
                                reply_to=RM_COACHING_REPLY_EMAIL)
        except Exception as e:
            print(f"[studio-credit] email send failed for {email}: {e!r}", flush=True)

    try:
        cx.execute(
            "INSERT INTO journey_events "
            "(ts, session_id, email, trigger, detail, rung_before, rung_after) "
            "VALUES (?, ?, ?, 'membership_granted', ?, '', '')",
            (datetime.utcnow().isoformat() + "Z", "", email,
             _json.dumps({"source": "studio_credit", "days": days, "membership_id": mid})))
    except Exception as e:
        print(f"[studio-credit] journey_events insert failed: {e!r}", flush=True)
    return {"membership_id": mid, "magic_link_url": magic_link_url, "notify": _notify}


def _active_membership_for_email(email):
    """Return the active membership row as a dict (with derived days_remaining), or None."""
    if not email:
        return None
    with sqlite3.connect(LOG_DB) as cx:
        cx.row_factory = sqlite3.Row
        row = cx.execute(
            "SELECT * FROM memberships WHERE email=? AND expires_at > ? "
            "ORDER BY expires_at DESC LIMIT 1",
            (email, datetime.utcnow().isoformat() + "Z")
        ).fetchone()
    if not row:
        return None
    d = dict(row)
    try:
        exp_dt = _parse_utc(d["expires_at"])
        d["days_remaining"] = max(0, (exp_dt - _now_utc()).days)
    except Exception:
        d["days_remaining"] = 0
    return d


def _portal_paid_gate_enabled():
    """Flag: gate portal biofield content behind payment (blur unpaid reveals).
    Default OFF so merging is safe — flip PORTAL_PAID_GATE_ENABLED=1 only after
    confirming every legitimately-paid Biofield client is recorded (has a
    biofield_readiness paid_at or an active membership), else they'd be blurred."""
    return os.environ.get("PORTAL_PAID_GATE_ENABLED", "").strip().lower() in ("1", "true", "yes", "on")


def _family_plan_enabled():
    """Flag: a caregiver's Family Plan entitles their whole consented household.
    Default OFF — when off, the paywall asks only whether THIS email paid, which
    is byte-identical to pre-plan behavior."""
    return (os.environ.get("FAMILY_PLAN_ENABLED", "") or "").strip().lower() in (
        "1", "true", "yes", "on")


def _portal_biofield_unlocked(email):
    """True when a portal biofield report's remedies/audio/PDF may un-blur: the
    client has PAID for it — a paid Biofield Analysis on record, OR an active
    membership (the $1 lifetime-access unlock), OR a caregiver's Family Plan
    covers them. A free E4L reveal published to the portal stays blurred until
    they pay — same gate as the /begin reveal funnel.
    Fail-closed (blurred) on any error. When the gate flag is off, everyone is
    treated as unlocked (pre-gate behavior).

    The Family Plan branch is what lets a household member with no payment of
    their own — a pet, a child — un-blur under the caregiver who bought the plan.
    Asking only about `email` blurred Sasha's report on Karin's own screen."""
    if not _portal_paid_gate_enabled():
        return True
    email = (email or "").strip().lower()
    if not email:
        return False
    try:
        if _has_paid_biofield(email):
            return True
        if _active_membership_for_email(email):
            return True
        if _family_plan_enabled():
            from dashboard import family_plan as _fp
            with sqlite3.connect(LOG_DB) as cx:
                cx.row_factory = sqlite3.Row
                _fp.init_family_plan_table(cx)
                return bool(_fp.covers(cx, email))
        return False
    except Exception:
        return False


def _biofield_audit_row(email, confirmed, scan_date, source, name=""):
    """One audit row: is this client's confirmed portal report un-blurred now?
    blurred_now = has a confirmed report but is NOT recorded as paid (no paid
    Biofield Analysis, no active membership) — the ones to eyeball."""
    email = (email or "").strip().lower()
    try:
        paid_bf = _has_paid_biofield(email)
    except Exception:
        paid_bf = False
    try:
        member = bool(_active_membership_for_email(email))
    except Exception:
        member = False
    unlocked = paid_bf or member
    return {"email": email, "name": name or "", "scan_date": scan_date, "source": source,
            "confirmed": bool(confirmed), "paid_biofield": paid_bf, "member": member,
            "unlocked": unlocked, "blurred_now": bool(confirmed and not unlocked)}


@app.route("/api/console/biofield-portal/audit", methods=["GET"])
def api_console_biofield_portal_audit():
    """Owner audit for the portal paywall: every client with a CONFIRMED portal
    biofield report who is NOT recorded as paid (so the gate now blurs them).
    Use it to catch legitimately-paid Biofield-Analysis clients whose payment
    isn't on record. Read-only."""
    if not _portal_console_ok():
        return jsonify({"error": "unauthorized"}), 401
    from dashboard import portal_biofield_reports as _pbr
    from dashboard import client_portal as _cp
    import json as _json
    rows, seen = [], set()
    with sqlite3.connect(LOG_DB) as cx:
        cx.row_factory = sqlite3.Row
        _pbr.init_table(cx)
        _cp.init_client_portal_table(cx)
        names = {(r["email"] or "").strip().lower(): (r["name"] or "")
                 for r in cx.execute("SELECT email, name FROM client_portals").fetchall()}
        # 1) per-scan reports — the client sees the LATEST, so its status drives blur.
        for r in cx.execute("SELECT DISTINCT lower(email) e FROM portal_biofield_reports "
                            "WHERE email IS NOT NULL AND email!=''").fetchall():
            em = r["e"]
            rep = _pbr.latest_report(cx, em) or {}
            confirmed = (rep.get("status") or "confirmed") == "confirmed"
            rows.append(_biofield_audit_row(em, confirmed, rep.get("scan_date"),
                                            "report", names.get(em, "")))
            seen.add(em)
        # 2) legacy single-report portals (content on client_portals, no per-scan rows).
        for r in cx.execute("SELECT lower(email) e, content_json FROM client_portals").fetchall():
            em = r["e"]
            if not em or em in seen:
                continue
            try:
                content = _json.loads(r["content_json"] or "{}")
            except Exception:
                content = {}
            if not (content.get("layers") or content.get("greeting")):
                continue  # no biofield content on this portal
            confirmed = (content.get("biofield_status") or "confirmed") == "confirmed"
            rows.append(_biofield_audit_row(em, confirmed, None, "legacy", names.get(em, "")))
            seen.add(em)
    blurred = sorted((x for x in rows if x["blurred_now"]), key=lambda x: x["email"])
    return jsonify({"ok": True, "gate_on": _portal_paid_gate_enabled(),
                    "reports_total": len(rows), "blurred_count": len(blurred),
                    "blurred": blurred})


@app.route("/api/console/biofield-portal/mark-paid", methods=["POST"])
def api_console_biofield_mark_paid():
    """Owner: record a paid Biofield Analysis for an email (biofield_readiness.
    paid_at) so _has_paid_biofield -> True and their portal report un-blurs. Used
    to fix legitimately-paid clients the audit flagged. Idempotent (seed_paid
    COALESCEs — never overwrites an existing payment)."""
    if not _portal_console_ok():
        return jsonify({"error": "unauthorized"}), 401
    body = request.get_json(silent=True) or {}
    email = (body.get("email") or "").strip().lower()
    if not email or "@" not in email:
        return jsonify({"ok": False, "error": "valid email required"}), 400
    from dashboard import biofield_store as _bf
    with _db_lock, sqlite3.connect(LOG_DB) as cx:
        _bf.init_table(cx)
        _bf.seed_paid(cx, email, via=(body.get("via") or "owner_console"),
                      order_ref=(body.get("order_ref") or "manual-unblur"))
    return jsonify({"ok": True, "email": email, "paid_biofield": _has_paid_biofield(email),
                    "unlocked": _portal_biofield_unlocked(email)})


@app.route("/api/console/client-scans/sync", methods=["POST"])
def api_console_client_scans_sync():
    """Owner sync: upsert a client's (or a batch of clients') E4L scan-date manifest into
    client_scans (populated by the local e4l-scan-manifest-push, since prod can't read e4l.db)."""
    if not _portal_console_ok():
        return jsonify({"error": "unauthorized"}), 401
    from dashboard import client_scans as _cs
    data = request.get_json(silent=True) or {}
    items = data.get("batch") or [{"email": data.get("email"), "scans": data.get("scans")}]
    total = 0
    new_rows = []            # ONLY genuinely newly-inserted scans this sync (not re-pushes)
    with _db_lock, sqlite3.connect(LOG_DB) as cx:
        _cs.init_client_scans_table(cx)
        for it in items:
            try:
                if not isinstance(it, dict):
                    continue
                _new = _cs.upsert_scans(cx, it.get("email"), it.get("scans") or [])
                new_rows.extend(_new); total += len(_new)
            except Exception as _e:
                print(f"[client-scans-sync] skipped bad item: {_e!r}", flush=True)
    # New-scan invite: keyed on the rows actually inserted THIS sync — never the global
    # notified_at backlog. A re-pushed manifest yields no new rows, so flipping the flag on
    # (with a fully-backfilled client_scans, per A) cannot mass-email the history.
    if _scan_request_enabled() and new_rows:
        try:
            from dashboard import analysis_quota as _aq
            from dashboard import notify_state as _ns2
            from dashboard import email_suppression as _es
            with _db_lock, sqlite3.connect(LOG_DB) as cx:
                _cs.init_client_scans_table(cx); _aq.init_analysis_quota_table(cx)
                for row in new_rows:
                    em, sd, sid = row["email"], row["scan_date"], row["scan_id"]
                    try:
                        # anti-nag: only when the owner can actually act on it
                        can_act = _is_paid_member(em) or not _aq.claimed_this_month(cx, em)
                        if can_act and not _es.is_suppressed(cx, em):
                            # lookup-only: the stable raw token stashed by client_portal
                            # (upsert_portal/ensure_token) in portal_notify_state. Never
                            # mints a portal for an email that doesn't have one.
                            _stt = _ns2.get_state(cx, em)
                            tok = _stt.get("portal_token")
                            if tok and _stt.get("opt_status") != "out":   # respect notify_state opt-out
                                _send_new_scan_email(em, sd, sid, tok)
                    except Exception as _e:
                        print(f"[new-scan-email] {em}: {_e!r}", flush=True)
                    _cs.mark_notified(cx, em, sd)   # mark regardless, so we never re-nag
        except Exception as _e:
            print(f"[new-scan-email] {_e!r}", flush=True)
    return jsonify({"ok": True, "upserted": total})


