def _send_new_scan_email(email, scan_date, scan_id, token):
    """New-scan invite: a one-click analyze link + the client's limit + upgrade path. Best-effort.
    Cc'd (private separate copy) to consented+subscribed caregivers via household.cc_recipients_for."""
    base = "https://illtowell.com"
    link = f"{base}/portal/{token}/analyze?scan_id={scan_id}&scan_date={scan_date}"
    subj = "Your new biofield scan is ready to analyze"
    body = (f"A new biofield scan ({scan_date}) is on file for you.\n\n"
            f"Would you like it analyzed? Free members get one analysis per month; members get unlimited.\n\n"
            f"Analyze this scan: {link}\n\nUpgrade for unlimited: {base}/prepay")
    recips = [email]
    try:
        from dashboard import household as _hh
        with sqlite3.connect(LOG_DB) as _cxh:
            _hh.init_household_tables(_cxh)
            recips += _hh.cc_recipients_for(_cxh, email)   # caregivers get their own copy
    except Exception:
        pass
    for to in dict.fromkeys(recips):   # de-dup, private separate copies
        try:
            try:
                from dashboard import email_suppression as _es
                with sqlite3.connect(LOG_DB) as _cxsup:
                    if _es.is_suppressed(_cxsup, to):
                        continue
            except Exception as _se:
                print(f"[new-scan-email] suppression check failed for {to}: {_se!r}", flush=True)
            _send_inquiry_email(to, subj, body)
        except Exception as _e:
            print(f"[new-scan-email] to {to}: {_e!r}", flush=True)


def membership_category(email):
    """Classify a member into 'none' | 'trial' | 'full' | 'paused' (see
    dashboard.subscriptions.category_for). 'full' is the gate for paid-member
    volume pricing; 'trial' (the $1-trial free first month, order_count=0) pays
    regular and accrues the missed discount as upgrade credit. Fail-closed to
    'none' so a lookup hiccup never grants the discount."""
    email = (email or "").strip().lower()
    if not email:
        return "none"
    try:
        from dashboard import subscriptions as _subs
        with sqlite3.connect(LOG_DB) as cx:
            cx.row_factory = sqlite3.Row
            cat = _subs.category_for(cx, email)
            if cat == "none":
                # Model #2: a $1 biofield DEPOSIT buyer holds only a day-based grant (no
                # subscription row), so category_for returns 'none'. Their Biofield
                # Analysis is unlocked, but the member DISCOUNT must be withheld until
                # they activate -> classify as 'trial'. Other grant-only members
                # (founding / studio_credit / coaching) intentionally stay 'none' (paid),
                # so this keys narrowly on the biofield deposit source.
                #
                # BUT only while the deposit is their ONLY active grant. Once they convert
                # (prepay term / founding / studio grant added), the deposit grant lingers
                # for the rest of its ~90-day window and must NOT keep withholding the
                # discount from a now-paying member — so require no OTHER active grant.
                now_iso = datetime.utcnow().isoformat() + "Z"
                deposit = cx.execute(
                    "SELECT 1 FROM memberships WHERE email=? AND expires_at > ? "
                    "AND source='biofield_trial' LIMIT 1", (email, now_iso)).fetchone()
                if deposit:
                    other_paid = cx.execute(
                        "SELECT 1 FROM memberships WHERE email=? AND expires_at > ? "
                        "AND source!='biofield_trial' LIMIT 1", (email, now_iso)).fetchone()
                    if not other_paid:
                        return "trial"
            return cat
    except Exception:
        return "none"


def _membership_active_at(cx, email, when_iso):
    """True iff a memberships row's paid span [granted_at, expires_at] covers `when_iso`.
    expires_at is a monotonic paid-through high-water mark (Phase 2A), so this
    reconstructs 'was paid-through on date D'. NULL expires_at = open-ended grant."""
    if not (email and when_iso):
        return False
    try:
        when = _parse_utc(when_iso)
    except Exception:
        return False
    for granted_at, expires_at in cx.execute(
            "SELECT granted_at, expires_at FROM memberships WHERE email=?", (email,)).fetchall():
        try:
            g = _parse_utc(granted_at)
        except Exception:
            continue
        if g > when:
            continue
        if not expires_at:
            return True
        try:
            if _parse_utc(expires_at) >= when:
                return True
        except Exception:
            continue
    return False


def _find_qualifying_order_for_coaching(cx, email):
    """Most-recent remedy-program order for `email` that is eligible (member active
    at its date) and has not already opened a coaching window. Returns order id or None."""
    if not email:
        return None
    placeholders = ",".join("?" * len(_coaching.QUALIFYING_SOURCES))
    rows = cx.execute(
        f"SELECT id, created_at FROM orders WHERE email=? AND status!='cancelled' "
        f"AND source IN ({placeholders}) ORDER BY datetime(created_at) DESC",
        (email, *sorted(_coaching.QUALIFYING_SOURCES))).fetchall()
    for r in rows:
        oid = r[0] if not isinstance(r, sqlite3.Row) else r["id"]
        created = r[1] if not isinstance(r, sqlite3.Row) else r["created_at"]
        if _coaching.window_for_order(cx, oid):
            continue
        if _membership_active_at(cx, email, created):
            return oid
    return None


def _open_coaching_for_order(cx, email, order_id, source, window_source="self_serve"):
    """Validate + open a coaching window for one remedy-program order.
    window_source labels HOW it was activated (self_serve / delivery / admin).
    Returns {ok, ...}: success -> created+ends_at; failure -> reason (+offer_99 if ineligible)."""
    if (source or "") not in _coaching.QUALIFYING_SOURCES:
        return {"ok": False, "reason": "not_qualifying"}
    row = cx.execute("SELECT created_at FROM orders WHERE id=? AND email=?",
                     (order_id, email)).fetchone()
    if not row:
        return {"ok": False, "reason": "not_found"}
    created_at = row[0] if not isinstance(row, sqlite3.Row) else row["created_at"]
    if not _membership_active_at(cx, email, created_at):
        return {"ok": False, "reason": "ineligible", "offer_99": True}
    res = _coaching.open_window(cx, email=email, order_id=order_id,
                                days=_coaching.WINDOW_DAYS, source=window_source)
    return {"ok": True, "created": res["created"], "ends_at": res["window"]["ends_at"]}


def _activate_coaching_for_shipment(cx, shipment, *, delivered_at):
    """Idempotent: on first delivery signal for a shipment, mark delivered_at and
    open a coaching window (source='delivery') for EVERY qualifying+eligible member
    order. A combined household shipment shares one tracking number across several
    member orders, so each client gets their own window (single shipments = 1
    member = unchanged behavior). open_window is no-stacking/one-per-order, so this
    never double-opens. Returns {ok, opened, members:[per-order result]}."""
    already = shipment["delivered_at"] if isinstance(shipment, sqlite3.Row) else shipment.get("delivered_at")
    if already:
        return {"skipped": "already_processed"}
    sid = shipment["id"] if isinstance(shipment, sqlite3.Row) else shipment.get("id")
    uuid = shipment["order_uuid"] if isinstance(shipment, sqlite3.Row) else shipment.get("order_uuid")
    _tracking.mark_shipment_delivered(cx, sid, delivered_at)
    members = _coaching.shipment_member_orders(cx, sid, uuid)
    if not members:
        return {"ok": False, "reason": "unresolved"}
    # resolved_email is the shipment's single parsed recipient — only a safe
    # fallback when there's exactly one member (never cross-assign it in a
    # multi-client household).
    resolved_email = (shipment["resolved_email"] if isinstance(shipment, sqlite3.Row)
                      else shipment.get("resolved_email"))
    single = len(members) == 1
    opened, results = 0, []
    for m in members:
        email = m["email"] or ((resolved_email or "").strip().lower() if single else "") or None
        if not email:
            results.append({"order_id": m["id"], "ok": False, "reason": "no_email"})
            continue
        res = _open_coaching_for_order(cx, email, m["id"], m["source"], window_source="delivery")
        results.append({"order_id": m["id"], **res})
        if res.get("ok"):
            opened += 1
    if opened:
        cx.execute("UPDATE shipments SET coaching_opened=1 WHERE id=?", (sid,))
        cx.commit()
    top = {"ok": opened > 0, "opened": opened, "members": results}
    # Surface a single opened window's ends_at so the per-order "Mark delivered"
    # message ("coaching month started through …") still renders a date. On a
    # multi-member household there's no single date to show.
    succeeded = [r for r in results if r.get("ok") and r.get("ends_at")]
    if len(succeeded) == 1:
        top["ends_at"] = succeeded[0]["ends_at"]
    return top


def _activate_coaching_by_order(cx, order_id):
    """Manual path: activate coaching for an order (resolve its shipment if any)."""
    order = cx.execute("SELECT id, email, source, shipment_id FROM orders WHERE id=?",
                       (order_id,)).fetchone()
    if not order:
        return {"ok": False, "reason": "not_found"}
    now_iso = datetime.utcnow().isoformat() + "Z"
    if order["shipment_id"]:
        sh = cx.execute("SELECT * FROM shipments WHERE id=?", (order["shipment_id"],)).fetchone()
        if sh:
            return _activate_coaching_for_shipment(cx, sh, delivered_at=now_iso)
    email = (order["email"] or "").strip().lower()
    if not email:
        return {"ok": False, "reason": "unresolved"}
    return _open_coaching_for_order(cx, email, order["id"], order["source"], window_source="delivery")


def _register_mark_delivered_action():
    from dashboard.actions import action as _act, get_action as _get, LOW_WRITE
    from dashboard import rbac as _r
    if _get("orders.mark_delivered"):
        return

    def _mark_delivered_exec(params, ctx):
        cx = (ctx or {}).get("cx") or (params or {}).get("cx")
        if cx is None:
            raise ValueError("no db connection")
        oid = int(params["order_id"])
        if not _bos_orders.set_order_status(cx, oid, "delivered"):
            raise ValueError(f"order #{oid} not found")
        res = _activate_coaching_by_order(cx, oid)
        if res.get("ok"):
            msg = f"Order #{oid} delivered — coaching month started (through {res.get('ends_at', '')[:10]})."
        elif res.get("reason") == "ineligible":
            msg = f"Order #{oid} delivered. Coaching not opened — member wasn't active in the order's month."
        else:
            msg = f"Order #{oid} delivered. Coaching not opened ({res.get('reason', 'n/a')})."
        return {"order_id": oid, "status": "delivered", "coaching": res, "message": msg}

    _act(key="orders.mark_delivered", module="orders", title="Mark delivered",
         description="Mark an order delivered and start the member's coaching month.",
         risk_tier=LOW_WRITE, permission=(_r.OWNER, _r.OPS, _r.VA))(_mark_delivered_exec)


_register_mark_delivered_action()


def _activate_coaching_by_tracking(tracking_number):
    """Webhook path: open its own connection, resolve shipment by tracking number, activate."""
    now_iso = datetime.utcnow().isoformat() + "Z"
    with _db_lock, sqlite3.connect(LOG_DB) as cx:
        cx.row_factory = sqlite3.Row
        sh = _tracking.shipment_by_tracking(cx, tracking_number)
        if not sh:
            return {"ok": False, "reason": "unknown_tracking"}
        return _activate_coaching_for_shipment(cx, sh, delivered_at=now_iso)


def _member_context_for_email(email, *, query_log_n=5):
    """Aggregate the member's recent context for the /chat agent overlay.

    Returns a dict with keys: intake_summary, recent_inquiries, recent_queries,
    voice_scan_summary.  All keys are always present; empty when no data found.
    """
    out = {
        "intake_summary": "",
        "recent_inquiries": [],
        "recent_queries": [],
        "voice_scan_summary": "",
    }
    if not email:
        return out

    # Intake from inbound_leads (most recent scoreapp / practice-better / concierge)
    try:
        with sqlite3.connect(LOG_DB) as cx:
            row = cx.execute(
                "SELECT first_name, raw_json FROM inbound_leads "
                "WHERE email=? AND source IN ('scoreapp','practice-better','concierge') "
                "ORDER BY id DESC LIMIT 1",
                (email,)
            ).fetchone()
            if row:
                first_name, raw_json_str = row
                parts = []
                if first_name:
                    parts.append(f"first name: {first_name}")
                try:
                    payload = json.loads(raw_json_str or "{}")
                    data = payload.get("data", payload) or {}
                    score = (data.get("total_score") or {}).get("percent") or data.get("score")
                    if score:
                        parts.append(f"assessment score: {score}%")
                    qs = data.get("quiz_questions") or []
                    for q in qs[:6]:
                        qt = (q.get("question") or "").strip()
                        ans = ", ".join(
                            (a.get("answer") or "").strip()
                            for a in (q.get("answers") or [])
                            if a.get("answer")
                        )
                        if qt and ans:
                            parts.append(f"  {qt}: {ans}")
                except Exception:
                    pass
                out["intake_summary"] = "\n".join(parts)
    except Exception as e:
        print(f"[member-context] intake fetch failed: {e!r}", flush=True)

    # Recent inquiries
    try:
        with sqlite3.connect(LOG_DB) as cx:
            cx.row_factory = sqlite3.Row
            for r in cx.execute(
                "SELECT main_challenge, main_goal, created_at FROM inquiries "
                "WHERE client_email=? ORDER BY created_at DESC LIMIT 3",
                (email,)
            ).fetchall():
                out["recent_inquiries"].append(dict(r))
    except Exception as e:
        print(f"[member-context] inquiries fetch failed: {e!r}", flush=True)

    # Recent queries. Production table uses 'query' column; test table uses
    # 'question'.  Try 'question' first; fall back to 'query' on OperationalError.
    try:
        with sqlite3.connect(LOG_DB) as cx:
            cx.row_factory = sqlite3.Row
            try:
                rows = cx.execute(
                    "SELECT question, ts FROM query_log WHERE email=? "
                    "ORDER BY id DESC LIMIT ?",
                    (email, int(query_log_n))
                ).fetchall()
                out["recent_queries"] = [{"question": r["question"], "ts": r["ts"]}
                                         for r in rows]
            except Exception:
                # Production table uses 'query' column; normalise to 'question' key
                rows = cx.execute(
                    "SELECT query, ts FROM query_log WHERE email=? "
                    "ORDER BY id DESC LIMIT ?",
                    (email, int(query_log_n))
                ).fetchall()
                out["recent_queries"] = [{"question": r["query"], "ts": r["ts"]}
                                         for r in rows]
    except Exception as e:
        print(f"[member-context] query_log fetch failed: {e!r}", flush=True)

    # Voice scan from Pinecone (best-effort; skipped if client not available)
    try:
        import pinecone  # noqa: F401
        # Locate the existing Pinecone client and e4l-scans namespace.
        # If unavailable (e.g. test environment), silently skip.
        pass
    except Exception:
        pass

    return out


def _format_member_context_block(member, ctx):
    """Format the member context dict into a compact human-readable block for
    injection into the /chat system prompt."""
    lines = ["===== MEMBER CONTEXT (active coaching member) ====="]
    if member and member.get("days_remaining") is not None:
        lines.append(f"Days remaining in current 30-day window: {member['days_remaining']}.")
    if ctx.get("intake_summary"):
        lines.append("Intake:")
        lines.append(ctx["intake_summary"])
    if ctx.get("recent_inquiries"):
        lines.append("Recent inquiries:")
        for r in ctx["recent_inquiries"]:
            lines.append(
                f"  challenge: {r.get('main_challenge', '')}; "
                f"goal: {r.get('main_goal', '')}"
            )
    if ctx.get("recent_queries"):
        lines.append("Recent questions:")
        for r in ctx["recent_queries"]:
            q = (r.get("question") or "").strip()
            if q:
                lines.append(f"  - {q}")
    if ctx.get("voice_scan_summary"):
        lines.append(f"Voice scan summary: {ctx['voice_scan_summary']}")
    lines.append("===== END MEMBER CONTEXT =====")
    return "\n".join(lines)


@app.route("/api/referral-sources", methods=["GET"])
def get_referral_sources():
    if CONSOLE_SECRET:
        key = request.headers.get("X-Console-Key", "") or request.args.get("key", "")
        if key != CONSOLE_SECRET and not _owner_token_ok(key):
            return jsonify({"error": "Unauthorized"}), 401
    with sqlite3.connect(LOG_DB) as cx:
        rows = cx.execute("""
            SELECT id, created_at, name, slug, description, utm_source, utm_medium, utm_campaign, active
            FROM referral_sources ORDER BY name ASC
        """).fetchall()
    cols = ["id","created_at","name","slug","description","utm_source","utm_medium","utm_campaign","active"]
    return jsonify({"sources": [dict(zip(cols, r)) for r in rows]})


@app.route("/api/referral-sources", methods=["POST"])
def post_referral_source():
    if CONSOLE_SECRET:
        key = request.headers.get("X-Console-Key", "") or request.args.get("key", "")
        if key != CONSOLE_SECRET and not _owner_token_ok(key):
            return jsonify({"error": "Unauthorized"}), 401
    data = request.get_json(force=True) or {}
    name     = (data.get("name") or "").strip()
    slug     = re.sub(r"[^a-z0-9]+", "-", (data.get("slug") or name).lower()).strip("-")
    desc     = (data.get("description") or "").strip()
    utm_src  = (data.get("utm_source") or slug).strip()
    utm_med  = (data.get("utm_medium") or "referral").strip()
    utm_camp = (data.get("utm_campaign") or "scoreapp-quiz").strip()
    if not name or not slug:
        return jsonify({"error": "name required"}), 400
    ts = datetime.now(timezone.utc).isoformat()
    try:
        with _db_lock, sqlite3.connect(LOG_DB) as cx:
            cx.execute("""
                INSERT INTO referral_sources (created_at, name, slug, description, utm_source, utm_medium, utm_campaign)
                VALUES (?,?,?,?,?,?,?)
            """, (ts, name, slug, desc, utm_src, utm_med, utm_camp))
            cx.commit()
    except sqlite3.IntegrityError:
        return jsonify({"error": f"slug '{slug}' already exists"}), 409
    return jsonify({"ok": True, "slug": slug,
                    "tracking_url": f"{QUIZ_URL}?ref={slug}"}), 201


@app.route("/api/referrals", methods=["GET"])
def get_referrals():
    if CONSOLE_SECRET:
        key = request.headers.get("X-Console-Key", "") or request.args.get("key", "")
        if key != CONSOLE_SECRET and not _owner_token_ok(key):
            return jsonify({"error": "Unauthorized"}), 401
    # Stats per utm_source
    with sqlite3.connect(LOG_DB) as cx:
        stats = cx.execute("""
            SELECT utm_source,
                   COUNT(*) as total,
                   MAX(received_at) as last_lead
            FROM referral_events
            GROUP BY utm_source
            ORDER BY total DESC
        """).fetchall()
        recent = cx.execute("""
            SELECT received_at, utm_source, utm_medium, utm_campaign,
                   first_name, last_name, email, quiz_score
            FROM referral_events
            ORDER BY received_at DESC LIMIT 50
        """).fetchall()
    stat_list = [{"utm_source": r[0], "total": r[1], "last_lead": r[2]} for r in stats]
    recent_list = [{"received_at": r[0], "utm_source": r[1], "utm_medium": r[2],
                    "utm_campaign": r[3], "name": f"{r[4] or ''} {r[5] or ''}".strip(),
                    "email": r[6], "quiz_score": r[7]} for r in recent]
    return jsonify({"stats": stat_list, "recent": recent_list})


