@app.route("/api/console/handoffs", methods=["GET"])
def api_console_handoffs():
    """Rae's inbox: portals handed off (content biofield_status=='ai_draft') awaiting
    review + publish. Console-secret gated. Newest handoff first."""
    if not _portal_console_ok():
        return jsonify({"error": "unauthorized"}), 401
    from dashboard import client_portal as _cp
    out = []
    with _db_lock, sqlite3.connect(LOG_DB) as cx:
        _cp.init_client_portal_table(cx)
        cx.row_factory = sqlite3.Row
        for r in cx.execute("SELECT email, name, updated_at, content_json FROM client_portals "
                            "WHERE TRIM(COALESCE(email,''))<>'' ORDER BY updated_at DESC").fetchall():
            try:
                st = (json.loads(r["content_json"] or "{}") or {}).get("biofield_status")
            except Exception:
                st = None
            if st == "ai_draft":
                # Does this client already have a raised invoice (order)? The handoff
                # raises one; surface it so Rae reviews + publishes both.
                inv = None
                try:
                    o = cx.execute(
                        "SELECT id, COALESCE(pay_status,'') pay, COALESCE(portal_published,0) pub "
                        "FROM orders WHERE lower(COALESCE(email,''))=lower(?) "
                        "AND COALESCE(status,'')<>'cancelled' ORDER BY id DESC LIMIT 1",
                        (r["email"],)).fetchone()
                    if o:
                        inv = {"order_id": o["id"], "pay_status": o["pay"],
                               "published": bool(o["pub"])}
                except Exception:
                    inv = None
                out.append({"email": r["email"], "name": r["name"] or "",
                            "handed_off_at": r["updated_at"] or "", "invoice": inv})
    return jsonify({"ok": True, "handoffs": out})


