def _biofield_status_brief(cx, email):
    """Board signals for a reveal's owner email: paid (active member) + order rollup.
    Drives the reveals board columns + order badge. Best-effort, never raises."""
    out = {"paid": False, "ordered": False, "order_count": 0,
           "order_total_cents": 0, "orders": []}
    email = (email or "").strip().lower()
    if not email:
        return out
    try:
        out["paid"] = bool(_active_membership_for_email(email))
    except Exception:
        pass
    try:
        rows = cx.execute(
            "SELECT total_cents FROM orders WHERE lower(email)=? AND status!='cancelled'",
            (email,)).fetchall()
        out["order_count"] = len(rows)
        out["ordered"] = len(rows) > 0
        out["order_total_cents"] = sum(int(r[0] or 0) for r in rows)
    except Exception:
        pass
    # Basket contents for the order-badge popup: each non-cancelled order's line
    # items. Kept in its own best-effort block so a minimal orders table (missing
    # items_json/created_at) still yields the totals above — only `orders` drops.
    try:
        orows = cx.execute(
            "SELECT id, COALESCE(created_at,'') , COALESCE(status,'') , "
            "COALESCE(total_cents,0) , COALESCE(items_json,'[]') "
            "FROM orders WHERE lower(email)=? AND status!='cancelled' ORDER BY id DESC",
            (email,)).fetchall()
        orders = []
        for oid, created_at, status, total_cents, items_json in orows:
            try:
                its = json.loads(items_json or "[]") or []
            except Exception:
                its = []
            orders.append({
                "id": oid, "created_at": created_at, "status": status,
                "total_cents": int(total_cents or 0),
                "items": [{"name": (it.get("name") or it.get("slug") or ""),
                           "qty": it.get("qty") or 1,
                           "line_cents": it.get("line_cents")}
                          for it in its if isinstance(it, dict)],
            })
        out["orders"] = orders
    except Exception:
        pass
    return out


def _people_brief(cx, email):
    """Best-effort name + tags for a reveal's owner email. Empty on miss/error.
    Tags are filtered to health conditions only — the `people.tags` field is a broad
    CRM bucket (marketing, lifecycle, chat topics, roles); real clinical conditions
    live in the Practice Better `pb:` namespace, so we allowlist those (shown without
    the pb: prefix) and drop the rest, so the reveals view shows just conditions."""
    from dashboard.biofield_profile import is_health_tag, clean_health_tag
    out = {"client_name": "", "tags": []}
    try:
        row = cx.execute("SELECT name, tags FROM people WHERE lower(email)=lower(?)",
                         ((email or "").strip(),)).fetchone()
        if row:
            out["client_name"] = (row[0] or "").strip()
            try:
                t = json.loads(row[1] or "[]")
                out["tags"] = [clean_health_tag(str(x)) for x in t
                               if is_health_tag(str(x))] if isinstance(t, list) else []
            except Exception:
                out["tags"] = []
    except Exception:
        pass
    return out


@app.route("/api/console/biofield-reveals", methods=["GET"])
def api_console_biofield_reveals():
    """List pending biofield reveals (first_approved=0) for console review."""
    if CONSOLE_SECRET:
        _key = request.headers.get("X-Console-Key", "") or request.args.get("key", "")
        if _key != CONSOLE_SECRET and not _owner_token_ok(_key):
            return jsonify({"error": "unauthorized"}), 401
    from dashboard import biofield_reveals as _br
    with sqlite3.connect(LOG_DB) as cx:
        _br.init_table(cx)
        drafts = _br.list_pending(cx)
        approved = _br.list_approved(cx)
        for d in drafts + approved:
            d.update(_people_brief(cx, d.get("email")))
            d.update(_biofield_status_brief(cx, d.get("email")))
        # Read-receipts (Task 5): additive, best-effort — a client's explicit
        # report open (see /api/portal/<token>/open), keyed the same way the
        # portal payload keys it (email|scan_date).
        try:
            from dashboard import opens as _op
            _op.init_opens_table(cx)
            for d in drafts + approved:
                d["opened"] = _op.get_open(cx, "report", _op.report_key(d.get("email", ""), d.get("scan_date", "")))
        except Exception as _e:
            print(f"[opens] reveals annotate skipped: {_e!r}", flush=True)
    return jsonify({"drafts": drafts, "approved": approved,
                    "scan_pull_enabled": _scan_pull_enabled()})


