@app.route("/api/practitioner/chat", methods=["POST"])
def api_practitioner_chat():
    """Practitioner-authenticated product-selection chat scoped to FF catalog.
    Auth via session token (401 if none). Returns {ok, reply, suggestions}."""
    pid = _practitioner_session_pid()
    if not pid:
        return jsonify({"ok": False, "error": "authentication required"}), 401

    body = request.get_json(silent=True) or {}
    message = body.get("message") or ""
    history = body.get("history") or []
    client_email = (body.get("client_email") or "").strip().lower()

    # Only act on a client this practitioner actually owns (authorization re-checked
    # every turn — client_email from the request is never trusted). Empty/unowned -> "".
    _subject = client_email if (client_email and _pp.client_belongs_to_practitioner(pid, client_email)) else ""
    _ally_ov = ash_ally.ally_overlay(LOG_DB, _subject)

    catalog = _build_ff_catalog()
    result = _chat.scoped_reply(message, history, catalog, overlay=_ally_ov)

    if _subject:
        try:
            import threading as _t
            _t.Thread(target=ash_ally.record_turn,
                      args=(LOG_DB, _db_lock, _subject, message, result.get("reply", "")),
                      daemon=True).start()
        except Exception:
            pass

    suggestions = []
    for slug in (result.get("suggested_slugs") or []):
        p = _get_product(slug)
        if not p:
            continue
        suggestions.append({
            "slug": slug,
            "name": p.get("name") or slug,
            "price_cents": _dropship.practitioner_price_for(pid, slug),
        })

    return jsonify({"ok": True, "reply": result["reply"], "suggestions": suggestions})


def _continuity_cx(cx):
    """Ensure the subscriptions table + the attribution/consent migration chain
    are present on this connection (mirrors the /api/console/members idiom), plus
    the scan_analyses table patient_view() reads from (normally created by the
    /api/e4l/scan-analysis ingestion route, but a patient with no scans pushed
    yet must still 200 with an empty trajectory rather than 500)."""
    from dashboard import subscriptions as _subs
    from dashboard import scan_analysis as _sa
    cx.row_factory = sqlite3.Row
    _subs.init_subscriptions_table(cx)
    _subs.migrate_add_membership_columns(cx)
    _subs.migrate_add_term_cap_column(cx)
    _subs.migrate_add_attribution_column(cx)
    _subs.migrate_add_consent_column(cx)
    _sa.init_table(cx)
    return cx


