@app.route("/reorder/request", methods=["POST"])
def reorder_request():
    """Email a magic link to start a reorder session. Always 200 (no enumeration)."""
    email = ((request.get_json(silent=True) or {}).get("email") or "").strip().lower()
    if email and "@" in email:
        token = secrets.token_urlsafe(32)
        now = _now_utc()
        with _db_lock, sqlite3.connect(LOG_DB) as cx:
            cx.execute(
                "INSERT INTO auth_tokens (token_hash, email, purpose, created_at, expires_at) "
                "VALUES (?,?,?,?,?)",
                (_hash_token(token), email, "reorder", now.isoformat(),
                 (now + timedelta(minutes=AUTH_TOKEN_TTL_MIN)).isoformat()))
            cx.commit()
        try:
            send_magic_link_email(email, "", f"{PUBLIC_BASE_URL}/reorder/auth/{token}")
        except Exception as e:
            print(f"[reorder] magic link send failed: {e!r}", flush=True)
    return jsonify({"ok": True})


@app.route("/reorder/auth/<token>", methods=["GET", "POST"])
def reorder_auth(token):
    """Validate the reorder magic link, set the rm_reorder_email cookie, → /reorder."""
    return _magic_link_login_view(
        token, purpose="reorder", cookie="rm_reorder_email", dest="/reorder",
        title="Sign in to reorder",
        heading="Welcome back",
        blurb="Continue to open your reorder page.",
        button="Continue",
        invalid_html=(
                "<p style='font-family:sans-serif;max-width:32rem;margin:3rem auto'>"
                "This reorder link is invalid or has expired. Please request a new one.</p>"
                "<button id='resend-link-btn' style='font-family:sans-serif;margin-top:12px;'>Request a fresh link</button>"
                "<script>(function(){"
                "var b=document.getElementById('resend-link-btn');if(!b)return;"
                "var parts=location.pathname.replace(/\\/+$/,'').split('/');"
                "var qp=new URLSearchParams(location.search);"
                "var token=qp.get('token')||parts[parts.length-1]||'';"
                "b.onclick=function(){"
                "b.disabled=true;"
                "fetch('/link/resend',{method:'POST',headers:{'Content-Type':'application/json'},"
                "body:JSON.stringify({token:token})})"
                ".then(function(){b.textContent='Check your email for a fresh link.';})"
                ".catch(function(){b.disabled=false;});};"
                "})();</script>"))


# ── Tokenized per-client portal ("Create Your Own Healing Adventure") ────────
# One durable row per client (dashboard/client_portal.py); the token is the only
# auth — no login, mirroring /invoice/<token>. Inherently dark: no route is
# reachable until a token is minted via /admin/portal/upsert (CONSOLE_SECRET) and
# shared with the client. First client: Brooke Webb.

def _portal_console_ok():
    if CONSOLE_SECRET:
        key = request.headers.get("X-Console-Key", "") or request.args.get("key", "")
        if key != CONSOLE_SECRET and not _owner_token_ok(key):
            return False
    return True


def _portal_open_is_owner():
    """True only when this request presents a valid console/owner key. Deliberately
    distinct from _portal_console_ok(), which vacuously returns True whenever
    CONSOLE_SECRET isn't configured at all (that gate protects console-only routes:
    'no secret configured → don't lock anyone out'). The read-receipts owner-skip
    needs the opposite default: absent an explicit owner key, treat the caller as a
    real client so a genuine portal/invoice open still records. Checks both this
    module's CONSOLE_SECRET and dashboard.CONSOLE_SECRET (the shared
    require_console_key gate) since either may be the one actually configured,
    plus a per-user OWNER-role token."""
    key = request.headers.get("X-Console-Key", "") or request.args.get("key", "")
    if not key:
        return False
    if CONSOLE_SECRET and key == CONSOLE_SECRET:
        return True
    import dashboard as _dash
    if _dash.CONSOLE_SECRET and key == _dash.CONSOLE_SECRET:
        return True
    return _owner_token_ok(key)


