def _client_species_for(email):
    """{"is_animal": True, "animal_name": ...} when the flag is on AND this client is an
    animal; None otherwise (flag off, human, unknown, or any error)."""
    if not _animal_greeting_enabled() or not email:
        return None
    try:
        from dashboard import client_species as _cs
        with sqlite3.connect(LOG_DB) as cx:
            _cs.init_table(cx)
            rec = _cs.get(cx, email)
        if rec and rec["is_animal"]:
            return {"is_animal": True, "animal_name": rec["animal_name"]}
    except Exception as _e:
        print(f"[client-species] {_e!r}", flush=True)
    return None


def _dependent_tos_enabled():
    """Flag: a caregiver's Terms acceptance covers the dependents in their care. Default
    OFF. When off, tos_agreed is is_member(primary_email) exactly — byte-identical to today.
    Flip only AFTER the gate copy says the caregiver agrees on behalf of those in their care
    (a counsel-approved wording)."""
    return (os.environ.get("DEPENDENT_TOS_ENABLED", "") or "").strip().lower() in (
        "1", "true", "yes", "on")


def _portal_tos_agreed(primary_email):
    """Has the Terms gate been satisfied for this token holder?

    The token holder's own agreement, OR (flag on) a linked, consented caregiver has agreed.
    A dependent — pet, infant, minor — has its own token but can never click 'I agree'; the
    caregiver agrees for it. Derived live from the household graph: caregivers_for() returns
    [] for any standalone adult, so this is byte-identical for non-dependents. It does NOT
    stamp the dependent's own tos_agreed_at, so compliance and funnel readers correctly still
    exclude a dependent who did not personally agree. Fail-closed to the token holder's own
    agreement on any error."""
    if is_member(email=primary_email):
        return True
    if not _dependent_tos_enabled() or not primary_email:
        return False
    try:
        from dashboard import household as _hh
        with sqlite3.connect(LOG_DB) as cx:
            caregivers = _hh.caregivers_for(cx, primary_email)   # a read; fetch then release
        for cg in caregivers:
            # is_member opens its own _db_lock connection, so do not nest it inside cx.
            if (_hh.is_dependent(cg["relationship"])
                    and cg["share_consent"] and is_member(email=cg["primary_email"])):
                return True
    except Exception as _e:
        print(f"[dependent-tos] {_e!r}", flush=True)
    return False


def _scan_rec_label(code, label):
    """Glen's rule for BFA: the label says BFA, and "aligner" both expands the acronym
    and describes the benefit. Every other code reads "<CODE> <label>"."""
    code, label = (code or "").strip(), (label or "").strip()
    if code == "BFA":
        return "Big Field Aligner (BFA)"
    return f"{code} {label}".strip()


def _scan_recommendations_for(email, scan_date=None):
    """The client's own E4L scan recommendations. None when off, unknown, or broken.

    Keyed on the E4L SCAN date, never the published-report date: a report can be filed
    under a date on which the client has no scan, and keying on that shows them nothing.
    An unknown scan_date falls back to the latest.

    miHealth rows (ER/MR) carry NO order_url — they are device cycles your practitioner
    runs, not products. Zero of them resolve to a slug, which is correct.
    """
    if not _scan_recommendations_enabled() or not email:
        return None
    try:
        from dashboard import scan_recommendations as _sr
        from dashboard.order_destination import destination_for
        with sqlite3.connect(LOG_DB) as cx:
            cx.row_factory = sqlite3.Row
            _sr.init_table(cx)
            dates = _sr.scan_dates_for(cx, email)
            if not dates:
                return None
            picked = scan_date if (scan_date and scan_date in dates) else dates[0]
            info, mih = _sr.split_by_section(_sr.for_scan_date(cx, email, picked))
        out_info = []
        for r in info:
            slug = _resolve_remedy_slug({"name": r["item_code"]}) or ""
            if slug and not _get_product(slug):
                slug = ""
            out_info.append({"code": r["item_code"],
                             "label": _scan_rec_label(r["item_code"], r["label"]),
                             "rank": r["priority_rank"], "protocol_days": r["protocol_days"],
                             "order_url": destination_for(slug)})
        out_mih = [{"code": r["item_code"], "label": (r["label"] or r["item_code"]),
                    "rank": r["priority_rank"], "protocol_days": r["protocol_days"]}
                   for r in mih]
        return {"scan_date": picked, "scan_dates": dates,
                "infoceuticals": out_info, "mihealth": out_mih}
    except Exception as _e:
        print(f"[scan-recs] {_e!r}", flush=True)
        return None


def _ff_query_specific_formulations(text, top_k):
    """Adapter: embed `text` and query the `specific-formulations` Pinecone
    namespace, reusing the module-level `embed()`/`_idx` this file already
    constructs (same client as `_assist_resolve_products`'s semantic fallback,
    app.py:~12862). Never raises — any embedding/Pinecone failure returns []."""
    try:
        res = _idx.query(vector=embed(text), top_k=top_k,
                         namespace="specific-formulations", include_metadata=True)
        out = []
        for m in (res.matches or []):
            md = dict(m.metadata or {})
            if not md.get("name"):
                md["name"] = md.get("title")
            out.append({"id": m.id, "score": float(m.score), "metadata": md})
        return out
    except Exception as _e:
        print(f"[ff-match] query failed: {_e!r}", flush=True)
        return []


_FF_EXCLUDED_SUBSTRINGS = (
    "living water bottle",
    "electrolyte mineral manna",
    "dental regen powder",
    "allerfree",
    "fungifuge",
    "bioavailability blend",
)
_FF_EXCLUDED_EXACT = ("endocrine restore", "comfort")


def _ff_auto_excluded(name):
    """True if `name` must NEVER be auto-recommended by the FF matcher.

    Mirrors the DEPRECATED PRODUCTS never-recommend rules that live as prose
    in the chat system prompt (app.py ~1638): discontinued products
    (Living Water Bottle, Electrolyte Mineral Manna, Dental Regen Powder),
    bare old names consolidated into a canonical replacement (bare
    "Endocrine Restore", bare "Comfort" -- exact-match ONLY, so
    "Endocrine Restore Powder" and "Comfort Synovial Syntropy" survive),
    AllerFree (-> Immune Modulation instead), Fungifuge (only valid as a
    Candida Cleanse follow-on, never a standalone auto-match), and
    Bioavailability Blend / Bioavailability Blend Powder (adjunct-only,
    never a standalone reveal recommendation). This is the hard candidate
    filter applied in BOTH the LLM path and the vector fallback path -- the
    single guarantee a never-recommend product cannot reach a client."""
    nl = (name or "").strip().lower()
    if not nl:
        return False
    if nl in _FF_EXCLUDED_EXACT:
        return True
    return any(s in nl for s in _FF_EXCLUDED_SUBSTRINGS)


def _parse_ff_rank(text, allowed_names):
    """Parse the LLM ranking response into [{"name", "meaning"}, ...].

    Tolerant: extracts the first JSON array found anywhere in `text`
    (survives ```json fences and surrounding prose). Keeps an entry ONLY if
    its `name` matches (case-insensitively) a name in `allowed_names` --
    the candidate set already filtered by `_ff_auto_excluded` and resolved
    to a sellable slug -- so a hallucinated or never-recommend product name
    can never survive this join. Maps back to the canonical (allowed-set)
    spelling of the name. `why`/`reason`/`meaning` (first present, in that
    order) becomes `meaning`. Returns [] on ANY parse failure, non-list
    payload, or empty match. Never raises."""
    if not text:
        return []
    try:
        allowed_map = {a.strip().lower(): a for a in (allowed_names or []) if a}
        m = re.search(r"\[.*\]", text, re.DOTALL)
        if not m:
            return []
        data = json.loads(m.group(0))
        if not isinstance(data, list):
            return []
        out = []
        for item in data:
            if not isinstance(item, dict):
                continue
            name = (item.get("name") or "").strip()
            if not name:
                continue
            canon = allowed_map.get(name.lower())
            if not canon:
                continue
            why = (item.get("why") or item.get("reason")
                   or item.get("meaning") or "").strip()
            out.append({"name": canon, "meaning": why})
        return out
    except Exception:
        return []


def _broad_benefit_slug_set():
    """Best-effort load of the Slice-1 `broad_benefit` store (Condition
    Support Programs) as a plain set of slugs, for use as a deterministic
    "broadly effective" signal in the FF matcher (Slice 2). Opened ONCE per
    `_make_ff_items_for` call -- never per-candidate -- to avoid a
    per-candidate DB round trip. Fails closed to an empty set on ANY error
    (missing table, locked db, etc.) so a store outage can never break the
    matcher -- it only silently drops the signal, leaving every candidate
    not-broad."""
    try:
        with sqlite3.connect(LOG_DB) as cx:
            broad_benefit.init_table(cx)
            # Seed once here too, so the "broadly effective" FF signal works on a
            # fresh deploy WITHOUT the support-programs console being opened first.
            # seed_if_empty is marker-guarded: a no-op after the first seed, and it
            # never resurrects an operator-cleared list or overwrites edits.
            broad_benefit.seed_if_empty(
                cx, (_load_support_programs_seed() or {}).get("broad_benefit_slugs") or [])
            return set(broad_benefit.all_slugs(cx))
    except Exception as _e:
        print(f"[ff-broad-benefit] {_e!r}", flush=True)
        return set()


def _ff_llm_rank(scan_labels, candidates):
    """Retrieval-augmented LLM ranking of FF product candidates for this
    scan's findings. `candidates` is the already-filtered, already-resolved
    list of {name, slug, url, meaning, broad_benefit} (never-recommend
    products already excluded). A candidate with `broad_benefit` true is
    rendered in the prompt with a "(broadly effective)" marker after its
    name (Slice 2), and the ranking guidance nudges the LLM to prefer a
    marked candidate when two otherwise fit the scan comparably -- this is
    a soft prompt signal only, never a hard reorder. Returns a ranked
    [{"name", "meaning"}, ...] (up to 5, in best-fit-first order) or None on
    ANY failure -- empty inputs, API error, or a garbage/empty parse --
    signalling the caller to fall back to the vector path. Never raises."""
    try:
        if not scan_labels or not candidates:
            return None
        findings_text = "\n".join(f"- {l}" for l in scan_labels if l)
        cand_lines = []
        for c in candidates:
            nm = (c.get("name") or "").strip()
            if not nm:
                continue
            # Deterministic "broadly effective" marker (Slice 2: wires the
            # Slice-1 broad_benefit store into this prompt) -- purely a
            # display hint for the LLM; the candidate's real `name` is
            # unaffected, so `_parse_ff_rank`'s allowed-name join still
            # works unchanged.
            label = f"{nm} (broadly effective)" if c.get("broad_benefit") else nm
            mn = (c.get("meaning") or "").strip()
            cand_lines.append(f"- {label}: {mn}" if mn else f"- {label}")
        candidates_text = "\n".join(cand_lines)
        if not findings_text or not candidates_text:
            return None
        prompt = (
            "You are selecting Dr. Glen's Functional Formulation supplements "
            "to COMPLEMENT a client's bioenergetic scan. The client already "
            "sees their own E4L infoceuticals separately on their scan card "
            "-- your job is to recommend DISTINCT Functional Formulation "
            "products from the candidate list below, not to repeat what's "
            "already shown to them. Select and rank a well-rounded support "
            "set of the candidate products that best support the client's "
            "PRIMARY terrain / organ-system patterns from the scan findings. "
            "Aim for 4 to 5 formulations when the candidate list offers that "
            "many relevant, distinct options; choose fewer ONLY if there "
            "genuinely aren't enough good fits.\n\n"
            "SCAN FINDINGS:\n" + findings_text + "\n\n"
            "CANDIDATE PRODUCTS (choose ONLY from this list, using each "
            "product's exact name as given -- never invent a product not "
            "listed here):\n" + candidates_text + "\n\n"
            "Ranking guidance:\n"
            "- Favor BROADLY-EFFECTIVE, foundational, widely-recommended "
            "formulations that support the client's overall terrain, over "
            "narrow single-purpose ones -- UNLESS a narrow finding is "
            "clearly the primary driver of this scan.\n"
            "- Rank by breadth of benefit combined with fit to the scan; a "
            "formulation that supports multiple findings should generally "
            "outrank one that supports only one.\n"
            "- Prefer a DISTINCT, non-redundant set: avoid picking several "
            "formulations that all target the exact same single system when "
            "better breadth is available in the candidate list.\n"
            "- Build a complete ongoing-support set: round it out with "
            "foundational, broadly-beneficial formulations rather than "
            "stopping at the single closest match -- but never pad with a "
            "formulation that does not fit the scan.\n"
            "- When two candidates fit the scan comparably, prefer the one "
            "marked \"(broadly effective)\"; a broadly-effective, "
            "foundational formulation marked this way is a good choice to "
            "round out the support set.\n\n"
            "Safety rules (defense-in-depth -- some of these may already be "
            "excluded from the candidate list above, but never select them "
            "regardless):\n"
            "- Never select a discontinued product.\n"
            "- \"Bioavailability Blend\" (or \"Bioavailability Blend "
            "Powder\") is adjunct-only -- never select it as a standalone "
            "recommendation.\n"
            "- Never select \"AllerFree\" -- \"Immune Modulation\" is the "
            "replacement.\n"
            "- Only select \"Fungifuge\" as a follow-on to a Candida "
            "Cleanse, never as a standalone recommendation.\n"
            "- Do NOT include any dosing instructions or amounts.\n\n"
            "Return STRICT JSON ONLY -- no prose, no markdown fence -- a "
            "JSON array of up to 5 objects, each shaped exactly "
            '{"name": "<exact candidate name>", "why": "<one concise '
            'clinical rationale tying the formulation to a scan finding, no '
            'dosing>"}, ordered best-fit first.'
        )
        msg = _cl.messages.create(
            model="claude-sonnet-5",
            max_tokens=700,
            messages=[{"role": "user", "content": prompt}],
        )
        text = "".join(getattr(block, "text", "") or ""
                       for block in (msg.content or []))
        allowed = {c.get("name") for c in candidates if c.get("name")}
        parsed = _parse_ff_rank(text, allowed)
        return parsed or None
    except Exception as _e:
        print(f"[ff-llm-rank] {_e!r}", flush=True)
        return None


def _make_ff_items_for(email, scan_date=None):
    """Compose this client's scan recommendations into ranked FF product
    matches: retrieve a broad candidate pool, filter it to a DISTINCT,
    qty-eligible Functional Formulation candidate set (never-recommend
    products excluded via `_ff_auto_excluded`; the client's own E4L
    infoceuticals excluded via the `_qty_eligible` gate AND by dropping any
    slug already on their scan card (`scan_slugs`); deduped by slug), tags
    each candidate `broad_benefit` (Slice 2: the Condition Support Programs
    `broad_benefit` store, loaded ONCE via `_broad_benefit_slug_set` --
    fail-closed/best-effort, never breaks the matcher), then rank via the
    inline LLM (`_ff_llm_rank`), which surfaces that flag as a prompt marker
    biased toward broadly-effective formulations. The `broad_benefit` key is
    internal to the candidate dict handed to `_ff_llm_rank` and is never
    copied into the returned items. Falls back to the pure vector path
    (`ff_matcher.generate_ff_matches`, same exclusions + same qty_eligible/
    non-scan-slug scoping) when the LLM ranking is unavailable or empty.
    Returns [] when scan recs are off, unknown, the client has none for this
    scan, or no distinct qty_eligible FF candidates survive filtering. Item
    shape is always {name, slug, url, meaning} -- NEVER a `dosing` key --
    never raises."""
    recs = _scan_recommendations_for(email, scan_date)
    if not recs:
        return []
    labels = [i["label"] for i in (recs.get("infoceuticals") or []) if i.get("label")]
    if not labels:
        return []

    # Slugs already shown to the client on the scan card (E4L infoceuticals) --
    # never re-surface these as an FF "match": parse each infoceutical's
    # order_url ("/begin/product/<slug>") down to its last path segment.
    scan_slugs = set()
    for i in (recs.get("infoceuticals") or []):
        order_url = (i.get("order_url") or "").strip()
        if not order_url:
            continue
        tail = order_url.rstrip("/").rsplit("/", 1)[-1].strip()
        if tail:
            scan_slugs.add(tail)

    # Loaded ONCE for this call (not per-candidate) -- see
    # `_broad_benefit_slug_set` for the fail-closed/best-effort contract.
    broad_slugs = _broad_benefit_slug_set()

    raw = _ff_query_specific_formulations("; ".join(labels), 120)
    candidates, seen = [], set()
    for r in raw:
        name = ((r.get("metadata") or {}).get("name") or "").strip()
        if not name or _ff_auto_excluded(name):
            continue
        slug = _resolve_buy_slug(name)
        if not slug or slug in seen or slug in scan_slugs:
            continue
        p = _get_product(slug)
        if not p or not _qty_eligible(p):
            # Excludes the client's own E4L infoceuticals (info_only,
            # qty_eligible False) -- candidates are scoped to Dr. Glen's
            # distinct Functional Formulation supplements only.
            continue
        seen.add(slug)
        candidates.append({
            "name": name,
            "slug": slug,
            "url": order_destination.destination_for(slug),
            "meaning": ((r.get("metadata") or {}).get("meaning") or "").strip(),
            # INTERNAL to the candidate dict handed to `_ff_llm_rank` --
            # never copied into the final returned items (see the LLM-path
            # and fallback-path item construction below, both of which
            # build a fresh {name, slug, url, meaning} dict).
            "broad_benefit": slug in broad_slugs,
        })
    if not candidates:
        # No distinct qty_eligible FF candidates survived -- graceful empty,
        # never fall through to an unfiltered (e.g. E4L-echoing) pool.
        return []

    ranked = _ff_llm_rank(labels, candidates)
    if ranked:
        cmap = {c["name"]: c for c in candidates}
        out = []
        for it in ranked:
            c = cmap.get(it["name"])
            if not c:
                continue
            out.append({"name": c["name"], "slug": c["slug"], "url": c["url"],
                        "meaning": it["meaning"]})
            if len(out) >= 5:
                break
        if out:
            return out

    # Fallback: pure vector path, same never-recommend exclusions PLUS the
    # same qty_eligible/non-scan-slug scoping applied via resolve_slug (a
    # name that resolves to an excluded, non-FF, or scan-card slug returns
    # None so ff_matcher drops it).
    def _fallback_resolve_slug(n):
        if _ff_auto_excluded(n):
            return None
        slug = _resolve_buy_slug(n)
        if not slug or slug in scan_slugs:
            return None
        p = _get_product(slug)
        if not p or not _qty_eligible(p):
            return None
        return slug

    scan_items = [{"label": l, "category": ""} for l in labels]
    return ff_matcher.generate_ff_matches(
        scan_items,
        query_matches=_ff_query_specific_formulations,
        resolve_slug=_fallback_resolve_slug,
        destination=order_destination.destination_for,
        top_k=5,
    )


def _current_scan_date_for(email):
    """The scan date the FF-matches card treats as 'current' for this email.

    Mirrors api_client_portal's own selection EXACTLY (app.py ~16056:
    `_scan_recommendations_for(email_for_reports, req_date or None)`) rather than
    re-deriving it: with no ?scan_date= override to thread through (this endpoint
    takes none), that call degenerates to `_scan_recommendations_for(email, None)`,
    whose own fallback is the newest E4L scan date (dashboard.scan_recommendations.
    scan_dates_for, DESC). Reuses that existing helper's 'picked' value (returned as
    its 'scan_date' key) instead of inventing a second selection rule. Returns ""
    (never None) when the flag is off or the client has no scans — ff_match_drafts'
    scan_date column is NOT NULL, so an empty string is the safe key, not None."""
    rec = _scan_recommendations_for(email, None)
    return (rec or {}).get("scan_date") or ""


def _ff_covered(cx, email):
    """Whether this client's FF matches are already paid/covered (Slice 3c gates
    dosing visibility on this). Real entitlement check: a paid Biofield Analysis
    on record, OR an active membership, OR (when FAMILY_PLAN_ENABLED) a
    caregiver's Family Plan covering this email. Mirrors
    _portal_biofield_unlocked's inner test, minus the paid-gate flag itself —
    coverage is about entitlement, not whether the blur flag is on. Fail-closed
    (False) on any error."""
    try:
        email = (email or "").strip().lower()
        if not email:
            return False
        if _has_paid_biofield(email):
            return True
        if _active_membership_for_email(email):
            return True
        if _family_plan_enabled():
            from dashboard import family_plan as _fp
            _fp.init_family_plan_table(cx)
            return bool(_fp.covers(cx, email))
        return False
    except Exception:
        return False


def _portal_options_for(email):
    """The client-facing options+pricing trio for the portal card. Prices are
    DATA-SOURCED (biofield-analysis catalog price + this client's courtesy override
    + FF base), never hardcoded. Best-effort — returns None on any error."""
    try:
        p = _get_product("biofield-analysis") or {}
        std = int(p.get("price_cents") or 0)
        value = int(p.get("service_value_cents") or 0)
        courtesy = None
        try:
            from dashboard import client_prices as _cp
            with sqlite3.connect(LOG_DB) as cx:
                courtesy = _cp.get_price(cx, email, "biofield-analysis")
        except Exception:
            courtesy = None
        analysis = courtesy if courtesy is not None else std
        opts = {"analysis_cents": analysis, "analysis_standard_cents": std,
                "analysis_value_cents": value, "ff_from_cents": _FF_BASE_CENTS,
                "is_courtesy": courtesy is not None and courtesy != std}
        # Family Plan (flag-gated). `active` is true for anyone the plan already
        # covers — a covered member must not be sold a plan they are on.
        if _family_plan_enabled():
            try:
                from dashboard import family_plan as _fp
                with sqlite3.connect(LOG_DB) as cx:
                    cx.row_factory = sqlite3.Row
                    _fp.init_family_plan_table(cx)
                    opts["family_plan"] = {
                        "price_cents": _fp.PLAN["amount_cents"],
                        "value_cents": _fp.PLAN["value_cents"],
                        "label": _fp.PLAN["label"],
                        "active": bool(_fp.covers(cx, email)),
                    }
            except Exception as _e:
                print(f"[portal-options/family] {_e!r}", flush=True)
        return opts
    except Exception:
        return None


def _scan_list_enabled():
    """Available-scan list feature (Task 2). Default OFF — when off, the portal
    payload never gains the 'available_scans' key, so responses stay byte-identical
    to pre-scan-list behavior."""
    return (os.environ.get("SCAN_LIST_ENABLED", "") or "").strip().lower() in (
        "1", "true", "yes")


def _scan_request_enabled():
    """Request-further-analysis feature (Task 3). Default OFF — when off, the
    request endpoint is inert ({ok:true,status:"disabled"}, no DB writes) and the
    portal payload's 'available_scans' items still get a 'requested' key (always
    False with no request rows ever created)."""
    return (os.environ.get("SCAN_REQUEST_ENABLED", "") or "").strip().lower() in (
        "1", "true", "yes")


def _scan_pull_enabled():
    return (os.environ.get("SCAN_PULL_ENABLED", "") or "").strip().lower() in ("1", "true", "yes", "on")


def _portal_offers_enabled() -> bool:
    """Master flag for the portal 'What's next' offer surface. Dark by default."""
    return os.environ.get("PORTAL_OFFERS_ENABLED", "").strip().lower() in (
        "1", "true", "yes", "on")


def _portal_program_page_enabled() -> bool:
    """Master flag for the client-portal membership program page. Dark by default."""
    return os.environ.get("PORTAL_PROGRAM_PAGE_ENABLED", "").strip().lower() in (
        "1", "true", "yes", "on")


def _program_paid_live_enabled() -> bool:
    """Whether the program page's Paid tier is a live, sellable Join. Dark by default."""
    return os.environ.get("PROGRAM_PAID_LIVE_ENABLED", "").strip().lower() in (
        "1", "true", "yes", "on")


def _enabled_offer_keys() -> set:
    """Which ladder rungs are purchasable right now (master + per-rung flags)."""
    if not _portal_offers_enabled():
        return set()
    keys = set()
    if os.environ.get("SUBSCRIPTIONS_ENABLED", "").strip().lower() in ("1", "true", "yes", "on"):
        keys.add("live_group")
    if os.environ.get("BIOFIELD_CHECKOUT_ENABLED", "").strip().lower() in ("1", "true", "yes", "on"):
        keys.add("biofield")
    return keys


def _portal_priced_lines(items, email=None):
    """Build QBO invoice lines from a portal's reorder items, honoring an optional
    per-item ``price_cents`` override (the practitioner-special price); else a
    volume rate — the order-wide mix/match rate for a paid member, the same-SKU
    (this line's own qty) rate for a non-member (Glen 2026-07 policy; see
    _inhouse_ff_unit_cents) — with a paid member's repertoire SKUs at their flat
    reorder rate (Task 5b — this is the ACTUAL checkout charge path, so it must
    match what the portal displays). Returns (lines, items_rec, subtotal_cents).

    email (optional): the portal token's client email — passed straight through to
    _resolve_repertoire_slugs AND _is_paid_member, each resolved ONCE for the
    whole cart (not per line)."""
    from dashboard import pricing as _pricing
    settings = _pricing.load_settings(_pricing_settings())
    total_ff_qty = _inhouse_total_ff_qty(items or [])
    rep_slugs = _resolve_repertoire_slugs(email)
    program_member = _is_paid_member(email)
    lines, items_rec, subtotal_cents = [], [], 0
    for it in (items or []):
        slug = (it.get("slug") or "").strip()
        p = _get_product(slug) if slug else None
        if not p:
            continue
        try:
            qty = max(1, min(int(it.get("qty", 1) or 1), 99))
        except Exception:
            qty = 1
        unit_cents = _inhouse_line_unit_cents(p, it.get("price_cents"), total_ff_qty, settings,
                                              repertoire_slugs=rep_slugs,
                                              program_member=program_member, line_qty=qty)
        subtotal_cents += unit_cents * qty
        lines.append({"name": p["name"], "amount": round(unit_cents / 100.0, 2),
                      "qty": qty, "item_id": p.get("qbo_item_id"), "description": p["name"]})
        items_rec.append({"name": p["name"], "qty": qty, "desc": p["name"],
                          "slug": slug, "unit_cents": unit_cents, "line_cents": unit_cents * qty})
    return lines, items_rec, subtotal_cents


def _rep_priced_unit_cents(p, *, repertoire_slugs, settings):
    """Real per-unit price (cents) for a solo qty=1 line of this product, via
    dashboard.pricing.compute() — the SAME engine function _price_cart delegates
    to (Task 4). Never hand-recomputes the discount formula: repertoire_slugs is
    forwarded straight into compute(), which applies repertoire_reorder_pct only
    when the slug is in the set AND the product is volume_eligible, exactly as
    at real checkout. Pass repertoire_slugs=None/empty to get the plain list
    price (no repertoire effect) — used for the non-member/hypothetical branches."""
    from dashboard import pricing as _pricing
    it = _engine_item(p, 1)
    priced = _pricing.compute([it], settings=settings, channel="retail",
                              repertoire_slugs=repertoire_slugs)
    return int(priced["lines"][0]["line_total_cents"])


def _parse_iso_dt(ts):
    """Parse a stored orders.created_at ISO8601 string to an aware datetime, or
    None on any parse failure (never raises)."""
    if not ts:
        return None
    try:
        s = str(ts).replace("Z", "+00:00")
        d = datetime.fromisoformat(s)
        if d.tzinfo is None:
            d = d.replace(tzinfo=timezone.utc)
        return d
    except Exception:
        return None


_PORTAL_CHANNEL_SOURCES = ("portal-reorder", "reorder")
# Storefront (remedymatch.com / GrooveKart) order channel. Glen 2026-07-11 reversed
# the old "portal-channel only" display rule: clients now see ALL their purchases in
# the portal (portal + storefront), consolidated. This is a DISPLAY label boundary
# only — the `source` data values are never renamed (they carry downstream semantics:
# coaching.QUALIFYING_SOURCES, filters, pricing).
_STOREFRONT_CHANNEL_SOURCES = ("groovekart",)


def _portal_display_channel(source):
    """Customer-facing provenance bucket for an order/purchase `source`. Glen
    2026-07-11: clients see ALL their purchases in the portal, every channel, and
    the label names the actual WEBSITE for clarity (see _portal_source_label).
    Named buckets: 'portal' + 'funnel' (both the illtowell.com site), 'storefront'
    (remedymatch.com); everything else (fmp / dispensary / biofield / wholesale /
    in-house / personal / dropship / ...) falls to 'clinic' — an in-office
    purchase with Dr. Glen's practice, which has no storefront URL. Labels-only
    boundary: the `source` data value is never touched (downstream semantics)."""
    if source in _PORTAL_CHANNEL_SOURCES:
        return "portal"
    if source in _STOREFRONT_CHANNEL_SOURCES:
        return "storefront"
    if source == "funnel":
        return "funnel"
    return "clinic"


def _portal_source_label(channel):
    """The customer-facing provenance line for a purchase, referencing the real
    website where it was placed (Glen 2026-07-11 — name the site for clarity,
    e.g. "Ordered on illtowell.com"). Migration-safe: the portal/funnel host is
    read from portal_base()/PUBLIC_BASE_URL at call time, so the myhealingoasis.com
    portal flip needs no code change here. Clinic purchases (fmp / dispensary /
    biofield / in-house / wholesale / ...) were placed directly by phone or email
    with the practice, not a self-serve site, so they're attributed to Healing
    Oasis rather than a URL (Glen 2026-07-11)."""
    from urllib.parse import urlparse
    if channel == "storefront":
        return "Ordered on remedymatch.com"
    if channel == "clinic":
        return "Ordered with Healing Oasis"
    if channel == "funnel":
        return f"Ordered on {urlparse(PUBLIC_BASE_URL).hostname or 'illtowell.com'}"
    return f"Ordered on {urlparse(portal_base()).hostname or 'illtowell.com'}"  # portal


def _portal_reorder_module(email):
    """REPERTOIRE_ENABLED-gated portal payload extension (Task 5): the client's
    real, portal-channel purchase history, re-priced through the actual
    repertoire-aware pricing engine (dashboard.pricing.compute(), the same
    function _price_cart delegates to — Task 4), plus a personalized non-member
    upsell and forward-framed 'locked' rows for older history a longer
    commitment would unlock.

    CONSOLIDATED DISPLAY (Glen 2026-07-11 — reverses the old "portal-channel only"
    rule): the reorder list now shows the client's WHOLE purchase record — portal
    purchases (orders-table 'portal-reorder'/'reorder') AND storefront purchases
    (orders-table 'groovekart' post-webhook + the purchase_history 'groovekart'
    slice for historical orders that predate it). Each row carries a `channel`
    ('portal' | 'storefront') the frontend maps to a provenance label, and an
    `is_reorder` flag (the SKU is in the client's purchase_history — a TRUE
    reorder) the frontend uses to reserve the word "Reorder" for real reorders.
    The `source` DATA values are never renamed — this is a label boundary only.
    Repertoire PRICING/eligibility stays all-channel (Task 4's design), so a SKU's
    discount doesn't depend on where it shows up, and storefront rows are priced
    through the SAME engine as portal rows (display == charge holds for them too).
    locked_rows + membership_upsell remain portal-channel (the pitch math is
    unchanged and out of scope for the consolidation).

    RESOLVED (Task 5b): /api/portal/<token>/checkout — the ACTUAL checkout endpoint
    wired to the portal's Reorder button — now threads the portal's email through
    _portal_priced_lines -> _inhouse_line_unit_cents -> _resolve_repertoire_slugs,
    which applies the SAME repertoire_reorder_pct/floor via pricing.apply_discount/
    unit_floor_cents that dashboard.pricing.compute() uses here. So `your_cents`
    (this display payload) and what /api/portal/<token>/checkout actually bills
    now agree to the cent. (Previously this was an open gap — display without a
    matching charge; see git history for the prior NOTE.)

    Never raises (caller wraps in try/except); returns {} for a blank email."""
    from dashboard import pricing as _pricing
    from dashboard import purchase_history as _ph
    email = (email or "").strip().lower()
    if not email:
        return {}
    with sqlite3.connect(LOG_DB) as cx:
        cx.row_factory = sqlite3.Row
        try:
            repertoire.init_repertoire_table(cx)  # fresh-DB guard
            rep_slugs = repertoire.repertoire_slugs(cx, email)
        except Exception as e:
            print(f"[portal-reorder] repertoire read failed for {email!r}: {e!r}", flush=True)
            rep_slugs = set()
        try:
            orders = _bos_orders.list_orders_by_email(cx, email, limit=200)
        except Exception as e:
            print(f"[portal-reorder] orders read failed for {email!r}: {e!r}", flush=True)
            orders = []
        try:
            _ph.init_purchase_history_table(cx)  # fresh-DB guard
            ph_rows = cx.execute(
                "SELECT slug, purchased_at, source FROM purchase_history WHERE email=?",
                (email,)).fetchall()
        except Exception as e:
            print(f"[portal-reorder] purchase_history read failed for {email!r}: {e!r}", flush=True)
            ph_rows = []
    # rep_slugs (full/unfiltered) drives the "in your repertoire" DISPLAY flag and
    # the locked_rows "already have it" check below — a non-FF product a member
    # bought IS still in their repertoire, it just isn't member-priced. rep_slugs_ff
    # (FF-only, Glen 2026-07 margin decision) is what PRICES your_cents, matching
    # _resolve_repertoire_slugs / _price_cart so display == charge for non-FF too.
    rep_slugs_ff = _ff_filter_slugs(rep_slugs)
    member = _is_paid_member(email)
    settings = _pricing.load_settings(_pricing_settings())
    now = datetime.now(timezone.utc)

    portal_orders = [o for o in orders
                     if (o.get("source") in _PORTAL_CHANNEL_SOURCES)
                     and (o.get("status") != "cancelled")]

    # --- purchase_history: the consolidated cross-channel record. `ph_slugs` (all
    # slices incl. fmp, resolved) is the "has this client bought before" oracle for
    # the per-row is_reorder flag; `ph_other` holds the NON-portal historical
    # purchases (storefront GrooveKart slice + fmp/clinic slice) that survive only
    # here (they predate the orders-table webhook / were never in the orders board)
    # and would otherwise never surface: slug -> (most-recent purchased_at, channel). ---
    ph_slugs, ph_other = set(), {}
    for r in ph_rows:
        s = _superseded((r["slug"] or "").strip().lower()) or ""
        if not s:
            continue
        ph_slugs.add(s)
        ch = _portal_display_channel(r["source"])
        if ch == "portal":
            continue  # portal purchases come from the orders table, not here
        at = r["purchased_at"] or ""
        cur = ph_other.get(s)
        if cur is None or at > cur[0]:
            ph_other[s] = (at, ch)

    # --- reorder: distinct SKUs from portal-channel history, most-recent qty
    # wins (orders come back most-recent-first already). ---
    reorder, seen, last_seen_at = [], set(), {}
    for o in portal_orders:
        created = o.get("created_at") or ""
        for it in (o.get("items") or []):
            slug = (it.get("slug") or "").strip().lower()
            if not slug:
                continue
            if slug not in last_seen_at or created > last_seen_at[slug]:
                last_seen_at[slug] = created
            if slug in seen:
                continue
            p = _get_product(slug)
            if not p:
                continue  # dropped/inactive since purchase — not purchasable now
            seen.add(slug)
            try:
                qty = max(1, int(it.get("qty", 1) or 1))
            except Exception:
                qty = 1
            regular_cents = int(p.get("price_cents") or 0)
            in_rep = slug in rep_slugs  # full set: display "in your repertoire" regardless of FF-ness
            your_cents = regular_cents
            if member and slug in rep_slugs_ff:  # FF-only: pricing
                your_cents = _rep_priced_unit_cents(p, repertoire_slugs=rep_slugs_ff, settings=settings)
            reorder.append({
                "slug": slug, "name": p.get("name", slug), "qty": qty,
                "regular_cents": regular_cents, "your_cents": your_cents,
                "is_member_price": your_cents < regular_cents,
                "in_repertoire": in_rep,
                "channel": "portal",
                "source_label": _portal_source_label("portal"),
                "is_reorder": slug in ph_slugs,
            })

    # --- locked_rows: FF SKUs (_qty_eligible — Glen 2026-07: the repertoire
    # discount is FF-only, so only these can ever unlock member pricing) last
    # bought 90-365 days ago, not already in the client's repertoire, tagged
    # with the shortest commitment tier whose seed window would reach that
    # purchase. ---
    locked_rows = []
    for slug in seen:
        if slug in rep_slugs:
            continue
        p = _get_product(slug)
        if not p or not _qty_eligible(p):
            continue
        seen_at = _parse_iso_dt(last_seen_at.get(slug))
        if not seen_at:
            continue
        age_days = (now - seen_at).days
        tier = None
        if 90 < age_days <= 180:
            tier = "6mo"
        elif 180 < age_days <= 365:
            tier = "12mo"
        if tier:
            locked_rows.append({
                "slug": slug, "name": p.get("name", slug),
                "regular_cents": int(p.get("price_cents") or 0), "tier": tier,
            })

    # --- membership_upsell: last-30-day portal-channel history, re-priced as
    # if the client were a member (repertoire_slugs forced to the purchased
    # slug so the hypothetical isn't gated on their CURRENT membership). ---
    cutoff_30 = (now - timedelta(days=30)).isoformat()
    recent = [o for o in portal_orders if (o.get("created_at") or "") >= cutoff_30]
    reorders_30d = len(recent)
    spend_30d_cents, member_would_pay_cents = 0, 0
    for o in recent:
        for it in (o.get("items") or []):
            slug = (it.get("slug") or "").strip().lower()
            p = _get_product(slug) if slug else None
            if not p:
                continue
            try:
                qty = max(1, int(it.get("qty", 1) or 1))
            except Exception:
                qty = 1
            try:
                paid_unit = it.get("unit_cents")
                paid_unit = int(paid_unit) if paid_unit is not None else int(p.get("price_cents") or 0)
            except Exception:
                paid_unit = int(p.get("price_cents") or 0)
            spend_30d_cents += paid_unit * qty
            if _qty_eligible(p):  # Glen 2026-07: repertoire discount is FF-only
                hyp_unit = _rep_priced_unit_cents(p, repertoire_slugs={slug}, settings=settings)
            else:
                hyp_unit = paid_unit
            member_would_pay_cents += hyp_unit * qty

    already_member = member
    if already_member:
        member_would_pay_cents = spend_30d_cents
        savings_cents = 0
    else:
        savings_cents = max(0, spend_30d_cents - member_would_pay_cents)
    net_after_fee_cents = _prepay.MONTHLY_ANCHOR_CENTS - savings_cents

    # --- all other channels: fold the client's WHOLE purchase record into the
    # reorder list (Glen 2026-07-11 — clients see ALL their purchases in the
    # portal, every channel). Candidates = every non-portal, non-cancelled
    # orders-table order (storefront GrooveKart + clinic: fmp/dispensary/biofield/
    # funnel/wholesale/in-house/personal/dropship/...) PLUS every non-portal
    # purchase_history row (historical, qty defaults to 1). Each row keeps the
    # channel of its most-recent purchase. Deduped against portal `seen` so a SKU
    # bought on portal too shows once, labeled portal (portal is processed first
    # and wins). Non-product line items (membership/coaching/service payments have
    # no catalog slug) are dropped by _get_product. Priced through the SAME
    # repertoire engine as the portal rows => display == charge. Appended AFTER
    # locked_rows/upsell so those stay portal-channel. ---
    other = {}  # slug -> (most_recent_purchased_at, qty, channel)
    def _consider_other(slug, at, qty, channel):
        cur = other.get(slug)
        if cur is None or at > cur[0]:
            other[slug] = (at, qty, channel)
    for o in orders:
        if o.get("status") == "cancelled":
            continue
        channel = _portal_display_channel(o.get("source"))
        if channel == "portal":
            continue  # portal purchases already handled above
        created = o.get("created_at") or ""
        for it in (o.get("items") or []):
            slug = _superseded((it.get("slug") or "").strip().lower()) or ""
            if not slug:
                continue
            try:
                qty = max(1, int(it.get("qty", 1) or 1))
            except Exception:
                qty = 1
            _consider_other(slug, created, qty, channel)
    for slug, (at, channel) in ph_other.items():
        _consider_other(slug, at, 1, channel)  # ph rows carry no qty

    for slug, (_at, qty, channel) in sorted(
            other.items(), key=lambda kv: kv[1][0], reverse=True):
        if slug in seen:
            continue  # already shown as a portal purchase
        p = _get_product(slug)
        if not p:
            continue  # dropped/inactive since purchase — not purchasable now
        seen.add(slug)
        regular_cents = int(p.get("price_cents") or 0)
        your_cents = regular_cents
        if member and slug in rep_slugs_ff:
            your_cents = _rep_priced_unit_cents(p, repertoire_slugs=rep_slugs_ff, settings=settings)
        reorder.append({
            "slug": slug, "name": p.get("name", slug), "qty": qty,
            "regular_cents": regular_cents, "your_cents": your_cents,
            "is_member_price": your_cents < regular_cents,
            "in_repertoire": slug in rep_slugs,
            "channel": channel,
            "source_label": _portal_source_label(channel),
            "is_reorder": slug in ph_slugs,
        })

    return {
        "reorder": reorder,
        "locked_rows": locked_rows,
        "membership_upsell": {
            "reorders_30d": reorders_30d,
            "spend_30d_cents": spend_30d_cents,
            "member_would_pay_cents": member_would_pay_cents,
            "savings_cents": savings_cents,
            "net_after_fee_cents": net_after_fee_cents,
            "already_member": already_member,
        },
    }


def _portal_chat_thread(email, limit=100):
    """The persisted portal chat thread for a client email (empty on any error)."""
    if not email:
        return []
    try:
        from dashboard import portal_chat as _pchat
        with sqlite3.connect(LOG_DB) as _cx:
            return _pchat.list_messages(_cx, email, limit=limit)
    except Exception as e:
        print(f"[portal-chat] thread load failed: {e!r}", flush=True)
        return []


def _portal_record_for(cx, token):
    """A portal content record by path token, OR — when client login is live —
    by the rm_portal_session cookie (the tokenless /portal/me logged-in home).
    Returns {email, name, content} or None. The token path is unchanged, so
    emailed /portal/<token> links keep working exactly as before."""
    from dashboard import client_portal as _cp
    portal = _cp.get_portal_by_token(cx, token)
    if portal:
        return portal
    if _client_login_enabled():
        from dashboard import portal_identity as _pi
        sess = request.cookies.get("rm_portal_session", "")
        ident = _pi.identity_from_session(cx, sess) if sess else None
        if ident:
            rec = _cp.get_portal_content_by_email(cx, ident.email)
            if rec:
                return {"email": ident.email, "name": rec.get("name"),
                        "content": rec.get("content")}
    return None


def _reorder_item_from_slug(slug, qty):
    """Build a reorder_items-shaped entry ({slug, qty}) for a slug merged in from
    an ACCEPTED practitioner recommendation (Task 2, fast-follow off #572).
    Deliberately carries NO price_cents override: the recommendation's
    suggested-step price is $0 on prod and must never be shown as a real cost.
    Omitting it makes this entry fall through to the SAME regular-catalog-price
    display path any other un-overridden reorder_items row already uses (see the
    `display` loop right below) — the authoritative price is computed later, at
    checkout, by _portal_priced_lines, exactly like every other reorder line."""
    return {"slug": slug, "qty": qty}


def _merge_accepted_recommendation_items(cx, email, reorder_items):
    """Merge an ACCEPTED practitioner recommendation's items into ``reorder_items``,
    deduped by lowercased slug, returning a NEW list in the same {slug, qty}
    reorder-item shape. Merges ONLY when the patient's active recommendation is
    status=='accepted' — a 'sent'/'dismissed'/absent rec leaves the list unchanged.

    This is the single source of truth for "an accepted recommendation lives in the
    patient's reorder list", so it must reach BOTH the portal DISPLAY payload
    (api_client_portal) AND the money path (the no-body reorder checkout) — otherwise
    the button charges a different set than the patient sees. Never raises — a merge
    failure must never break a portal render or a checkout."""
    base = list(reorder_items or [])
    try:
        if not email:
            return base
        from dashboard import practitioner_recommendations as _pr
        cx.row_factory = sqlite3.Row
        _pr.init_table(cx)
        rec = _pr.active_for_patient(cx, email)
        if not rec or rec.get("status") != "accepted":
            return base
        have = {(it.get("slug") or "").strip().lower() for it in base}
        for it in (rec.get("items") or []):
            slug = (it.get("slug") or "").strip().lower()
            if not slug or slug in have:
                continue
            try:
                qty = max(1, min(int(it.get("qty", 1) or 1), 99))
            except Exception:
                qty = 1
            base.append(_reorder_item_from_slug(slug, qty))
            have.add(slug)
        return base
    except Exception:
        return base


def _accepted_recommendation_slugs(cx, email):
    """Lowercased slugs from the patient's ACCEPTED practitioner recommendation
    (empty set otherwise). The doctor's recommendation IS the authorization to buy,
    so these slugs are entitled at reorder checkout even for a remedy the patient has
    never purchased before — used to union into _portal_entitled_slugs so the
    entitlement gate can't drop a freshly-recommended item. Never raises."""
    try:
        merged = _merge_accepted_recommendation_items(cx, email, [])
        return {(it.get("slug") or "").strip().lower()
                for it in merged if (it.get("slug") or "").strip()}
    except Exception:
        return set()


# ── EVOX remote-session booking routes ───────────────────────────────────────
from datetime import date as _evox_date, timedelta as _evox_td

def _hst_now():
    """Naive wall-clock 'now' in Hawaii (UTC-10, no DST) — matches the naive slot
    grid used by dashboard.evox.available_slots so `s <= now` filters real past."""
    from datetime import datetime as _dt, timezone as _tz, timedelta as _tdd
    return _dt.now(_tz.utc).astimezone(_tz(_tdd(hours=-10))).replace(tzinfo=None)

def appmod_calendar_window(range_name):
    """Forward-looking inclusive (lo, hi) day window for EVOX availability. Unlike
    the console's `_calendar_range_window` (which returns the CURRENT calendar week
    Mon-Sun and would show only PAST days late in the week), this always starts at
    today so a client never sees an un-bookable past slot. '2day' = today+tomorrow;
    anything else = a rolling 7-day window (today .. today+6)."""
    today = _hst_now().date()
    span = 1 if (range_name or "").lower() == "2day" else 6
    return today.isoformat(), (today + _evox_td(days=span)).isoformat()

def _evox_days(range_name):
    lo, hi = appmod_calendar_window(range_name)
    d0 = _evox_date.fromisoformat(lo); d1 = _evox_date.fromisoformat(hi)
    return [d0 + _evox_td(days=i) for i in range((d1 - d0).days + 1)]

def _evox_ident(cx, token):
    from dashboard import portal_identity as _pi
    return _pi.resolve_identity(cx, token=token,
                                session_token=request.cookies.get("rm_portal_session", ""),
                                client_login_enabled=_client_login_enabled())

