def _unknown_slugs_in_items(items, modifiers=None):
    """Slugs (item-level, alt-level, or modifier-item-level) not resolvable
    in the live catalog. Order-preserving, de-duplicated. Validation NEVER
    blocks a save — Glen may be saving a work-in-progress program — it only
    surfaces a warning for the editor to display."""
    seen = set()
    unknown = []
    for it in (items or []):
        slug = (it.get("slug") or "").strip()
        if slug and not _get_product(slug) and slug not in seen:
            seen.add(slug)
            unknown.append(slug)
        for alt in (it.get("alts") or []):
            aslug = (alt.get("slug") or "").strip()
            if aslug and not _get_product(aslug) and aslug not in seen:
                seen.add(aslug)
                unknown.append(aslug)
    for mod in (modifiers or []):
        for it in (mod.get("items") or []):
            slug = (it.get("slug") or "").strip()
            if slug and not _get_product(slug) and slug not in seen:
                seen.add(slug); unknown.append(slug)
    return unknown


@app.route("/api/console/condition-programs", methods=["POST"])
def api_console_condition_programs_upsert():
    """Owner console: upsert one condition program (Glen's edit pass).
    Saves regardless of unknown slugs (work-in-progress is fine) but reports
    any item/alt slug not resolvable in the live catalog via unknown_slugs."""
    if not _portal_console_ok():
        return jsonify({"error": "unauthorized"}), 401
    body = request.get_json(silent=True) or {}
    key = (body.get("condition_key") or "").strip()
    if not key:
        return jsonify({"error": "condition_key required"}), 400
    items = body.get("items") or []
    modifiers = body.get("modifiers") or []
    unknown_slugs = _unknown_slugs_in_items(items, modifiers)
    with sqlite3.connect(LOG_DB) as cx:
        cx.row_factory = sqlite3.Row
        _init_support_programs_tables(cx)
        condition_programs.upsert(cx, key, body.get("label") or "",
                                   bool(body.get("consult_recommended")),
                                   items, modifiers)
    return jsonify({"ok": True, "unknown_slugs": unknown_slugs})


@app.route("/api/console/broad-benefit", methods=["POST"])
def api_console_broad_benefit_toggle():
    """Owner console: add or remove a slug from the broad-benefit flag list.
    An unknown slug is still added (Glen may be flagging a product ahead of
    catalog import) but the response flags it via unknown_slug so the editor
    can warn."""
    if not _portal_console_ok():
        return jsonify({"error": "unauthorized"}), 401
    body = request.get_json(silent=True) or {}
    slug = (body.get("slug") or "").strip()
    action = (body.get("action") or "").strip().lower()
    if not slug or action not in ("add", "remove"):
        return jsonify({"error": "slug and action ('add'|'remove') required"}), 400
    with sqlite3.connect(LOG_DB) as cx:
        cx.row_factory = sqlite3.Row
        _init_support_programs_tables(cx)
        if action == "add":
            broad_benefit.add(cx, slug)
        else:
            broad_benefit.remove(cx, slug)
        updated = broad_benefit.all_slugs(cx)
    resp = {"ok": True, "broad_benefit": updated}
    if action == "add" and not _get_product(slug):
        resp["unknown_slug"] = True
    return jsonify(resp)


# ── Condition Support Programs (Slice 3: client eye-condition resolver) ─────
# Maps a client's health tags/conditions to one of the 9 support-program keys,
# with an operator override (dashboard/client_conditions.py) that always wins.
# Console-only in this slice -- no client-facing surface yet.

_SUPPORT_PROGRAM_CONDITION_KEYS = (
    "glaucoma-elevated-iop", "glaucoma-normal-iop", "dry-amd", "wet-amd",
    "senile-cataract", "psc-cataract", "dry-eye", "retinitis-pigmentosa",
    "diabetic-retinopathy",
)

# Normalized (lowercase, hyphens->spaces, collapsed whitespace) tag phrase ->
# one of the 9 support-program keys. UNAMBIGUOUS mappings only -- a bare
# "glaucoma" or "cataract" (no elevated/normal or senile/psc qualifier) is
# deliberately absent here; _condition_key_from_tags treats those as a signal
# to skip, not a match, so the operator must set the specific one via the
# client_conditions override rather than have the resolver guess.
_CONDITION_TAG_MAP = {
    "wet amd": "wet-amd",
    "neovascular amd": "wet-amd",
    "exudative amd": "wet-amd",
    "dry amd": "dry-amd",
    "atrophic amd": "dry-amd",
    "dry eye": "dry-eye",
    "retinitis pigmentosa": "retinitis-pigmentosa",
    "rp": "retinitis-pigmentosa",
    "diabetic retinopathy": "diabetic-retinopathy",
    "dr": "diabetic-retinopathy",
    "psc": "psc-cataract",
    "psc cataract": "psc-cataract",
    "posterior subcapsular": "psc-cataract",
    "senile cataract": "senile-cataract",
    "age related cataract": "senile-cataract",
    "nuclear cataract": "senile-cataract",
    "glaucoma elevated": "glaucoma-elevated-iop",
    "ocular hypertension": "glaucoma-elevated-iop",
    "high iop": "glaucoma-elevated-iop",
    "elevated iop": "glaucoma-elevated-iop",
    "normal tension glaucoma": "glaucoma-normal-iop",
    "normal tension": "glaucoma-normal-iop",
    "low iop glaucoma": "glaucoma-normal-iop",
    "normal iop": "glaucoma-normal-iop",
}

# Bare terms that name a CONDITION FAMILY but not a specific one of the 9 keys
# (a client tagged just "glaucoma" or just "cataract" is ambiguous -- which of
# the two glaucoma/cataract programs applies is a clinical call, not a guess).
_AMBIGUOUS_CONDITION_TERMS = {"glaucoma", "cataract"}


def _normalize_condition_tag(tag):
    t = (tag or "").strip().strip('[]"\'')
    if t.lower().startswith("pb:"):
        t = t[3:]
    t = t.strip().lower().replace("-", " ").replace("_", " ")
    return " ".join(t.split())


def _condition_key_from_tags(tags):
    """First unambiguous match among `tags` (a client's condition/tag strings)
    to one of the 9 support-program condition keys, or None. A bare
    "glaucoma"/"cataract" (no qualifier) is ambiguous and is skipped, not
    guessed -- later tags are still checked."""
    for raw in (tags or []):
        norm = _normalize_condition_tag(raw)
        if not norm or norm in _AMBIGUOUS_CONDITION_TERMS:
            continue
        key = _CONDITION_TAG_MAP.get(norm)
        if key:
            return key
    return None


def _client_condition_for(email):
    """Resolve a client's eye-condition support-program key: the operator
    override (dashboard/client_conditions.py) wins; otherwise auto-detect from
    the client's `people.conditions` + `people.tags`. Best-effort -- any error
    returns None, never raises."""
    email = (email or "").strip().lower()
    if not email:
        return None
    try:
        from dashboard import client_conditions as _cc
        with sqlite3.connect(LOG_DB) as cx:
            cx.row_factory = sqlite3.Row
            _cc.init_table(cx)
            override = _cc.get(cx, email)
            if override:
                return override
            row = cx.execute(
                "SELECT conditions, tags FROM people WHERE lower(email)=lower(?)",
                (email,)).fetchone()
            if not row:
                return None
            tags = []
            for col in ("conditions", "tags"):
                try:
                    v = json.loads(row[col] or "[]")
                except Exception:
                    v = []
                if isinstance(v, list):
                    tags.extend(str(x) for x in v)
            return _condition_key_from_tags(tags)
    except Exception:
        return None


def _support_program_item_view(it):
    """One authored program item -> the portal-facing shape: {name, url,
    dose?, note?, alts?}. Carries dose/note only when present; each alt ->
    {name, url}. Does NOT apply _qty_eligible/never-recommend filtering --
    these are Glen's explicit authored lists, rendered exactly as stored."""
    slug = (it.get("slug") or "").strip()
    view = {"name": it.get("name") or slug, "url": order_destination.destination_for(slug)}
    if it.get("dose"):
        view["dose"] = it["dose"]
    if it.get("note"):
        view["note"] = it["note"]
    alts = it.get("alts") or []
    if alts:
        view["alts"] = [
            {"name": a.get("name") or (a.get("slug") or "").strip(),
             "url": order_destination.destination_for((a.get("slug") or "").strip())}
            for a in alts
        ]
    return view


def _client_facts_for(email):
    """Per-client intake facts driving client-reported program modifiers.
    Best-effort; any error returns {}."""
    try:
        from dashboard import client_facts as _cf
        with sqlite3.connect(LOG_DB) as cx:
            cx.row_factory = sqlite3.Row
            return _cf.get_facts(cx, email)
    except Exception:
        return {}


_CLIENT_FACT_COPY = {
    "on_areds2": {
        "label": "I'm already taking an AREDS2 eye formula (e.g. PreserVision).",
        "hint": "We'll skip the three Macular Wellness carotenoids your AREDS2 already covers.",
    },
}

ALLOWED_CLIENT_FACT_KEYS = set(_CLIENT_FACT_COPY.keys())  # e.g. {"on_areds2"}


def _client_facts_offered(prog, facts):
    """Client-reported modifier facts this program exposes, with current values.
    De-duped by modifier `when`; only keys we have copy for are surfaced."""
    out, seen = [], set()
    for mod in (prog.get("modifiers") or []):
        if mod.get("source") != "client-reported":
            continue
        key = mod.get("when")
        if not key or key in seen or key not in _CLIENT_FACT_COPY:
            continue
        seen.add(key)
        copy = _CLIENT_FACT_COPY[key]
        out.append({"key": key, "label": copy["label"], "hint": copy["hint"],
                    "value": bool(facts.get(key))})
    return out


PRL_LINK = "https://truly.vip/prl"  # Glen's practitioner ordering link (code 021a1a)


def _prl_ff_view(best_ff, relation):
    if not best_ff:
        return None
    try:
        slug = _resolve_remedy_slug({"name": best_ff})
    except Exception:
        slug = None
    return {"name": best_ff, "relation": relation or "consider", "slug": slug}


def _prl_supplement_for(email, scan_date):
    """The client's PRL Supplement card, or None (flag off / no scan / no coverage).
    Best-effort — any error returns None, never raises. Uses a captured per-scan
    mirror verbatim when present, else derives from the scan's item codes.

    `focus_areas_for_items` returns ALL item-matched focus areas ranked by hit
    count, including ones with no PRL products (uncovered) -- it does not filter
    those out. Dropping uncovered focus areas must happen INSIDE the ranked walk,
    not via a pre-slice to 6: a pre-slice can let uncovered focus areas that
    out-rank a covered one consume all 6 slots and starve the card of real
    entries. So here we rank all, then walk keeping only covered focus areas,
    stopping once 6 covered ones are collected."""
    if not _prl_supplement_enabled():
        return None
    try:
        from dashboard import prl_supplement as _prl
        with sqlite3.connect(LOG_DB) as cx:
            cx.row_factory = sqlite3.Row
            _prl.init_tables(cx)
            email_norm = (email or "").strip().lower()
            dates = [r[0] for r in cx.execute(
                "SELECT DISTINCT scan_date FROM scan_recommendations "
                "WHERE email=? AND scan_date IS NOT NULL AND scan_date<>'' "
                "ORDER BY scan_date DESC", (email_norm,)).fetchall()]
            if not dates:
                return None
            sd = (scan_date or "").strip()
            picked = sd if (sd and sd in dates) else dates[0]
            rows = cx.execute(
                "SELECT scan_id, item_code, label FROM scan_recommendations "
                "WHERE email=? AND scan_date=? ORDER BY priority_rank",
                (email_norm, picked)).fetchall()
            if not rows:
                return None
            scan_id = rows[0]["scan_id"]
            codes = [r["item_code"] for r in rows]
            code_labels = {}
            for r in rows:
                bare_c = (r["item_code"] or "").split(" - ")[0]
                code_labels[bare_c] = r["label"] or r["item_code"]

            # 1) mirror override
            mirror = _prl.mirror_for_scan(cx, scan_id)
            if mirror and isinstance(mirror.get("patterns"), list):
                fas = []
                for p in mirror["patterns"]:
                    prods = []
                    for pr in (p.get("PRLProducts") or []):
                        nm = pr.get("Name")
                        prow = cx.execute(
                            "SELECT url, best_ff, relation FROM prl_products WHERE name=?",
                            (nm,)).fetchone()
                        prods.append({"name": nm,
                                      "url": (prow["url"] if prow else None),
                                      "ff": _prl_ff_view(prow["best_ff"], prow["relation"]) if prow else None})
                    fas.append({"name": p.get("Name"),
                                "items": [it.get("ScanItemName") for it in (p.get("PatternItems") or [])],
                                "products": prods})
                if fas:
                    return {"source": "mirror", "prl_link": PRL_LINK, "focus_areas": fas}

            # 2) derive -- rank all item-matched focus areas, keep only covered
            # ones while walking (do NOT slice to 6 before filtering: see
            # docstring above for why that starves the card).
            bare = [(c or "").split(" - ")[0] for c in codes]
            ranked = _prl.focus_areas_for_items(cx, bare)
            fas = []
            for fa in ranked:
                prods = []
                for pr in _prl.products_for_focus_area(cx, fa["focus_area_id"]):
                    prods.append({"name": pr["name"], "url": pr.get("url"),
                                  "ff": _prl_ff_view(pr.get("best_ff"), pr.get("relation"))})
                if not prods:
                    continue
                fa_codes = {r["item_code"] for r in cx.execute(
                    "SELECT item_code FROM prl_focus_area_items WHERE focus_area_id=?",
                    (fa["focus_area_id"],)).fetchall()}
                matched = [code_labels.get(bc, bc) for bc in bare if bc in fa_codes]
                fas.append({"name": fa["focus_area_name"], "items": matched, "products": prods})
                if len(fas) >= 6:
                    break
            if not fas:
                return None
            return {"source": "derived", "prl_link": PRL_LINK, "focus_areas": fas}
    except Exception:
        return None


def _support_program_for(email):
    """The (member-aware) client's support-program portal card, or None when
    the flag is off, the client has no resolved condition, or the resolved
    program doesn't exist. Best-effort -- any error returns None, never
    raises. Item order is preserved from the authored program, with the
    resolver's modifiers (base ± diagnosis-implied/client-reported) applied."""
    try:
        key = _client_condition_for(email)
        if not key:
            return None
        with sqlite3.connect(LOG_DB) as cx:
            cx.row_factory = sqlite3.Row
            _init_support_programs_tables(cx)
            prog = condition_programs.get(cx, key)
        if not prog:
            return None
        facts = _client_facts_for(email)
        resolved = condition_programs.resolve_program_items(
            prog, audience="client", client_facts=facts)
        result = {
            "condition_key": prog["condition_key"],
            "label": prog["label"],
            "consult_recommended": bool(prog["consult_recommended"]),
            "items": [_support_program_item_view(it) for it in resolved],
        }
        offered = _client_facts_offered(prog, facts)
        if offered:
            result["client_facts"] = offered
        return result
    except Exception:
        return None


def _life_stress_for(email):
    """The client's Life Stress essence recommendation (E4L scan emotion patterns
    matched to supportive Terrain Restore essences), or None when there's no scan,
    no matched emotions, or no resolvable essence. Best-effort — any error returns
    None, never raises. When the practitioner has curated this client's essences,
    the curation replaces the auto-pool (block gets curated=True)."""
    try:
        import datetime as _dt_ls
        block = life_stress.recommend(email, _dt_ls.date.today().isoformat())
        from dashboard import life_stress_curation
        with sqlite3.connect(LOG_DB) as _cx_lsc:
            block = life_stress_curation.apply(_cx_lsc, email, block, _PRODUCTS)
        return block
    except Exception:
        return None


def _practitioner_program_card(email):
    """The client-facing card for a practitioner-composed program (Task 5).
    Distinct from `_support_program_for` (the condition-driven program) and
    from the reco-card (the one-shot AI nudge) -- this is the practitioner's
    standing, hand-composed program for this patient. Best-effort: None on
    any error, when the flag is off, or when no program is saved."""
    if not _program_composer_enabled():
        return None
    try:
        from dashboard import practitioner_programs as _pgm
        with sqlite3.connect(LOG_DB) as cx:
            cx.row_factory = sqlite3.Row
            saved = _pgm.get(cx, email)
            if not saved:
                return None
            _init_support_programs_tables(cx)
            prog = condition_programs.get(cx, saved.get("condition_key")) if saved.get("condition_key") else None
        label = (prog or {}).get("label") or "Your Practitioner's Program"
        return {"label": label, "note": saved.get("note") or "",
                "items": [_support_program_item_view(it) for it in (saved.get("items") or [])]}
    except Exception:
        return None


def _practitioner_candidate_view(it):
    """One authored/modifier program item -> the practitioner-composer candidate
    shape: {slug, name, dose?, alts?}. Names/slug only — the client card later
    runs `_support_program_item_view` for URLs."""
    v = {"slug": (it.get("slug") or "").strip(), "name": it.get("name") or (it.get("slug") or "")}
    if it.get("dose"): v["dose"] = it["dose"]
    if it.get("alts"): v["alts"] = [{"slug": a.get("slug"), "name": a.get("name")} for a in it["alts"]]
    return v


@app.route("/api/practitioner/condition-program/<path:patient_email>", methods=["GET"])
def api_practitioner_condition_program_get(patient_email):
    """The practitioner's condition-program composer candidate list for a
    patient (Task 3): the authored program's base items plus each modifier's
    items, pre-checked per `condition_programs.resolve_program_items` (so
    diagnosis-implied+client_default and client-reported-with-fact items come
    back checked; clinician-measured items always come back unchecked, since
    the resolver never auto-applies those — the practitioner toggles them by
    hand), alongside any already-saved practitioner_programs row."""
    if not _program_composer_enabled():
        return ("", 404)
    pid = _practitioner_session_pid()
    if not pid:
        return jsonify({"ok": False, "error": "not signed in"}), 401
    email = (patient_email or "").strip().lower()
    from dashboard import continuity_view as _cv, practitioner_programs as _pgm
    with sqlite3.connect(LOG_DB) as cx:
        cx.row_factory = sqlite3.Row
        _continuity_cx(cx)
        if not _cv.authorized_patient(cx, pid, email):
            return jsonify({"ok": False, "error": "not authorized for this patient"}), 403
        key = _client_condition_for(email)
        _init_support_programs_tables(cx)
        prog = condition_programs.get(cx, key) if key else None
        saved = _pgm.get(cx, email)
    if not prog:
        return jsonify({"ok": True, "condition_key": key, "label": None,
                        "candidates": [], "saved": (saved and {"items": saved["items"], "note": saved["note"]})})
    resolved = {(it.get("slug") or "") for it in condition_programs.resolve_program_items(
        prog, audience="practitioner", client_facts=_client_facts_for(email))}
    candidates = []
    for it in (prog.get("items") or []):
        candidates.append({**_practitioner_candidate_view(it), "section": "base", "checked": True})
    for mod in (prog.get("modifiers") or []):
        if mod.get("action") != "add":
            continue
        for it in (mod.get("items") or []):
            candidates.append({**_practitioner_candidate_view(it), "section": "modifier",
                               "when": mod.get("when"), "source": mod.get("source"),
                               "checked": (it.get("slug") or "") in resolved})
    return jsonify({"ok": True, "condition_key": prog["condition_key"], "label": prog["label"],
                    "candidates": candidates,
                    "saved": (saved and {"items": saved["items"], "note": saved["note"]})})


@app.route("/api/practitioner/condition-program", methods=["POST"])
def api_practitioner_condition_program_save():
    """Save the practitioner's composed condition program for a patient
    (Task 4) — the write side of Task 3's candidate list. Same guard order
    as the GET: flag off -> 404, no pid -> 401, not authorized -> 403
    (checked BEFORE any write)."""
    if not _program_composer_enabled():
        return ("", 404)
    pid = _practitioner_session_pid()
    if not pid:
        return jsonify({"ok": False, "error": "not signed in"}), 401
    body = request.get_json(silent=True) or {}
    email = (body.get("patient_email") or "").strip().lower()
    from dashboard import continuity_view as _cv, practitioner_programs as _pgm
    with sqlite3.connect(LOG_DB) as cx:
        cx.row_factory = sqlite3.Row
        _continuity_cx(cx)
        if not _cv.authorized_patient(cx, pid, email):
            return jsonify({"ok": False, "error": "not authorized for this patient"}), 403
        _pgm.upsert(cx, patient_email=email, practitioner_id=pid,
                    condition_key=(body.get("condition_key") or ""),
                    items=body.get("items") or [], note=body.get("note") or "")
    return jsonify({"ok": True, "saved": True})


@app.route("/api/portal/<token>/support-program/add-to-invoice", methods=["POST"])
def api_portal_support_program_add_to_invoice(token):
    """The paid add-to-invoice action for the condition support-program card
    (Slice 4b) — the MONEY-WRITE step. Creates ONE unpaid, unpublished invoice
    draft (`orders` row), idempotently keyed on (email, condition_key) via a
    deterministic external_ref, priced at the client's real FF price
    (_ff_line_cents, same pricer as the FF add-to-invoice endpoint).

    THE GATE IS DIFFERENT FROM FF: this is open to ANY client who resolves to a
    support program (they've been tagged with an eye condition) — there is no
    _ff_covered / entitlement check here, deliberately. A client with no
    resolved condition is rejected (409); everyone else, covered or not, may
    queue their program onto an invoice for Rae to finalize.

    Only the program's PRIMARY items are priced/queued — `alts` are either/or
    choices Rae finalizes in the composer, not auto-added."""
    if not _support_programs_enabled():
        return ("", 404)
    with sqlite3.connect(LOG_DB) as cx:
        cx.row_factory = sqlite3.Row
        from dashboard import client_portal as _cp
        _cp.init_client_portal_table(cx)
        portal = _portal_record_for(cx, token)
        if not portal:
            return jsonify({"error": "unknown token"}), 404
        email = (portal.get("email") or "").strip().lower()
        # same ?member= household resolution as api_portal_ff_matches (fail-closed)
        if _household_view_enabled() and email:
            try:
                from dashboard import household as _hh
                with sqlite3.connect(LOG_DB) as _cxh:
                    _hh.init_household_tables(_cxh)
                    _m = (request.args.get("member")
                          or (request.get_json(silent=True) or {}).get("member")
                          or "").strip().lower()
                    if _m and _hh.can_view(_cxh, email, _m):
                        email = _m
            except Exception as _e:
                print(f"[support-program/add-to-invoice] household {_e!r}", flush=True)
        sp = _support_program_for(email)
        if not sp or not sp.get("items"):
            return jsonify({"error": "no support program"}), 409
        # Consult-recommended conditions (e.g. Wet AMD) are not one-click orderable:
        # the client is directed to book a consultation for an individualized program.
        # The group + product-page order links still show; only the add-to-invoice is withheld.
        if sp.get("consult_recommended"):
            return jsonify({"error": "consultation recommended"}), 409
        key = sp["condition_key"]
        _init_support_programs_tables(cx)
        prog = condition_programs.get(cx, key)
        raw_items = condition_programs.resolve_program_items(
            (prog or {}), audience="client", client_facts=_client_facts_for(email))
        ext = f"SPINV-{email}-{key}"  # deterministic -> idempotent via UNIQUE(source, external_ref)
        # Insert-once: never rewrite an existing support-program-invoice order. A second
        # click after Rae has priced/advanced or paid the order must not touch it.
        existing = _bos_orders.find_order_by_external_ref(cx, ext)
        if existing and existing.get("source") == "in-house":
            return jsonify({"ok": True, "order_ref": ext, "already_added": True})
        from dashboard import client_prices as _cp_init
        _cp_init.init_table(cx)
        items = []
        for it in raw_items:  # PRIMARY items only -- alts are either/or, not auto-added
            slug = (it.get("slug") or "").strip()
            unit = _ff_line_cents(cx, email, slug)
            items.append({"slug": slug, "name": it.get("name") or slug,
                          "qty": 1, "unit_cents": unit, "line_cents": unit})
        total = sum(i["line_cents"] for i in items)
        _bos_orders.upsert_order(
            cx, source="in-house", external_ref=ext, status="proposed",
            email=email, name=(portal.get("name") or ""),
            items=items, total_cents=total, channel="support-program",
            invoice_note=f"{sp['label']} support program — pending Rae invoicing")
        cx.commit()
        return jsonify({"ok": True, "order_ref": ext})


@app.route("/api/portal/<token>/client-fact", methods=["POST"])
def api_portal_client_fact(token):
    """Client self-reports a boolean intake fact (e.g. on_areds2) that drives a
    client-reported program modifier. Identity comes from the portal TOKEN, never
    the body. Key is whitelisted so this can't set arbitrary facts. Returns the
    re-resolved support_program for a live card re-render."""
    if not _support_programs_enabled():
        return ("", 404)
    body = request.get_json(silent=True) or {}
    key = (body.get("key") or "").strip()
    if key not in ALLOWED_CLIENT_FACT_KEYS:
        return jsonify({"ok": False, "error": "unknown fact key"}), 400
    with sqlite3.connect(LOG_DB) as cx:
        cx.row_factory = sqlite3.Row
        portal = _portal_record_for(cx, token)
        if not portal:
            return jsonify({"ok": False, "error": "unknown token"}), 404
        email = (portal.get("email") or "").strip().lower()
        from dashboard import client_facts as _cf
        _cf.set_fact(cx, email, key, bool(body.get("value")))
    return jsonify({"ok": True, "support_program": _support_program_for(email)})


@app.route("/api/portal/<token>/life-stress/selection", methods=["POST"])
def api_portal_life_stress_selection(token):
    """Save the client's Life Stress essence SELECTION (a preference, not an order).
    No invoice/Stripe/QBO is written — only life_stress_selections. Only slugs in the
    client's current pool are kept (a client can only prefer what they were offered)."""
    if not _life_stress_enabled():
        return ("", 404)
    with sqlite3.connect(LOG_DB) as cx:
        cx.row_factory = sqlite3.Row
        from dashboard import client_portal as _cp
        _cp.init_client_portal_table(cx)
        portal = _portal_record_for(cx, token)
        if not portal:
            return jsonify({"error": "unknown token"}), 404
        email = (portal.get("email") or "").strip().lower()
        # same ?member= household resolution as the support-program endpoint (fail-closed)
        if _household_view_enabled() and email:
            try:
                from dashboard import household as _hh
                with sqlite3.connect(LOG_DB) as _cxh:
                    _hh.init_household_tables(_cxh)
                    _m = (request.args.get("member")
                          or (request.get_json(silent=True) or {}).get("member")
                          or "").strip().lower()
                    if _m and _hh.can_view(_cxh, email, _m):
                        email = _m
            except Exception as _e:
                print(f"[life-stress/selection] household {_e!r}", flush=True)
        # pool-filter: keep only slugs the client was actually offered
        block = _life_stress_for(email) or {}
        pool = {it.get("slug") for it in block.get("items", []) if it.get("slug")}
        submitted = [str(s).strip() for s in ((request.get_json(silent=True) or {}).get("slugs") or []) if str(s).strip()]
        filtered = [s for s in submitted if s in pool]
        life_stress_selection.set(cx, email, filtered)
        return jsonify({"ok": True, "saved": filtered})


@app.route("/api/practitioner/life-stress-selection/<path:patient_email>", methods=["GET"])
def api_practitioner_life_stress_selection(patient_email):
    """Read-only view of a client's saved Life Stress essence selection, for the
    practitioner (Glen/Rae). Returns the full pool + which slugs the client picked.
    Same guard order as the condition-program composer GET: flag off -> 404,
    no pid -> 401, not authorized -> 403 (checked before any patient data read)."""
    if not _life_stress_enabled():
        return ("", 404)
    pid = _practitioner_session_pid()
    if not pid:
        return jsonify({"ok": False, "error": "not signed in"}), 401
    email = (patient_email or "").strip().lower()
    from dashboard import continuity_view as _cv
    from dashboard import life_stress_curation
    with sqlite3.connect(LOG_DB) as cx:
        cx.row_factory = sqlite3.Row
        _continuity_cx(cx)
        if not _cv.authorized_patient(cx, pid, email):
            return jsonify({"ok": False, "error": "not authorized for this patient"}), 403
        selected = life_stress_selection.get(cx, email)
        row = cx.execute("SELECT updated_at FROM life_stress_selections WHERE email=?",
                         (email,)).fetchone()
        cur = life_stress_curation.get(cx, email)
    import datetime as _dt_lsp
    try:
        block = life_stress.recommend(email, _dt_lsp.date.today().isoformat()) or {}
    except Exception:
        block = {}
    pool = [{"slug": it.get("slug"), "name": it.get("name"),
             "pattern": (it.get("note") or "")} for it in block.get("items", [])]
    return jsonify({"ok": True, "pool": pool, "selected": selected,
                    "updated_at": (row["updated_at"] if row else None),
                    "curation": cur})


@app.route("/api/practitioner/life-stress-curation/<path:patient_email>", methods=["POST"])
def api_practitioner_life_stress_curation(patient_email):
    """Practitioner saves a curated essence list for a client (the prescription that
    replaces the auto-pool). Empty slugs -> clears the curation. Same guard order as
    the life-stress-selection read: flag off -> 404, no pid -> 401, not authorized ->
    403 (checked before any write). No money path -- writes only life_stress_curations."""
    if not _life_stress_enabled():
        return ("", 404)
    pid = _practitioner_session_pid()
    if not pid:
        return jsonify({"ok": False, "error": "not signed in"}), 401
    email = (patient_email or "").strip().lower()
    body = request.get_json(silent=True) or {}
    submitted = [str(s).strip() for s in (body.get("slugs") or []) if str(s).strip()]
    note = str(body.get("note") or "")
    # keep only slugs that resolve to a real product
    prods = (_PRODUCTS.get("products") or {})
    valid = [s for s in submitted if s in prods or life_stress.slug_for_essence(s, _PRODUCTS)]
    from dashboard import continuity_view as _cv
    from dashboard import life_stress_curation
    with sqlite3.connect(LOG_DB) as cx:
        cx.row_factory = sqlite3.Row
        _continuity_cx(cx)
        if not _cv.authorized_patient(cx, pid, email):
            return jsonify({"ok": False, "error": "not authorized for this patient"}), 403
        if valid:
            life_stress_curation.set(cx, email, pid, valid, note)
        else:
            life_stress_curation.clear(cx, email)
    return jsonify({"ok": True, "saved": valid})


@app.route("/api/practitioner/terrain-restore-catalog", methods=["GET"])
def api_practitioner_terrain_restore_catalog():
    """All Terrain Restore products (essences + tinctures + gemmos), for the
    practitioner's Life Stress substitution search. Signed-in practitioner only;
    not per-patient (it's a catalog, not patient data)."""
    if not _life_stress_enabled():
        return ("", 404)
