@app.route("/api/portal/<token>/chat", methods=["POST", "OPTIONS"])
def api_portal_chat(token):
    if request.method == "OPTIONS":
        return "", 200
    data = request.get_json() or {}
    query = (data.get("query") or "").strip()
    history = data.get("history") or []
    with sqlite3.connect(LOG_DB) as cx:
        from dashboard import client_portal as _cp
        _cp.init_client_portal_table(cx)
        portal = _portal_record_for(cx, token)
    if not portal:
        return jsonify({"error": "not found"}), 404
    email = (portal.get("email") or "").strip().lower()
    content = portal.get("content") or {}
    try:
        with sqlite3.connect(LOG_DB) as ocx:
            ocx.row_factory = sqlite3.Row
            from dashboard import orders as _o
            client_orders = _o.list_orders_by_email(ocx, email)
    except Exception:
        client_orders = []
    from dashboard import portal_concierge as _pcz
    ctx = _pcz.build_context(content, client_orders)
    _sys = _pcz.system_prompt(ctx)
    _ally_ov = ash_ally.ally_overlay(LOG_DB, email)
    if _ally_ov:
        _sys = _ally_ov + "\n\n" + _sys
    # RAG (best-effort, fail-open) — embed the query ONCE and reuse for both the
    # knowledge base and Community content retrieval.
    context_str = ""
    qvec = None
    try:
        qvec = embed(query)
        matches = _match_query_namespaces(qvec)
        context_str, _ = build_context(matches) if matches else ("", [])
    except Exception as e:
        print(f"[portal-concierge] retrieval: {e}", flush=True)
    community_related = []
    if qvec is not None:
        try:
            with sqlite3.connect(LOG_DB) as ccx:
                ccx.row_factory = sqlite3.Row
                community_related = _community_related(ccx, qvec, _is_paid_member(email), k=2)
        except Exception as e:
            print(f"[community-chat] related: {e}", flush=True)
    if community_related:
        titles = "; ".join(r["title"] for r in community_related)
        context_str = (context_str + "\n" if context_str else "") + \
            f"Relevant community sessions the member can open: {titles}."
    messages = []
    for m in history[-8:]:
        c = (m.get("content") or "").strip()
        if not c:
            continue  # Anthropic rejects empty content strings
        r = "user" if m.get("role") == "user" else "assistant"
        messages.append({"role": r, "content": c[:2000]})
    user_block = (f"CONTEXT:\n{context_str}\n\n" if context_str else "") + query
    messages.append({"role": "user", "content": user_block})

    def generate():
        if community_related:
            yield sse({"related": community_related})
        full = []
        try:
            with _cl.messages.stream(model="claude-haiku-4-5-20251001", max_tokens=700,
                                     system=_sys, messages=messages) as stream:
                for tok in stream.text_stream:
                    tok = _strip_dash(tok); full.append(tok); yield sse({"token": tok})
        except Exception as e:
            yield sse({"error": f"Claude error: {e}"}); return
        answer = "".join(full)
        try:
            import threading as _t
            _t.Thread(target=ash_ally.record_turn,
                      args=(LOG_DB, _db_lock, email, query, answer),
                      daemon=True).start()
        except Exception:
            pass
        # Persist the turn to the durable portal chat thread (remembered across
        # sessions; Dr. Glen can reply into it from the console).
        try:
            from dashboard import portal_chat as _pchat
            with _db_lock, sqlite3.connect(LOG_DB) as _pcx:
                _pchat.record_exchange(_pcx, email, query, answer,
                                       client_name=(portal.get("name") or "You"))
        except Exception as e:
            print(f"[portal-chat] persist failed: {e!r}", flush=True)
        # Triage: flag messages that need Dr. Glen's attention -> console + email him.
        try:
            import threading as _t2
            _t2.Thread(target=_triage_portal_message,
                       args=(email, portal.get("name") or "", query, answer),
                       daemon=True).start()
        except Exception:
            pass
        # Refresh the member's TCM element state from their recent chat (paid
        # members only; drives the Glendalf backdrop). Fire-and-forget, text mode.
        try:
            import threading as _t3

            def _refresh_element(em):
                try:
                    if not _active_membership_for_email(em):
                        return
                    from dashboard import portal_element, member_element_state
                    with sqlite3.connect(LOG_DB) as _rcx:
                        scores = portal_element.analyze(_rcx, em)
                    if not scores:
                        return
                    with _db_lock, sqlite3.connect(LOG_DB) as _wcx:
                        member_element_state.upsert(_wcx, em, scores, source="portal_chat")
                except Exception as e:
                    print(f"[portal-element] refresh failed: {e!r}", flush=True)

            _t3.Thread(target=_refresh_element, args=(email,), daemon=True).start()
        except Exception:
            pass
        try:
            convo = "\n".join(f"{m['role']}: {m['content']}" for m in messages[-2:]) + f"\nassistant: {answer}"
            mx = _cl.messages.create(model="claude-haiku-4-5-20251001", max_tokens=120,
                                     system=_CONCIERGE_EXTRACT_SYSTEM,
                                     messages=[{"role": "user", "content": convo[:3500]}])
            txt = mx.content[0].text.strip()
            if txt.startswith("```"):
                txt = txt.split("```", 2)[1]
                if txt.startswith("json\n"): txt = txt[5:]
            obj = json.loads(txt)
            if obj.get("suggest") and obj.get("name"):
                c = _resolve_complement(obj["name"])
                if c and (c["in_catalog"] or c["url"]):
                    yield sse({"suggestion": c})
        except Exception as e:
            print(f"[portal-concierge] extract: {e!r}", flush=True)
        yield sse({"done": True})

    return Response(stream_with_context(generate()), content_type="text/event-stream",
                    headers={"Cache-Control": "no-cache", "X-Accel-Buffering": "no"})


@app.route("/api/console/portal/<path:email>/messages")
def api_console_portal_messages(email):
    """Console: read a client's persisted portal chat thread (console-gated)."""
    if not _portal_console_ok():
        return jsonify({"error": "unauthorized"}), 401
    return jsonify({"email": (email or "").strip().lower(),
                    "messages": _portal_chat_thread(email)})


def _notify_client_of_reply(email, name):
    """Best-effort: email the client that Dr. Glen replied, linking their portal.
    Respects opt-out; suppression handled downstream. Returns True if sent."""
    email = (email or "").strip().lower()
    if not email:
        return False
    try:
        from dashboard import notify_state as _ns
        from dashboard import client_portal as _cp
        with _db_lock, sqlite3.connect(LOG_DB) as cx:
            _ns.init_table(cx)
            if _ns.get_state(cx, email).get("opt_status") == "out":
                return False
            token = _cp.ensure_token(cx, email, name or "")
        link = portal_link(token)
        _send_full_report_email(
            email, name, "Dr. Glen replied to you 🌺",
            f"Aloha {name or ''},\n\nDr. Glen just replied to you in your Healing Oasis "
            f"portal. Come read it and continue the conversation here:\n\n{link}\n\n"
            f"With aloha,\nDr. Glen & Rae")
        return True
    except Exception as e:
        print(f"[portal-chat] reply notify failed: {e!r}", flush=True)
        return False


@app.route("/api/console/portal/<path:email>/message", methods=["POST"])
def api_console_portal_message(email):
    """Console: Dr. Glen (or Rae) posts a reply into a client's portal chat thread.
    Appears in the client's chat as a practitioner message and persists; by default
    also emails the client that a reply is waiting (pass notify=false to skip)."""
    if not _portal_console_ok():
        return jsonify({"error": "unauthorized"}), 401
    data = request.get_json(silent=True) or {}
    content = (data.get("content") or "").strip()
    author = (data.get("author") or "Dr. Glen").strip() or "Dr. Glen"
    notify = data.get("notify", True)
    if not content:
        return jsonify({"error": "empty message"}), 400
    from dashboard import portal_chat as _pchat
    from dashboard import client_portal as _cp
    with _db_lock, sqlite3.connect(LOG_DB) as cx:
        mid = _pchat.add_message(cx, email, _pchat.PRACTITIONER, content, author=author)
        rec = _cp.get_portal_content_by_email(cx, email) or {}
    notified = False
    if mid is not None and notify:
        notified = _notify_client_of_reply(email, rec.get("name") or "")
    return jsonify({"ok": mid is not None, "id": mid, "notified": notified})


@app.route("/api/console/portal/<path:email>/draft-reply", methods=["POST"])
def api_console_portal_draft_reply(email):
    """Console: AI-draft Dr. Glen's personal reply to a client's latest portal-chat
    message (grounded in their thread + portal data), to seed the composer. Glen
    edits then sends. Console-gated; drafting only — nothing is posted or emailed."""
    if not _portal_console_ok():
        return jsonify({"error": "unauthorized"}), 401
    from dashboard import portal_chat as _pchat, portal_concierge as _pcz, client_portal as _cp
    with sqlite3.connect(LOG_DB) as cx:
        msgs = _pchat.list_messages(cx, email, limit=20)
        rec = _cp.get_portal_content_by_email(cx, email) or {}
    if not msgs:
        return jsonify({"ok": True, "draft": ""})
    try:
        with sqlite3.connect(LOG_DB) as ocx:
            ocx.row_factory = sqlite3.Row
            from dashboard import orders as _o
            orders = _o.list_orders_by_email(ocx, email)
    except Exception:
        orders = []
    ctx = _pcz.build_context(rec.get("content") or {}, orders)
    sys = _pcz.system_prompt(ctx) + (
        "\n\nYou are drafting DR. GLEN'S OWN personal reply to this client (first person, warm, "
        "signed 'Dr. Glen'), to address their most recent message in the thread below. Keep it "
        "concise and grounded in their data. If it needs a consultation, a custom Terrain "
        "Restore, or clinical judgment, say Dr. Glen will follow up personally.")
    who = lambda m: ("Client" if m["role"] in ("client", "user")
                     else ("Dr. Glen" if m["role"] == "practitioner" else "Assistant"))
    convo = "\n".join(f"{who(m)}: {m['content']}" for m in msgs[-12:])
    try:
        r = _cl.messages.create(model="claude-haiku-4-5-20251001", max_tokens=500, system=sys,
                                messages=[{"role": "user",
                                           "content": "CONVERSATION:\n" + convo + "\n\nDraft Dr. Glen's reply:"}])
        draft = _strip_dash(r.content[0].text.strip())
    except Exception as e:
        return jsonify({"ok": False, "error": str(e)[:200]}), 502
    return jsonify({"ok": True, "draft": draft})


def _triage_portal_message(email, name, query, answer):
    """Background: classify a client's portal message; if it needs Dr. Glen's
    attention, store a triage item and email him full context + a recommendation."""
    try:
        from dashboard import portal_triage as _pt

        def _complete(system, user):
            m = _cl.messages.create(model="claude-haiku-4-5-20251001", max_tokens=300,
                                    system=system, messages=[{"role": "user", "content": user}])
            return m.content[0].text

        res = _pt.classify(_complete, query, answer)
        if not res:
            return
        with _db_lock, sqlite3.connect(LOG_DB) as cx:
            _pt.add_item(cx, email, name, res["category"], res["urgency"],
                         res["summary"], res["recommendation"], query, answer)
        # All flagged items show in the console queue + roll into the daily digest;
        # only HIGH urgency emails Dr. Glen immediately.
        if res["urgency"] != "high":
            return
        subject = f"[Portal triage · {res['urgency']}] {res['category']} — {name or email}"
        try:
            token = None
            with _db_lock, sqlite3.connect(LOG_DB) as cx:
                from dashboard import client_portal as _cp
                token = _cp.ensure_token(cx, email, name or "")
            link = portal_link(token) if token else ""
        except Exception:
            link = ""
        body = (f"A client message may need your attention.\n\n"
                f"Client: {name or ''} <{email}>\n"
                f"Category: {res['category']}   Urgency: {res['urgency']}\n\n"
                f"What they need: {res['summary']}\n"
                f"Recommendation: {res['recommendation']}\n\n"
                f"--- Their message ---\n{query}\n\n"
                f"--- AI answer given ---\n{answer}\n\n"
                f"Reply in their portal chat (console → Biofield Portal Editor → Portal chat),"
                f" or open their portal:\n{link}\n")
        try:
            _send_full_report_email("drglenswartwout@gmail.com", "Dr. Glen", subject, body)
        except Exception as e:
            print(f"[triage] email failed: {e!r}", flush=True)
    except Exception as e:
        print(f"[triage] {e!r}", flush=True)


