def _portal_entitled_slugs(email):
    """The set of slugs this portal client is entitled to reorder — their own
    portal-channel purchase history (the SAME source Task 5's `reorder` module
    displays; see _portal_reorder_module). Used to guard Task 6b's per-item
    checkout so a posted body can never charge an arbitrary catalog SKU the
    client never actually bought through the portal. Never raises; empty set
    on any lookup failure (fails closed — an empty set rejects every slug)."""
    try:
        mod = _portal_reorder_module(email)
    except Exception as e:
        print(f"[portal-reorder] entitlement lookup failed for {email!r}: {e!r}", flush=True)
        return set()
    return {(row.get("slug") or "").strip().lower()
            for row in (mod.get("reorder") or []) if row.get("slug")}


@app.route("/api/portal/<token>/checkout", methods=["POST"])
def api_client_portal_checkout(token):
    """Build a real live Stripe checkout for the client's remedies at their
    portal price. Two sources for WHICH items get charged:

    - Task 6b: an optional JSON body {items:[{slug, qty}]} (or the {slug, qty}
      shorthand for a single row) charges EXACTLY those items — this is what
      each per-row "Reorder" button now posts, so clicking a row reorders that
      row's product, not the whole curated cart. Every posted slug is checked
      against _portal_entitled_slugs (the client's own purchase history) and
      rejected if it isn't there; qty is clamped; any posted price/price_cents
      is dropped on the floor — price is ALWAYS computed server-side by
      _portal_priced_lines, never trusted from the client.
    - Absent body (unchanged, backward compatible): the practitioner-curated
      `content.reorder_items` cart, per-item practitioner-special override
      honored, exactly as before Task 6b.

    Either way, pricing goes through the SAME repertoire-aware
    _portal_priced_lines (Task 5b), so member pricing holds; the add-then-
    confirm + QBO invoice + Stripe-URL flow is identical either way."""
    from dashboard import client_portal as _cp
    with sqlite3.connect(LOG_DB) as cx:
        _cp.init_client_portal_table(cx)
        portal = _portal_record_for(cx, token)
    if not portal:
        return jsonify({"error": "not found"}), 404
    email = (portal.get("email") or "").strip().lower()
    body = request.get_json(silent=True) or {}
    posted = body.get("items")
    if posted is None and (body.get("slug") or "").strip():
        posted = [{"slug": body.get("slug"), "qty": body.get("qty", 1)}]
    if posted:
        if not isinstance(posted, list) or not posted:
            return jsonify({"error": "Invalid items."}), 400
        entitled = _portal_entitled_slugs(email)
        # An ACCEPTED doctor recommendation IS the authorization to buy — union its
        # slugs into the entitled set so a never-before-purchased recommended remedy
        # (e.g. its own per-row "Reorder" button) is purchasable. Only accepted-rec
        # slugs are added; general entitlement is NOT broadened.
        try:
            with sqlite3.connect(LOG_DB) as _rcx:
                entitled = entitled | _accepted_recommendation_slugs(_rcx, email)
        except Exception:
            pass  # entitlement-union failure must never break checkout
        if _WISHLIST_ENABLED:
            # The customer's own saved-and-chosen wishlist item is authorization
            # to buy it, same as an accepted recommendation. Union those slugs so
            # a wishlist-only (never-before-purchased) slug is purchasable at the
            # member price. Failure must never break checkout.
            try:
                from dashboard import wishlist as _wl
                with sqlite3.connect(LOG_DB) as _wcx:
                    _wl.init_wishlist_table(_wcx)
                    entitled = entitled | _wl.slugs_for(_wcx, "email:" + email)
            except Exception:
                pass
        items = []
        for it in posted:
            if not isinstance(it, dict):
                return jsonify({"error": "Invalid items."}), 400
            slug = (it.get("slug") or "").strip().lower()
            if not slug or slug not in entitled:
                return jsonify({"error": "That item isn't available to reorder."}), 400
            try:
                qty = max(1, min(int(it.get("qty", 1) or 1), 99))
            except Exception:
                qty = 1
            items.append({"slug": slug, "qty": qty})  # price_cents NEVER accepted from the client
    else:
        # No body = the "Order my remedies" button. Charge the SAME merged set the
        # portal display shows (curated reorder_items + accepted-rec items), so an
        # accepted recommendation actually reaches the invoice instead of 400'ing
        # ("no longer available") or being silently dropped.
        base_items = (portal.get("content") or {}).get("reorder_items") or []
        try:
            with sqlite3.connect(LOG_DB) as _rcx:
                items = _merge_accepted_recommendation_items(_rcx, email, base_items)
        except Exception:
            items = base_items  # merge failure must never break checkout
    lines, items_rec, subtotal_cents = _portal_priced_lines(items, email=email)
    if not lines:
        return jsonify({"error": "Your remedies are no longer available — please reach out and we'll help."}), 400
    if not _STRIPE_ACTIVE:
        return jsonify({"error": "Card checkout is temporarily unavailable. Please reach out and we'll help."}), 503
    try:
        ship = {}
        try:
            with sqlite3.connect(LOG_DB) as cx:
                cx.row_factory = sqlite3.Row
                prior = _bos_orders.list_orders_by_email(cx, email, limit=1)
            if prior:
                ship = prior[0].get("address") or {}
        except Exception:
            ship = {}  # no prior order / address on file — proceed; collected at checkout
        # Paid-only (QBO Stage 3): no QBO customer/invoice exists at checkout time.
        # checkout_ref is the stable order/correlation key; the exact line/discount
        # payload is persisted via set_order_qbo_lines for /begin/checkout-return
        # (kind=="reorder", set by _stripe_checkout_url_for_reorder below) to book a
        # line-faithful QBO Sales Receipt once the customer actually pays.
        checkout_ref = _uuid.uuid4().hex
        qbo_payload = {"lines": lines, "discount_cents": 0, "tax_cents": 0}
        out = {"invoice_id": checkout_ref, "customer_id": "",
               "doc_number": "", "total": round(subtotal_cents / 100.0, 2)}
        _ingest_order(source="portal-reorder", external_ref=checkout_ref, email=email,
                      name=ship.get("name", ""), items=items_rec,
                      total_cents=int(subtotal_cents),
                      address=ship, channel="retail")
        try:
            with _sqlite3.connect(LOG_DB) as _lcx:
                _bos_orders.set_order_qbo_lines(_lcx, checkout_ref, qbo_payload)
        except Exception as _e:
            print(f"[portal-reorder] persist qbo_lines failed: {_e!r}", flush=True)
        stripe_url = _stripe_checkout_url_for_reorder(out, email)
        if not stripe_url:
            return jsonify({"error": _CARD_UNAVAILABLE}), 502
        return jsonify({"ok": True, "stripe_url": stripe_url})
    except Exception as e:
        app.logger.exception("portal checkout failed")
        return jsonify({"error": f"{type(e).__name__}: {e}"}), 500


def _active_recommendation_card(cx, email):
    """The patient's actionable practitioner recommendation for the portal card,
    or None (Task 8). ONLY a 'sent' (not-yet-acted) recommendation surfaces — once
    accepted or dismissed the card is gone. Items are resolved to remedy NAMES; NO
    price is shown here: the suggested-step price is $0 on prod (its source table is
    local-only), so it is never displayed as a real cost. Accept itself mints no
    price either — the authoritative member price appears later, at the patient's
    reorder checkout (_portal_priced_lines)."""
    from dashboard import practitioner_recommendations as _pr
    try:
        rec = _pr.active_for_patient(cx, email)
    except Exception:
        return None
    if not rec or rec.get("status") != "sent":
        return None
    items = []
    for it in (rec.get("items") or []):
        d = it if isinstance(it, dict) else {}
        slug = (d.get("slug") or "").strip()
        name = (d.get("name") or "").strip()
        if not name and slug:
            p = _get_product(slug)
            name = (p or {}).get("name") if p else ""
        name = name or slug or "Recommended remedy"
        try:
            qty = max(1, min(int(d.get("qty", 1) or 1), 99))
        except Exception:
            qty = 1
        items.append({"slug": slug, "name": name, "qty": qty})  # price deliberately omitted
    return {"id": rec["id"], "note": rec.get("note") or "", "items": items}


