def _get_consult_booked(cx):
    try:
        rows = cx.execute("SELECT lower(email) FROM evox_bookings "
                          "WHERE session_type='biofield-consult' AND status='booked'").fetchall()
        return {r[0] for r in rows}
    except Exception:
        return set()


