@app.route("/api/cron/coach-subscriptions/charge", methods=["POST"])
def coach_subscriptions_charge_cron():
    """Monthly charge cron for paid coaching subscriptions (arc slice 2b, Task 3).

    Charges each active subscription whose next_charge_at is due, off the
    vaulted card. On success: records the charge, grants this cycle's included
    service, and advances next_charge_at one month (only way the date moves,
    so a same-day re-run cannot double-charge). On failure: records the
    charge, marks the sub past_due (no grant, no date advance), and does a
    best-effort notify of the member and Glen."""
    if request.headers.get("X-Console-Key") != CONSOLE_SECRET:
        return jsonify({"error": "unauthorized"}), 401
    from dashboard import coach_subscriptions as _cs, stripe_pay as _sp, subscriptions as _subs
    from datetime import date as _date
    today = _date.today().isoformat()
    charged = failed = 0
    with sqlite3.connect(LOG_DB) as rcx:
        rcx.row_factory = sqlite3.Row
        _cs.init_sub_tables(rcx)
        due_rows = _cs.due(rcx, today)
    for sub in due_rows:
        email = sub["member_email"]
        tier = sub["tier"]
        try:
            res = _sp.charge_off_session(
                sub["stripe_customer_id"], sub["payment_method_id"], sub["amount_cents"],
                description=f"Coaching with {_cs.TIERS.get(tier, {}).get('label', '')}",
                metadata={"kind": "coach_sub_cycle", "tier": tier, "email": email})
            ok = res.get("status") == "succeeded"
            pi_id = res.get("id") or ""
        except Exception:
            # A raised exception (timeout, connection error, etc.) is treated the
            # same as a non-succeeded charge for THIS sub only, so it cannot abort
            # the batch and skip every subscription after it.
            app.logger.exception("coach sub charge raised for %s", email)
            ok = False
            pi_id = ""
        with _db_lock, sqlite3.connect(LOG_DB) as cx:
            cx.row_factory = sqlite3.Row
            _cs.init_sub_tables(cx)
            _cs.record_charge(cx, email=email, tier=tier, amount_cents=sub["amount_cents"],
                              pi_id=pi_id, status="succeeded" if ok else "failed")
            if ok:
                _grant_cycle_service(cx, email, tier)
                _cs.mark_charged(cx, email, _subs.add_months(today, 1))
            else:
                _cs.mark_failed(cx, email)
        if ok:
            charged += 1
        else:
            failed += 1
            html = (f"<p>We could not process this month's coaching charge for {email}. "
                    f"Please update the card on file to keep coaching active.</p>")
            try:
                send_evox_email(email, "", "Your coaching payment did not go through", html, html, b"")
            except Exception:
                app.logger.exception("coach sub failure notify (member) failed for %s", email)
            try:
                send_evox_email(GLEN_CONSULT_EMAIL, "Glen", f"Coaching charge failed: {email}",
                                html, html, b"")
            except Exception:
                app.logger.exception("coach sub failure notify (glen) failed for %s", email)
    return jsonify({"charged": charged, "failed": failed})


@app.route("/api/cron/household-holds/sweep", methods=["POST"])
def household_holds_sweep_cron():
    """Auto-release hold groups past their ship-by deadline: 2+ orders -> one
    combined shipment; a lone order -> just un-held so it ships normally. Idempotent:
    a released group is no longer 'open' so a re-run skips it."""
    if request.headers.get("X-Console-Key") != CONSOLE_SECRET:
        return jsonify({"error": "unauthorized"}), 401
    from dashboard import household_holds as _holds
    released = combined = 0
    with _db_lock, sqlite3.connect(LOG_DB) as cx:
        cx.row_factory = sqlite3.Row
        _holds.init_hold_tables(cx)
        for g in _holds.due_holds(cx):
            res = _holds.release_hold(cx, g["id"], by="deadline")
            released += 1
            ids = res["order_ids"]
            if len(ids) >= 2:
                try:
                    _release_to_shipment(cx, ids, created_by="deadline-release")
                    combined += 1
                except Exception as e:
                    print(f"[hold-sweep] create_shipment({ids}) failed: {e!r}", flush=True)
    return jsonify({"ok": True, "released": released, "combined": combined})


@app.route("/api/cron/qbo-heal-pending", methods=["POST"])
def api_cron_qbo_heal_pending():
    """Sweep orders stuck at qbo_sales_receipt_id='PENDING' (crashed/interrupted
    booking) and resolve each: stamp the existing QBO receipt if one already
    exists, or re-claim + rebook if none does. See dashboard.qbo_heal for the
    full resolution logic. Rides the existing daily briefings cron (folded in
    by scripts/run_briefings_cron.py) -- no separate Render cron service.
    Auth: X-Cron-Secret header matching CRON_SECRET (falls back to CONSOLE_SECRET)."""
    key = (request.headers.get("X-Cron-Secret", "") or request.args.get("key", "")).strip()
    expected = os.environ.get("CRON_SECRET") or os.environ.get("CONSOLE_SECRET", "")
    if not expected or key != expected:
        return jsonify({"error": "unauthorized"}), 401
    from dashboard import qbo_heal as _heal, qbo_billing as _qb, qbo_sale as _qs, orders as _ord
    # Serialized under _db_lock (mirrors /api/cron/household-holds/sweep above): two
    # overlapping sweeps in this process cannot interleave, which is what closes the
    # concurrent-rebook / double-book window on a single web instance. See qbo_heal's
    # module docstring for why the CAS clear alone does not make that safe.
    with _db_lock:
        cx = _sqlite3.connect(LOG_DB); cx.row_factory = _sqlite3.Row
        try:
            healed = _heal.heal_pending_receipts(
                cx,
                find_receipt=_qb.find_sales_receipt_by_ref,
                book=lambda cx2, o: _qs.book_sale_on_payment(cx2, o),
                stamp=_ord.set_order_sales_receipt_id)
        finally:
            cx.close()
    return jsonify({"ok": True, "healed": healed, "count": len(healed)})


@app.route("/api/cron/family-plan/charge", methods=["POST"])
def family_plan_charge_cron():
    """Daily charge cron for paid Family Plans. Charges each due, non-comp, active
    plan off the vaulted card. On success: record + advance next_charge_at one month.
    On failure: record, mark past_due, and reschedule the next attempt two days out
    (spacing the dunning retries); after 4 failed attempts (every other day, ~6 days
    of grace) cancel the plan. past_due still entitles mid-cycle, so grace is bounded.
    Comped plans (next_charge_at NULL / source='comp') are never due. A same-day
    re-run cannot double-charge: a success moves next_charge_at a month out and a
    failure moves it two days out, so a just-processed row is no longer due."""
    if request.headers.get("X-Console-Key") != CONSOLE_SECRET:
        return jsonify({"error": "unauthorized"}), 401
    from dashboard import family_plan as _fp, stripe_pay as _sp, subscriptions as _subs
    from datetime import date as _date, timedelta as _timedelta
    today = _date.today().isoformat()
    retry_at = (_date.today() + _timedelta(days=2)).isoformat()  # dunning: next attempt 2 days out
    charged = failed = cancelled = 0
    with sqlite3.connect(LOG_DB) as rcx:
        rcx.row_factory = sqlite3.Row
        _fp.init_family_plan_table(rcx)
        due_rows = _fp.due(rcx, today)
    for sub in due_rows:
        email = sub["caregiver_email"]
        try:
            res = _sp.charge_off_session(
                sub["stripe_customer_id"], sub["payment_method_id"], sub["amount_cents"],
                description=_fp.PLAN["label"],
                metadata={"kind": "family_plan_cycle", "email": email})
            ok = res.get("status") == "succeeded"
            pi_id = res.get("id") or ""
        except Exception:
            app.logger.exception("family plan charge raised for %s", email)
            ok = False
            pi_id = ""
        with _db_lock, sqlite3.connect(LOG_DB) as cx:
            cx.row_factory = sqlite3.Row
            _fp.init_family_plan_table(cx)
            _fp.record_charge(cx, caregiver_email=email, amount_cents=sub["amount_cents"],
                              pi_id=pi_id, status="succeeded" if ok else "failed")
            if ok:
                _fp.mark_charged(cx, email, _subs.add_months(today, 1))
            else:
                _fp.mark_failed(cx, email, retry_at)
                row = _fp.get(cx, email)
                if row and int(row.get("fail_count") or 0) >= 4:
                    _fp.set_status(cx, email, "cancelled")
                    was_cancelled = True
                else:
                    was_cancelled = False
        if ok:
            charged += 1
        else:
            failed += 1
            if was_cancelled:
                cancelled += 1
            html = (f"<p>We could not process this month's Family Plan charge for {email}. "
                    f"Please update the card on file from your portal to keep the plan active.</p>")
            try:
                send_evox_email(email, "", "Your Family Plan payment did not go through",
                                html, html, b"")
            except Exception:
                app.logger.exception("family plan failure notify (member) failed for %s", email)
            try:
                send_evox_email(GLEN_CONSULT_EMAIL, "Glen", f"Family Plan charge failed: {email}",
                                html, html, b"")
            except Exception:
                app.logger.exception("family plan failure notify (glen) failed for %s", email)
    return jsonify({"charged": charged, "failed": failed, "cancelled": cancelled})


