@app.route("/api/consult/book", methods=["POST"])
def consult_book():
    from dashboard import evox as _ev, consult as _consult
    body = request.get_json(force=True) or {}
    start_ts = (body.get("start_ts") or "").strip()
    _init_calendar_table()  # create_booking inserts a calendar_events row
    with _db_lock, sqlite3.connect(LOG_DB) as cx:
        cx.row_factory = sqlite3.Row
        _ev.init_evox_tables(cx); _consult.init_consult_tables(cx)
        ident = _evox_ident(cx, request.args.get("token", ""))
        if ident is None:
            return jsonify({"error": "not_found"}), 404
        if not _consult.consult_is_ready(cx, ident.email):
            return jsonify({"error": "not_ready"}), 403
        from dashboard import intake as _intake
        _intake.init_intake_table(cx)
        if not _intake.is_submitted(cx, ident.email):
            return jsonify({"error": "intake_required"}), 409
        try:
            d = _evox_date.fromisoformat(start_ts[:10])
        except ValueError:
            return jsonify({"error": "bad_start_ts"}), 400
        busy = _ev.rae_busy_intervals(cx, d.isoformat(), d.isoformat(), practitioner="glen")
        if start_ts not in _ev.available_slots([d], GLEN_CONSULT_HOURS, busy,
                                               _ev.booked_starts(cx, practitioner="glen"),
                                               _hst_now(), duration_min=30):
            return jsonify({"error": "slot_unavailable"}), 409
        try:
            b = _ev.create_booking(cx, ident.email, start_ts, duration_min=30,
                                   practitioner="glen", session_type="biofield-consult",
                                   medium="video")
        except _ev.SlotTaken:
            return jsonify({"error": "slot_taken"}), 409
        email = ident.email
    # --- lock released ---
    try:
        from dashboard import client_portal as _cp
        with sqlite3.connect(LOG_DB) as cx2:
            token = _cp.ensure_token(cx2, email, "") if hasattr(_cp, "ensure_token") else None
        b["portal_url"] = portal_link(token) if token else f"{portal_base()}/portal/login"
    except Exception:
        b["portal_url"] = f"{portal_base()}/portal/login"
    _consult_send_confirmations(email, b)
    return jsonify({"ok": True, "start_ts": start_ts})


@app.route("/api/consult/join")
def consult_join():
    from dashboard import consult as _consult
    with sqlite3.connect(LOG_DB) as cx:
        cx.row_factory = sqlite3.Row
        from dashboard import evox as _ev
        _ev.init_evox_tables(cx)
        ident = _evox_ident(cx, request.args.get("token", ""))
        if ident is None:
            return jsonify({"error": "not_found"}), 404
        rows = cx.execute("SELECT start_ts FROM evox_bookings WHERE lower(email)=? "
                          "AND session_type='biofield-consult' AND status='booked' "
                          "ORDER BY start_ts", (ident.email,)).fetchall()
        if not rows:
            return jsonify({"error": "no_booking"}), 404
        now = _hst_now()
        for r in rows:
            if _consult.within_join_window(r["start_ts"], now):
                return jsonify({"ok": True, "join_url": GLEN_PMI_URL})
        # not in any window: report the next upcoming consult start (if any)
        upcoming = [r["start_ts"] for r in rows if r["start_ts"] >= now.isoformat()]
        return jsonify({"error": "not_in_window",
                        "start_ts": (upcoming[0] if upcoming else rows[-1]["start_ts"])}), 403


def _triage_ident(cx, token):
    from dashboard import triage as _triage
    return _triage.resolve_invite(cx, token)


def _triage_hours(practitioner):
    return GLEN_CONSULT_HOURS if practitioner == "glen" else EVOX_HOURS


def _triage_send_confirmations(token, invite, booking):
    try:
        from dashboard import evox as _ev
        p = invite["practitioner"]; email = invite["email"]
        start = booking["start_ts"]; nice = start.replace("T", " ")
        if p == "rae":
            who = "Rae"; note_email = EVOX_RAE_EMAIL
            phone = EVOX_RAE_PHONE or "the number in this email"
            line = f"At your appointment time, call Rae at {phone}."
        else:
            who = "Dr. Glen"; note_email = GLEN_CONSULT_EMAIL
            page = f"{PUBLIC_BASE_URL}/triage/{token}"
            line = f"At your appointment time, open your booking page and click Join your call: {page}"
        ics = _ev.build_ics(uid=booking["ics_uid"], start_ts=start, end_ts=booking["end_ts"],
                            summary=f"15 minute call with {who}",
                            description=line, location=("Phone" if p == "rae" else "Zoom (join from your page)"))
        c_html = (f"<p>Your 15 minute call with {who} is booked for <b>{nice} HST</b>.</p>"
                  f"<p>{line}</p><p>The calendar invite is attached.</p>")
        c_text = f"Call with {who} booked for {nice} HST. {line}"
        n_html = f"<p>New triage booked: <b>{invite.get('name') or email}</b> ({email}) on <b>{nice} HST</b>.</p>"
        for to, nm, subj, html, text in [
            (email, invite.get("name") or "", f"Your call with {who} is booked", c_html, c_text),
            (note_email, who, f"Triage booked: {email}", n_html, n_html)]:
            try:
                send_evox_email(to, nm, subj, html, text, ics)
            except Exception:
                app.logger.exception("triage confirmation send failed to %s", to)
    except Exception:
        app.logger.exception("triage confirmation build failed")


