@app.route("/api/console/client-photo", methods=["POST"])
def api_console_client_photo():
    """Store a client's photo (base64), keyed by email. Pushed from the local intake
    app's upload or a console upload. Console-key gated. See client-photos Slice 1."""
    if not _portal_console_ok():
        return jsonify({"error": "unauthorized"}), 401
    import base64 as _b64
    body = request.get_json(silent=True) or {}
    email = (body.get("email") or "").strip().lower()
    img_b64 = body.get("image") or ""
    if not email or "@" not in email or not img_b64:
        return jsonify({"ok": False, "error": "email and image required"}), 400
    try:
        blob = _b64.b64decode(img_b64)
    except Exception:
        return jsonify({"ok": False, "error": "bad base64 image"}), 400
    if not blob:
        return jsonify({"ok": False, "error": "empty image"}), 400
    from dashboard import client_photos as _cph
    with _db_lock, sqlite3.connect(LOG_DB) as cx:
        _cph.put(cx, email, blob, (body.get("content_type") or "image/jpeg"),
                 source=(body.get("source") or "console"),
                 force=bool(body.get("force", True)))
    return jsonify({"ok": True, "email": email})


@app.route("/client-photo/<path:email>")
def serve_client_photo(email):
    """Serve a client's photo for console/reveal surfaces. Owner/console gated
    (portal-token-scoped read comes with Slice 2). 404 when absent so <img onerror>
    hides cleanly."""
    if not (_portal_console_ok() or _portal_open_is_owner()):
        return jsonify({"error": "unauthorized"}), 401
    from dashboard import client_photos as _cph
    with sqlite3.connect(LOG_DB) as cx:
        rec = _cph.get(cx, email)
    if not rec:
        return Response("", status=404)
    resp = Response(rec["blob"], mimetype=rec["content_type"])
    resp.headers["Cache-Control"] = "private, max-age=300"
    return resp


@app.route("/api/console/portal-link", methods=["GET"])
def api_console_portal_link():
    """Return the /portal/<token> link for one client by email (reuses the stable
    token; re-mints only if just a hash was on file). Never creates a portal for an
    email that doesn't already have one."""
    if not _portal_console_ok():
        return jsonify({"error": "unauthorized"}), 401
    email = (request.args.get("email") or "").strip().lower()
    if not email:
        return jsonify({"ok": False, "error": "email required"}), 400
    from dashboard import client_portal as _cp
    with _db_lock, sqlite3.connect(LOG_DB) as cx:
        _cp.init_client_portal_table(cx)
        link, reissued = _cp.portal_link_for(cx, email, portal_base())
    if not link:
        return jsonify({"ok": True, "found": False, "email": email})
    return jsonify({"ok": True, "found": True, "email": email,
                    "link": link, "reissued": reissued})


@app.route("/api/console/portal-link/resend", methods=["POST"])
def api_console_portal_link_resend():
    """Email a client their portal link (for someone who lost it and won't
    self-serve at /portal/login). Reuses the stable link."""
    if not _portal_console_ok():
        return jsonify({"error": "unauthorized"}), 401
    body = request.get_json(silent=True) or {}
    email = (body.get("email") or "").strip().lower()
    if not email:
        return jsonify({"ok": False, "error": "email required"}), 400
    from dashboard import client_portal as _cp
    with _db_lock, sqlite3.connect(LOG_DB) as cx:
        _cp.init_client_portal_table(cx)
        link, reissued = _cp.portal_link_for(cx, email, portal_base())
        row = cx.execute("SELECT name FROM client_portals WHERE email=?", (email,)).fetchone()
        name = (row[0] if row else "") or ""
    if not link:
        return jsonify({"ok": False, "error": "no portal for that email"}), 404
    first = (" " + name.split()[0]) if name.strip() else ""
    login = portal_base() + "/portal/login"
    sent_via, err = _send_full_report_email(
        email, name, "Your Remedy Match portal link",
        f"Aloha{first},\n\nHere is the link to your personal Remedy Match portal:\n\n{link}\n\n"
        f"Bookmark it — it's your home base. If you ever lose it, you can also sign in "
        f"anytime at {login} with this email.\n\n— Dr. Glen Swartwout")
    return jsonify({"ok": bool(sent_via), "sent_via": sent_via, "error": err,
                    "link": link, "reissued": reissued})


