@app.route("/api/console/portal/backfill-findings", methods=["POST"])
def api_console_portal_backfill_findings():
    """Surgically set content.findings on an EXISTING portal (or one of its
    biofield-report rows) without touching any other field, sending any email, or
    ever creating a portal. Backfills portals published before findings were baked
    in at publish time. scan_date present -> patch that report row; absent -> patch
    the portal record. Console-key gated."""
    if not _portal_console_ok():
        return jsonify({"error": "unauthorized"}), 401
    body = request.get_json(silent=True) or {}
    email = (body.get("email") or "").strip().lower()
    findings = body.get("findings")
    scan_date = (body.get("scan_date") or "").strip()
    if not email or not isinstance(findings, list):
        return jsonify({"ok": False, "error": "email and findings[] required"}), 400
    from dashboard import client_portal as _cp, portal_biofield_reports as _pbr
    with _db_lock, sqlite3.connect(LOG_DB) as cx:
        _cp.init_client_portal_table(cx)
        _pbr.init_table(cx)
        rec = _cp.get_portal_content_by_email(cx, email)
        if not rec:
            return jsonify({"ok": False, "found": False}), 404   # never create
        patched_portal = False
        patched_reports = 0
        if scan_date:
            rep = _pbr.get_report(cx, email, scan_date)
            if rep:
                rc = dict(rep.get("content") or {})
                rc["findings"] = findings
                _pbr.upsert_report(cx, email, scan_date, rep.get("scan_id") or "",
                                   rc, rep.get("status") or "confirmed")
                patched_reports = 1
        else:
            content = dict(rec.get("content") or {})
            content["findings"] = findings
            _cp.upsert_portal(cx, email, rec.get("name") or "", content)
            patched_portal = True
    return jsonify({"ok": True, "found": True,
                    "patched_portal": patched_portal, "patched_reports": patched_reports})


@app.route("/api/console/family-plan", methods=["GET", "POST"])
def api_console_family_plan():
    """Owner: enrol a caregiver on the Family Plan, or read who it covers.

    v1 enrollment is operator-driven (Glen takes payment, then enrols), mirroring
    the $300 tier's "just reply to arrange it". `source='comp'` grants the same
    entitlement with no card and no charge date, for a client made whole.
    POST is idempotent — family_subscriptions is keyed on caregiver_email, so a
    double-click re-activates rather than stacking a second plan.
    """
    if not _portal_console_ok():
        return jsonify({"error": "unauthorized"}), 401
    from dashboard import family_plan as _fp
    from dashboard import household as _hh
    if request.method == "GET":
        email = (request.args.get("email") or "").strip().lower()
        if not email:
            return jsonify({"error": "email required"}), 400
        with sqlite3.connect(LOG_DB) as cx:
            cx.row_factory = sqlite3.Row
            _fp.init_family_plan_table(cx)
            _hh.init_household_tables(cx)
            active = _fp.is_active(cx, email)
            covered = [m["email"] for m in _hh.members_for(cx, email)
                       if m["share_consent"]] if active else []
            return jsonify({"ok": True, "email": email, "active": active,
                            "plan": _fp.get(cx, email), "covered_members": covered})
    body = request.get_json(silent=True) or {}
    email = (body.get("email") or "").strip().lower()
    if not email:
        return jsonify({"error": "email required"}), 400
    source = (body.get("source") or "stripe").strip().lower()
    next_charge_at = (body.get("next_charge_at") or "").strip() or None
    # Optional special per-household price (cents). Absent -> the standard PLAN price.
    amount_cents = body.get("amount_cents")
    try:
        amount_cents = int(amount_cents) if amount_cents is not None else None
    except (TypeError, ValueError):
        return jsonify({"error": "amount_cents must be an integer number of cents"}), 400
    if amount_cents is not None and amount_cents < 0:
        return jsonify({"error": "amount_cents must be non-negative"}), 400
    with _db_lock:
        with sqlite3.connect(LOG_DB) as cx:
            cx.row_factory = sqlite3.Row
            _fp.init_family_plan_table(cx)
            _fp.activate(cx, email, next_charge_at=next_charge_at, source=source,
                         amount_cents=amount_cents)
    return jsonify({"ok": True, "email": email, "source": source,
                    "amount_cents": (amount_cents if amount_cents is not None
                                     else _fp.PLAN["amount_cents"])})


