@app.route("/api/cert/portal-invite", methods=["POST"])
def api_cert_portal_invite():
    """Console-gated: email a cert participant their practitioner-portal magic link."""
    if CONSOLE_SECRET:
        key = request.headers.get("X-Console-Key", "") or request.args.get("key", "")
        if key != CONSOLE_SECRET and not _owner_token_ok(key):
            return jsonify({"error": "Unauthorized"}), 401
    body = request.get_json(silent=True) or {}
    email = (body.get("email") or "").strip()
    if not email:
        return jsonify({"error": "email required"}), 400
    pid = _pp.id_for_email(email)
    if not pid:
        return jsonify({"ok": True, "sent": False, "reason": "no practitioner record"})
    try:
        name = _pp.name_for_email(email) or ""
        # Invite link is emailed (not clicked within 15 min), so give it a 7-day TTL.
        magic = _pp.create_magic_link_token(pid, email, ttl_min=7 * 24 * 60)
        _send_practitioner_magic_link(
            email, name, f"{PUBLIC_BASE_URL}/practitioner/login-verify?token={magic}")
    except Exception as e:
        print(f"[cert-portal-invite] failed for {email}: {e!r}", flush=True)
        return jsonify({"ok": False, "error": "send failed"}), 500
    return jsonify({"ok": True, "sent": True, "email": email})


# ── Console practitioner admin (add + roster + edit) ───────────────────────────

def _owner_token_ok(key):
    """True if `key` is an OWNER-role per-user access token (e.g. Rae). Lets the
    console's CONSOLE_SECRET gates also accept an owner token. VA tokens (Shaira)
    map to 'va' and return False. Defined here; resolves _role_for_token at call
    time (it is a module global, defined later in this file)."""
    try:
        return bool(key) and _role_for_token(key) == _bos_rbac.OWNER
    except Exception:
        return False


def _console_key_ok():
    """True if the request carries the console key, an OWNER token, or no key is configured."""
    if not CONSOLE_SECRET:
        return True
    key = request.headers.get("X-Console-Key", "") or request.args.get("key", "")
    return key == CONSOLE_SECRET or _owner_token_ok(key)


def _send_practitioner_invite(email, name, pid):
    """Mint a 7-day practitioner magic link and email it. Returns True on send."""
    magic = _pp.create_magic_link_token(pid, email, ttl_min=7 * 24 * 60)
    _send_practitioner_magic_link(
        email, name or "", f"{PUBLIC_BASE_URL}/practitioner/login-verify?token={magic}")
    return True


