@app.route("/api/console/cert/notify-cohort", methods=["POST"])
def api_cert_notify_cohort():
    """Console button: email the Level 1 assignment notice to cert students (portal_role=coach).
    Pass ?dry_run=1 to preview the recipient list without sending."""
    if not _console_key_ok():
        return jsonify({"error": "Unauthorized"}), 401
    dry = (request.args.get("dry_run") or "").strip().lower() in ("1", "true", "yes")
    from dashboard import practitioner_admin as _pa
    from dashboard import cert_notify as _cn
    try:
        roster = _pa.list_practitioners()
    except Exception as e:  # noqa: BLE001
        return jsonify({"ok": False, "error": f"roster unavailable: {e}"}), 502
    # Cert students = coaches below Level 12 (Level-12 = instructors, who don't get the homework).
    students = [p for p in roster
                if (p.get("email") and p.get("portal_role") == "coach"
                    and int(p.get("modules_completed") or 0) < 12
                    and (p.get("email") or "").strip().lower() not in _COHORT_EXCLUDE_EMAILS)]
    recipients = []
    for p in students:
        pid = _norm_pid(p.get("id"))
        email = (p.get("email") or "").strip()
        name = p.get("name") or ""
        record_url = _cert_l1_assignment(pid, email, p.get("modules_completed") or 0)["record_url"]
        if dry:
            recipients.append({"email": email, "name": name})
        else:
            recipients.append({"email": email,
                               "sent": bool(_cn.send_assignment_notice(
                                   email, name, record_url, practitioner_id=pid))})
    return jsonify({"ok": True, "dry_run": dry, "count": len(students), "recipients": recipients})


@app.route("/api/console/practitioners", methods=["POST"])
def api_console_practitioners_create():
    """Console-gated: add (or link by email) a practitioner — role, classification,
    cert level + wholesale access (independent), finder listing, and optional invite."""
    if not _console_key_ok():
        return jsonify({"error": "Unauthorized"}), 401
    from dashboard import practitioner_admin as _pa
    clean, err = _pa.validate_new_practitioner(request.get_json(silent=True) or {})
    if err:
        return jsonify({"error": err}), 400
    pid = _pa.create_or_update_practitioner(clean)
    if clean["city"] or clean["state"]:
        try:
            _pa.geocode_and_set_location(pid, clean["city"], clean["state"], clean["country"])
        except Exception as e:
            print(f"[console-practitioners] geocode failed for {pid}: {e!r}", flush=True)
    sent = False
    if clean["send_invite"]:
        try:
            sent = _send_practitioner_invite(clean["email"], clean["name"], pid)
        except Exception as e:
            print(f"[console-practitioners] invite failed for {clean['email']}: {e!r}", flush=True)
    return jsonify({"ok": True, "practitioner_id": pid, "invite_sent": sent})


@app.route("/api/console/practitioners/<pid>/edit", methods=["POST"])
def api_console_practitioners_edit(pid):
    """Console-gated row actions: level_access | finder | location | resend_invite."""
    if not _console_key_ok():
        return jsonify({"error": "Unauthorized"}), 401
    from dashboard import practitioner_admin as _pa
    body = request.get_json(silent=True) or {}
    action = (body.get("action") or "").strip()
    if action == "level_access":
        try:
            level = int(body.get("level", 0))
        except (TypeError, ValueError):
            return jsonify({"error": "level must be a number"}), 400
        _pa.set_level_and_access(pid, level, bool(body.get("wholesale_access")))
        return jsonify({"ok": True})
    if action == "credentials":
        _pa.set_credentials(pid, body.get("credentials"))
        return jsonify({"ok": True})
    if action == "finder":
        _pa.set_finder_visibility(pid, bool(body.get("show")))
        return jsonify({"ok": True})
    if action == "location":
        _pa.geocode_and_set_location(pid, body.get("city"), body.get("state"),
                                     body.get("country"))
        return jsonify({"ok": True})
    if action == "resend_invite":
        email = (body.get("email") or "").strip()
        if not email:
            return jsonify({"error": "email required"}), 400
        try:
            _send_practitioner_invite(email, (body.get("name") or "").strip(), pid)
        except Exception as e:
            print(f"[console-practitioners] resend failed for {email}: {e!r}", flush=True)
            return jsonify({"ok": False, "error": "send failed"}), 500
        return jsonify({"ok": True, "sent": True})
    return jsonify({"error": "unknown action"}), 400


@app.route("/api/console/care-share/reverse", methods=["POST"])
def api_console_care_share_reverse():
    """Owner console action: reverse a previously-posted care-share credit when a
    Continuous Care membership charge is manually refunded. There is no Stripe
    refund webhook for this — this is the manual path. Body {sub_id, order_count}
    identifies the exact charge event (same event_ref the earn side used:
    care_share:<sub_id>:<order_count>); wallet.reverse_care_share reverses the
    EXACT amount that was posted for that event_ref (read from the ledger, not
    recomputed at the doctor's current cert rate) and is idempotent — it
    no-ops if that credit was never posted."""
    if not _console_key_ok():
        return jsonify({"ok": False, "error": "unauthorized"}), 401
    body = request.get_json(silent=True) or {}
    sub_id = body.get("sub_id")
    order_count = body.get("order_count")
    from dashboard import subscriptions as _subs
    with sqlite3.connect(LOG_DB) as cx:
        cx.row_factory = sqlite3.Row
        sub = _subs.get(cx, sub_id)
    if not sub or not sub.get("attributed_practitioner_id"):
        return jsonify({"ok": False, "error": "no attributed care-share for that subscription"}), 404
    from dashboard import wallet as _wallet
    pid = sub["attributed_practitioner_id"]
    reversed_cents = _wallet.reverse_care_share(
        str(pid), event_ref=f"care_share:{sub['id']}:{int(order_count)}")
    return jsonify({"ok": True, "reversed_cents": reversed_cents})


def _run_biofield_bonuses(dry_run=False):
    """Sweep active certification commitments and grant due bonus Biofields concierge-style
    (one todos task + idempotent ledger row per grant). Flag-gated (CERT_BONUS_ENABLED) — a
    no-op when off. Returns {ok, granted, ...}. Called by both the cron route and the daily
    in-process scheduler job."""
    if not _cert_bonus_enabled():
        return {"ok": True, "granted": 0, "message": "disabled"}

    from dashboard import cert_bonus
    _init_todos_table()
    from datetime import date as _date, datetime as _dt, timezone as _tz
    today = _date.today().isoformat()

    granted_total = 0
    with sqlite3.connect(LOG_DB) as cx:
        cx.row_factory = sqlite3.Row
        cert_bonus.init_tables(cx)
        for c in cert_bonus.list_active(cx):
            email = c["email"]
            try:
                modules = _pp.modules_completed_for_email(email) or 0
            except Exception:
                modules = 0
            due = cert_bonus.due_bonuses(
                started_at=c["started_at"],
                modules_completed=modules,
                granted=cert_bonus.granted_pairs(cx, email),
                today=today,
            )
            for kind, idx in due:
                if dry_run:
                    granted_total += 1
                    continue
                now = _dt.now(_tz.utc).isoformat()
                cur = cx.execute(
                    """INSERT INTO todos (created_at, owner, category, title, body,
                                          priority, source, dedup_key)
                       VALUES (?, ?, ?, ?, ?, ?, ?, ?)
                       ON CONFLICT(dedup_key) DO NOTHING""",
                    (now, "glen", "biofield-bonus",
                     f"Biofield bonus due — {email} ({kind} {idx})",
                     (f"Certification bonus Biofield earned by {email} "
                      f"({kind} {idx}). Schedule and run the Biofield analysis "
                      "for the client as part of their certification benefit."),
                     "normal", "cert-bonus",
                     f"cert-bonus-{email}-{kind}-{idx}"))
                todo_id = cur.lastrowid
                cert_bonus.record_grant(cx, email, kind=kind, idx=idx, todo_id=todo_id)
                granted_total += 1
        cx.commit()
    return {"ok": True, "granted": granted_total, "dry_run": bool(dry_run)}


@app.route("/api/cron/biofield-bonuses", methods=["POST"])
def cron_biofield_bonuses():
    """Cron sweep for certification bonus Biofields (also runs daily in-process via the
    scheduler). Auth: X-Cron-Secret (== CRON_SECRET, falls back to CONSOLE_SECRET).
    Monthly (1..12, one per elapsed month) + one per completed module; idempotent ledger
    + todos task per grant. ?dry_run=1 counts only. Flag-gated by CERT_BONUS_ENABLED."""
    key = (request.headers.get("X-Cron-Secret", "")
           or request.headers.get("X-Console-Key", "")
           or request.args.get("key", ""))
    expected = os.environ.get("CRON_SECRET") or os.environ.get("CONSOLE_SECRET", "")
    if not expected or key != expected:
        return jsonify({"error": "unauthorized"}), 401
    dry_run = request.args.get("dry_run", "").lower() in ("1", "true", "yes")
    return jsonify(_run_biofield_bonuses(dry_run=dry_run))


@app.route("/api/cron/reply-watch", methods=["POST"])
def cron_reply_watch():
    """Run the Gmail inbox reply watcher inside the web container — where the Gmail token
    on the persistent disk (/data/google-token.json) and chat_log.db live. A standalone
    Render cron container has neither, so (like every other cron here) the thin curl cron
    calls this and the work happens here. Auth: X-Cron-Secret (== CRON_SECRET, falls back
    to CONSOLE_SECRET). Idempotent: already-labeled messages (AMG_PROCESSED / AMG_NONUSER)
    are excluded by the search query, so re-running is safe. ?dry_run=1 classifies without
    sending/labeling; ?max=N caps messages scanned (default 50)."""
    key = (request.headers.get("X-Cron-Secret", "")
           or request.headers.get("X-Console-Key", "")
           or request.args.get("key", ""))
    expected = os.environ.get("CRON_SECRET") or os.environ.get("CONSOLE_SECRET", "")
    if not expected or key != expected:
        return jsonify({"error": "unauthorized"}), 401
    dry_run = request.args.get("dry_run", "").lower() in ("1", "true", "yes")
    try:
        max_messages = int(request.args.get("max", "50"))
    except (TypeError, ValueError):
        max_messages = 50
    max_messages = max(1, max_messages)  # 0/negative would silently scan nothing or 400 Gmail
    from reply_watcher import process_inbox_replies
    from dashboard import gmail_token as _gt
    from google.auth.exceptions import RefreshError
    try:
        counts = process_inbox_replies(db_path=str(LOG_DB), dry_run=dry_run,
                                       max_messages=max_messages)
    except (_gt.GmailTokenMissing, RefreshError) as e:
        now_iso = datetime.now(timezone.utc).isoformat()
        if _gt.should_send_alert(str(LOG_DB), "inbox_gmail", now_iso):
            _send_token_alert(
                "Gmail token needs re-auth (reply-watcher down)",
                "The reply-watcher could not load its Gmail token from the DB or "
                "disk. Re-run '~/AI-Training/02 Skills/google-auth.py' and PUT it to "
                f"/api/tokens/inbox_gmail.\n\nDetail: {e}",
            )
            _gt.record_alert(str(LOG_DB), "inbox_gmail", now_iso)
        return jsonify({"ok": False, "error": str(e), "token_missing": True}), 500
    except Exception as e:  # noqa: BLE001
        return jsonify({"ok": False, "error": str(e)}), 500
    # Drop the per-message `details` blob to keep the cron response small.
    return jsonify({"ok": True, **{k: v for k, v in counts.items() if k != "details"}})


@app.route("/api/reorder/items", methods=["GET"])
def api_reorder_items():
    email = _reorder_email_from_cookie()
    if not email:
        return jsonify({"error": "not signed in"}), 401
    _sid = (request.cookies.get("amg_session") or "").strip()
    if not is_member(_sid, email):
        return jsonify({"ok": False, "need_optin": True,
                        "error": "Please agree to our Terms to continue your order."}), 403
    scope = (request.args.get("scope") or "last").strip().lower()
    with sqlite3.connect(LOG_DB) as cx:
        cx.row_factory = sqlite3.Row
        orders = _bos_orders.list_orders_by_email(cx, email)
    src = orders[:1] if scope == "last" else orders
    seen, items = set(), []
    for o in src:
        for it in (o.get("items") or []):
            nm = (it.get("name") or "").strip()
            if not nm or nm.lower() in seen:
                continue
            seen.add(nm.lower())
            slug = _resolve_buy_slug(nm)
            p = _get_product(slug) if slug else None
            items.append({
                "name": nm,
                "slug": (p.get("slug") if p else None),
                "current_price_cents": (p.get("price_cents") if p else None),
                "current_price": (f"${p['price_cents'] / 100:.2f}" if p else None),
                "qty": int(it.get("qty") or 1),
                "last_ordered": (o.get("created_at") or "")[:10],
                "available": bool(p),
            })
    # Annotate each item with whether the buyer has already reviewed it.
    # Open a dedicated short connection — the orders cx is already closed.
    from dashboard import product_reviews as _pr
    with sqlite3.connect(LOG_DB) as rcx:
        for it in items:
            s = it.get("slug")
            if not _REVIEWS_ENABLED:
                it["reviewed"] = True
            elif s:
                it["reviewed"] = _pr.has_reviewed(rcx, s, email)
            else:
                it["reviewed"] = True  # unavailable item; no slug to review
    return jsonify({"email": email, "scope": scope, "items": items})


