def _init_leads_table():
    with sqlite3.connect(LOG_DB) as cx:
        cx.execute("""
            CREATE TABLE IF NOT EXISTS inbound_leads (
                id          INTEGER PRIMARY KEY AUTOINCREMENT,
                received_at TEXT    NOT NULL,
                source      TEXT    NOT NULL,
                email       TEXT,
                first_name  TEXT,
                last_name   TEXT,
                phone       TEXT,
                raw_json    TEXT,
                ghl_contact_id TEXT,
                ghl_opp_id     TEXT,
                ghl_error      TEXT
            )
        """)
        # Per-item action columns (interactive dashboard) — idempotent migration
        for col, ddl in [("tags",             "TEXT DEFAULT '[]'"),
                         ("status",           "TEXT DEFAULT 'pending'"),
                         ("last_outbound_at", "TEXT DEFAULT ''")]:
            try:
                cx.execute(f"ALTER TABLE inbound_leads ADD COLUMN {col} {ddl}")
            except Exception:
                pass
        cx.commit()

_init_leads_table()


def _log_inbound_lead(source, email, first_name, last_name, phone, raw, ghl_result):
    ts = datetime.now(timezone.utc).isoformat()
    with _db_lock, sqlite3.connect(LOG_DB) as cx:
        cx.execute("""
            INSERT INTO inbound_leads
              (received_at, source, email, first_name, last_name, phone, raw_json,
               ghl_contact_id, ghl_opp_id, ghl_error)
            VALUES (?,?,?,?,?,?,?,?,?,?)
        """, (ts, source, email, first_name, last_name, phone, raw,
              ghl_result.get("contact_id"),
              ghl_result.get("opportunity_id"),
              ghl_result.get("contact_error") or ghl_result.get("pipeline_error")))
        cx.commit()


def _record_webhook_debug(source, raw, headers=None):
    """Best-effort: persist a raw inbound webhook body for diagnosis, captured on
    EVERY hit — including ones the handler later rejects (e.g. GrooveKart order
    webhooks that 400 on 'No email in payload' because the field names don't match).
    Lets us see the real payload and fix the mapping. Self-creating table; never
    raises into the webhook path."""
    try:
        ts = datetime.now(timezone.utc).isoformat()
        with _db_lock, sqlite3.connect(LOG_DB) as cx:
            cx.execute("""
                CREATE TABLE IF NOT EXISTS webhook_debug (
                    id          INTEGER PRIMARY KEY AUTOINCREMENT,
                    received_at TEXT NOT NULL,
                    source      TEXT NOT NULL,
                    headers     TEXT,
                    raw         TEXT
                )
            """)
            cx.execute(
                "INSERT INTO webhook_debug (received_at, source, headers, raw) VALUES (?,?,?,?)",
                (ts, source, (headers or "")[:4000], (raw or "")[:40000]))
            cx.commit()
    except Exception as e:
        print(f"[webhook-debug] record failed: {e!r}", flush=True)


