CONSOLE_SECRET = os.environ.get("CONSOLE_SECRET", os.environ.get("WEBHOOK_SECRET", ""))

def _init_todos_table():
    with sqlite3.connect(LOG_DB) as cx:
        cx.execute("""
            CREATE TABLE IF NOT EXISTS todos (
                id             INTEGER PRIMARY KEY AUTOINCREMENT,
                created_at     TEXT NOT NULL,
                owner          TEXT NOT NULL,
                category       TEXT DEFAULT 'General',
                title          TEXT NOT NULL,
                body           TEXT DEFAULT '',
                priority       TEXT DEFAULT 'normal',
                status         TEXT DEFAULT 'open',
                delegated_to   TEXT DEFAULT '',
                delegated_at   TEXT DEFAULT '',
                done_at        TEXT DEFAULT '',
                source         TEXT DEFAULT '',
                dedup_key      TEXT UNIQUE,
                ai_summary      TEXT DEFAULT '',
                suggested_reply TEXT DEFAULT '',
                action_note     TEXT DEFAULT '',
                core_message    TEXT DEFAULT '',
                received_at     TEXT DEFAULT ''
            )
        """)
        # Migrate existing tables that predate these columns
        for col, ddl in [("ai_summary", "TEXT DEFAULT ''"), ("suggested_reply", "TEXT DEFAULT ''"),
                         ("action_note", "TEXT DEFAULT ''"), ("core_message", "TEXT DEFAULT ''"),
                         ("received_at", "TEXT DEFAULT ''"),
                         ("phase", "TEXT NOT NULL DEFAULT 'plan'"),
                         ("first_started_at", "TEXT DEFAULT ''")] :
            try:
                cx.execute(f"ALTER TABLE todos ADD COLUMN {col} {ddl}")
            except Exception:
                pass
        # Backfill phase from existing status (one-time; idempotent)
        try:
            cx.execute("UPDATE todos SET phase='complete' WHERE status='done' AND (phase IS NULL OR phase='plan')")
        except Exception:
            pass
        cx.commit()

_init_todos_table()


def _init_workspace_schema():
    """Tables backing the per-owner Workspace page (focused item, threads, time, steps)."""
    with sqlite3.connect(LOG_DB) as cx:
        cx.execute("""
            CREATE TABLE IF NOT EXISTS owner_state (
                owner            TEXT PRIMARY KEY,
                focused_todo_id  INTEGER,
                updated_at       TEXT NOT NULL DEFAULT (datetime('now'))
            )
        """)
        cx.execute("""
            CREATE TABLE IF NOT EXISTS todo_messages (
                id          INTEGER PRIMARY KEY AUTOINCREMENT,
                todo_id     INTEGER NOT NULL,
                role        TEXT NOT NULL,
                content     TEXT NOT NULL,
                created_at  TEXT NOT NULL DEFAULT (datetime('now')),
                FOREIGN KEY (todo_id) REFERENCES todos(id)
            )
        """)
        cx.execute("CREATE INDEX IF NOT EXISTS idx_todo_messages_todo ON todo_messages(todo_id, created_at)")
        cx.execute("""
            CREATE TABLE IF NOT EXISTS todo_time_sessions (
                id                INTEGER PRIMARY KEY AUTOINCREMENT,
                todo_id           INTEGER NOT NULL,
                owner             TEXT NOT NULL,
                started_at        TEXT NOT NULL DEFAULT (datetime('now')),
                ended_at          TEXT,
                duration_seconds  INTEGER,
                FOREIGN KEY (todo_id) REFERENCES todos(id)
            )
        """)
        cx.execute("CREATE INDEX IF NOT EXISTS idx_todo_time_todo ON todo_time_sessions(todo_id)")
        cx.execute("CREATE INDEX IF NOT EXISTS idx_todo_time_open ON todo_time_sessions(owner, ended_at)")
        cx.execute("""
            CREATE TABLE IF NOT EXISTS todo_steps (
                id        INTEGER PRIMARY KEY AUTOINCREMENT,
                todo_id   INTEGER NOT NULL,
                sequence  INTEGER NOT NULL,
                text      TEXT NOT NULL,
                done      INTEGER NOT NULL DEFAULT 0,
                done_at   TEXT,
                FOREIGN KEY (todo_id) REFERENCES todos(id)
            )
        """)
        cx.execute("CREATE INDEX IF NOT EXISTS idx_todo_steps_todo ON todo_steps(todo_id, sequence)")
        # Per-user access tokens (Phase 2): supersede the shared CONSOLE_SECRET for
        # offshore / per-user access (Shaira). Admin (CONSOLE_SECRET) keeps full access.
        cx.execute("""
            CREATE TABLE IF NOT EXISTS workspace_users (
                id            INTEGER PRIMARY KEY AUTOINCREMENT,
                name          TEXT NOT NULL UNIQUE,
                display_name  TEXT DEFAULT '',
                scope         TEXT NOT NULL,
                created_at    TEXT NOT NULL DEFAULT (datetime('now'))
            )
        """)
        cx.execute("""
            CREATE TABLE IF NOT EXISTS access_tokens (
                token         TEXT PRIMARY KEY,
                user_id       INTEGER NOT NULL,
                created_at    TEXT NOT NULL DEFAULT (datetime('now')),
                last_used_at  TEXT,
                revoked_at    TEXT,
                note          TEXT DEFAULT '',
                FOREIGN KEY (user_id) REFERENCES workspace_users(id)
            )
        """)
        cx.execute("CREATE INDEX IF NOT EXISTS idx_access_tokens_user ON access_tokens(user_id)")
        cx.execute("CREATE INDEX IF NOT EXISTS idx_access_tokens_active ON access_tokens(token, revoked_at)")
        # Daily monitoring reports (Phase 4) — one row per owner per day, upserted on re-run.
        cx.execute("""
            CREATE TABLE IF NOT EXISTS daily_reports (
                id            INTEGER PRIMARY KEY AUTOINCREMENT,
                owner         TEXT NOT NULL,
                report_date   TEXT NOT NULL,
                report_md     TEXT NOT NULL DEFAULT '',
                metrics_json  TEXT NOT NULL DEFAULT '{}',
                created_at    TEXT NOT NULL DEFAULT (datetime('now')),
                UNIQUE(owner, report_date)
            )
        """)
        cx.commit()

_init_workspace_schema()


def _init_calendar_table():
    with sqlite3.connect(LOG_DB) as cx:
        cx.execute("""
            CREATE TABLE IF NOT EXISTS calendar_events (
                id              INTEGER PRIMARY KEY AUTOINCREMENT,
                pushed_at       TEXT NOT NULL,
                google_cal_id   TEXT NOT NULL,
                google_event_id TEXT NOT NULL,
                calendar_name   TEXT DEFAULT '',
                summary         TEXT NOT NULL,
                start           TEXT NOT NULL,
                end             TEXT DEFAULT '',
                location        TEXT DEFAULT '',
                owner           TEXT DEFAULT 'glen',
                status          TEXT DEFAULT 'visible',
                cal_alert       INTEGER DEFAULT 0,
                UNIQUE(google_cal_id, google_event_id)
            )
        """)
        try:
            cx.execute("ALTER TABLE calendar_events ADD COLUMN cal_alert INTEGER DEFAULT 0")
        except Exception:
            pass
        cx.execute("""
            CREATE TABLE IF NOT EXISTS calendar_suppressed (
                id            INTEGER PRIMARY KEY AUTOINCREMENT,
                owner         TEXT NOT NULL DEFAULT 'glen',
                title_pattern TEXT NOT NULL,
                day_of_week   INTEGER,
                hour          INTEGER,
                created_at    TEXT NOT NULL,
                UNIQUE(owner, title_pattern, day_of_week, hour)
            )
        """)
        # Migrate old schema if needed
        for col in ["day_of_week INTEGER", "hour INTEGER", "title_pattern TEXT DEFAULT ''"]:
            try:
                cx.execute(f"ALTER TABLE calendar_suppressed ADD COLUMN {col}")
            except Exception:
                pass
        # Per-calendar -> owner map (so Rae's & Shaira's shared Google calendars land
        # in their own lane; unknown calendars default to glen). Seeded from the
        # CALENDAR_OWNER_MAP env JSON on init: {"<google_cal_id>": "rae", ...}.
        cx.execute("""
            CREATE TABLE IF NOT EXISTS calendar_owner_map (
                google_cal_id TEXT PRIMARY KEY,
                owner         TEXT NOT NULL,
                calendar_name TEXT DEFAULT ''
            )
        """)
        # Accomplishments: manually-logged "what got done" entries, separate from the
        # Google-events mirror (calendar_events). Shown in the calendar's
        # Accomplishments mode.
        cx.execute("""
            CREATE TABLE IF NOT EXISTS calendar_accomplishments (
                id         INTEGER PRIMARY KEY AUTOINCREMENT,
                owner      TEXT NOT NULL,
                title      TEXT NOT NULL,
                at         TEXT NOT NULL,
                notes      TEXT DEFAULT '',
                created_by TEXT DEFAULT '',
                created_at TEXT NOT NULL
            )
        """)
        try:
            _raw_map = os.environ.get("CALENDAR_OWNER_MAP", "")
            if _raw_map:
                for _cal_id, _ow in (json.loads(_raw_map) or {}).items():
                    cx.execute(
                        "INSERT OR IGNORE INTO calendar_owner_map (google_cal_id, owner) "
                        "VALUES (?,?)", (_cal_id, str(_ow).lower()))
        except Exception:
            pass
        cx.commit()

_init_calendar_table()


def _calendar_range_window(range_name, anchor=None):
    """Inclusive ('YYYY-MM-DD' start, end) for a calendar view range.

    Anchor defaults to today in HST (UTC-10, no DST). Ranges:
      today | 2day (today+tomorrow) | week (Mon-Sun containing anchor) | month.
    """
    from datetime import date as _date
    import calendar as _calmod
    if anchor:
        d = _date.fromisoformat(anchor)
    else:
        d = (datetime.now(timezone.utc) - timedelta(hours=10)).date()
    rn = (range_name or "today").lower()
    if rn == "2day":
        return d.isoformat(), (d + timedelta(days=1)).isoformat()
    if rn == "week":
        mon = d - timedelta(days=d.weekday())
        return mon.isoformat(), (mon + timedelta(days=6)).isoformat()
    if rn == "month":
        first = d.replace(day=1)
        last = first.replace(day=_calmod.monthrange(d.year, d.month)[1])
        return first.isoformat(), last.isoformat()
    return d.isoformat(), d.isoformat()  # today / unknown


def _calendar_owner_for(google_cal_id, calendar_name, mapping):
    """Resolve a calendar's owner from the map (by google_cal_id, then name).
    Unknown -> 'glen' (preserves the historical default)."""
    if mapping:
        if google_cal_id and google_cal_id in mapping:
            return mapping[google_cal_id]
        if calendar_name and calendar_name in mapping:
            return mapping[calendar_name]
    return "glen"


def _load_calendar_owner_map(cx):
    mp = {}
    try:
        for cal_id, ow, name in cx.execute(
                "SELECT google_cal_id, owner, calendar_name FROM calendar_owner_map"):
            if cal_id:
                mp[cal_id] = ow
            if name:
                mp[name] = ow
    except Exception:
        pass
    return mp


def _normalize_cal_title(title: str) -> str:
    """Strip session numbers and minor variation markers from event titles."""
    import re as _re
    t = title
    t = _re.sub(r'\s+\d+\s*:', ':', t)               # "Training 4:" → "Training:"
    t = _re.sub(r':\s*\d+\s*:', ':', t)               # ": 4:" → ":"
    t = _re.sub(r'\s+\d+\s*$', '', t)                 # trailing numbers
    t = _re.sub(r'\[\d+\s+of\s+\d+[^\]]*\]', '', t)  # "[11 of 100 spots filled]"
    t = _re.sub(r'\s+', ' ', t).strip()
    return t.lower()


def _parse_event_start(start_iso: str):
    """Return (day_of_week 0=Mon, hour) from ISO start string, or (None, None)."""
    if not start_iso or 'T' not in start_iso:
        return None, None
    try:
        d = datetime.fromisoformat(start_iso.replace('Z', '+00:00'))
        return d.weekday(), d.hour
    except Exception:
        return None, None



_CAL_ALL_OWNERS = ("glen", "rae", "shaira")


@app.route("/api/calendar", methods=["GET"])
def get_calendar():
    ok, ctx, code = _auth()
    if not ok:
        return jsonify({"error": "Unauthorized" if code == 401 else "Forbidden"}), code

    status = request.args.get("status", "visible")
    kind = (request.args.get("kind", "events") or "events").lower()
    range_name = request.args.get("range")
    anchor = request.args.get("date")

    # Owners by scope: admin (Glen/Rae) sees all three (or an `owners=` subset);
    # a scoped user (e.g. workspace:shaira) is forced to her own lane.
    if ctx.get("scope") == "admin":
        req = request.args.get("owners") or request.args.get("owner")
        if req:
            owners = [o.strip().lower() for o in req.split(",")
                      if o.strip().lower() in _CAL_ALL_OWNERS]
        else:
            owners = list(_CAL_ALL_OWNERS)
    else:
        own = _owner_from_scope(ctx.get("scope", ""))
        owners = [own] if own else []
    if not owners:
        return jsonify({"events": []})

    # Date window: explicit range -> inclusive [start,end]; legacy (no range) -> today onward.
    if range_name:
        wstart, wend = _calendar_range_window(range_name, anchor)
        date_clause, date_params = "AND substr({col},1,10) BETWEEN ? AND ?", [wstart, wend]
    else:
        date_clause, date_params = "AND substr({col},1,10) >= date('now')", []
    placeholders = ",".join("?" for _ in owners)

    with sqlite3.connect(LOG_DB) as cx:
        if kind == "accomplishments":
            rows = cx.execute(f"""
                SELECT id, owner, title, at, notes, created_by, created_at
                FROM calendar_accomplishments
                WHERE owner IN ({placeholders})
                  {date_clause.format(col='at')}
                ORDER BY at ASC
            """, (*owners, *date_params)).fetchall()
            cols = ["id", "owner", "title", "at", "notes", "created_by", "created_at"]
            items = [dict(zip(cols, r), kind="accomplishment") for r in rows]
            return jsonify({"events": items})

        rows = cx.execute(f"""
            SELECT id, google_cal_id, google_event_id, calendar_name,
                   summary, start, end, location, owner, status, cal_alert
            FROM calendar_events
            WHERE owner IN ({placeholders}) AND status=?
              {date_clause.format(col='start')}
            ORDER BY start ASC
        """, (*owners, status, *date_params)).fetchall()
    cols = ["id","google_cal_id","google_event_id","calendar_name",
            "summary","start","end","location","owner","status","cal_alert"]
    return jsonify({"events": [dict(zip(cols, r), kind="event") for r in rows]})


@app.route("/api/calendar", methods=["POST"])
def post_calendar():
    if CONSOLE_SECRET:
        key = request.headers.get("X-Console-Key", "") or request.args.get("key", "")
        if key != CONSOLE_SECRET and not _owner_token_ok(key):
            return jsonify({"error": "Unauthorized"}), 401

    items = request.get_json(force=True) or []
    if isinstance(items, dict):
        items = [items]

    ts = datetime.now(timezone.utc).isoformat()
    upserted = skipped = 0
    with _db_lock, sqlite3.connect(LOG_DB) as cx:
        # Build suppression rules per owner: list of (title_pattern, day_of_week, hour)
        sup_rows = cx.execute(
            "SELECT owner, title_pattern, day_of_week, hour FROM calendar_suppressed"
        ).fetchall()
        suppressed = {}  # owner → list of (pattern, dow, hour)
        for row_owner, pattern, dow, hr in sup_rows:
            suppressed.setdefault(row_owner, []).append((pattern, dow, hr))

        owner_map = _load_calendar_owner_map(cx)
        for ev in items:
            # Precedence: an explicit calendar->owner mapping (Rae's/Shaira's shared
            # calendars) wins over the cron's heuristic `owner`, which wins over glen.
            mapped = (owner_map.get(ev.get("google_cal_id", ""))
                      or owner_map.get(ev.get("calendar_name", "")))
            owner   = mapped or ev.get("owner") or "glen"
            summary = ev.get("summary", "(no title)")
            start   = ev.get("start", "")
            norm    = _normalize_cal_title(summary)
            ev_dow, ev_hr = _parse_event_start(start)
            # Check suppression: title_pattern match + same day-of-week + same hour
            is_suppressed = False
            for pattern, dow, hr in suppressed.get(owner, []):
                if norm == pattern:
                    if (dow is None or dow == ev_dow) and (hr is None or hr == ev_hr):
                        is_suppressed = True
                        break
            if is_suppressed:
                skipped += 1
                continue
            try:
                cx.execute("""
                    INSERT INTO calendar_events
                      (pushed_at, google_cal_id, google_event_id, calendar_name,
                       summary, start, end, location, owner)
                    VALUES (?,?,?,?,?,?,?,?,?)
                    ON CONFLICT(google_cal_id, google_event_id) DO UPDATE SET
                      pushed_at=excluded.pushed_at,
                      calendar_name=excluded.calendar_name,
                      summary=excluded.summary,
                      start=excluded.start,
                      end=excluded.end,
                      location=excluded.location,
                      owner=excluded.owner
                    WHERE status='visible'
                """, (ts,
                      ev.get("google_cal_id",""),
                      ev.get("google_event_id",""),
                      ev.get("calendar_name",""),
                      summary,
                      ev.get("start",""),
                      ev.get("end",""),
                      ev.get("location",""),
                      owner))
                upserted += 1
            except Exception:
                pass
        cx.commit()
    return jsonify({"ok": True, "upserted": upserted, "skipped": skipped}), 201


@app.route("/api/calendar/accomplishment", methods=["POST"])
def post_calendar_accomplishment():
    """Log an accomplishment for an owner's lane. Admin may log for any owner;
    a scoped user may only log for her own owner."""
    ok, ctx, code = _auth()
    if not ok:
        return jsonify({"error": "Unauthorized" if code == 401 else "Forbidden"}), code
    body = request.get_json(silent=True) or {}
    owner = (body.get("owner") or "glen").lower()
    if not _can_access_owner(ctx, owner):
        return jsonify({"error": "Forbidden"}), 403
    title = (body.get("title") or "").strip()
    if not title:
        return jsonify({"error": "title required"}), 400
    at = body.get("at") or datetime.now(timezone.utc).isoformat()
    notes = body.get("notes", "") or ""
    created_by = ctx.get("user_name") or "admin"
    now = datetime.now(timezone.utc).isoformat()
    with _db_lock, sqlite3.connect(LOG_DB) as cx:
        cx.execute(
            "INSERT INTO calendar_accomplishments "
            "(owner, title, at, notes, created_by, created_at) VALUES (?,?,?,?,?,?)",
            (owner, title, at, notes, created_by, now))
        cx.commit()
    return jsonify({"ok": True})


@app.route("/api/calendar/<int:event_id>", methods=["PATCH"])
def patch_calendar(event_id):
    if CONSOLE_SECRET:
        key = request.headers.get("X-Console-Key", "") or request.args.get("key", "")
        if key != CONSOLE_SECRET and not _owner_token_ok(key):
            return jsonify({"error": "Unauthorized"}), 401

    data = request.get_json(force=True) or {}
    action = data.get("action", "hide")

    # Delegate: MOVE the event onto another owner's console calendar. Console-only
    # (synthetic google id, google_cal_id='delegated' so the Google sync never
    # touches it). The delegated copy appears on the delegatee's lane and the
    # original is hidden from the delegator's lane (status='hidden' so the next
    # Google sync's `WHERE status='visible'` upsert won't resurrect it).
    if action == "delegate":
        to = (data.get("to") or "").lower()
        if to not in ("glen", "rae", "shaira"):
            return jsonify({"error": "Invalid delegate target"}), 400
        with _db_lock, sqlite3.connect(LOG_DB) as cx:
            row = cx.execute(
                "SELECT summary, start, end, location, owner FROM calendar_events WHERE id=?",
                (event_id,)).fetchone()
            if not row:
                return jsonify({"error": "not found"}), 404
            summary, start, end, location, from_owner = row
            cx.execute("""
                INSERT INTO calendar_events
                  (pushed_at, google_cal_id, google_event_id, calendar_name,
                   summary, start, end, location, owner, status, cal_alert)
                VALUES (?, 'delegated', ?, ?, ?, ?, ?, ?, ?, 'visible', 0)
                ON CONFLICT(google_cal_id, google_event_id) DO UPDATE SET
                  status='visible', summary=excluded.summary, start=excluded.start,
                  end=excluded.end, location=excluded.location,
                  calendar_name=excluded.calendar_name, pushed_at=excluded.pushed_at
            """, (datetime.now(timezone.utc).isoformat(), f"deleg-{event_id}-{to}",
                  f"Delegated by {(from_owner or 'glen').title()}",
                  summary, start, end, location, to))
            # Hide the original from the delegator's lane (move, not copy).
            cx.execute("UPDATE calendar_events SET status='hidden' WHERE id=?", (event_id,))
            cx.commit()
        return jsonify({"ok": True, "delegated_to": to})

    if action == "show":
        new_status = "visible"
    elif action == "delete":
        new_status = "delete_requested"
    else:
        new_status = "hidden"
    with _db_lock, sqlite3.connect(LOG_DB) as cx:
        cx.execute("UPDATE calendar_events SET status=? WHERE id=?", (new_status, event_id))
        cx.commit()
    return jsonify({"ok": True, "status": new_status})


