# ── Subscription email helper ─────────────────────────────────────────────────

def _mint_membership_cancel_url(cx, email: str) -> str:
    """Mint a fresh one-click membership-cancel token (FTC/ROSCA easy-cancel) and
    return its URL. Returns '' when email or PUBLIC_BASE_URL is missing (the link
    would be unusable). Mirrors the cancel token minted at biofield-trial grant."""
    if not (email and PUBLIC_BASE_URL):
        return ""
    tok = secrets.token_urlsafe(32)
    cx.execute(
        "INSERT INTO auth_tokens (token_hash, email, purpose, created_at, expires_at)"
        " VALUES (?,?,?,?,?)",
        (_hash_token(tok), email, "membership_cancel",
         datetime.now(timezone.utc).isoformat(),
         (datetime.now(timezone.utc) + timedelta(days=MEMBERSHIP_CANCEL_TTL_DAYS)).isoformat()))
    cx.commit()
    return f"{PUBLIC_BASE_URL}/membership/cancel/{tok}"


def _send_subscription_email(to_email: str, kind: str, data: dict):
    """Send a subscription lifecycle email. Best-effort — NEVER raises.

    kind: 'heads_up' | 'free_month_thanks' | 'receipt' | 'payment_failed' | 'setup_confirm'
    data: dict with relevant context fields (next_charge_date, amount, etc.)
    Returns (sent_via, error_or_none) same shape as _send_full_report_email.
    """
    try:
        charge_date = data.get("next_charge_date", "")
        amount_str = ""
        raw_cents = data.get("total_cents")
        if raw_cents is not None:
            amount_str = f"${int(raw_cents) / 100:.2f}"

        is_membership = data.get("kind") == "membership"

        if kind == "heads_up":
            if is_membership:
                cancel_url = data.get("cancel_url")
                pause_url = (cancel_url.replace("/membership/cancel/", "/membership/pause/")
                             if cancel_url else "")
                subject = f"Reminder: your membership renews on {charge_date}"
                body = (
                    f"Aloha,\n\n"
                    f"Just a quick heads-up about your membership. On {charge_date} "
                    + (f"your card will be charged {amount_str} for the coming month"
                       if amount_str else "your card will be charged for the coming month")
                    + ". Everything stays unlocked in the meantime.\n\n"
                    + (("Need a breather? You can pause just next month's payment in two clicks "
                        "(it resumes on its own the month after, and you lose nothing):\n\n"
                        f"{pause_url}\n\n") if pause_url else "")
                    + (("Or, if you'd rather cancel, that's one click too, no charge, no reply "
                        f"needed:\n\n{cancel_url}\n\n") if cancel_url
                       else "If you need to make a change, visit your member portal before that date.\n\n")
                    + "In wellness,\nDr. Glen"
                )
            else:
                subject = f"Reminder: your Remedy Match subscription charges on {charge_date}"
                body = (
                    f"Hi,\n\n"
                    f"Just a quick heads-up — your next Remedy Match subscription order will be "
                    f"charged automatically on {charge_date}.\n\n"
                    f"If you need to skip or pause, visit your subscription portal before that date.\n\n"
                    f"In wellness,\nDr. Glen"
                )
        elif kind == "free_month_thanks":
            charge_date = data.get("next_charge_date", "")
            subject = "A free month, with our thanks"
            body = (
                "Aloha,\n\n"
                "Because of a kind referral you shared, we are extending your next month "
                "of membership on us. There is nothing you need to do, and you will not be "
                f"charged on {charge_date}. Everything stays unlocked.\n\n"
                "Thank you for helping someone else begin their healing.\n\n"
                "In wellness,\nDr. Glen"
            )
        elif kind == "receipt":
            inv_id = data.get("invoice_id", "")
            if is_membership and data.get("product") == "continuous_care":
                # Continuous Care (6/12mo term, card on file) — distinct from the group
                # coaching bundle even though both are kind="membership".
                cancel_url = data.get("cancel_url")
                subject = f"Your Continuous Care payment - {amount_str}"
                body = (
                    f"Aloha,\n\n"
                    f"Your Continuous Care payment has been processed. Thank you for continuing "
                    f"your healing journey with us.\n\n"
                    f"Amount charged: {amount_str}\n"
                    + (f"Invoice: {inv_id}\n" if inv_id else "")
                    + f"\nYour next payment date: {charge_date}\n\n"
                    + (f"You can cancel anytime, no reply needed:\n\n{cancel_url}\n\n"
                       if cancel_url else "")
                    + "In wellness,\nDr. Glen"
                )
            elif is_membership:
                subject = f"Your live group coaching payment — {amount_str}"
                body = (
                    f"Hi,\n\n"
                    f"Your live group coaching payment has been processed successfully.\n\n"
                    f"Amount charged: {amount_str}\n"
                    + (f"Invoice: {inv_id}\n" if inv_id else "")
                    + f"\nYour next payment date: {charge_date}\n\n"
                    f"Thank you for being part of the group.\n\n"
                    f"In wellness,\nDr. Glen"
                )
            else:
                body = (
                    f"Hi,\n\n"
                    f"Your Remedy Match subscription order has been processed successfully.\n\n"
                    f"Amount charged: {amount_str}\n"
                    + (f"Invoice: {inv_id}\n" if inv_id else "")
                    + f"\nYour next order will ship on {charge_date}.\n\n"
                    f"Thank you for your continued trust.\n\n"
                    f"In wellness,\nDr. Glen"
                )
                subject = f"Your Remedy Match subscription order is confirmed — {amount_str}"
        elif kind == "payment_failed":
            fail_count = data.get("failed_count", 1)
            subject = "Action needed: Remedy Match subscription payment failed"
            body = (
                f"Hi,\n\n"
                f"We were unable to process your Remedy Match subscription payment"
                + (f" ({amount_str})" if amount_str else "")
                + f".\n\n"
                f"This is attempt {fail_count}. After 3 failed attempts your subscription "
                f"will be placed on hold.\n\n"
                f"Please update your payment method or contact us so we can get this sorted out.\n\n"
                f"In wellness,\nDr. Glen"
            )
        elif kind == "setup_confirm":
            subject = "Welcome to Remedy Match Subscribe & Grow"
            body = (
                f"Hi,\n\n"
                f"Your Remedy Match subscription is now active. Your first order has been placed "
                f"and your card is securely vaulted for future cycles.\n\n"
                f"Your next charge date: {charge_date}\n\n"
                f"You can skip, pause, or cancel anytime through your subscription portal.\n\n"
                f"In wellness,\nDr. Glen"
            )
        else:
            subject = f"Remedy Match subscription update"
            body = f"Subscription update ({kind}).\n\nIn wellness,\nDr. Glen"

        return _send_full_report_email(to_email, "", subject, body)
    except Exception as e:
        print(f"[sub-email] kind={kind} to={to_email} failed: {e!r}", flush=True)
        return ("error", str(e))


def _fm_headsup_referral(cx, email):
    from dashboard import free_month as _fm
    try:
        return _fm.has_active_paying_referral(cx, email)
    except Exception:
        return False


# ── Daily subscription charge scheduler ──────────────────────────────────────

@app.route("/api/cron/charge-subscriptions", methods=["POST"])
def cron_charge_subscriptions():
    """Daily charge scheduler for active subscriptions.

    Auth: X-Cron-Secret header matching CRON_SECRET (or CONSOLE_SECRET fallback).
    Supports ?dry_run=1 — computes + logs without charging or mutating.

    Two passes:
      1. Heads-up: send 3-day advance notice emails for upcoming charges.
      2. Charge: process due subs (skip skipped, charge active, dun failed).

    Returns {ok, charged, skipped, failed, notified, dry_run}.
    """
    key = request.headers.get("X-Cron-Secret", "")
    expected = os.environ.get("CRON_SECRET") or os.environ.get("CONSOLE_SECRET", "")
    if not expected or key != expected:
        return jsonify({"error": "unauthorized"}), 401

    if not _subscriptions_enabled():
        return jsonify({"ok": True, "skipped": 0, "charged": 0, "failed": 0,
                        "notified": 0, "comped": 0, "dry_run": False,
                        "message": "subscriptions disabled"}), 200

    dry_run = request.args.get("dry_run", "").lower() in ("1", "true", "yes")

    from dashboard import subscriptions as _subs
    from datetime import date as _date

    today = _date.today().isoformat()  # YYYY-MM-DD

    charged = skipped = failed = notified = comped = 0

    with sqlite3.connect(LOG_DB) as cx:
        cx.row_factory = sqlite3.Row
        # Run idempotent migration to ensure failed_count column exists
        _subs.migrate_add_failed_count(cx)
        _subs.migrate_add_membership_columns(cx)
        _subs.migrate_add_term_cap_column(cx)
        _subs.migrate_add_attribution_column(cx)
        _subs.migrate_add_consent_column(cx)
        _subs.migrate_add_free_months(cx)

        # ── Pass 1: Heads-up emails (3-day advance notice) ────────────────────
        try:
            upcoming = _subs.list_heads_up_due(cx, as_of=today, lead_days=3)
        except Exception as e:
            print(f"[sub-cron] heads-up query failed: {e!r}", flush=True)
            upcoming = []

        for sub in upcoming:
            try:
                _is_mbr = sub.get("kind") == "membership"
                _banked = int(sub.get("free_months_remaining") or 0) > 0
                _ref_ok = (_is_mbr and not _banked and _free_month_enabled()
                           and _fm_headsup_referral(cx, sub["email"]))
                _will_comp = _is_mbr and (_banked or _ref_ok)
                if not dry_run:
                    # Lock a referral-earned free month NOW (bank it) so a referral
                    # that churns before the charge date cannot turn this thank-you
                    # into a charge. Idempotent per cycle via next_charge_date. Only
                    # send the thank-you if the bank actually succeeded — a member
                    # who is thanked must actually be banked.
                    _locked = _banked
                    if _ref_ok:
                        from dashboard import free_month as _fm
                        _locked = _fm.grant_free_month(
                            cx, sub["email"], months=1, reason="referral_headsup",
                            idem_key=f"headsup:{sub['id']}:{sub['next_charge_date']}") is not None
                        if not _locked:
                            print(f"[free-month] heads-up bank returned None, not promising "
                                  f"sub={sub['id']} email={sub['email']}", flush=True)
                    if _will_comp and _locked:
                        _send_subscription_email(sub["email"], "free_month_thanks",
                                                 {"next_charge_date": sub["next_charge_date"]})
                        _subs.set_last_notified_date(cx, sub["id"], sub["next_charge_date"])
                    else:
                        _hu_data = {"next_charge_date": sub["next_charge_date"],
                                    "kind": sub.get("kind", "product"),
                                    "total_cents": sub.get("amount_cents")}
                        # Membership reminders carry a one-click cancel link (FTC/ROSCA
                        # easy-cancel) minted fresh per send.
                        if _is_mbr:
                            _hu_data["cancel_url"] = _mint_membership_cancel_url(cx, sub["email"])
                        _send_subscription_email(sub["email"], "heads_up", _hu_data)
                        _subs.set_last_notified_date(cx, sub["id"], sub["next_charge_date"])
                notified += 1
                print(f"[sub-cron] heads-up {'(dry)' if dry_run else ''}"
                      f" sub={sub['id']} date={sub['next_charge_date']} comp={_will_comp}", flush=True)
            except Exception as e:
                print(f"[sub-cron] heads-up sub={sub['id']} error: {e!r}", flush=True)

        # Snapshot the charge list BEFORE consuming skips. list_due (skip_next=0) and
        # list_skip_due (skip_next=1) are disjoint right now; if we queried due AFTER the
        # skip pass, a just-consumed sub (skip cleared, date advanced but possibly still
        # due) would wrongly re-enter the charge loop and get billed for a cycle it skipped.
        try:
            due = _subs.list_due(cx, as_of=today)
        except Exception as e:
            print(f"[sub-cron] list_due query failed: {e!r}", flush=True)
            due = []

        # ── Pass 2a: Skip cycles ───────────────────────────────────────────────
        try:
            skip_due = _subs.list_skip_due(cx, as_of=today)
        except Exception as e:
            print(f"[sub-cron] skip-due query failed: {e!r}", flush=True)
            skip_due = []

        for sub in skip_due:
            try:
                if not dry_run:
                    _subs.consume_skip(cx, sub["id"])
                skipped += 1
                print(f"[sub-cron] skip {'(dry)' if dry_run else ''}"
                      f" sub={sub['id']}", flush=True)
            except Exception as e:
                print(f"[sub-cron] consume_skip sub={sub['id']} error: {e!r}", flush=True)

        # ── Pass 2b: Charge the snapshot of due (non-skip) subs ────────────────
        for sub in due:
            sid = sub["id"]
            try:
                if sub.get("kind") == "membership":
                    amount_cents = int(sub.get("amount_cents") or 0)
                    if amount_cents <= 0:
                        continue
                    # Free-month comp: banked counter first, then the Mechanic A
                    # referral threshold. A comp advances the cycle WITHOUT charging
                    # and WITHOUT bumping order_count, extends access, and skips
                    # care_share (funded by the $99 we are not collecting).
                    from dashboard import free_month as _fm
                    _from_bank = int(sub.get("free_months_remaining") or 0) > 0
                    _do_comp = _from_bank or (
                        _free_month_enabled() and _fm.has_active_paying_referral(cx, sub["email"]))
                    if _do_comp:
                        if dry_run:
                            print(f"[sub-cron] DRY free-month comp sub={sid} bank={_from_bank}", flush=True)
                            comped += 1
                            continue
                        did = _fm.comp_membership_cycle(
                            cx, sid,
                            reason=("banked" if _from_bank else "referral_active"),
                            idem_key=f"{'bank' if _from_bank else 'ref'}:{sid}:{sub['next_charge_date']}",
                            from_bank=_from_bank)
                        if did:
                            try:
                                _u = _subs.get(cx, sid)
                                if _u and _u.get("next_charge_date"):
                                    _until = (datetime.fromisoformat(_u["next_charge_date"])
                                              + timedelta(days=MEMBERSHIP_GRANT_GRACE_DAYS)).isoformat() + "Z"
                                    _extend_membership_grant(cx, sub["email"], _until, "membership_free_month")
                            except Exception as _e:
                                print(f"[free-month] grant extend failed sid={sid}: {_e!r}", flush=True)
                            comped += 1
                        continue
                    # A capped term (term_charges_total set) = Continuous Care; an uncapped
                    # membership = the legacy group-coaching bundle. Keep the card-statement
                    # descriptor, QBO line, and receipt email all naming the same product.
                    _is_cc = bool(sub.get("term_charges_total"))
                    _product = "continuous_care" if _is_cc else "group_coaching"
                    _charge_label = ("Remedy Match Continuous Care" if _is_cc
                                     else "Remedy Match live group coaching")
                    _line_label = "Continuous Care" if _is_cc else "Live Group Coaching"
                    if dry_run:
                        print(f"[sub-cron] DRY membership charge sub={sid} "
                              f"email={sub['email']} amount={amount_cents}", flush=True)
                        charged += 1
                        continue
                    res = stripe_pay.charge_off_session(
                        sub["stripe_customer_id"], sub["stripe_payment_method_id"],
                        amount_cents, description=_charge_label,
                        metadata={"sub": str(sid), "kind": "membership"})
                    if res.get("status") == "succeeded":
                        external_ref = res.get("id") or ""
                        _ingest_order(source="membership", external_ref=external_ref,
                                      email=sub["email"], items=[], total_cents=amount_cents,
                                      address={}, channel="retail")
                        # Paid-only (QBO Stage 3): no QBO invoice/customer for this charge --
                        # book ONE line-faithful Sales Receipt inline now that payment is
                        # confirmed. Best-effort + idempotent (book_sale_on_payment claims
                        # the booking slot atomically), so this can never break the charge/
                        # subscription-bookkeeping path below.
                        try:
                            from dashboard import qbo_sale as _qsale
                            qbo_payload = {
                                "lines": [{"name": _line_label,
                                          "amount": round(amount_cents / 100.0, 2), "qty": 1}],
                                "discount_cents": 0, "tax_cents": 0}
                            _bos_orders.set_order_qbo_lines(cx, external_ref, qbo_payload)
                            _o = _bos_orders.find_order_by_external_ref(cx, external_ref)
                            if _o:
                                _qsale.book_sale_on_payment(cx, dict(_o))
                        except Exception as qe:
                            print(f"[sub-cron] membership qbo sale booking failed sid={sid}: {qe!r}",
                                  flush=True)
                        _subs.advance_after_charge(cx, sid)
                        _subs.reset_failed_count(cx, sid)
                        updated = _subs.get(cx, sid)
                        # Turnkey continuity fee-share: credit the enrolling doctor.
                        # Re-read (updated) is AFTER advance_after_charge, so
                        # order_count reflects this just-completed charge — the
                        # event_ref care_share:<id>:<order_count> must be unique per charge.
                        try:
                            if updated and updated.get("kind") == "membership":
                                from dashboard import care_share as _cshare
                                _cshare.credit_for_charge(
                                    updated, charge_cents=int(updated.get("amount_cents") or 0))
                        except Exception as e:
                            print(f"[care-share] credit failed sid={sid}: {e!r}", flush=True)
                        try:
                            if updated and updated.get("next_charge_date"):
                                _until = (datetime.fromisoformat(updated["next_charge_date"])
                                          + timedelta(days=MEMBERSHIP_GRANT_GRACE_DAYS)).isoformat() + "Z"
                                _extend_membership_grant(cx, sub["email"], _until, "membership_renewal")
                        except Exception as _ge:
                            print(f"[sub-cron] grant-extend sub={sid}: {_ge!r}", flush=True)
                        try:
                            _send_subscription_email(sub["email"], "receipt", {
                                "total_cents": amount_cents, "invoice_id": "",
                                "kind": "membership", "product": _product,
                                "next_charge_date": updated["next_charge_date"] if updated else ""})
                        except Exception as ee:
                            print(f"[sub-cron] membership email sub={sid}: {ee!r}", flush=True)
                        # Term cap: a fixed-term Continuous Care sub stops after its committed
                        # number of charges (no auto-renew). NULL cap = legacy uncapped membership.
                        try:
                            _cap = updated.get("term_charges_total") if updated else None
                            if _cap and updated.get("order_count", 0) >= int(_cap):
                                _subs.set_status(cx, sid, "cancelled")
                        except Exception as _ce:
                            print(f"[sub-cron] term-cap sub={sid}: {_ce!r}", flush=True)
                        charged += 1
                    else:
                        _subs.bump_failed_count(cx, sid)
                        failed += 1
                    continue

                items = sub.get("items") or []
                ship = sub.get("ship_address") or {}
                order_count = sub.get("order_count", 0)
                # Per-line loyalty: bundle lines climb 12->29, single SKUs 3->25.
                # Gated to 0 for all lines when the member isn't paid-through.
                active = bool(_active_membership_for_email(sub["email"]))

                # Price the order
                try:
                    pc = _price_cart(items, ship=ship, subscriber_order_count=order_count,
                                     subscriber_active=active,
                                     program_member=_is_paid_member(sub["email"]),
                                     email=sub["email"])
                except CheckoutError as ce:
                    print(f"[sub-cron] price_cart sub={sid}: {ce!r}", flush=True)
                    failed += 1
                    continue

                discount_cents = int(pc.get("discount_cents", 0))
                points_redeemed_cents = int(pc.get("points_redeemed_cents", 0))
                shipping_cents = int(pc.get("shipping_cents", 0))
                # Charge the discounted product subtotal + shipping. GET is absorbed
                # (recorded, not billed to the customer), so use subtotal_cents NOT total_cents
                # (which includes get_cents). This matches the reorder invoice total.
                total_cents = int(pc["priced"].get("subtotal_cents", 0)) + shipping_cents

                if dry_run:
                    print(f"[sub-cron] DRY charge sub={sid} email={sub['email']}"
                          f" amount={total_cents}", flush=True)
                    charged += 1
                    continue

                # Charge off-session
                res = stripe_pay.charge_off_session(
                    sub["stripe_customer_id"],
                    sub["stripe_payment_method_id"],
                    total_cents,
                    description="Remedy Match subscription",
                    metadata={"sub": str(sid)},
                )

                if res.get("status") == "succeeded":
                    external_ref = res.get("id") or ""

                    # Record the order
                    _ingest_order(
                        source="subscription",
                        external_ref=external_ref,
                        email=sub["email"],
                        items=pc.get("items_rec") or [],
                        total_cents=total_cents,
                        address=ship,
                        channel="retail",
                        get_cents=pc["priced"].get("get_cents", 0),
                        discount_cents=discount_cents,
                        points_redeemed_cents=points_redeemed_cents,
                        shipping_cents=shipping_cents,
                    )

                    # Paid-only (QBO Stage 3): no QBO invoice/customer for this charge --
                    # book ONE line-faithful Sales Receipt inline now that payment is
                    # confirmed. Best-effort + idempotent (book_sale_on_payment claims
                    # the booking slot atomically), so this can never break the charge/
                    # subscription-bookkeeping path below.
                    try:
                        from dashboard import qbo_sale as _qsale
                        qbo_payload = {
                            "lines": pc["qbo_lines"] + _shipping_line(shipping_cents),
                            "discount_cents": discount_cents + points_redeemed_cents,
                            "tax_cents": 0,
                        }
                        _bos_orders.set_order_qbo_lines(cx, external_ref, qbo_payload)
                        _o = _bos_orders.find_order_by_external_ref(cx, external_ref)
                        if _o:
                            _qsale.book_sale_on_payment(cx, dict(_o))
                    except Exception as qe:
                        print(f"[sub-cron] qbo sale booking failed sid={sid}: {qe!r}", flush=True)

                    _subs.advance_after_charge(cx, sid)
                    _subs.reset_failed_count(cx, sid)

                    # Advance to get next_charge_date for receipt email
                    updated = _subs.get(cx, sid)
                    _maybe_extend_founding_membership(cx, sub, updated)
                    _send_subscription_email(sub["email"], "receipt", {
                        "total_cents": total_cents,
                        "invoice_id": "",
                        "kind": sub.get("kind", "product"),
                        "next_charge_date": updated["next_charge_date"] if updated else "",
                    })
                    charged += 1
                    print(f"[sub-cron] charged sub={sid} pi={res.get('id')}"
                          f" amount={total_cents}", flush=True)

                else:
                    # Failed or requires_action — dun
                    _subs.bump_failed_count(cx, sid)
                    updated = _subs.get(cx, sid)
                    new_fail_count = (updated or {}).get("failed_count", 1)

                    if new_fail_count >= 3:
                        _subs.set_status(cx, sid, "past_due")
                        print(f"[sub-cron] past_due sub={sid} after {new_fail_count} failures",
                              flush=True)

                    _send_subscription_email(sub["email"], "payment_failed", {
                        "total_cents": total_cents,
                        "failed_count": new_fail_count,
                        "status": res.get("status"),
                        "decline_code": res.get("decline_code"),
                    })
                    failed += 1
                    print(f"[sub-cron] payment failed sub={sid}"
                          f" status={res.get('status')} fail_count={new_fail_count}",
                          flush=True)

            except Exception as e:
                print(f"[sub-cron] sub={sid} unexpected error: {e!r}", flush=True)
                failed += 1

    return jsonify({
        "ok": True,
        "charged": charged,
        "skipped": skipped,
        "failed": failed,
        "notified": notified,
        "comped": comped,
        "dry_run": dry_run,
    })


@app.route("/api/cron/backfill-membership-grants", methods=["POST"])
def cron_backfill_membership_grants():
    key = request.headers.get("X-Cron-Secret", "")
    expected = os.environ.get("CRON_SECRET") or os.environ.get("CONSOLE_SECRET", "")
    if not expected or key != expected:
        return jsonify({"error": "unauthorized"}), 401
    dry = request.args.get("dry_run", "").lower() in ("1", "true", "yes")
    from dashboard import subscriptions as _subs
    fixed = 0
    with _db_lock, sqlite3.connect(LOG_DB) as cx:
        cx.row_factory = sqlite3.Row
        _subs.init_subscriptions_table(cx); _subs.migrate_add_membership_columns(cx); _subs.migrate_add_term_cap_column(cx); _subs.migrate_add_attribution_column(cx); _subs.migrate_add_consent_column(cx)
        rows = cx.execute("SELECT DISTINCT email, next_charge_date FROM subscriptions "
                          "WHERE kind='membership' AND status='active'").fetchall()
        for r in rows:
            until = (datetime.fromisoformat(r["next_charge_date"]) + timedelta(days=MEMBERSHIP_GRANT_GRACE_DAYS)).isoformat() + "Z"
            cur = cx.execute("SELECT MAX(expires_at) FROM memberships WHERE email=?", (r["email"],)).fetchone()
            have = cur[0] if cur else None
            if not (have and have >= until):
                fixed += 1
                if not dry:
                    _extend_membership_grant(cx, r["email"], until, "backfill_2026_06")
    return jsonify({"ok": True, "fixed": fixed, "dry_run": dry})


@app.route("/api/cron/easypost-sync", methods=["POST"])
def cron_easypost_sync():
    """Register EasyPost trackers for shipments we have tracking numbers for, and
    backstop-poll registered-but-undelivered trackers. Opens coaching windows on
    delivered. No-op when EasyPost is unconfigured (safe to schedule pre-go-live)."""
    key = request.headers.get("X-Cron-Secret", "")
    expected = os.environ.get("CRON_SECRET") or os.environ.get("CONSOLE_SECRET", "")
    if not expected or key != expected:
        return jsonify({"error": "unauthorized"}), 401
    from dashboard import easypost as _ep
    if not _ep.is_configured():
        return jsonify({"ok": True, "registered": 0, "activated": 0, "skipped": "easypost_unconfigured"})
    registered = 0
    activated = 0
    now_iso = datetime.utcnow().isoformat() + "Z"
    with _db_lock, sqlite3.connect(LOG_DB) as cx:
        cx.row_factory = sqlite3.Row
        _tracking.init_tracking_schema(cx); _tracking.migrate_add_delivery_columns(cx)
        # 1) register trackers for shipments with a tracking number but no tracker yet
        for r in cx.execute(
                "SELECT id, tracking_number FROM shipments WHERE tracking_number IS NOT NULL "
                "AND easypost_tracker_id IS NULL AND delivered_at IS NULL LIMIT 100").fetchall():
            try:
                t = _ep.create_tracker(r["tracking_number"])
                _tracking.set_shipment_tracker(cx, r["id"], t.get("tracker_id", ""))
                registered += 1
                if (t.get("status") or "").lower() == "delivered":
                    sh = cx.execute("SELECT * FROM shipments WHERE id=?", (r["id"],)).fetchone()
                    if _activate_coaching_for_shipment(cx, sh, delivered_at=now_iso).get("ok"):
                        activated += 1
            except Exception as e:
                print(f"[easypost-sync register] {r['tracking_number']}: {e!r}", flush=True)
        # 2) backstop poll: registered, not yet delivered
        for r in cx.execute(
                "SELECT * FROM shipments WHERE easypost_tracker_id IS NOT NULL "
                "AND delivered_at IS NULL LIMIT 100").fetchall():
            try:
                st = _ep.get_tracker(r["easypost_tracker_id"])
                if (st.get("status") or "").lower() == "delivered":
                    if _activate_coaching_for_shipment(cx, r, delivered_at=now_iso).get("ok"):
                        activated += 1
            except Exception as e:
                print(f"[easypost-sync poll] {r['easypost_tracker_id']}: {e!r}", flush=True)
    return jsonify({"ok": True, "registered": registered, "activated": activated})


# ── One-time Gmail token upload (helper for first-time setup on Render) ───────
# Local token at ~/.config/google/token.json gets POSTed here once and
# persisted to /data/google-token.json on the web service's disk.
@app.route("/admin/upload-gmail-token", methods=["POST"])
@require_console_key
def admin_upload_gmail_token():
    try:
        body = request.get_json(silent=True) or {}
        token_json = body.get("token")
        if not token_json:
            return fail("token field required (paste contents of ~/.config/google/token.json)", status=400)
        # Validate it parses + has expected shape
        if isinstance(token_json, str):
            import json as _json
            token_json = _json.loads(token_json)
        for required in ("token", "refresh_token", "client_id", "client_secret"):
            if required not in token_json:
                return fail(f"token JSON missing field: {required}", status=400)
        target = os.environ.get("GMAIL_TOKEN_PATH", "/data/google-token.json")
        Path(target).parent.mkdir(parents=True, exist_ok=True)
        import json as _json
        with open(target, "w") as f:
            _json.dump(token_json, f)
        os.chmod(target, 0o600)
        return ok({
            "saved_to": target,
            "scopes": token_json.get("scopes", []),
            "client_id_suffix": token_json.get("client_id", "")[-12:],
        })
    except Exception as e: return fail(e, status=500)


