@app.route("/coaching/auth/<token>", methods=["GET", "POST"])
def coaching_auth_token(token):
    email = _validate_membership_magic_link(token)
    if not email:
        html = _render_static_template("coaching.html", status="error")
        return html, 410, {"Content-Type": "text/html; charset=utf-8"}
    if request.method == "GET":
        # Don't consume on GET -- a mail scanner's prefetch would burn the
        # token before the member ever clicks. See _confirm_post_page.
        return _confirm_post_page(
            request.path, title="Sign in to Remedy Match coaching",
            heading="Welcome back",
            blurb="Continue to open your coaching dashboard.",
            button="Continue")
    # Consume the token
    th = _hash_token(token)
    now_iso = datetime.utcnow().isoformat() + "Z"
    with _db_lock, sqlite3.connect(LOG_DB) as cx:
        cur = cx.execute(
            "UPDATE auth_tokens SET consumed_at=? WHERE token_hash=? AND consumed_at IS NULL",
            (now_iso, th)
        )
        if cur.rowcount != 1:
            html = _render_static_template("coaching.html", status="error")
            return html, 410, {"Content-Type": "text/html; charset=utf-8"}
    # Mint amg_session if absent, then set rm_member_email cookie
    session_id = request.cookies.get("amg_session", "")
    minted = not session_id
    if minted:
        session_id = secrets.token_urlsafe(16)
    resp = redirect("/coaching", code=302)
    if minted:
        resp.set_cookie("amg_session", session_id,
                        max_age=60 * 60 * 24 * 365, httponly=True,
                        samesite="Lax", secure=request.is_secure)
    resp.set_cookie("rm_member_email", email,
                    max_age=60 * 60 * 24 * 365, httponly=True,
                    samesite="Lax", secure=request.is_secure)
    return resp


@app.route("/coaching/activate/<token>", methods=["GET", "POST"])
def coaching_activate(token):
    """GET previews; POST opens the coaching window for the order the token names."""
    th = _hash_token((token or "").strip())
    with _db_lock, sqlite3.connect(LOG_DB) as cx:
        cx.row_factory = sqlite3.Row
        row = cx.execute(
            "SELECT email, extra, expires_at, consumed_at FROM auth_tokens "
            "WHERE token_hash=? AND purpose='coaching_activate'", (th,)).fetchone()
        email = None
        order_id = None
        if row and not row["consumed_at"]:
            try:
                exp = _parse_utc(row["expires_at"])
                if exp >= datetime.now(timezone.utc):
                    email = row["email"]
                    order_id = (json.loads(row["extra"] or "{}")).get("order_id")
            except Exception:
                pass
        if not email:
            payload = {"valid": False}
        else:
            order = cx.execute("SELECT id, source, created_at FROM orders WHERE id=?",
                               (order_id,)).fetchone() if order_id is not None else None
            if request.method == "POST":
                if order is None:
                    payload = {"valid": True, "confirmed": True, "ok": False, "reason": "not_found"}
                else:
                    res = _open_coaching_for_order(cx, email, int(order["id"]), order["source"])
                    if res.get("ok"):
                        cx.execute("UPDATE auth_tokens SET consumed_at=? WHERE token_hash=? AND consumed_at IS NULL",
                                   (datetime.utcnow().isoformat() + "Z", th))
                        cx.commit()
                    payload = {"valid": True, "confirmed": True, **res}
            else:
                payload = {"valid": True, "confirmed": False,
                           "order_date": (order["created_at"][:10] if order else None),
                           "window_days": _coaching.WINDOW_DAYS}
    html = (STATIC / "coaching-activate.html").read_text()
    safe = (json.dumps(payload).replace("<", "\\u003c")
            .replace(">", "\\u003e").replace("&", "\\u0026"))
    html = html.replace("</head>", f"<script>window.__COACHING__ = {safe};</script>\n</head>")
    resp = Response(html, mimetype="text/html", status=200)
    resp.headers["Cache-Control"] = "no-cache, no-store, must-revalidate"
    resp.headers["Pragma"] = "no-cache"
    return resp


@app.route("/hold/<token>/ship", methods=["GET", "POST"])
def household_hold_ship(token):
    """Caregiver 'ship now' release page for a household hold group. GET renders
    a scanner-safe confirm (no mutation); POST releases the hold and, when it
    has 2+ member orders, groups them into a combined_shipments shipment. See
    _confirm_post_page for why GET must never consume the token."""
    from dashboard import household_holds as _holds
    invalid = ("<!doctype html><meta charset=utf-8><title>Link expired</title>"
               "<div style='font-family:Georgia,serif;max-width:520px;margin:60px auto'>"
               "<h1>This shipment is already on its way</h1>"
               "<p>Nothing more to do — your household order has been released.</p></div>")
    with _db_lock, sqlite3.connect(LOG_DB) as cx:
        cx.row_factory = sqlite3.Row
        _holds.init_hold_tables(cx)
        hold = _holds.hold_by_release_token(cx, token)
        if hold is None or hold["status"] != "open":
            return invalid, (200 if hold else 404)
        if request.method == "GET":
            members = hold.get("members") or []
            names = ", ".join((m.get("name") or m.get("email") or f"#{m['id']}") for m in members)
            return _confirm_post_page(
                f"/hold/{token}/ship",
                title="Ship your household order",
                heading="Ship your household order now?",
                blurb=f"This will send your household's order ({names}) to fulfillment now. "
                      "Anything ordered after this ships separately.",
                button="Ship it now")
        # POST: release, then hand to the combined-shipment layer
        res = _holds.release_hold(cx, hold["id"], by="caregiver")
        ids = res["order_ids"]
        try:
            _release_to_shipment(cx, ids, created_by="caregiver-release")
        except Exception as e:
            print(f"[hold-ship] create_shipment({ids}) failed: {e!r}", flush=True)
    return ("<!doctype html><meta charset=utf-8><title>On its way</title>"
            "<div style='font-family:Georgia,serif;max-width:520px;margin:60px auto'>"
            "<h1>Done — your order is on its way</h1>"
            "<p>We’ll email tracking as soon as it ships.</p></div>"), 200


