def _release_to_shipment(cx, order_ids, *, created_by):
    """Group released hold orders into one combined shipment and recompute
    fair-share shipping. Returns the shipment id (None for a lone order)."""
    from dashboard import combined_shipments as _cs
    if len(order_ids) < 2:
        return None
    made = _cs.create_shipment(cx, order_ids, created_by=created_by)
    sid = made["id"]
    try:
        _recompute_combined_shipping(cx, sid)
    except Exception as e:
        print(f"[hold-release] recompute shipping failed for #{sid}: {e!r}", flush=True)
    return sid


def _hold_new_order_and_invite(cx, order_id):
    """Hold a new order and, if it OPENED a new household group, email the caregiver
    the 'ship now' invite (one per group). Fail-open: never break order creation."""
    from dashboard import household_holds as _holds
    _holds.init_hold_tables(cx)
    res = _holds.maybe_hold_new_order(cx, order_id)
    if res and res.get("opened"):
        try:
            _holds.send_invite(cx, res["group_id"], base_url=PUBLIC_BASE_URL)
        except Exception as _e:
            print(f"[hold] send_invite skipped for group {res.get('group_id')}: {_e!r}", flush=True)
    return res


def _recompute_combined_shipping(cx, sid):
    """Recompute a combined shipment's ONE-parcel shipping (the geometric packer on
    the union of all members' bottles, via the same _price_cart the invoices use)
    and split it across members in proportion to each member's OWN standalone
    shipping — so each pays their fair share and the combining saving is passed on
    pro-rata. Only UNPAID members are re-billed; a member already paid keeps its
    invoice as billed, but if combining lowered their fair share below what they
    paid, the overpayment is recorded as an order credit (overpay_credit_cents) for
    Rae to apply forward or refund. Returns a summary dict."""
    members = _bos_orders.orders_in_group(cx, sid)
    if len(members) < 2:
        return {"ok": False, "error": "shipment has fewer than 2 members"}
    ship_addr = {"country": "US"}
    try:
        sh = _bos_combined_shipments.get_shipment(cx, sid) or {}
        ship_addr = {**(sh.get("ship_to") or {}), "country": "US"}
    except Exception:
        pass

    def _cart(o):
        return [{"slug": (it.get("slug") or "").strip(), "qty": int(it.get("qty", 1) or 1)}
                for it in (o.get("items") or []) if (it.get("slug") or "").strip()]

    def _ship_of(cart):
        if not cart:
            return 0
        try:
            return int((_price_cart(cart, ship=ship_addr, channel="retail") or {}).get("shipping_cents") or 0)
        except Exception as e:
            print(f"[combined-ship] price failed: {e!r}", flush=True)
            return 0

    union = []
    for m in members:
        union += _cart(m)
    combined = _ship_of(union)
    weights = [_ship_of(_cart(m)) for m in members]   # each member's standalone shipping
    shares = _bos_combined_shipments.split_shipping_proportional(combined, weights)
    updates = []
    for m, share in zip(members, shares):
        old_ship = int(m.get("shipping_cents") or 0)
        if (m.get("pay_status") or "unpaid") == "paid":
            # A paid invoice is frozen (never re-billed). But if combining lowered
            # this member's fair share below what they paid standalone, record the
            # overpayment as a credit on the order (informational — total/shipping
            # untouched) so Rae can apply it to the next order or refund it.
            # Idempotent: recompute + REPLACE on every recalc, never stack.
            credit = _bos_combined_shipments.paid_member_overpay_cents(
                m.get("paid_cents"), m.get("total_cents"), old_ship, int(share))
            _bos_orders.set_order_overpay_credit(cx, m["id"], credit)
            # Slice 2 (dark): also grant the credit to the customer's spendable
            # ship_credit balance so it auto-applies to their next order / can be
            # refunded. Keyed to this paid order's external_ref, idempotent.
            if credit > 0 and _ship_credit_enabled():
                from dashboard import ship_credit as _ship_credit
                _ship_credit.grant(cx, m.get("email"), credit,
                                   source_ref=m.get("external_ref"))
            updates.append({"order_id": m["id"], "name": m.get("name") or "",
                            "skipped": "paid", "shipping_cents": old_ship,
                            "fair_share_cents": int(share),
                            "overpay_credit_cents": credit})
            continue
        new_total = max(0, int(m.get("total_cents") or 0) - old_ship + int(share))
        _bos_orders.set_order_shipping(cx, m["id"], int(share), new_total)
        updates.append({"order_id": m["id"], "name": m.get("name") or "",
                        "old_shipping_cents": old_ship, "new_shipping_cents": int(share),
                        "new_total_cents": new_total})
    return {"ok": True, "shipment_id": sid,
            "combined_shipping_cents": combined, "members": updates}


@app.route("/api/console/shipments/<int:sid>/recalc-shipping", methods=["POST"])
def console_shipment_recalc_shipping(sid):
    """Owner/ops: recompute + split one-parcel shipping across a combined shipment's
    unpaid members (proportional to each member's own standalone shipping). A paid
    member whose share drops below what they paid gets an overpayment credit
    recorded on their order (not re-billed)."""
    actor = _bos_actor()
    if actor is None:
        return jsonify({"ok": False, "error": "unauthorized"}), 401
    with _db_lock, _sqlite3.connect(LOG_DB) as cx:
        cx.row_factory = _sqlite3.Row
        res = _recompute_combined_shipping(cx, sid)
    return jsonify(res), (200 if res.get("ok") else 400)


def _is_shipping_line_name(name):
    """True for any QBO shipping/handling line. Substring match on 'shipping' (covers
    the funnel/reorder line 'Shipping (USPS)' / 'USPS shipping' as well as plain
    'Shipping & Handling'); no formulation in the catalog is named with 'shipping'."""
    n = (name or "").strip().lower()
    return ("shipping" in n) or (n in ("s&h", "handling"))


def _qbo_invoice_to_items(inv, catalog):
    """Pure: rebuild priced order line items from a QBO invoice's Line array. Returns
    (items, line_sum_cents). Each item = {name, qty, desc, slug, unit_cents, line_cents}.
    Shipping lines are dropped (the order carries shipping separately). slug is resolved
    via the product catalog (None if unresolved). Used to repair reorder/portal-reorder
    orders whose stored items were saved without per-line pricing."""
    items, line_sum = [], 0
    for L in (inv.get("Line") or []):
        if L.get("DetailType") != "SalesItemLineDetail":
            continue
        d = L.get("SalesItemLineDetail") or {}
        try:
            qty = int(d.get("Qty") or 1) or 1
        except (TypeError, ValueError):
            qty = 1
        amount = int(round(float(L.get("Amount") or 0) * 100))
        nm = ((d.get("ItemRef") or {}).get("name") or L.get("Description") or "").strip()
        if _is_shipping_line_name(nm):
            continue
        unit = int(round(amount / qty)) if qty else amount
        slug = _pp.name_to_slug(nm, catalog) if nm else None
        items.append({"name": nm, "qty": qty, "desc": nm,
                      "slug": slug, "unit_cents": unit, "line_cents": unit * qty})
        line_sum += unit * qty
    return items, line_sum


@app.route("/api/console/orders/reprice-from-qbo", methods=["POST"])
def console_reprice_orders_from_qbo():
    """Prod-ops: repair reorder/portal-reorder orders whose stored line items have no
    per-line price (saved name+qty only), so the invoice/print page shows real pricing.
    Rebuilds each order's items from its authoritative QBO invoice (external_ref). Only
    touches items_json — total/discount/shipping/status are left untouched.
    Owner-only (CONSOLE_SECRET / CRON_SECRET — a per-user VA token can't reach this
    write), mirroring the sibling /api/console/reconcile-qbo. Query params: ?dry_run=1
    to preview without writing; ?order_id=N to scope to one order (and force re-pricing
    even if it already has prices)."""
    key = (request.headers.get("X-Console-Key", "")
           or request.headers.get("X-Cron-Secret", "")
           or request.args.get("key", ""))
    allowed = {s for s in (os.environ.get("CONSOLE_SECRET"), os.environ.get("CRON_SECRET")) if s}
    if not allowed or key not in allowed:
        return jsonify({"ok": False, "error": "unauthorized"}), 401
    dry = request.args.get("dry_run") in ("1", "true", "yes", "on")
    only = (request.args.get("order_id") or "").strip()
    from dashboard import qbo_billing as _qb_local
    catalog = (_PRODUCTS.get("products") or {})
    cx = _sqlite3.connect(LOG_DB)
    cx.row_factory = _sqlite3.Row
    results = []
    try:
        orders = _bos_orders.list_orders(cx, limit=500)
        for o in orders:
            if only and str(o.get("id")) != only:
                continue
            if o.get("source") not in ("reorder", "portal-reorder"):
                continue
            its = o.get("items") or []
            already_priced = any((i.get("unit_cents") or i.get("line_cents")) for i in its)
            # Default sweep skips already-priced orders; an explicit order_id re-prices.
            if already_priced and not only:
                continue
            ref = (o.get("external_ref") or "").strip()
            rec = {"id": o.get("id"), "external_ref": ref, "status": o.get("status"),
                   "order_total_cents": int(o.get("total_cents") or 0)}
            if not ref:
                rec["skipped"] = "no external_ref"
                results.append(rec)
                continue
            try:
                inv = _qb_local.get_invoice(ref)
            except Exception as e:
                rec["error"] = f"qbo get_invoice failed: {type(e).__name__}: {e}"
                results.append(rec)
                continue
            if not inv:
                # get_invoice returns the bare Invoice dict (None when QBO has none).
                rec["skipped"] = "QBO invoice not found"
                results.append(rec)
                continue
            new_items, line_sum = _qbo_invoice_to_items(inv, catalog)
            rec["lines"] = new_items
            rec["line_sum_cents"] = line_sum
            if not new_items:
                rec["skipped"] = "no product lines on QBO invoice"
                results.append(rec)
                continue
            if not dry:
                cx.execute("UPDATE orders SET items_json=?, updated_at=? WHERE id=?",
                           (json.dumps(new_items), _bos_orders._now(), o.get("id")))
                cx.commit()
                rec["applied"] = True
            results.append(rec)
    finally:
        cx.close()
    return jsonify({"ok": True, "dry_run": dry, "count": len(results), "results": results})


