@app.route("/api/console/backfill-legacy-payments", methods=["POST"])
def api_backfill_legacy_payments():
    """Owner/OPS: one-time backfill of pre-ledger PAID orders into the order_payments
    ledger as source='legacy' rows (amount = the order's legacy paid_cents; NO QBO
    push). Default is a DRY RUN (reports the plan, writes nothing); ?dry_run=0 applies.
    Body {"skip":[order_id,...]} excludes orders (e.g. one under active QBO
    reconciliation whose legacy paid_cents is wrong). Idempotent (orders that already
    have a ledger row are excluded); biofield trials excluded."""
    actor = _bos_actor()
    if actor is None or actor.role not in (_bos_rbac.OWNER, _bos_rbac.OPS):
        return jsonify({"ok": False, "error": "unauthorized"}), 401
    dry = (request.args.get("dry_run") or "1").strip().lower() not in ("0", "false", "no")
    body = request.get_json(silent=True) or {}
    skip = body.get("skip") or []
    cx = _sqlite3.connect(LOG_DB); cx.row_factory = _sqlite3.Row
    try:
        _op.ensure_table(cx)
        res = _op.backfill_legacy_payments(cx, dry_run=dry, skip_order_ids=skip)
        return jsonify({"ok": True, "dry_run": dry, **res})
    finally:
        cx.close()


@app.route("/api/console/customers/rename", methods=["POST"])
def api_console_customer_rename():
    """Owner: correct a customer's display name across their people record and all
    their orders (keyed by email) — the invoice bills to the ORDER name, so a
    person-only edit wouldn't reach it. Body: {email, name, first_name?, last_name?}.
    Only non-blank fields are written."""
    actor = _bos_actor()
    if actor is None or actor.role != _bos_rbac.OWNER:
        return jsonify({"ok": False, "error": "unauthorized"}), 401
    body = request.get_json(silent=True) or {}
    from dashboard import customers as _cust
    cx = _sqlite3.connect(LOG_DB)
    try:
        res = _cust.rename_by_email(
            cx, body.get("email"), name=body.get("name"),
            first_name=body.get("first_name"), last_name=body.get("last_name"))
    except ValueError as e:
        return jsonify({"ok": False, "error": str(e)}), 400
    finally:
        cx.close()
    return jsonify({"ok": True, **res})


# ── Feature-flag report ───────────────────────────────────────────────────────
_FLAG_NAME_RE = re.compile(r"^_?[A-Z][A-Z0-9_]*_ENABLED$")
_FLAG_TRUTHY = ("1", "true", "yes", "on")


def _flag_report():
    """Every *_ENABLED flag this process knows about.

    TWO kinds exist and they differ in a way that matters:
      - import-time constants (module globals, fixed when the process started). These
        can go STALE: set the env var, skip the deploy, and the app still behaves as if
        the flag were off. `value` therefore reads the GLOBAL, not os.environ.
      - call-time reads (no global at all; os.environ is read inside a function on each
        request, e.g. SCAN_REQUEST_ENABLED at app.py:14808). Never stale. A globals scan
        would never find them, so discovery is the UNION of globals and env keys.

    A deleted var and a deliberate false make the app behave identically but mean
    different things, so `env_present` is reported separately. A deleted CALL-TIME flag
    has neither a global nor an env key and so vanishes from this report entirely — the
    checker's absent-from-response rule is what catches that case.

    Only booleans, only *_ENABLED keys: no other env var can leak through here."""
    out = {}
    for name, val in list(globals().items()):
        if isinstance(val, bool) and _FLAG_NAME_RE.match(name):
            out[name] = {"value": bool(val),
                         "env_present": name in os.environ,
                         "source": "import"}
    for name in os.environ:
        if name in out or not _FLAG_NAME_RE.match(name):
            continue
        raw = (os.environ.get(name) or "").strip().lower()
        out[name] = {"value": raw in _FLAG_TRUTHY,
                     "env_present": True,
                     "source": "runtime"}
    return out


@app.route("/api/console/flags", methods=["GET"])
@require_console_key
def api_console_flags():
    """Owner: every feature flag as the RUNNING PROCESS sees it, plus whether each env
    var exists at all. Read-only. Consumed by scripts/surface_check.py's daily drift
    check — a flag with no HTTP surface (REPERTOIRE_ENABLED, INVOICE_PAYLINK_ENABLED)
    cannot be watched any other way."""
    try:
        return ok({"flags": _flag_report()})
    except Exception as e:
        return fail(e)


@app.route("/api/console/client-prefs", methods=["GET", "POST"])
def api_console_client_prefs():
    """Owner: read/set a client's fulfillment defaults (today: pickup_default).
    GET ?email= -> {pickup_default}; POST {email, pickup_default} sets it.
    pickup_default must be present in the POST body (explicit true/false) —
    an omitted key is rejected rather than treated as false.

    This is the ONLY writer. An order's Pickup tick is a per-order override and
    never lands here — a client's default changes when the owner says so, not as
    a side effect of one order being collected or mailed."""
    actor = _bos_actor()
    if actor is None or actor.role != _bos_rbac.OWNER:
        return jsonify({"ok": False, "error": "unauthorized"}), 401
    from dashboard import client_prefs as _cpf
    cx = _sqlite3.connect(LOG_DB)
    try:
        _cpf.init_table(cx)
        if request.method == "GET":
            email = (request.args.get("email") or "").strip().lower()
            if not email:
                return jsonify({"ok": False, "error": "email required"}), 400
            # Most-recent recorded payment method for this client, so the order
            # builder can pre-select the way they last paid (falling back to the
            # Stripe default when they have no history). Read-only; a missing
            # orders table or column just means "no history" -> None.
            last_pay_method = None
            try:
                _r = cx.execute(
                    "SELECT pay_method FROM orders WHERE lower(email)=? "
                    "AND pay_method IS NOT NULL AND TRIM(pay_method)!='' "
                    "ORDER BY created_at DESC, id DESC LIMIT 1", (email,)).fetchone()
                if _r:
                    last_pay_method = _r[0]
            except sqlite3.OperationalError:
                pass
            return jsonify({"ok": True, "email": email,
                            "pickup_default": _cpf.get_pickup_default(cx, email),
                            "last_pay_method": last_pay_method})
        body = request.get_json(silent=True) or {}
        email = (body.get("email") or "").strip().lower()
        if not email:
            return jsonify({"ok": False, "error": "email required"}), 400
        # A partial or retried request must not silently un-set a client
        # preference — require the caller to state pickup_default explicitly,
        # even when turning it off, so absence can never masquerade as "false".
        if "pickup_default" not in body:
            return jsonify({"ok": False,
                            "error": "pickup_default required (explicit true/false)"}), 400
        _cpf.set_pickup_default(cx, email, bool(body.get("pickup_default")))
        return jsonify({"ok": True, "email": email,
                        "pickup_default": _cpf.get_pickup_default(cx, email)})
    finally:
        cx.close()


@app.route("/api/console/client-prices", methods=["GET", "POST", "DELETE"])
def api_console_client_prices():
    """Owner: view/set/remove a client's persistent special prices (email+slug ->
    cents). Applied by the in-house pricer when no explicit per-line override is
    typed. GET ?email= lists one client (no email = all clients with prices);
    POST {email, prices:[{slug,price_cents,note}]} (or a single {email,slug,
    price_cents}); DELETE {email, slug}."""
    actor = _bos_actor()
    if actor is None or actor.role != _bos_rbac.OWNER:
        return jsonify({"ok": False, "error": "unauthorized"}), 401
    from dashboard import client_prices as _cp
    cx = _sqlite3.connect(LOG_DB)
    try:
        _cp.init_table(cx)
        if request.method == "GET":
            email = (request.args.get("email") or "").strip().lower()
            if email:
                return jsonify({"ok": True, "email": email, "prices": _cp.list_for(cx, email),
                                "ff_flat_cents": _cp.get_ff_flat(cx, email)})
            return jsonify({"ok": True, "clients": _cp.clients_with_prices(cx)})
        body = request.get_json(silent=True) or {}
        email = (body.get("email") or "").strip().lower()
        if not email:
            return jsonify({"ok": False, "error": "email required"}), 400
        if request.method == "DELETE":
            slug = (body.get("slug") or "").strip()
            if not slug:
                return jsonify({"ok": False, "error": "slug required"}), 400
            _cp.remove(cx, email, slug)
            return jsonify({"ok": True, "prices": _cp.list_for(cx, email)})
        # (a) Flat rate for ALL of this client's FFs.
        if body.get("ff_flat_cents") not in (None, ""):
            try:
                _cp.set_ff_flat(cx, email, int(body["ff_flat_cents"]))
                return jsonify({"ok": True, "ff_flat_cents": _cp.get_ff_flat(cx, email)})
            except (ValueError, TypeError):
                return jsonify({"ok": False, "error": "invalid ff_flat_cents"}), 400
        # (b) One $ applied to the FF products on this order (server picks the FFs).
        # A slug that is not FF-eligible (or is missing/inactive) is NOT priced. Report
        # those as `skipped`: dropping them silently still returned ok/saved, so the
        # price simply never persisted. Most of the catalog is not FF-eligible, so this
        # is the common case, not an edge one.
        if body.get("these_ff_cents") not in (None, ""):
            try:
                pc = int(body["these_ff_cents"])
            except (ValueError, TypeError):
                return jsonify({"ok": False, "error": "invalid these_ff_cents"}), 400
            saved, applied, skipped = 0, [], []
            for s in (body.get("slugs") or []):
                s = (s or "").strip()
                if not s:
                    continue
                pr = _get_product(s)          # None when missing OR inactive
                if pr is None:
                    skipped.append({"slug": s, "reason": "not in the catalog"})
                elif not _qty_eligible(pr):
                    skipped.append({"slug": s, "reason": "not a Functional Formulation"})
                else:
                    _cp.set_price(cx, email, s, pc, note="FFs-on-invoice")
                    saved += 1
                    applied.append(s)
            return jsonify({"ok": True, "saved": saved, "applied": applied,
                            "skipped": skipped, "prices": _cp.list_for(cx, email)})
        # (c) Explicit per-SKU list (the "save line prices" button).
        items = body.get("prices")
        if items is None and body.get("slug"):
            items = [{"slug": body.get("slug"), "price_cents": body.get("price_cents"),
                      "note": body.get("note")}]
        saved = 0
        for it in (items or []):
            slug = (it.get("slug") or "").strip()
            pc = it.get("price_cents")
            if not slug or pc in (None, ""):
                continue
            try:
                _cp.set_price(cx, email, slug, int(pc), it.get("note"))
                saved += 1
            except (ValueError, TypeError):
                continue
        return jsonify({"ok": True, "saved": saved, "prices": _cp.list_for(cx, email)})
    finally:
        cx.close()


@app.route("/api/console/cohorts", methods=["GET", "POST"])
def api_console_cohorts():
    """Owner: the cohort catalog (Phase 1). GET lists cohorts + the flag state;
    POST upserts one {key, name, policy:{type,...}, description?, active?}."""
    actor = _bos_actor()
    if actor is None or actor.role != _bos_rbac.OWNER:
        return jsonify({"ok": False, "error": "unauthorized"}), 401
    from dashboard import cohorts as _co
    cx = _sqlite3.connect(LOG_DB)
    try:
        _co.init_tables(cx)
        if request.method == "GET":
            return jsonify({"ok": True, "cohorts": _co.list_cohorts(cx),
                            "pricing_enabled": _cohort_pricing_enabled()})
        b = request.get_json(silent=True) or {}
        try:
            _co.upsert_cohort(cx, key=b.get("key"), name=b.get("name"),
                              policy=b.get("policy") or {}, description=b.get("description", ""),
                              active=bool(b.get("active", True)), is_default=bool(b.get("is_default", False)))
        except ValueError as e:
            return jsonify({"ok": False, "error": str(e)}), 400
        return jsonify({"ok": True, "cohorts": _co.list_cohorts(cx)})
    finally:
        cx.close()


@app.route("/api/console/cohorts/members", methods=["GET", "POST", "DELETE"])
def api_console_cohort_members():
    """Owner: cohort membership. GET ?email= lists a client's cohorts; POST
    {email, cohort_key, source?, expires_at?} adds; DELETE {email, cohort_key}."""
    actor = _bos_actor()
    if actor is None or actor.role != _bos_rbac.OWNER:
        return jsonify({"ok": False, "error": "unauthorized"}), 401
    from dashboard import cohorts as _co
    cx = _sqlite3.connect(LOG_DB)
    try:
        _co.init_tables(cx)
        if request.method == "GET":
            email = (request.args.get("email") or "").strip().lower()
            return jsonify({"ok": True, "email": email,
                            "cohorts": _co.member_cohorts(cx, email) if email else []})
        b = request.get_json(silent=True) or {}
        email = (b.get("email") or "").strip().lower()
        key = (b.get("cohort_key") or "").strip()
        if not email or not key:
            return jsonify({"ok": False, "error": "email and cohort_key required"}), 400
        if request.method == "DELETE":
            _co.remove_member(cx, email, key)
            return jsonify({"ok": True, "cohorts": _co.member_cohorts(cx, email)})
        try:
            _co.add_member(cx, email, key, source=b.get("source", "admin"),
                           expires_at=b.get("expires_at"))
        except ValueError as e:
            return jsonify({"ok": False, "error": str(e)}), 400
        return jsonify({"ok": True, "cohorts": _co.member_cohorts(cx, email)})
    finally:
        cx.close()


# ── Plan choice step (Phase 5) — client picks how they earn savings ────────────
# Sent ~3 weeks after delivery ("softly gets them thinking about reordering").
def _mint_plan_choice_token(email):
    tok = secrets.token_urlsafe(24)
    now = datetime.now(timezone.utc)
    with _db_lock, _sqlite3.connect(LOG_DB) as cx:
        cx.execute("INSERT INTO auth_tokens (token_hash, email, purpose, created_at, expires_at) "
                   "VALUES (?,?,?,?,?)",
                   (_hash_token(tok), (email or "").strip().lower(), "plan_choice",
                    now.isoformat(), (now + timedelta(days=60)).isoformat()))
        cx.commit()
    return tok


def _email_from_plan_choice_token(token):
    th = _hash_token((token or "").strip())
    now = datetime.now(timezone.utc).isoformat()
    with _sqlite3.connect(LOG_DB) as cx:
        row = cx.execute(
            "SELECT email FROM auth_tokens WHERE token_hash=? AND purpose='plan_choice' "
            "AND (expires_at IS NULL OR expires_at > ?)", (th, now)).fetchone()
    return (row[0] if row else None)


@app.route("/choose/<token>")
def plan_choice_page(token):
    resp = send_from_directory(STATIC, "choose.html")
    resp.headers["Cache-Control"] = "no-cache, no-store, must-revalidate"
    return resp


@app.route("/api/choose/<token>", methods=["GET"])
def api_plan_choice_get(token):
    email = _email_from_plan_choice_token(token)
    if not email:
        return jsonify({"ok": False, "error": "this link is invalid or expired"}), 404
    from dashboard import cohorts as _co
    cx = _sqlite3.connect(LOG_DB)
    try:
        _co.init_tables(cx)
        plans = [{"key": c["key"], "name": c["name"], "description": c["description"]}
                 for c in _co.choosable_cohorts(cx)]
        chosen = [c["key"] for c in _co.member_cohorts(cx, email)
                  if c["key"] in {p["key"] for p in plans}]
        name = ""
        try:
            r = cx.execute("SELECT name FROM people WHERE lower(email)=? LIMIT 1", (email,)).fetchone()
            name = (r[0] if r else "") or ""
        except Exception:
            name = ""
    finally:
        cx.close()
    return jsonify({"ok": True, "name": name, "plans": plans,
                    "chosen_key": (chosen[0] if chosen else None)})


@app.route("/api/choose/<token>", methods=["POST"])
def api_plan_choice_set(token):
    email = _email_from_plan_choice_token(token)
    if not email:
        return jsonify({"ok": False, "error": "this link is invalid or expired"}), 404
    key = ((request.get_json(silent=True) or {}).get("cohort_key") or "").strip()
    from dashboard import cohorts as _co
    with _db_lock, _sqlite3.connect(LOG_DB) as cx:
        _co.init_tables(cx)
        ok = _co.set_choice(cx, email, key)
    if not ok:
        return jsonify({"ok": False, "error": "not a valid plan"}), 400
    return jsonify({"ok": True, "chosen_key": key})


def _plan_choice_pending(days=21, window=10):
    """Emails delivered ~`days` ago (within a `window`-day band) that haven't picked
    a plan yet — the 3-week nudge cohort. Best-effort; empty on any gap."""
    try:
        from dashboard import cohorts as _co
        with _sqlite3.connect(LOG_DB) as cx:
            cx.row_factory = _sqlite3.Row
            _co.init_tables(cx)
            choice_keys = {c["key"] for c in _co.choosable_cohorts(cx)}
            if not choice_keys:
                return []
            lo = (datetime.utcnow() - timedelta(days=days + window)).isoformat() + "Z"
            hi = (datetime.utcnow() - timedelta(days=days)).isoformat() + "Z"
            rows = cx.execute(
                "SELECT DISTINCT lower(resolved_email) e FROM shipments "
                "WHERE delivered_at IS NOT NULL AND delivered_at >= ? AND delivered_at <= ? "
                "AND resolved_email IS NOT NULL AND resolved_email != ''", (lo, hi)).fetchall()
            out = []
            for r in rows:
                em = r["e"]
                if em and not any(c["key"] in choice_keys for c in _co.member_cohorts(cx, em)):
                    out.append(em)
            return out
    except Exception as _e:
        print(f"[plan-choice] pending skipped: {_e!r}", flush=True)
        return []


@app.route("/api/console/plan-choice/pending", methods=["GET"])
def api_console_plan_choice_pending():
    if not _portal_console_ok():
        return jsonify({"error": "unauthorized"}), 401
    return jsonify({"ok": True, "pending": _plan_choice_pending()})


@app.route("/api/console/plan-choice/send", methods=["POST"])
def api_console_plan_choice_send():
    """Owner: email the plan-choice link to one client (or the whole pending band).
    The ~3-week automation would call this from a cron piggyback."""
    if not _portal_console_ok():
        return jsonify({"error": "unauthorized"}), 401
    body = request.get_json(silent=True) or {}
    one = (body.get("email") or "").strip().lower()
    targets = [one] if one else _plan_choice_pending()
    base = PUBLIC_BASE_URL.rstrip("/")
    sent = []
    for em in targets:
        try:
            tok = _mint_plan_choice_token(em)
            link = f"{base}/choose/{tok}"
            body_txt = ("Aloha,\n\nAs you settle into your remedies, we're building ways to make "
                        "staying on your healing path more affordable. Take a moment to pick how "
                        "you'd like to earn your savings going forward:\n\n" + link +
                        "\n\nMahalo,\nDr. Glen Swartwout")
            _send_full_report_email(em, "", "Choose how you'd like to earn your savings", body_txt)
            sent.append(em)
        except Exception as _e:
            print(f"[plan-choice] send to {em} failed: {_e!r}", flush=True)
    return jsonify({"ok": True, "sent": sent, "count": len(sent)})


# ── Customer invoice pay-link (Phase 3) — PUBLIC, token-scoped ─────────────────
# Auth is the per-order token ONLY (never the console key). All pricing is
# recomputed server-side; client-sent prices are ignored; the Stripe amount comes
# from the order's server-side total. One token ⇄ one order.
def _invoice_order_for_token(token):
    oid = _pp.order_id_from_invoice_token(token)
    if not oid:
        return None
    cx = _sqlite3.connect(LOG_DB); cx.row_factory = _sqlite3.Row
    try:
        return _bos_orders.get_order(cx, int(oid))
    finally:
        cx.close()


def _invoice_points_balance(order):
    """Customer's redeemable points balance (email-keyed, lowercased to match the ledger)."""
    from dashboard import points as _points
    email = (order.get("email") or "").strip().lower()
    if not email:
        return 0
    cx = _sqlite3.connect(LOG_DB)
    try:
        _points.init_points_table(cx)
        return _points.balance(cx, email)
    finally:
        cx.close()


def _invoice_line_view(l):
    """Customer-safe line + service-fee anchoring. A line whose product is a
    `service` (e.g. Biofield Analysis) carries its catalog Value/Regular anchors so
    the invoice can sort it to the top and show them above the per-client Special
    (unit_cents). Public page can't reach the console catalog API, so resolve here."""
    out = {"slug": l.get("slug"), "name": l.get("name"), "qty": int(l.get("qty") or 0),
           "unit_cents": int(l.get("unit_cents") or 0), "line_cents": int(l.get("line_cents") or 0)}
    p = _get_product(l.get("slug") or "")
    if p:
        if p.get("service"):
            # Service fee carries explicit Value(SRP)/Regular anchors + sorts to top.
            out["service"] = True
            out["srp_cents"] = p.get("service_value_cents")
            out["regular_cents"] = p.get("service_regular_cents")
        else:
            base = p.get("price_cents")
            out["regular_cents"] = base
            # Value (SRP) anchor shown struck-through above the Regular price, in order:
            #   1. the product's own regular_cents — FMP's retail_sug_price — when it is
            #      genuinely above the charge price (essences $80/$70, infoceuticals
            #      $40/$39.97, CDS $40/$35, WholOmega 120ct $230/$190).
            #   2. the flat $80 FF anchor, for a $69.97 FF carrying no explicit SRP.
            #   3. otherwise none: Value == Regular and the invoice prints no anchor.
            # info_only lines never anchor. A regular_cents <= price is incoherent data
            # and is ignored here rather than at render time.
            srp = p.get("regular_cents")
            if p.get("info_only"):
                srp = base
            elif not (isinstance(srp, int) and srp > base):
                srp = _FF_SRP_CENTS if base == _FF_BASE_CENTS else base
            out["srp_cents"] = srp
    return out


def _titlecase_name(s):
    """Normalize a person name to Title Case for display. Client names are often
    stored all-lowercase (or all-caps) by import/portal flows — 'steven blank' →
    'Steven Blank'. Only touch values that are entirely one case; leave already
    mixed-case names (McDonald, DeLuca, O'Brien) exactly as stored, since those are
    intentional and str.title() would mangle them. str.title() capitalizes across
    spaces, hyphens and apostrophes, so 'mary-jane' and \"o'brien\" come out right.
    Also HTML-unescapes first: some records stored the name entity-escaped (e.g.
    \"desiree&#39; dallaguardia\"), which would otherwise print the raw entity."""
    s = _ihtml.unescape((s or "").strip())
    if s and (s == s.lower() or s == s.upper()):
        return s.title()
    return s


def _invoice_display_name(order):
    """Best-effort, Title-Cased billed-to name for the invoice. An order's own `name`
    column is blank for portal/reorder/import flows that don't re-collect it (the same
    gap the /api/orders board backfills). Resolve in order: order name → linked person
    record → people table by email → shipping-address name. Never raises."""
    def _resolve():
        nm = (order.get("name") or "").strip()
        if nm:
            return nm
        try:
            from dashboard import customers as _cust
            cx = _sqlite3.connect(LOG_DB)
            cx.row_factory = _sqlite3.Row
            try:
                pid = order.get("person_id")
                if pid:
                    p = _cust.get_person(cx, pid)
                    if p and (p.get("name") or "").strip():
                        return p["name"].strip()
                em = (order.get("email") or "").strip().lower()
                if em:
                    row = cx.execute(
                        "SELECT name FROM people WHERE lower(email)=? "
                        "AND TRIM(COALESCE(name,''))<>'' ORDER BY id LIMIT 1", (em,)).fetchone()
                    if row and (row["name"] or "").strip():
                        return row["name"].strip()
            finally:
                cx.close()
        except Exception as e:  # noqa: BLE001 — name is cosmetic; never break the invoice
            print(f"[invoice] name fallback skipped: {e!r}", flush=True)
        return ((order.get("address") or {}).get("name") or "").strip()
    return _titlecase_name(_resolve())


def _invoice_summary(order):
    """Customer-safe view — no person_id, notes, phone, or full address."""
    lines = order.get("items") or []
    subtotal = sum(int(l.get("line_cents") or 0) for l in lines)
    member_credit_cents = 0
    return {
        "member_credit_cents": member_credit_cents,
        "points_balance_cents": _invoice_points_balance(order),
        "external_ref": order.get("external_ref"),
        "created_at": order.get("created_at"),
        "name": _invoice_display_name(order),
        "invoice_note": order.get("invoice_note") or "",
        "lines": [_invoice_line_view(l) for l in lines],
        "subtotal_cents": subtotal,
        "discount_cents": int(order.get("discount_cents") or 0),
        "adjustment_cents": int(order.get("adjustment_cents") or 0),
        "shipping_cents": int(order.get("shipping_cents") or 0),
        "get_cents": int(order.get("get_cents") or 0),
        "points_redeemed_cents": int(order.get("points_redeemed_cents") or 0),
        "ship_credit_applied_cents": int(order.get("ship_credit_applied_cents") or 0),
        "total_cents": int(order.get("total_cents") or 0),
        "status": order.get("status"),
        "pay_status": order.get("pay_status") or "unpaid",
        "editable": order.get("status") in ("proposed", "confirmed"),
        "pay_enabled": bool(INVOICE_PAYLINK_ENABLED and _STRIPE_ACTIVE),
        "paylink_enabled": bool(INVOICE_PAYLINK_ENABLED),
    }


@app.route("/invoice/<token>")
def invoice_page(token):
    if not _pp.order_id_from_invoice_token(token):
        return ("<!doctype html><meta charset=utf-8><title>Invoice</title>"
                "<div style='font-family:sans-serif;max-width:480px;margin:80px auto;text-align:center'>"
                "<h2>This invoice link is invalid or has expired.</h2>"
                "<p>Please contact us for a fresh link.</p></div>"), 403
    resp = send_from_directory(STATIC, "invoice.html")
    resp.headers["Cache-Control"] = "no-cache, no-store, must-revalidate"
    return resp


@app.route("/api/invoice/<token>", methods=["GET"])
def api_invoice_get(token):
    order = _invoice_order_for_token(token)
    if not order:
        return jsonify({"ok": False, "error": "invalid or expired invoice"}), 404
    summary = _invoice_summary(order)
    summary["savings_offer"] = _order_savings_offer(order)   # switch-to-save (None unless a cheaper plan)
    oid = order.get("id")
    cx = _sqlite3.connect(LOG_DB)
    cx.row_factory = _sqlite3.Row
    try:
        _op.ensure_table(cx)
        _bal = _op.balance(cx, oid)
        _pays = [p for p in _op.list_payments(cx, oid)
                 if p["status"] == "active"]
        summary["payments"] = [
            {"date": (p["paid_at"] or "")[:10], "method": p["method"],
             "kind": p["kind"], "amount_cents": p["amount_cents"]} for p in _pays]
        summary["balance_due_cents"] = _bal["balance_cents"]
        summary["refunded_cents"] = _bal["refunded_cents"]
    finally:
        cx.close()
    if _read_receipts_enabled():
        try:
            # NOTE: aliased _opens (not _op) — a local `as _op` here would shadow
            # the module-level order_payments `_op` used above for the whole
            # function scope (Python's static scoping), raising UnboundLocalError
            # on every call regardless of whether this branch runs.
            from dashboard import opens as _opens
            with sqlite3.connect(LOG_DB) as _cxo:
                _opens.init_opens_table(_cxo)
                summary["opened"] = _opens.get_open(_cxo, "invoice", _opens.invoice_key(token))
        except Exception as _e:
            print(f"[opens] invoice {_e!r}", flush=True)
    return jsonify({"ok": True, "order": summary})


def _order_savings_offer(order):
    """Switch-to-save: would a plan this client ISN'T on make THIS (unpaid) order
    cheaper? Returns {cohort_key, cohort_name, current_total_cents, new_total_cents,
    savings_cents} or None. Dark unless COHORT_PRICING_ENABLED. Never raises."""
    try:
        if not _cohort_pricing_enabled():
            return None
        if order.get("pay_status") == "paid" or order.get("status") not in ("proposed", "confirmed"):
            return None
        email = (order.get("email") or "").strip().lower()
        if not email:
            return None
        from dashboard import cohorts as _co
        cx = _sqlite3.connect(LOG_DB)
        cx.row_factory = _sqlite3.Row
        try:
            _co.init_tables(cx)
            cands = _co.candidate_cohorts(cx, email)
            if not cands:
                return None
            earned = _earned_reorder_slugs(cx, email)
            lines, units = [], []
            for it in (order.get("items") or []):
                slug = (it.get("slug") or "").strip()
                p = _get_product(slug) if slug else None
                if not p:
                    continue
                lines.append({"slug": slug, "qty": int(it.get("qty") or 1),
                              "list_cents": int(p.get("price_cents") or 0), "is_ff": _qty_eligible(p)})
                units.append(int(it.get("unit_cents") or 0))
            return _co.savings_offer(lines, units, cands, earned_slugs=earned)
        finally:
            cx.close()
    except Exception as _e:
        print(f"[switch-to-save] offer skipped: {_e!r}", flush=True)
        return None


@app.route("/api/invoice/<token>/apply-plan", methods=["POST"])
def api_invoice_apply_plan(token):
    """Switch-to-save action: reprice THIS unpaid order at the chosen plan's prices
    (lowest-wins vs current); if forever=true, enroll the client in that cohort so
    future orders get it too. Client-authed by the invoice token."""
    order = _invoice_order_for_token(token)
    if not order:
        return jsonify({"ok": False, "error": "invalid or expired invoice"}), 404
    if order.get("pay_status") == "paid" or order.get("status") not in ("proposed", "confirmed"):
        return jsonify({"ok": False, "error": "this order can no longer be changed"}), 409
    body = request.get_json(silent=True) or {}
    key = (body.get("cohort_key") or "").strip()
    forever = bool(body.get("forever"))
    email = (order.get("email") or "").strip().lower()
    from dashboard import cohorts as _co
    cx = _sqlite3.connect(LOG_DB)
    cx.row_factory = _sqlite3.Row
    try:
        _co.init_tables(cx)
        c = _co.get_cohort(cx, key)
        if not c or not c.get("active"):
            return jsonify({"ok": False, "error": "plan not found"}), 404
        pol = c.get("policy") or {}
        earned = _earned_reorder_slugs(cx, email)
        new_items, new_sub = [], 0
        for it in (order.get("items") or []):
            slug = (it.get("slug") or "").strip()
            p = _get_product(slug) if slug else None
            unit = int(it.get("unit_cents") or 0)
            qty = int(it.get("qty") or 1)
            if p:
                is_ff = _qty_eligible(p)
                cand = (_co.reorder_loyalty_price([c], slug=slug, is_ff=is_ff, earned_slugs=earned)
                        if pol.get("type") == "reorder_loyalty"
                        else _co.policy_unit_cents(pol, slug=slug,
                                                   list_cents=int(p.get("price_cents") or 0), is_ff=is_ff))
                if cand is not None:
                    unit = min(unit, cand)
            ni = dict(it)
            ni["unit_cents"], ni["line_cents"] = unit, unit * qty
            new_items.append(ni)
            new_sub += unit * qty
        disc = int(order.get("discount_cents") or 0)
        adj = int(order.get("adjustment_cents") or 0)
        ship = int(order.get("shipping_cents") or 0)
        pts = int(order.get("points_redeemed_cents") or 0)
        new_total = max(0, max(0, new_sub - disc + adj) + ship - pts)
        _bos_orders.upsert_order(
            cx, source=order["source"], external_ref=order["external_ref"],
            email=order.get("email") or "", name=order.get("name") or "",
            items=new_items, total_cents=new_total, discount_cents=disc,
            adjustment_cents=adj, shipping_cents=ship, points_redeemed_cents=pts)
        if forever and email:
            _co.add_member(cx, email, key, source="switch-to-save")
        updated = _bos_orders.get_order(cx, order["id"])
    finally:
        cx.close()
    return jsonify({"ok": True, "switched_forever": bool(forever and email),
                    "order": _invoice_summary(updated)})


@app.route("/api/invoice/<token>/update", methods=["POST"])
def api_invoice_update(token):
    order = _invoice_order_for_token(token)
    if not order:
        return jsonify({"ok": False, "error": "invalid or expired invoice"}), 404
    if order.get("status") not in ("proposed", "confirmed"):
        return jsonify({"ok": False, "error": "this invoice can no longer be changed"}), 409
    body = request.get_json(silent=True) or {}
    cart, items_rec, subtotal_list = [], [], 0
    for ln in (body.get("lines") or []):
        slug = (ln.get("slug") or "").strip()
        p = _get_product(slug)
        if not p:
            continue
        qty = max(0, min(int(ln.get("qty") or 0), 99))
        if qty <= 0:
            continue
        unit_cents = int(p.get("price_cents") or 0)  # SERVER price only — ignore client
        line_cents = unit_cents * qty
        subtotal_list += line_cents
        cart.append({"slug": slug, "qty": qty})
        items_rec.append({"slug": slug, "name": p["name"], "qty": qty,
                          "unit_cents": unit_cents, "line_cents": line_cents})
    if not cart:
        return jsonify({"ok": False, "error": "no valid items"}), 400
    ship = order.get("address") or {}
    try:
        # Gate Type-2 order-total pricing on membership so a member editing their own
        # invoice is priced the same as at checkout (not overcharged).
        pc = _price_cart(cart, ship=ship, channel="retail",
                         program_member=_is_paid_member(order.get("email") or ""),
                         email=(order.get("email") or ""))
        discount_cents = int(pc.get("discount_cents") or 0)
        shipping_cents = _bos_orders.effective_shipping_cents(
            (order.get("channel") or "") == "pickup", pc.get("shipping_cents"))
        get_cents = int((pc.get("priced") or {}).get("get_cents") or 0)
    except Exception as e:
        print(f"[invoice.update] pricing fell back: {e!r}", flush=True)
        discount_cents, shipping_cents, get_cents = 0, 0, 0
    total_cents = max(0, subtotal_list - discount_cents) + shipping_cents
    # Carry points forward, re-capped to the new total AND the live balance.
    points = min(int(order.get("points_redeemed_cents") or 0), total_cents,
                 _invoice_points_balance(order))
    total_cents -= points
    cx = _sqlite3.connect(LOG_DB); cx.row_factory = _sqlite3.Row
    try:
        _bos_orders.upsert_order(
            cx, source=order["source"], external_ref=order["external_ref"],
            email=order.get("email") or "", name=order.get("name") or "",
            phone=order.get("phone") or "", person_id=order.get("person_id"),
            items=items_rec, total_cents=total_cents, address=ship,
            channel=(order.get("channel") or "retail"),
            get_cents=get_cents, discount_cents=discount_cents,
            points_redeemed_cents=points, shipping_cents=shipping_cents)
        updated = _bos_orders.get_order(cx, order["id"])
    finally:
        cx.close()
    try:
        from dashboard import inbox as _inbox
        _inbox.send_email("drglenswartwout@gmail.com",
                          f"Invoice {order.get('external_ref')} changed by customer",
                          f"Customer updated invoice {order.get('external_ref')} — "
                          f"new total ${total_cents/100:,.2f}.")
    except Exception as _e:
        print(f"[invoice] owner notify skipped: {_e!r}", flush=True)
    return jsonify({"ok": True, "order": _invoice_summary(updated)})


@app.route("/api/invoice/<token>/cancel", methods=["POST"])
def api_invoice_cancel(token):
    """Customer cancels their own unpaid order from the invoice page. Marks it
    cancelled (only while proposed/confirmed/new and not paid/shipped) and emails
    the owner so a client-initiated cancel is never silent."""
    order = _invoice_order_for_token(token)
    if not order:
        return jsonify({"ok": False, "error": "invalid or expired invoice"}), 404
    if order.get("pay_status") == "paid" or order.get("status") in _bos_orders._TERMINAL_STATUSES:
        return jsonify({"ok": False, "error": "This order can no longer be cancelled "
                        "online — please reach out and we'll help."}), 409
    cx = _sqlite3.connect(LOG_DB)
    cx.row_factory = _sqlite3.Row
    try:
        _bos_orders.set_order_status(cx, order["id"], "cancelled")
        try:  # best-effort audit note; never blocks the cancel
            cx.execute("UPDATE orders SET notes=COALESCE(notes,'')||? WHERE id=?",
                       (f"\n[cancelled by client {datetime.utcnow().date().isoformat()}]",
                        order["id"]))
            cx.commit()
        except Exception:
            pass
    finally:
        cx.close()
    try:
        from dashboard import inbox as _inbox
        ref = order.get("external_ref") or f"#{order['id']}"
        _inbox.send_email("drglenswartwout@gmail.com",
                          f"Order {ref} CANCELLED by customer",
                          f"{order.get('name') or ''} <{order.get('email') or ''}> cancelled order "
                          f"{ref} (${(int(order.get('total_cents') or 0))/100:,.2f}) from the invoice page.")
    except Exception as _e:
        print(f"[invoice] cancel notify skipped: {_e!r}", flush=True)
    return jsonify({"ok": True})


@app.route("/api/invoice/<token>/apply-points", methods=["POST"])
def api_invoice_apply_points(token):
    """Customer applies points against the invoice total. Server is the ONLY
    authority on the amount: capped to the pre-points total AND the live balance.
    Persisted as points_redeemed_cents so it's redeemed at payment."""
    order = _invoice_order_for_token(token)
    if not order:
        return jsonify({"ok": False, "error": "invalid or expired invoice"}), 404
    if order.get("status") not in ("proposed", "confirmed"):
        return jsonify({"ok": False, "error": "this invoice can no longer be changed"}), 409
    requested = max(0, int((request.get_json(silent=True) or {}).get("cents") or 0))
    # Work from the pre-points (gross) total so re-applying is idempotent.
    gross_total = int(order.get("total_cents") or 0) + int(order.get("points_redeemed_cents") or 0)
    new_points = max(0, min(requested, gross_total, _invoice_points_balance(order)))
    new_total = gross_total - new_points
    cx = _sqlite3.connect(LOG_DB); cx.row_factory = _sqlite3.Row
    try:
        _bos_orders.upsert_order(
            cx, source=order["source"], external_ref=order["external_ref"],
            email=order.get("email") or "", name=order.get("name") or "",
            phone=order.get("phone") or "", person_id=order.get("person_id"),
            items=order.get("items"), total_cents=new_total, address=order.get("address") or {},
            channel="retail", get_cents=int(order.get("get_cents") or 0),
            discount_cents=int(order.get("discount_cents") or 0),
            points_redeemed_cents=new_points, shipping_cents=int(order.get("shipping_cents") or 0))
        updated = _bos_orders.get_order(cx, order["id"])
    finally:
        cx.close()
    return jsonify({"ok": True, "order": _invoice_summary(updated)})


@app.route("/api/invoice/<token>/pay", methods=["POST"])
def api_invoice_pay(token):
    order = _invoice_order_for_token(token)
    if not order:
        return jsonify({"ok": False, "error": "invalid or expired invoice"}), 404
    if order.get("pay_status") == "paid" or order.get("status") not in ("proposed", "confirmed"):
        return jsonify({"ok": False, "error": "this invoice is already paid"}), 409
    if not INVOICE_PAYLINK_ENABLED:
        return jsonify({"ok": False, "error": "online payment is not enabled yet"}), 403
    method = ((request.get_json(silent=True) or {}).get("method") or "card").strip().lower()
    amount = int(order.get("total_cents") or 0)  # SERVER amount only
    if method == "card":
        _card_unavailable = ("Card payment is temporarily unavailable — "
                             "please use Zelle or Wise, or contact us.")
        if not _STRIPE_ACTIVE:
            return jsonify({"ok": False, "error": _card_unavailable}), 503
        from dashboard import stripe_pay as _sp
        ext = order.get("external_ref")
        # A Stripe failure (bad key, API error, timeout) must NOT 500 a paying
        # customer — degrade to a clean message pointing at Zelle/Wise.
        try:
            sess = _sp.create_checkout_session(
                amount, customer_email=order.get("email") or "",
                description=f"Remedy Match invoice {ext}",
                metadata={"kind": "in-house", "order_id": str(order["id"]),
                          "invoice_id": ext, "customer_id": ""},
                success_url=f"{PUBLIC_BASE_URL}/begin/checkout-return?session_id={{CHECKOUT_SESSION_ID}}",
                cancel_url=f"{PUBLIC_BASE_URL}/invoice/{token}")
            url = sess.get("url")
        except Exception as e:
            app.logger.warning(f"[invoice.pay] stripe session failed for {ext}: {e!r}")
            _alert_stripe("invoice-card", e)
            url = None
        if not url:
            return jsonify({"ok": False, "error": _card_unavailable}), 502
        return jsonify({"ok": True, "method": "card", "url": url})
    if method in ("zelle", "wise"):
        amt = "$%.2f" % (amount / 100)
        if method == "zelle":
            to = os.environ.get("ZELLE_PAY_TO", "drglenswartwout@gmail.com")
            instr = f"Send {amt} via Zelle to {to}, then tap “I’ve sent payment”."
        else:
            link = os.environ.get("WISE_PAY_LINK", "")
            instr = (f"Pay {amt} via Wise" + (f": {link}" if link else " — we’ll email you Wise details")
                     + ", then tap “I’ve sent payment”.")
        return jsonify({"ok": True, "method": method, "instructions": instr})
    return jsonify({"ok": False, "error": "unknown payment method"}), 400


@app.route("/api/invoice/<token>/claim-paid", methods=["POST"])
def api_invoice_claim_paid(token):
    order = _invoice_order_for_token(token)
    if not order:
        return jsonify({"ok": False, "error": "invalid or expired invoice"}), 404
    if order.get("pay_status") == "paid" or order.get("status") not in ("proposed", "confirmed"):
        return jsonify({"ok": False, "error": "this invoice is already paid"}), 409
    method = ((request.get_json(silent=True) or {}).get("method") or "").strip().lower()
    if method not in ("zelle", "wise"):
        return jsonify({"ok": False, "error": "unknown payment method"}), 400
    cx = _sqlite3.connect(LOG_DB); cx.row_factory = _sqlite3.Row
    try:
        _bos_orders.set_order_payment_claimed(cx, order["id"], method=method)
    finally:
        cx.close()
    try:
        from dashboard import inbox as _inbox
        _inbox.send_email(
            "drglenswartwout@gmail.com",
            f"Payment claimed: invoice {order.get('external_ref')}",
            f"{order.get('name') or 'A customer'} reports sending "
            f"${int(order.get('total_cents') or 0)/100:,.2f} via {method} for invoice "
            f"{order.get('external_ref')}. Confirm receipt, then Record payment.")
    except Exception as _e:
        print(f"[invoice] claim notify skipped: {_e!r}", flush=True)
    return jsonify({"ok": True, "message": "Thanks — we’ll confirm your payment shortly."})


@app.route("/api/invoice/<token>/chat", methods=["POST"])
def api_invoice_chat(token):
    order = _invoice_order_for_token(token)
    if not order:
        return jsonify({"ok": False, "error": "invalid or expired invoice"}), 404
    email = (order.get("email") or "").strip().lower()
    body = request.get_json(silent=True) or {}
    catalog = _build_ff_catalog()
    _ally_ov = ash_ally.ally_overlay(LOG_DB, email)
    _msg = body.get("message") or ""
    result = _chat.scoped_reply(_msg, body.get("history") or [], catalog, overlay=_ally_ov)
    try:
        import threading as _t
        _t.Thread(target=ash_ally.record_turn,
                  args=(LOG_DB, _db_lock, email, _msg, result.get("reply", "")),
                  daemon=True).start()
    except Exception:
        pass
    suggestions = []
    for slug in (result.get("suggested_slugs") or []):
        p = _get_product(slug)
        if not p:
            continue
        suggestions.append({"slug": slug, "name": p.get("name") or slug,
                            "price_cents": p.get("price_cents") or 0})
    return jsonify({"ok": True, "reply": result.get("reply", ""), "suggestions": suggestions})


