@app.route("/api/orders", methods=["GET", "POST"])
def bos_orders_create():
    actor = _bos_actor()
    if actor is None:
        return jsonify({"ok": False, "error": "unauthorized"}), 401
    if request.method == "GET":
        cx = _sqlite3.connect(LOG_DB)
        cx.row_factory = _sqlite3.Row
        try:
            try:
                rows = _bos_orders.list_orders(
                    cx, status=request.args.get("status"),
                    limit=min(int(request.args.get("limit", 200) or 200), 500))
            except (TypeError, ValueError):
                rows = _bos_orders.list_orders(cx)
            # Annotate each order with per-line fulfillment + backorder units, using a
            # single grouped query over order_fulfillments (no per-order round-trips).
            try:
                filled = {}
                for e in cx.execute(
                        "SELECT order_id, line_index, COALESCE(SUM(qty),0) FROM order_fulfillments "
                        "GROUP BY order_id, line_index").fetchall():
                    filled[(int(e[0]), int(e[1]))] = int(e[2])
                for o in rows:
                    oid = int(o.get("id"))
                    back = 0
                    flines = []
                    for i, it in enumerate(o.get("items") or []):
                        ordered = int(it.get("qty") or 0)
                        f = filled.get((oid, i), 0)
                        bo = max(0, ordered - f)
                        back += bo
                        flines.append({"index": i, "ordered": ordered, "fulfilled": f, "backordered": bo})
                    o["fulfillment"] = flines
                    o["backorder_units"] = back
            except Exception as _e:
                print(f"[orders] backorder annotate skipped: {_e!r}", flush=True)
            # Display-name fallback: many orders carry only a shipping name, which is
            # blank for portal/reorder flows that don't re-collect it. Backfill the
            # display name from the people table by email (one grouped query).
            try:
                need = sorted({(o.get("email") or "").strip().lower()
                               for o in rows if not (o.get("name") or "").strip()
                               and (o.get("email") or "").strip()})
                if need:
                    ph = ",".join("?" * len(need))
                    by_email = {}
                    for em, nm in cx.execute(
                            f"SELECT lower(email), name FROM people WHERE lower(email) IN ({ph})",
                            need).fetchall():
                        if (nm or "").strip() and em not in by_email:
                            by_email[em] = nm.strip()
                    for o in rows:
                        if not (o.get("name") or "").strip():
                            o["name"] = by_email.get((o.get("email") or "").strip().lower(), o.get("name") or "")
                # Title-Case the display name on every card: names are often stored
                # all-lowercase by import/portal flows. Same rule as the invoice —
                # only re-cases values that are entirely one case, leaving already
                # mixed-case names (McDonald, DeLuca) intact.
                for o in rows:
                    o["name"] = _titlecase_name(o.get("name"))
            except Exception as _e:
                print(f"[orders] name backfill skipped: {_e!r}", flush=True)
            # Annotate each order with the client's published biofield report PDF
            # (latest CONFIRMED report only), so Rae can print it at pack time.
            try:
                from dashboard import portal_biofield_reports as _pbr
                _pbr.init_table(cx)
                emails = {(o.get("email") or "").strip().lower()
                          for o in rows if (o.get("email") or "").strip()}
                pdf_urls = _pbr.report_pdf_urls(cx, emails)
                for o in rows:
                    o["biofield_pdf_url"] = pdf_urls.get((o.get("email") or "").strip().lower(), "")
            except Exception as _e:
                print(f"[orders] biofield pdf annotate skipped: {_e!r}", flush=True)
            # Ledger paid/balance annotation: attach ledger_paid_cents/ledger_balance_cents
            # ONLY to orders that have active order_payments rows (a payment or refund
            # recorded), so pre-ledger / legacy-paid orders keep their pay_status badge
            # without a misleading "balance = full total". One grouped query — no
            # per-order round-trips. Raw SQL (NOT the _op module: this handler locally
            # rebinds `_op` to dashboard.opens further down, which would shadow it).
            try:
                _led = {}
                for e in cx.execute(
                        "SELECT order_id, kind, COALESCE(SUM(amount_cents),0) FROM order_payments "
                        "WHERE status='active' GROUP BY order_id, kind").fetchall():
                    _led.setdefault(int(e[0]), {"payment": 0, "refund": 0})[e[1]] = int(e[2] or 0)
                for o in rows:
                    led = _led.get(int(o.get("id")))
                    if led:
                        paid = led["payment"] - led["refund"]
                        o["ledger_paid_cents"] = paid
                        o["ledger_balance_cents"] = int(o.get("total_cents") or 0) - paid
            except Exception as _e:
                print(f"[orders] ledger balance annotate skipped: {_e!r}", flush=True)
            # Reward-gift attach (Phase 2 Slice 2 Task 4): show a member's earned-but-
            # unfulfilled reward gift on the pack board for their next order, across ALL
            # order sources, so Rae can pack it. Gated — off by default, no payload change.
            try:
                if _reward_gifts_enabled():
                    from dashboard import review_gifts as _rg
                    for o in rows:
                        o["reward_gifts"] = _rg.pending_reward_for(cx, (o.get("email") or "").strip().lower())
            except Exception as _e:
                print(f"[orders] reward-gift annotate skipped: {_e!r}", flush=True)
            # Read-receipts (Task 5): additive, best-effort — whether the client
            # has opened the invoice link most recently SENT for this order
            # (orders.invoice_token, set by orders.send_invoice). Orders that
            # were never sent an invoice (or only reprinted, never sent) carry
            # no token and get no annotation.
            try:
                from dashboard import opens as _op
                _op.init_opens_table(cx)
                for o in rows:
                    tok = (o.get("invoice_token") or "").strip()
                    if tok:
                        o["invoice_opened"] = _op.get_open(cx, "invoice", _op.invoice_key(tok))
            except Exception as _e:
                print(f"[orders] invoice open annotate skipped: {_e!r}", flush=True)
        finally:
            cx.close()
        return jsonify({"ok": True, "data": rows})
    # --- existing POST body unchanged below ---
    b = request.get_json(silent=True) or {}
    ref = str(b.get("external_ref") or f"manual-{_bos_orders._now()}")
    cx = _sqlite3.connect(LOG_DB)
    cx.row_factory = _sqlite3.Row
    try:
        oid = _bos_orders.upsert_order(
            cx, source="manual", external_ref=ref, email=b.get("email", ""),
            name=b.get("name", ""), phone=b.get("phone", ""), items=b.get("items") or [],
            total_cents=int(b.get("total_cents") or 0), address=b.get("address") or {},
            channel=b.get("channel", "retail"))
        try:
            _hold_new_order_and_invite(cx, oid)
        except Exception as _e:
            print(f"[hold] hold+invite skipped: {_e!r}", flush=True)
    except Exception as e:
        return jsonify({"ok": False, "error": str(e)}), 400
    finally:
        cx.close()
    return jsonify({"ok": True, "order_id": oid})


@app.route("/api/backorders", methods=["GET"])
def bos_backorders():
    """Reorder worklist: per-product units backordered across open orders."""
    actor = _bos_actor()
    if actor is None or actor.role not in (_bos_rbac.OWNER, _bos_rbac.OPS):
        return jsonify({"ok": False, "error": "unauthorized"}), 401
    cx = _sqlite3.connect(LOG_DB)
    cx.row_factory = _sqlite3.Row
    try:
        data = _bos_orders.backorder_rollup(cx)
    finally:
        cx.close()
    return jsonify({"ok": True, "data": data})


